landmarks:index:v1:fd3f208d8a36c2d4c1635faf71ebfd48	a:3:{s:4:"data";a:2:{i:0;a:18:{s:2:"id";i:456;s:7:"city_id";i:18;s:4:"city";a:3:{s:2:"id";i:18;s:4:"slug";s:5:"amran";s:4:"name";s:10:"عمران";}s:11:"external_id";s:14:"amran-old-city";s:4:"name";s:36:"مدينة عمران القديمة";s:7:"name_en";s:17:"Old City of Amran";s:11:"description";s:351:"عاصمة المحافظة، وتتميز ببوابتها القديمة (باب اليمن) وأسوارها الطينية. [7] تشتهر بمنازلها المبنية من الطين (الزابور) والتي تتميز بطراز معماري فريد يختلف عن المدن الحجرية المجاورة مثل ثلا وشبام. [7]";s:14:"description_en";s:252:"The capital of the governorate, distinguished by its ancient gate (Bab al-Yemen) and mud walls. [7] It is renowned for its mud-built houses (Zabur) featuring a unique architectural style distinct from neighboring stone cities like Thula and Shibam. [7]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:8:"mudbrick";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:6:"طين";}s:8:"latitude";d:15.65;s:9:"longitude";d:43.95;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:1;a:18:{s:2:"id";i:6;s:7:"city_id";i:1;s:4:"city";a:3:{s:2:"id";i:1;s:4:"slug";s:5:"sanaa";s:4:"name";s:10:"صنعاء";}s:11:"external_id";s:18:"sanaa-bab-al-yaman";s:4:"name";s:17:"باب اليمن";s:7:"name_en";s:12:"Bab al-Yemen";s:11:"description";s:449:"هو البوابة الرئيسية المتبقية لسور صنعاء القديم، ويعتبر المدخل الجنوبي للمدينة التاريخية. يعود تاريخه إلى أكثر من ألف عام، ويتميز بتصميمه المهيب الذي يعكس تاريخ صنعاء العريق. يؤدي مباشرة إلى سوق الملح والساحة المقابلة له التي تعج بالنشاط والحياة.";s:14:"description_en";s:297:"It is the main remaining gate of the wall of the Old City of Sana'a and serves as the southern entrance to the historic city. Dating back over a thousand years, it features a majestic design that reflects Sana'a's ancient history. It leads directly to Souq Al-Milh and its vibrant adjacent square.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:4:"gate";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"بوابة";}s:8:"latitude";d:15.3514045;s:9:"longitude";d:44.2162899;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:115:"https://www.yementourism.com/images/aathenewpic/bodyimg/onlyinyemen/Architectures/sanaa-city-in-yemen-1600x1071.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}}s:5:"links";a:4:{s:5:"first";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=1";s:4:"last";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=1";s:4:"prev";N;s:4:"next";N;}s:4:"meta";a:8:{s:12:"current_page";i:1;s:4:"from";i:1;s:9:"last_page";i:1;s:5:"links";a:3:{i:0;a:3:{s:3:"url";N;s:5:"label";s:16:"&laquo; Previous";s:6:"active";b:0;}i:1;a:3:{s:3:"url";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=1";s:5:"label";s:1:"1";s:6:"active";b:1;}i:2;a:3:{s:3:"url";N;s:5:"label";s:12:"Next &raquo;";s:6:"active";b:0;}}s:4:"path";s:44:"http://localhost:8000/api/v1/admin/landmarks";s:8:"per_page";i:15;s:2:"to";i:2;s:5:"total";i:2;}}	1777493585
landmarks:index:v1:f9857f782789f2039447c53d05a3ab39	a:3:{s:4:"data";a:15:{i:0;a:18:{s:2:"id";i:612;s:7:"city_id";i:24;s:4:"city";a:3:{s:2:"id";i:24;s:4:"slug";s:6:"hadibo";s:4:"name";s:10:"حديبو";}s:11:"external_id";s:14:"shabwah-castle";s:4:"name";s:17:"قلعة شبوة";s:7:"name_en";s:14:"Shabwah Castle";s:11:"description";s:236:"قلعة تاريخية تقع في محافظة شبوة، تتميز بموقعها الاستراتيجي وعمارتها الدفاعية المميزة. تعتبر من أهم المعالم التاريخية في المنطقة.";s:14:"description_en";s:209:"A historic castle situated in Shabwah Governorate, distinguished by its strategic location and distinctive defensive architecture. It is considered one of the most important historical landmarks in the region.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"عسكري";}s:8:"latitude";d:14.53;s:9:"longitude";i:47;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/shabwah/shabwah_castle1.jpg";i:1;s:44:"images/landmarks/shabwah/shabwah_castle2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:1;a:18:{s:2:"id";i:581;s:7:"city_id";i:23;s:4:"city";a:3:{s:2:"id";i:23;s:4:"slug";s:6:"mahrah";s:4:"name";s:12:"المهرة";}s:11:"external_id";s:19:"hawf-forest-reserve";s:4:"name";s:34:"محمية حوف الطبيعية";s:7:"name_en";s:19:"Hawf Nature Reserve";s:11:"description";s:481:"أهم وأشهر معلم في المهرة، وهي أكبر غابة موسمية في شبه الجزيرة العربية. [1, 2] خلال موسم الخريف (من يونيو إلى سبتمبر)، تتحول جبالها إلى بساط أخضر كثيف يغطيه الضباب، وتتدفق فيها الشلالات، مما يخلق منظراً استوائياً فريداً. وهي مدرجة ضمن مواقع التراث العالمي لليونسكو. [1, 2]";s:14:"description_en";s:361:"The most important and famous landmark in Al Mahrah, being the largest seasonal forest in the Arabian Peninsula. [1, 2] During the Khareef (monsoon) season (from June to September), its mountains turn into a dense green carpet blanketed in fog, with cascading waterfalls, creating a unique tropical scene. It is inscribed as a UNESCO World Heritage site. [1, 2]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:7:"reserve";i:2;s:6:"forest";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"محمية";i:2;s:8:"غابة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:16.65;s:9:"longitude";d:53.05;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:2;a:18:{s:2:"id";i:559;s:7:"city_id";i:22;s:4:"city";a:3:{s:2:"id";i:22;s:4:"slug";s:7:"shabwah";s:4:"name";s:8:"شبوة";}s:11:"external_id";s:14:"shabwah-castle";s:4:"name";s:17:"قلعة شبوة";s:7:"name_en";s:14:"Shabwah Castle";s:11:"description";s:236:"قلعة تاريخية تقع في محافظة شبوة، تتميز بموقعها الاستراتيجي وعمارتها الدفاعية المميزة. تعتبر من أهم المعالم التاريخية في المنطقة.";s:14:"description_en";s:209:"A historic castle situated in Shabwah Governorate, distinguished by its strategic location and distinctive defensive architecture. It is considered one of the most important historical landmarks in the region.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"عسكري";}s:8:"latitude";d:14.53;s:9:"longitude";i:47;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/shabwah/shabwah_castle1.jpg";i:1;s:44:"images/landmarks/shabwah/shabwah_castle2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:18:{s:2:"id";i:518;s:7:"city_id";i:21;s:4:"city";a:3:{s:2:"id";i:21;s:4:"slug";s:5:"lahij";s:4:"name";s:6:"لحج";}s:11:"external_id";s:13:"dar-al-aroosa";s:4:"name";s:45:"دار العرائس (قصر السلطان)";s:7:"name_en";s:30:"Dar Al-Arais (Sultan's Palace)";s:11:"description";s:366:"أشهر معلم في مدينة الحوطة، كان القصر الصيفي لسلاطين لحج. [1, 2] يتميز بطرازه المعماري الفريد الذي يمزج بين الطابعين الهندي والعربي، وكان مركزاً للحياة السياسية والثقافية والفنية في السلطنة العبدلية. [1, 2]";s:14:"description_en";s:279:"The most famous landmark in the city of Al-Hawtah, it was the summer palace for the Sultans of Lahij. [1, 2] Featuring a unique architectural style that blends Indian and Arab aesthetics, it was a hub for political, cultural, and artistic life during the Abdali Sultanate. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:10:"ثقافي";}s:8:"latitude";d:13.058;s:9:"longitude";d:44.885;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:18:{s:2:"id";i:501;s:7:"city_id";i:20;s:4:"city";a:3:{s:2:"id";i:20;s:4:"slug";s:6:"aljawf";s:4:"name";s:10:"الجوف";}s:11:"external_id";s:21:"baraqish-ancient-city";s:4:"name";s:45:"مدينة براقش (يثل القديمة)";s:7:"name_en";s:34:"City of Baraqish (Ancient Yathill)";s:11:"description";s:395:"أشهر وأهم مدينة أثرية في الجوف، كانت عاصمة مملكة معين الدينية. [1, 2] تتميز بسورها العظيم وأبراجها الـ 57 التي لا تزال قائمة، وتضم بداخلها بقايا معابد وقصور ومنازل، وتعتبر من أكمل المدن الأثرية في شبه الجزيرة العربية. [1, 2]";s:14:"description_en";s:324:"The most famous and significant ancient city in Al-Jawf, it was the religious capital of the Minaean Kingdom. [1, 2] Known for its great wall and 57 towers that still stand, it houses the remains of temples, palaces, and homes inside. It is considered one of the most complete ancient cities in the Arabian Peninsula. [1, 2]";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:7:"ancient";i:3;s:4:"city";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"قديم";i:3;s:10:"مدينة";}s:8:"latitude";d:15.8333;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:18:{s:2:"id";i:481;s:7:"city_id";i:19;s:4:"city";a:3:{s:2:"id";i:19;s:4:"slug";s:5:"dhale";s:4:"name";s:12:"الضالع";}s:11:"external_id";s:11:"jabal-jihaf";s:4:"name";s:15:"جبل جحاف";s:7:"name_en";s:11:"Mount Jihaf";s:11:"description";s:384:"أحد أشهر وأعلى الجبال في الضالع، وهو عبارة عن سلسلة جبلية واسعة تضم العديد من القرى والحصون. [1, 2] يشتهر بزراعة البن عالي الجودة، ومدرجاته الزراعية الخضراء، وأجوائه المعتدلة، ويعتبر محمية طبيعية وسياحية متكاملة.";s:14:"description_en";s:296:"One of the most famous and highest mountains in Ad Dhale, it is a broad mountain range comprising many villages and forts. [1, 2] It is renowned for cultivating high-quality coffee, its green agricultural terraces, and a moderate climate, rendering it a comprehensive natural and tourist reserve.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:13.75;s:9:"longitude";d:44.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:18:{s:2:"id";i:451;s:7:"city_id";i:18;s:4:"city";a:3:{s:2:"id";i:18;s:4:"slug";s:5:"amran";s:4:"name";s:10:"عمران";}s:11:"external_id";s:19:"thula-historic-city";s:4:"name";s:38:"مدينة ثُلا التاريخية";s:7:"name_en";s:22:"Historic City of Thula";s:11:"description";s:445:"واحدة من أجمل وأكمل المدن التاريخية المحصنة في اليمن، وهي مدرجة على القائمة التمهيدية لليونسكو. [1, 2] تتميز بسورها الحجري الذي يحيط بها، ومنازلها البرجية الشاهقة المبنية من الحجر، وشوارعها المرصوفة، وحصنها المنيع (حصن الغراب) الذي يطل عليها. [1, 2]";s:14:"description_en";s:314:"One of the most beautiful and complete fortified historic cities in Yemen, inscribed on the UNESCO tentative list. [1, 2] It is distinguished by the stone wall surrounding it, its towering stone-built tower houses, its paved streets, and its impregnable fort (Mutahhar Fort/Fort of the Crow) overlooking it. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:6:"unesco";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"يونسكو";i:3;s:12:"معماري";}s:8:"latitude";d:15.5833;s:9:"longitude";d:43.8833;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:18:{s:2:"id";i:420;s:7:"city_id";i:17;s:4:"city";a:3:{s:2:"id";i:17;s:4:"slug";s:5:"bayda";s:4:"name";s:14:"البيضاء";}s:11:"external_id";s:20:"amiriya-school-radaa";s:4:"name";s:42:"المدرسة العامرية (رداع)";s:7:"name_en";s:24:"Amiriya Madrasa (Rada'a)";s:11:"description";s:416:"تحفة معمارية إسلامية فريدة تقع في مدينة رداع. بناها السلطان عامر بن عبدالوهاب الطاهري عام 1504م. [1, 2] تتميز بقبابها المزخرفة وكتاباتها ونقوشها الجصية الملونة، وتعتبر من أهم المعالم الإسلامية في اليمن وكانت مركزاً علمياً هاماً. [1, 2]";s:14:"description_en";s:331:"A unique Islamic architectural masterpiece located in the city of Rada'a. Built by Sultan Amir bin Abdulwahab Al-Tahir in 1504 AD. [1, 2] It features ornate domes, colorful stucco inscriptions, and carvings, and is considered one of the most important Islamic landmarks in Yemen, having been a significant scientific center. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:7:"islamic";i:3;s:6:"school";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:12:"إسلامي";i:3;s:10:"مدرسة";}s:8:"latitude";d:14.4147;s:9:"longitude";d:44.7731;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:18:{s:2:"id";i:399;s:7:"city_id";i:16;s:4:"city";a:3:{s:2:"id";i:16;s:4:"slug";s:6:"mahwit";s:4:"name";s:14:"المحويت";}s:11:"external_id";s:15:"shibam-kawkaban";s:4:"name";s:32:"مدينة شبام كوكبان";s:7:"name_en";s:20:"Shibam Kawkaban City";s:11:"description";s:422:"مدينة تاريخية فريدة تتكون من جزأين: شبام التي تقع أسفل الجبل، وكوكبان المدينة المحصنة على قمته. [1, 2] ترتبطان بطريق مشاة صخري متدرج، وتشتهر كوكبان بحصونها ومنازلها الشاهقة ومساجدها التاريخية، وتوفر إطلالات بانورامية لا مثيل لها. [1, 2]";s:14:"description_en";s:323:"A unique historical city consisting of two parts: Shibam, located at the foot of the mountain, and Kawkaban, the fortified city on its summit. [1, 2] They are connected by a stepped rocky pedestrian path. Kawkaban is famous for its forts, towering houses, and historic mosques, offering unparalleled panoramic views. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:8:"mountain";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:8:"جبلي";i:3;s:12:"معماري";}s:8:"latitude";d:15.5136;s:9:"longitude";d:43.8819;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:18:{s:2:"id";i:369;s:7:"city_id";i:15;s:4:"city";a:3:{s:2:"id";i:15;s:4:"slug";s:6:"hajjah";s:4:"name";s:6:"حجة";}s:11:"external_id";s:21:"qalat-alqahira-hajjah";s:4:"name";s:32:"قلعة القاهرة (حجة)";s:7:"name_en";s:21:"Cairo Castle (Hajjah)";s:11:"description";s:401:"من أبرز القلاع التاريخية في اليمن، تقع على قمة جبل وتطل على مدينة حجة. [1, 2] يعود تاريخها إلى القرن الحادي عشر الميلادي، وكانت حصناً استراتيجياً ومركزاً للحكم، وتتميز بعمارتها العسكرية الفريدة وإطلالاتها البانورامية. [1, 2]";s:14:"description_en";s:287:"One of the most prominent historical castles in Yemen, located atop a mountain overlooking the city of Hajjah. [1, 2] Dating back to the 11th century AD, it was a strategic fortress and a center of governance, distinguished by its unique military architecture and panoramic views. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";i:3;s:6:"مطل";}s:8:"latitude";d:15.6897;s:9:"longitude";d:43.5975;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:18:{s:2:"id";i:349;s:7:"city_id";i:14;s:4:"city";a:3:{s:2:"id";i:14;s:4:"slug";s:5:"abean";s:4:"name";s:8:"أبين";}s:11:"external_id";s:11:"abyan-delta";s:4:"name";s:17:"دلتا أبين";s:7:"name_en";s:11:"Abyan Delta";s:11:"description";s:301:"تعتبر من أخصب الأراضي الزراعية في اليمن وتشتهر بزراعة الفواكه والخضروات والقطن طويل التيلة. [1, 10] تمثل الدلتا منظراً طبيعياً خلاباً وتعتبر سلة غذاء رئيسية للمنطقة. [1]";s:14:"description_en";s:228:"Considered one of the most fertile agricultural lands in Yemen, famous for cultivating fruits, vegetables, and long-staple cotton. [1, 10] The delta is a breathtaking natural landscape and a major breadbasket for the region. [1]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:11:"agriculture";i:2;s:6:"scenic";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"زراعة";i:2;s:21:"مناظر خلابة";}s:8:"latitude";d:13.1667;s:9:"longitude";d:45.3333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:18:{s:2:"id";i:334;s:7:"city_id";i:13;s:4:"city";a:3:{s:2:"id";i:13;s:4:"slug";s:5:"shihr";s:4:"name";s:10:"الشحر";}s:11:"external_id";s:22:"ash-shihr-grand-mosque";s:4:"name";s:38:"الجامع الكبير بالشحر";s:7:"name_en";s:25:"Great Mosque in Ash Shihr";s:11:"description";s:354:"يُعد أول مسجد بني في حضرموت في السنة العاشرة للهجرة. [4, 12] مر المسجد بالعديد من التجديدات والتوسعات عبر تاريخه الطويل، ويتميز بعمارته الإسلامية التقليدية، وكان مركزاً هاماً للعلم ونشر الدين. [4, 16]";s:14:"description_en";s:292:"Considered the first mosque built in Hadhramaut in the tenth year of Hijra. [4, 12] The mosque has undergone many renovations and expansions over its long history, characterized by its traditional Islamic architecture, and was an important center for knowledge and spreading religion. [4, 16]";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:14.754023;s:9:"longitude";d:49.605589;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:18:{s:2:"id";i:323;s:7:"city_id";i:12;s:4:"city";a:3:{s:2:"id";i:12;s:4:"slug";s:6:"seiyun";s:4:"name";s:10:"سيئون";}s:11:"external_id";s:23:"seiyun-alkathiri-palace";s:4:"name";s:56:"قصر سيئون (قصر السلطان الكثيري)";s:7:"name_en";s:39:"Seiyun Palace (Kathiri Sultan's Palace)";s:11:"description";s:343:"أكبر مبنى طيني في العالم وأبرز معلم في وادي حضرموت. [1] كان القصر مقراً للسلطنة الكثيرية، ويتميز بتصميمه الفريد ولونه الأبيض، ويضم حالياً متحفاً للآثار. صورته مطبوعة على فئة الألف ريال يمني.";s:14:"description_en";s:304:"The largest mud-brick building in the world and the most prominent landmark in Wadi Hadhramaut. [1] The palace was the seat of the Kathiri Sultanate, distinguished by its unique design and white color, and currently houses an archaeological museum. Its image is printed on the 1,000 Yemeni Rial banknote.";s:10:"categories";a:5:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:6:"museum";i:4;s:8:"landmark";}s:14:"category_names";a:5:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:8:"متحف";i:4;s:8:"معلم";}s:8:"latitude";d:15.966;s:9:"longitude";d:48.778;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/seiyun/alkathiri_palace1.jpg";i:1;s:45:"images/landmarks/seiyun/alkathiri_palace2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:18:{s:2:"id";i:306;s:7:"city_id";i:11;s:4:"city";a:3:{s:2:"id";i:11;s:4:"slug";s:5:"saada";s:4:"name";s:8:"صعدة";}s:11:"external_id";s:14:"saada-old-city";s:4:"name";s:34:"مدينة صعدة القديمة";s:7:"name_en";s:18:"Old City of Sa'dah";s:11:"description";s:359:"مدينة تاريخية فريدة محاطة بسور طيني ضخم، وتعتبر من أقدم المدن المأهولة في اليمن. [1] تتميز بمنازلها الطينية المزخرفة، وأزقتها الضيقة، وأسواقها التقليدية، وتضم العديد من المساجد والمقابر التاريخية.";s:14:"description_en";s:253:"A unique historical city surrounded by a massive mud wall, considered one of the oldest inhabited cities in Yemen. [1] It is characterized by its decorated mud houses, narrow alleys, and traditional markets, and houses many historical mosques and tombs.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:8:"cultural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:10:"ثقافي";}s:8:"latitude";d:16.943;s:9:"longitude";d:43.761;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/saada/saada_old_city1.jpg";i:1;s:42:"images/landmarks/saada/saada_old_city2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:18:{s:2:"id";i:277;s:7:"city_id";i:10;s:4:"city";a:3:{s:2:"id";i:10;s:4:"slug";s:6:"dhamar";s:4:"name";s:8:"ذمار";}s:11:"external_id";s:19:"dhamar-grand-mosque";s:4:"name";s:36:"الجامع الكبير بذمار";s:7:"name_en";s:22:"Great Mosque of Dhamar";s:11:"description";s:363:"أحد أقدم المساجد في اليمن، يُقال إن أساساته تعود إلى فترة معاذ بن جبل. [1] يتميز بتصميمه الذي يجمع بين الأصالة والزخارف الإسلامية، وبمكتبته التي تضم مخطوطات نادرة، ويعتبر قلب المدينة الروحي والتاريخي.";s:14:"description_en";s:295:"One of the oldest mosques in Yemen, its foundations are said to date back to the time of Muadh bin Jabal. [1] It is characterized by its design combining authenticity with Islamic decorations, and its library housing rare manuscripts. It serves as the spiritual and historical heart of the city.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";i:3;s:12:"إسلامي";}s:8:"latitude";d:14.553;s:9:"longitude";d:44.405;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:48:"images/landmarks/dhamar/dhamar_grand_mosque1.jpg";i:1;s:48:"images/landmarks/dhamar/dhamar_grand_mosque2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:5:"links";a:4:{s:5:"first";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=1";s:4:"last";s:52:"http://localhost:8000/api/v1/admin/landmarks?page=42";s:4:"prev";N;s:4:"next";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=2";}s:4:"meta";a:8:{s:12:"current_page";i:1;s:4:"from";i:1;s:9:"last_page";i:42;s:5:"links";a:15:{i:0;a:3:{s:3:"url";N;s:5:"label";s:16:"&laquo; Previous";s:6:"active";b:0;}i:1;a:3:{s:3:"url";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=1";s:5:"label";s:1:"1";s:6:"active";b:1;}i:2;a:3:{s:3:"url";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=2";s:5:"label";s:1:"2";s:6:"active";b:0;}i:3;a:3:{s:3:"url";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=3";s:5:"label";s:1:"3";s:6:"active";b:0;}i:4;a:3:{s:3:"url";s:51:"http://localhost:8000/api/v1/admin/landmarks?page=4";s:5:"