cities:index:v1:sall:qnone:p1:pp100	a:3:{s:4:"data";a:29:{i:0;a:13:{s:2:"id";i:6;s:4:"slug";s:3:"ibb";s:4:"name";s:4:"إب";s:7:"name_en";s:3:"Ibb";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:12:"ibb_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:50;s:9:"landmarks";a:50:{i:0;a:17:{s:2:"id";i:178;s:7:"city_id";i:6;s:11:"external_id";s:10:"ibb-palace";s:4:"name";s:28:"قصر إب التاريخي";s:7:"name_en";s:19:"Historic Ibb Palace";s:11:"description";s:270:"قصر تاريخي يقع في مدينة إب، يتميز بعمارته اليمنية التقليدية الفريدة وزخارفه الجميلة. يعكس تاريخ وثقافة المنطقة ويعتبر من أهم المعالم السياحية فيها.";s:14:"description_en";s:242:"A historic palace located in the city of Ibb, notable for its unique traditional Yemeni architecture and beautiful decorations. It reflects the history and culture of the region and is considered one of its most important tourist attractions.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"ثقافي";}s:8:"latitude";d:13.9638123;s:9:"longitude";d:44.1908959;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/ycgokoCmdyNar16g7";s:6:"images";a:2:{i:0;s:36:"images/landmarks/ibb/ibb_palace1.jpg";i:1;s:36:"images/landmarks/ibb/ibb_palace2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:1;a:17:{s:2:"id";i:179;s:7:"city_id";i:6;s:11:"external_id";s:12:"ibb-old-city";s:4:"name";s:30:"مدينة إب القديمة";s:7:"name_en";s:15:"Old City of Ibb";s:11:"description";s:367:"القلب التاريخي لمدينة إب، تتميز بأزقتها المرصوفة بالحجارة ومبانيها الشاهقة المبنية من الحجر والمزينة بالزخارف الجصية (القضاض). [1] التجول فيها يأخذك في رحلة عبر الزمن لمشاهدة العمارة اليمنية التقليدية.";s:14:"description_en";s:245:"The historical heart of Ibb city, characterized by its cobblestone alleys and towering stone buildings adorned with gypsum decorations (Qadadh). [1] Strolling through it takes you on a journey through time to see traditional Yemeni architecture.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"cultural";i:2;s:13:"architectural";i:3;s:4:"city";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"ثقافي";i:2;s:12:"معماري";i:3;s:10:"مدينة";}s:8:"latitude";d:13.97;s:9:"longitude";d:44.185;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/landmarks/ibb/ibb_old_city1.jpg";i:1;s:38:"images/landmarks/ibb/ibb_old_city2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:2;a:17:{s:2:"id";i:180;s:7:"city_id";i:6;s:11:"external_id";s:19:"jibla-historic-city";s:4:"name";s:38:"مدينة جبلة التاريخية";s:7:"name_en";s:22:"Historic City of Jibla";s:11:"description";s:338:"عاصمة الدولة الصليحية، وهي مدينة أثرية مدرجة على القائمة التمهيدية لليونسكو. [2] تشتهر بجامع الملكة أروى وشوارعها الضيقة ونظامها المائي القديم، وتعتبر متحفاً مفتوحاً للعمارة الإسلامية.";s:14:"description_en";s:247:"The capital of the Sulayhid state, it is an archaeological city listed on UNESCO's tentative list. [2] Famous for the Queen Arwa Mosque, its narrow streets, and its ancient water system, it is considered an open-air museum of Islamic architecture.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:6:"unesco";i:3;s:4:"city";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:12:"يونسكو";i:3;s:10:"مدينة";}s:8:"latitude";d:13.92;s:9:"longitude";d:44.143;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/landmarks/ibb/jibla_city1.jpg";i:1;s:36:"images/landmarks/ibb/jibla_city2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:3;a:17:{s:2:"id";i:181;s:7:"city_id";i:6;s:11:"external_id";s:17:"queen-arwa-mosque";s:4:"name";s:30:"جامع الملكة أروى";s:7:"name_en";s:17:"Queen Arwa Mosque";s:11:"description";s:322:"مسجد تاريخي عظيم يقع في قلب مدينة جبلة، بنته الملكة أروى بنت أحمد الصليحي. [3] يتميز بتصميمه المعماري الفريد ومئذنتيه، ويضم ضريح الملكة، ويعتبر من أهم المعالم الإسلامية في اليمن.";s:14:"description_en";s:257:"A great historical mosque located in the heart of Jibla, built by Queen Arwa bint Ahmad Al-Sulayhi. [3] Distinguished by its unique architectural design and its two minarets, it houses the Queen's tomb and is one of Yemen's most important Islamic landmarks.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";i:3;s:12:"إسلامي";}s:8:"latitude";d:13.919;s:9:"longitude";d:44.144;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/ibb/queen_arwa_mosque1.jpg";i:1;s:43:"images/landmarks/ibb/queen_arwa_mosque2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:4;a:17:{s:2:"id";i:182;s:7:"city_id";i:6;s:11:"external_id";s:17:"dhu-jiblah-bridge";s:4:"name";s:35:"جسر شهارة (جسر جبلة)";s:7:"name_en";s:30:"Shaharah Bridge (Jibla Bridge)";s:11:"description";s:298:"جسر حجري قديم ومقوس يربط بين ضفتي السائلة في مدينة جبلة. [4] يعتبر تحفة هندسية رائعة ومن معالم المدينة البارزة، ويوفر إطلالات جميلة على المدينة والمناطق المحيطة بها.";s:14:"description_en";s:236:"An old arched stone bridge connecting the two banks of Al-Sailah in the city of Jibla. [4] It is considered a magnificent engineering masterpiece and a prominent city landmark, providing beautiful views of the city and its surroundings.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:6:"bridge";i:3;s:11:"engineering";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:6:"جسر";i:3;s:10:"هندسي";}s:8:"latitude";d:13.921;s:9:"longitude";d:44.145;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/landmarks/ibb/jibla_bridge1.jpg";i:1;s:38:"images/landmarks/ibb/jibla_bridge2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:5;a:17:{s:2:"id";i:183;s:7:"city_id";i:6;s:11:"external_id";s:23:"al-jalaliyya-mosque-ibb";s:4:"name";s:25:"جامع الجلالية";s:7:"name_en";s:20:"Al-Jalaliyyah Mosque";s:11:"description";s:292:"أحد أبرز المساجد التاريخية في مدينة إب القديمة. [5] يتميز بقبته البيضاء الكبيرة ومئذنته الشاهقة، ويعود تاريخ بنائه إلى العصر العثماني، وهو معلم ديني ومعماري هام.";s:14:"description_en";s:232:"One of the most prominent historic mosques in the old city of Ibb. [5] Featuring a large white dome and a towering minaret, its construction dates back to the Ottoman era, making it an important religious and architectural landmark.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";i:3;s:7:"ottoman";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";i:3;s:12:"عثماني";}s:8:"latitude";d:13.971;s:9:"longitude";d:44.186;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/ibb/al_jalaliyya_mosque1.jpg";i:1;s:45:"images/landmarks/ibb/al_jalaliyya_mosque2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:6;a:17:{s:2:"id";i:184;s:7:"city_id";i:6;s:11:"external_id";s:20:"hisn-taizz-al-ashraf";s:4:"name";s:50:"حصن تعز الأشرف (حصن الدملؤة)";s:7:"name_en";s:38:"Al-Ashraf Taiz Fort (Al-Dumluwah Fort)";s:11:"description";s:326:"قلعة تاريخية منيعة تقع على قمة جبل شاهق في مديرية حزم العدين. [6] تعتبر من أمنع القلاع في اليمن، وتتميز بتحصيناتها القوية وخزانات المياه المنحوتة في الصخر، وتوفر إطلالات بانورامية.";s:14:"description_en";s:263:"An impregnable historical fortress located atop a towering mountain in the Hazm Al-Udayn district. [6] Regarded as one of the most impenetrable castles in Yemen, it is noted for its strong fortifications and rock-carved water reservoirs, offering panoramic views.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:14:"archaeological";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:8:"أثري";i:3;s:12:"إطلالة";}s:8:"latitude";d:13.85;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/ibb/damlua_fortress1.jpg";i:1;s:41:"images/landmarks/ibb/damlua_fortress2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:7;a:17:{s:2:"id";i:185;s:7:"city_id";i:6;s:11:"external_id";s:13:"wadi-bana-ibb";s:4:"name";s:22:"وادي بنا (إب)";s:7:"name_en";s:16:"Wadi Banna (Ibb)";s:11:"description";s:330:"ينبع وادي بنا الشهير من المرتفعات الخضراء لمحافظة إب. [7] تشكل منابعه ومجراه الأعلى في المحافظة ودياناً خضراء ومدرجات زراعية غاية في الجمال، وتعتبر من أروع المناظر الطبيعية في اليمن.";s:14:"description_en";s:261:"The famous Wadi Banna originates from the green highlands of Ibb Governorate. [7] Its springs and upper course in the province form exceedingly beautiful green valleys and agricultural terraces, regarded as some of the most spectacular natural scenery in Yemen.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:4:"wadi";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعي";}s:8:"latitude";d:14.1;s:9:"longitude";d:44.35;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/ibb/wadi_bana_ibb1.jpg";i:1;s:39:"images/landmarks/ibb/wadi_bana_ibb2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:8;a:17:{s:2:"id";i:186;s:7:"city_id";i:6;s:11:"external_id";s:13:"mashwara-park";s:4:"name";s:21:"منتزه مشورة";s:7:"name_en";s:14:"Mashwarah Park";s:11:"description";s:331:"غابة طبيعية كثيفة تقع على أحد الجبال القريبة من مدينة إب. [8] تعتبر من أشهر المتنزهات الطبيعية في المحافظة، حيث يقصدها الزوار للاستمتاع بالطبيعة الخضراء والهواء النقي وأجواء الغابات.";s:14:"description_en";s:203:"A dense natural forest situated on a mountain near the city of Ibb. [8] It is one of the most famous natural parks in the governorate, visited to enjoy the verdant nature, fresh air, and forest ambiance.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:4:"park";i:2;s:6:"forest";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"حديقة";i:2;s:8:"غابة";i:3;s:12:"ترفيهي";}s:8:"latitude";d:14.01;s:9:"longitude";d:44.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/ibb/mashwara_park1.jpg";i:1;s:39:"images/landmarks/ibb/mashwara_park2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:9;a:17:{s:2:"id";i:187;s:7:"city_id";i:6;s:11:"external_id";s:16:"ibb-tourist-park";s:4:"name";s:30:"منتزه إب السياحي";s:7:"name_en";s:16:"Ibb Tourist Park";s:11:"description";s:337:"يقع على سفح جبل ربي، وهو المنتزه الرسمي والأشهر في مدينة إب. [1, 2] يتميز بإطلالاته الرائعة على المدينة والمناطق المحيطة، ويضم مساحات خضراء ومرافق للزوار، ويعتبر وجهة رئيسية للعائلات. [1, 2]";s:14:"description_en";s:250:"Located on the slope of Mount Rabbi, it is the official and most famous park in Ibb city. [1, 2] It boasts wonderful views of the city and its surroundings, features green spaces and visitor facilities, and is a prime destination for families. [1, 2]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"family";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:10:"عائلي";i:3;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:10;a:17:{s:2:"id";i:188;s:7:"city_id";i:6;s:11:"external_id";s:19:"al-shaheed-park-ibb";s:4:"name";s:35:"حديقة منتزه ٢٢ مايو";s:7:"name_en";s:16:"22nd of May Park";s:11:"description";s:316:"إحدى الحدائق العامة الهامة في مدينة إب، وتقع بالقرب من جامعة إب. [3] تعتبر متنفسًا حيويًا للسكان وتضم مساحات خضراء وألعابًا للأطفال، وتشهد إقبالًا كبيرًا خاصة في المناسبات. [3]";s:14:"description_en";s:232:"One of the important public parks in Ibb city, located near Ibb University. [3] It serves as a vital recreational spot for residents, containing green areas and children's games, and sees large crowds especially during holidays. [3]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:11;a:17:{s:2:"id";i:189;s:7:"city_id";i:6;s:11:"external_id";s:20:"al-aadain-waterfalls";s:4:"name";s:34:"شلالات وادي العدين";s:7:"name_en";s:24:"Wadi Al-Udayn Waterfalls";s:11:"description";s:354:"تقع في مديرية العدين، وهي مجموعة من الشلالات التي تتدفق في الوادي مكونة مناظر طبيعية خلابة. [6] تعتبر المنطقة وجهة مثالية لمحبي الطبيعة والمغامرات والباحثين عن الاستمتاع بجمال المياه المتدفقة. [6]";s:14:"description_en";s:250:"Located in the Al-Udayn district, this is a series of waterfalls cascading into the valley, creating breathtaking natural scenery. [6] The area is an ideal destination for nature and adventure lovers looking to enjoy the beauty of flowing waters. [6]";s:10:"categories";a:3:{i:0;s:9:"waterfall";i:1;s:6:"valley";i:2;s:12:"natural-park";}s:14:"category_names";a:3:{i:0;s:8:"شلال";i:1;s:8:"وادي";i:2;s:21:"منتزه طبيعي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:12;a:17:{s:2:"id";i:190;s:7:"city_id";i:6;s:11:"external_id";s:18:"mashurah-waterfall";s:4:"name";s:19:"شلال مشورة";s:7:"name_en";s:19:"Mashwarah Waterfall";s:11:"description";s:280:"يقع في مديرية ريف إب، ويعتبر من أجمل الشلالات في المحافظة. [7] يتدفق من أعالي الجبال ليشكل منظرًا بديعًا، وهو وجهة شهيرة للنزهات والتقاط الصور التذكارية. [7]";s:14:"description_en";s:246:"Located in the rural district of Ibb, it is considered one of the most beautiful waterfalls in the governorate. [7] Flowing from the high mountains to form a magnificent scene, it is a popular spot for picnics and taking commemorative photos. [7]";s:10:"categories";a:3:{i:0;s:9:"waterfall";i:1;s:12:"natural-park";i:2;s:6:"scenic";}s:14:"category_names";a:3:{i:0;s:8:"شلال";i:1;s:21:"منتزه طبيعي";i:2;s:23:"مناظر طبيعية";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:13;a:17:{s:2:"id";i:191;s:7:"city_id";i:6;s:11:"external_id";s:19:"al-adhari-waterfall";s:4:"name";s:45:"شلالات العذاري (وادي عنة)";s:7:"name_en";s:33:"Al-Adhari Waterfalls (Wadi Annah)";s:11:"description";s:307:"مجموعة من الشلالات والعيون المائية التي تتدفق في وادي عنة بمديرية السدة. [9] تعتبر من أجمل المناظر المائية في إب، خاصة بعد مواسم الأمطار، حيث تجذب الزوار بجمالها الطبيعي.";s:14:"description_en";s:230:"A group of waterfalls and water springs flowing in Wadi Annah in the As Saddah district. [9] Ranked among the most beautiful water scenes in Ibb, particularly after the rainy seasons, attracting visitors with their natural beauty.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:9:"waterfall";i:2;s:6:"scenic";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:21:"مناظر خلابة";i:3;s:8:"مائي";}s:8:"latitude";d:14.15;s:9:"longitude";d:44.45;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/ibb/al_adhari_waterfall1.jpg";i:1;s:45:"images/landmarks/ibb/al_adhari_waterfall2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:14;a:17:{s:2:"id";i:192;s:7:"city_id";i:6;s:11:"external_id";s:16:"dar-al-izz-jibla";s:4:"name";s:46:"دار العز (قصر الملكة أروى)";s:7:"name_en";s:32:"Dar Al-Izz (Queen Arwa's Palace)";s:11:"description";s:325:"بقايا قصر الملكة أروى الذي كان يقع في مدينة جبلة. [10] على الرغم من أن الكثير منه قد تهدم، إلا أن أطلاله لا تزال شاهدة على عظمة الدولة الصليحية، وهو موقع أثري هام بجوار الجامع الكبير.";s:14:"description_en";s:249:"The ruins of Queen Arwa's palace located in the city of Jibla. [10] Even though much of it has been destroyed, its ruins still bear witness to the greatness of the Sulayhid state, serving as an important archaeological site next to the Great Mosque.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:5:"ruins";i:3;s:6:"palace";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:10:"أطلال";i:3;s:6:"قصر";}s:8:"latitude";d:13.918;s:9:"longitude";d:44.144;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/landmarks/ibb/dar_al_izz1.jpg";i:1;s:36:"images/landmarks/ibb/dar_al_izz2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:15;a:17:{s:2:"id";i:193;s:7:"city_id";i:6;s:11:"external_id";s:24:"dhafar-himyarite-capital";s:4:"name";s:50:"مدينة ظفار يريم (عاصمة حمير)";s:7:"name_en";s:31:"Zafar Yarim (Capital of Himyar)";s:11:"description";s:326:"أطلال العاصمة القديمة لمملكة حمير، تقع بالقرب من مدينة يريم. [1] يضم الموقع بقايا قصر ريدان الملكي، ومعابد قديمة، ونقوش مسندية، ويعتبر من أهم المواقع الأثرية في تاريخ اليمن القديم.";s:14:"description_en";s:278:"The ruins of the ancient capital of the Himyarite Kingdom, located near the city of Yarim. [1] The site includes the remains of the royal Raydan Palace, ancient temples, and Musnad inscriptions, making it one of the most important archaeological sites in ancient Yemeni history.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:12:"ancient-city";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:21:"مدينة قديمة";}s:8:"latitude";d:14.215;s:9:"longitude";d:44.395;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/archaeological/ibb/dhafar_city1.jpg";i:1;s:42:"images/archaeological/ibb/dhafar_city2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:16;a:17:{s:2:"id";i:194;s:7:"city_id";i:6;s:11:"external_id";s:10:"ibb-castle";s:4:"name";s:33:"قلعة إب (دار الشرف)";s:7:"name_en";s:26:"Ibb Castle (Dar Al-Sharaf)";s:11:"description";s:290:"حصن تاريخي منيع يقع على قمة جبل في قلب مدينة إب القديمة. [2] كان يستخدم كمركز للحكم والدفاع عن المدينة، ويوفر إطلالات بانورامية على المدينة والمناطق المحيطة بها.";s:14:"description_en";s:218:"An impregnable historical fortress situated on a mountaintop in the heart of the Old City of Ibb. [2] It was used as a center for governance and city defense, providing panoramic views of the city and its surroundings.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:12:"معماري";i:3;s:12:"إطلالة";}s:8:"latitude";d:13.972;s:9:"longitude";d:44.184;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/archaeological/ibb/ibb_castle1.jpg";i:1;s:41:"images/archaeological/ibb/ibb_castle2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:17;a:17:{s:2:"id";i:195;s:7:"city_id";i:6;s:11:"external_id";s:23:"al-saddah-historic-town";s:4:"name";s:40:"مدينة السدة التاريخية";s:7:"name_en";s:26:"Historic City of As Saddah";s:11:"description";s:265:"بلدة قديمة تقع شرق مدينة إب، وتعتبر مركزاً تاريخياً هاماً. [3] تشتهر بأسوارها القديمة ومساجدها التاريخية، وكانت محطة هامة على طرق التجارة القديمة.";s:14:"description_en";s:186:"An old town located east of Ibb city, considered a significant historical center. [3] Known for its ancient walls and historic mosques, it was a crucial stop on the ancient trade routes.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";}s:8:"latitude";d:14.16;s:9:"longitude";d:44.43;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/archaeological/ibb/al_saddah_town1.jpg";i:1;s:45:"images/archaeological/ibb/al_saddah_town2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:18;a:17:{s:2:"id";i:196;s:7:"city_id";i:6;s:11:"external_id";s:11:"hisn-samara";s:4:"name";s:17:"حصن سمارة";s:7:"name_en";s:12:"Samarah Fort";s:11:"description";s:309:"حصن تاريخي استراتيجي يقع على قمة جبل سمارة، ويشرف على الطريق الرئيسي بين صنعاء وإب. [4] لعب دوراً دفاعياً وتجارياً هاماً عبر العصور، وتنتشر حوله القرى ذات المناظر الخلابة.";s:14:"description_en";s:239:"A strategic historical fort positioned on the peak of Mount Samarah, overlooking the main road between Sana'a and Ibb. [4] It played an important defensive and commercial role throughout the ages, and is surrounded by picturesque villages.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";i:3;s:5:"ruins";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:10:"عسكري";i:3;s:10:"أطلال";}s:8:"latitude";d:14.18;s:9:"longitude";d:44.33;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/archaeological/ibb/hisn_samara1.jpg";i:1;s:42:"images/archaeological/ibb/hisn_samara2.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:19;a:17:{s:2:"id";i:197;s:7:"city_id";i:6;s:11:"external_id";s:23:"al-amiriya-school-radaa";s:4:"name";s:42:"المدرسة العامرية (رضاع)";s:7:"name_en";s:24:"Amiriya Madrasa (Rada'a)";s:11:"description";s:358:"على الرغم من أنها تقع إدارياً في محافظة البيضاء، إلا أنها قريبة جداً من حدود إب وتعتبر معلماً رئيسياً في المنطقة. [5] هي تحفة معمارية من العصر الطاهري، تتميز بزخارفها الجصية الملونة وتصميمها الفريد.";s:14:"description_en";s:265:"Although administratively located in Al Bayda Governorate, it is very close to the borders of Ibb and is a major landmark in the region. [5] It is an architectural masterpiece from the Tahirid era, characterized by its colorful stucco decorations and unique design.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:7:"islamic";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:12:"إسلامي";i:3;s:12:"معماري";}s:8:"latitude";d:14.41;s:9:"longitude";d:44.76;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:48:"images/archaeological/ibb/al_amiriya_school1.jpg";i:1;s:48:"images/archaeological/ibb/al_amiriya_school2.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:20;a:17:{s:2:"id";i:198;s:7:"city_id";i:6;s:11:"external_id";s:12:"hisn-khawlan";s:4:"name";s:30:"حصن خولان (بعدان)";s:7:"name_en";s:21:"Khawlan Fort (Ba'dan)";s:11:"description";s:298:"حصن قديم يقع في مديرية بعدان، وهي منطقة تشتهر بقلاعها وحصونها المنيعة. [6] يمثل الحصن نموذجاً للعمارة الدفاعية اليمنية التقليدية، ويقع وسط مناظر طبيعية خضراء ساحرة.";s:14:"description_en";s:229:"An ancient fort located in the Ba'dan district, an area renowned for its impenetrable castles and fortresses. [6] The fort exemplifies traditional Yemeni defensive architecture, nestled amidst enchanting green natural landscapes.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:5:"ruins";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:10:"أطلال";}s:8:"latitude";d:14.02;s:9:"longitude";d:44.28;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/archaeological/ibb/hisn_khawlan1.jpg";i:1;s:43:"images/archaeological/ibb/hisn_khawlan2.jpg";}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:21;a:17:{s:2:"id";i:199;s:7:"city_id";i:6;s:11:"external_id";s:14:"old-yarim-city";s:4:"name";s:34:"مدينة يريم القديمة";s:7:"name_en";s:17:"Old City of Yarim";s:11:"description";s:332:"المركز التاريخي لمدينة يريم، يضم عدداً من المنازل والمساجد القديمة. [7] كانت يريم مدينة هامة في العصور الإسلامية، وموقعها بالقرب من العاصمة الحميرية ظفار يمنحها أهمية تاريخية إضافية.";s:14:"description_en";s:230:"The historic center of Yarim city, containing a number of old houses and mosques. [7] Yarim was an important city during Islamic times, and its proximity to the Himyarite capital Zafar grants it additional historical significance.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";}s:8:"latitude";d:14.29;s:9:"longitude";d:44.37;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/archaeological/ibb/old_yarim_city1.jpg";i:1;s:45:"images/archaeological/ibb/old_yarim_city2.jpg";}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:22;a:17:{s:2:"id";i:200;s:7:"city_id";i:6;s:11:"external_id";s:19:"al-manar-mosque-ibb";s:4:"name";s:21:"مسجد المنار";s:7:"name_en";s:15:"Al-Manar Mosque";s:11:"description";s:296:"مسجد أثري يقع في مدينة إب القديمة، ويتميز بتصميمه البسيط والقديم. [8] يُعتقد أنه من أقدم مساجد المدينة، وهو جزء لا يتجزأ من النسيج التاريخي والديني للمدينة القديمة.";s:14:"description_en";s:232:"An archaeological mosque located in the Old City of Ibb, notable for its simple and ancient design. [8] It is believed to be one of the city's oldest mosques and is an integral part of the old city's historical and religious fabric.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:9:"religious";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:8:"ديني";i:2;s:12:"تاريخي";}s:8:"latitude";d:13.969;s:9:"longitude";d:44.187;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/archaeological/ibb/al_manar_mosque1.jpg";i:1;s:46:"images/archaeological/ibb/al_manar_mosque2.jpg";}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:23;a:17:{s:2:"id";i:201;s:7:"city_id";i:6;s:11:"external_id";s:8:"hisn-hab";s:4:"name";s:15:"حصن حَبّ";s:7:"name_en";s:9:"Habb Fort";s:11:"description";s:315:"حصن تاريخي يقع في مديرية بعدان، وهو من الحصون التي سُجنت فيها الملكة أروى لفترة من الزمن. [9] يتميز بموقعه المنيع على قمة جبل، ويحتوي على مدافن حبوب وآبار مياه منحوتة في الصخر.";s:14:"description_en";s:247:"A historic fortress located in the Ba'dan district, it is one of the forts where Queen Arwa was imprisoned for a time. [9] It stands out for its impregnable position on a mountain peak and contains grain silos and water wells carved into the rock.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:14:"archaeological";i:3;s:5:"ruins";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:8:"أثري";i:3;s:10:"أطلال";}s:8:"latitude";d:13.98;s:9:"longitude";d:44.3;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/archaeological/ibb/hisn_hab1.jpg";i:1;s:39:"images/archaeological/ibb/hisn_hab2.jpg";}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:24;a:17:{s:2:"id";i:202;s:7:"city_id";i:6;s:11:"external_id";s:16:"ancient-dams-ibb";s:4:"name";s:44:"السدود الحميرية القديمة";s:7:"name_en";s:22:"Ancient Himyarite Dams";s:11:"description";s:317:"تنتشر في أرجاء محافظة إب بقايا سدود قديمة تعود إلى العصر الحميري. [10] هذه السدود، مثل سد قتاب وسد الشروم، هي شواهد أثرية على براعة اليمنيين القدماء في هندسة الري وإدارة المياه.";s:14:"description_en";s:272:"Remnants of ancient dams dating back to the Himyarite era are scattered across the Ibb Governorate. [10] These dams, such as the Qutab Dam and Al-Shuroum Dam, are archaeological testaments to the ingenuity of ancient Yemenis in irrigation engineering and water management.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:3:"dam";i:2;s:10:"historical";i:3;s:11:"engineering";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:4:"سد";i:2;s:12:"تاريخي";i:3;s:10:"هندسي";}s:8:"latitude";d:14.15;s:9:"longitude";d:44.38;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/archaeological/ibb/ancient_dams1.jpg";i:1;s:43:"images/archaeological/ibb/ancient_dams2.jpg";}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:25;a:17:{s:2:"id";i:203;s:7:"city_id";i:6;s:11:"external_id";s:9:"wadi-anna";s:4:"name";s:15:"وادي عنة";s:7:"name_en";s:10:"Wadi Annah";s:11:"description";s:348:"أحد أجمل وأخصب الأودية في محافظة إب، يقع في مديرية السدة. [1] يشتهر بمياهه المتدفقة وشلالاته الموسمية (مثل شلالات العذاري) ومدرجاته الزراعية الخضراء التي تزرع فيها مختلف أنواع الحبوب والفواكه.";s:14:"description_en";s:270:"One of the most beautiful and fertile valleys in Ibb Governorate, located in the As Saddah district. [1] It is famous for its flowing waters, seasonal waterfalls (like Al-Adhari waterfalls), and green agricultural terraces where various grains and fruits are cultivated.";s:10:"categories";a:5:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:9:"waterfall";i:4;s:11:"agriculture";}s:14:"category_names";a:5:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:8:"شلال";i:4;s:10:"زراعي";}s:8:"latitude";d:14.15;s:9:"longitude";d:44.45;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:31:"images/water/ibb/wadi_anna1.jpg";i:1;s:31:"images/water/ibb/wadi_anna2.jpg";}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:26;a:17:{s:2:"id";i:204;s:7:"city_id";i:6;s:11:"external_id";s:11:"wadi-al-dur";s:4:"name";s:19:"وادي الدور";s:7:"name_en";s:12:"Wadi Al-Dawr";s:11:"description";s:302:"وادي جميل يقع في مديرية الشعر، ويتميز بمناظره الطبيعية الخلابة ومياهه الجارية. [2] يعتبر متنفساً طبيعياً للسكان والزوار، خاصة في مواسم الأمطار حيث تزداد خضرته وجماله.";s:14:"description_en";s:243:"A beautiful valley located in the Ash Sha'ir district, characterized by its breathtaking landscapes and running waters. [2] It is a natural retreat for locals and visitors, especially during the rainy seasons when its lushness and beauty peak.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:10:"recreation";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.05;s:9:"longitude";d:44.5;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:33:"images/water/ibb/wadi_al_dur1.jpg";i:1;s:33:"images/water/ibb/wadi_al_dur2.jpg";}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:27;a:17:{s:2:"id";i:205;s:7:"city_id";i:6;s:11:"external_id";s:21:"al-sailah-river-jibla";s:4:"name";s:35:"نهر السائلة في جبلة";s:7:"name_en";s:24:"Al-Sailah River in Jibla";s:11:"description";s:301:"مجرى مائي يخترق مدينة جبلة التاريخية، وتتدفق فيه المياه بعد هطول الأمطار. [3] يشكل مع الجسر الحجري القديم والبيوت المطلة عليه منظراً تاريخياً وطبيعياً فريداً من نوعه.";s:14:"description_en";s:214:"A watercourse cutting through the historic city of Jibla, flowing with water after rainfall. [3] Together with the ancient stone bridge and the houses overlooking it, it forms a unique historical and natural scene.";s:10:"categories";a:4:{i:0;s:12:"water-course";i:1;s:10:"historical";i:2;s:6:"scenic";i:3;s:4:"city";}s:14:"category_names";a:4:{i:0;s:17:"مجرى مائي";i:1;s:12:"تاريخي";i:2;s:21:"مناظر خلابة";i:3;s:10:"مدينة";}s:8:"latitude";d:13.92;s:9:"longitude";d:44.144;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/water/ibb/al_sailah_jibla1.jpg";i:1;s:37:"images/water/ibb/al_sailah_jibla2.jpg";}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:28;a:17:{s:2:"id";i:206;s:7:"city_id";i:6;s:11:"external_id";s:13:"al-aadeen-dam";s:4:"name";s:17:"سد العدين";s:7:"name_en";s:12:"Al-Udayn Dam";s:11:"description";s:325:"سد حديث نسبياً يقع في مديرية العدين، بني بهدف حجز مياه الأمطار وتغذية المياه الجوفية. [4] شكلت بحيرة السد منظراً مائياً جميلاً وسط الجبال، وأصبحت مقصداً للتنزه والاستمتاع بالمنظر.";s:14:"description_en";s:247:"A relatively modern dam located in the Al-Udayn district, built to harvest rainwater and recharge groundwater. [4] The dam's lake created a beautiful waterscape amidst the mountains and has become a destination for strolling and enjoying the view.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:4:"lake";i:2;s:16:"water-management";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:10:"بحيرة";i:2;s:19:"إدارة مياه";i:3;s:12:"ترفيهي";}s:8:"latitude";d:13.75;s:9:"longitude";d:43.95;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:35:"images/water/ibb/al_aadeen_dam1.jpg";i:1;s:35:"images/water/ibb/al_aadeen_dam2.jpg";}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:29;a:17:{s:2:"id";i:207;s:7:"city_id";i:6;s:11:"external_id";s:16:"manar-waterfalls";s:4:"name";s:34:"شلالات وادي المنار";s:7:"name_en";s:24:"Wadi Al-Manar Waterfalls";s:11:"description";s:326:"مجموعة من الشلالات الصغيرة والعيون المائية التي تنحدر من الجبال في منطقة المنار بمديرية بعدان. [5] تتميز المنطقة بجمالها الطبيعي الأخاذ وتعتبر وجهة لهواة التنزه والمشي في الطبيعة.";s:14:"description_en";s:243:"A collection of small waterfalls and water springs descending from the mountains in the Al-Manar area, Ba'dan district. [5] The region is noted for its breathtaking natural beauty and is a destination for hiking and nature walking enthusiasts.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:4:"wadi";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:17:"تنزه جبلي";}s:8:"latitude";d:13.99;s:9:"longitude";d:44.29;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/water/ibb/manar_waterfalls1.jpg";i:1;s:38:"images/water/ibb/manar_waterfalls2.jpg";}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:30;a:17:{s:2:"id";i:208;s:7:"city_id";i:6;s:11:"external_id";s:10:"wadi-surah";s:4:"name";s:17:"وادي سورة";s:7:"name_en";s:10:"Wadi Surah";s:11:"description";s:281:"وادي خصب يقع في مديرية فرع العدين، ويشتهر بمدرجاته الزراعية المعلقة ومياهه الجارية. [6] يوفر الوادي مناظر طبيعية ريفية هادئة وجميلة تعكس جمال الريف اليمني.";s:14:"description_en";s:230:"A fertile valley situated in the Far Al-Udayn district, famous for its hanging agricultural terraces and running waters. [6] The valley offers serene and beautiful rural landscapes that reflect the charm of the Yemeni countryside.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.8;s:9:"longitude";d:43.88;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:32:"images/water/ibb/wadi_surah1.jpg";i:1;s:32:"images/water/ibb/wadi_surah2.jpg";}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:31;a:17:{s:2:"id";i:209;s:7:"city_id";i:6;s:11:"external_id";s:17:"borkan-hot-spring";s:4:"name";s:34:"حمام بركان الطبيعي";s:7:"name_en";s:19:"Burkan Natural Bath";s:11:"description";s:323:"ينبوع مياه كبريتية حارة يقع في مديرية القفر. [7] يقصده الناس للاستشفاء بمياهه التي يُعتقد أن لها خصائص علاجية لأمراض الجلد والمفاصل، ويعتبر من مواقع السياحة العلاجية في المحافظة.";s:14:"description_en";s:269:"A hot sulfurous water spring located in the Al-Qafr district. [7] People visit it for healing through its waters, which are believed to possess therapeutic properties for skin and joint diseases, and it is considered one of the medical tourism sites in the governorate.";s:10:"categories";a:4:{i:0;s:10:"hot-spring";i:1;s:11:"therapeutic";i:2;s:7:"natural";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:17:"ينبوع حار";i:1;s:10:"علاجي";i:2;s:10:"طبيعي";i:3;s:8:"مائي";}s:8:"latitude";d:14.25;s:9:"longitude";d:44.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/water/ibb/borkan_hot_spring1.jpg";i:1;s:39:"images/water/ibb/borkan_hot_spring2.jpg";}s:10:"sort_order";i:32;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:32;a:17:{s:2:"id";i:210;s:7:"city_id";i:6;s:11:"external_id";s:16:"saylat-al-rabadi";s:4:"name";s:25:"سائلة الربادي";s:7:"name_en";s:16:"Al-Rabadi Sailah";s:11:"description";s:318:"مجرى مائي يمر عبر مدينة إب، ويتجمع فيه الماء من عدة أودية صغيرة. [8] على الرغم من وقوعه في منطقة حضرية، إلا أنه يضيف لمسة طبيعية للمدينة ويصبح منظراً جميلاً عند جريان المياه فيه.";s:14:"description_en";s:233:"A watercourse passing through the city of Ibb, where water collects from several small valleys. [8] Despite its location in an urban area, it adds a natural touch to the city and becomes a beautiful sight when water flows through it.";s:10:"categories";a:3:{i:0;s:12:"water-course";i:1;s:5:"urban";i:2;s:6:"nature";}s:14:"category_names";a:3:{i:0;s:17:"مجرى مائي";i:1;s:8:"حضري";i:2;s:10:"طبيعي";}s:8:"latitude";d:13.96;s:9:"longitude";d:44.18;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/water/ibb/saylat_al_rabadi1.jpg";i:1;s:38:"images/water/ibb/saylat_al_rabadi2.jpg";}s:10:"sort_order";i:33;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:33;a:17:{s:2:"id";i:211;s:7:"city_id";i:6;s:11:"external_id";s:16:"al-mashannah-dam";s:4:"name";s:17:"سد المشنة";s:7:"name_en";s:14:"Al-Mashnah Dam";s:11:"description";s:298:"سد يقع بالقرب من مدينة إب، تم إنشاؤه لحصاد مياه الأمطار. [9] أدت البحيرة التي تكونت خلف السد إلى خلق بيئة رطبة تجذب الطيور وتوفر منظراً مائياً جميلاً للسكان المحليين.";s:14:"description_en";s:211:"A dam located near the city of Ibb, built for rainwater harvesting. [9] The lake formed behind the dam has created a wetland environment that attracts birds and offers a beautiful waterscape for local residents.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:4:"lake";i:2;s:16:"water-management";i:3;s:13:"bird-watching";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:10:"بحيرة";i:2;s:19:"إدارة مياه";i:3;s:25:"مراقبة الطيور";}s:8:"latitude";d:13.95;s:9:"longitude";d:44.17;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/water/ibb/al_mashannah_dam1.jpg";i:1;s:38:"images/water/ibb/al_mashannah_dam2.jpg";}s:10:"sort_order";i:34;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:34;a:17:{s:2:"id";i:212;s:7:"city_id";i:6;s:11:"external_id";s:14:"wadi-al-shorom";s:4:"name";s:21:"وادي الشروم";s:7:"name_en";s:15:"Wadi Al-Shuroum";s:11:"description";s:310:"وادي تاريخي يقع بالقرب من مدينة ظفار يريم، ويحتوي على بقايا سد حميري قديم. [10] يجمع الوادي بين الأهمية الأثرية والجمال الطبيعي، حيث تسقي مياهه الأراضي الزراعية المحيطة به.";s:14:"description_en";s:238:"A historical valley located near the city of Zafar Yarim, containing the remains of an old Himyarite dam. [10] The valley combines archaeological significance with natural beauty, as its waters irrigate the surrounding agricultural lands.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:14:"archaeological";i:3;s:3:"dam";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:8:"أثري";i:3;s:4:"سد";}s:8:"latitude";d:14.22;s:9:"longitude";d:44.41;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/water/ibb/wadi_al_shorom1.jpg";i:1;s:36:"images/water/ibb/wadi_al_shorom2.jpg";}s:10:"sort_order";i:35;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:35;a:17:{s:2:"id";i:213;s:7:"city_id";i:6;s:11:"external_id";s:12:"jabal-baadan";s:4:"name";s:28:"منتزه جبل بعدان";s:7:"name_en";s:17:"Mount Ba'dan Park";s:11:"description";s:363:"جبل شاهق وشهير يقع شرق مدينة إب، وتنتشر على سفوحه العديد من القرى الخضراء والحصون التاريخية. [1] يعتبر الجبل بأكمله منتزهًا طبيعيًا مفتوحًا، ويوفر إطلالات بانورامية رائعة ومسارات للمشي لمسافات طويلة.";s:14:"description_en";s:241:"A famous towering mountain located east of Ibb city, with many green villages and historic forts dotting its slopes. [1] The entire mountain is considered an open natural park, providing magnificent panoramic views and trails for long hikes.";s:10:"categories";a:5:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:4:"park";i:3;s:9:"viewpoint";i:4;s:6:"hiking";}s:14:"category_names";a:5:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:10:"منتزه";i:3;s:12:"إطلالة";i:4;s:17:"تنزه جبلي";}s:8:"latitude";i:14;s:9:"longitude";d:44.28;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/mountains/ibb/jabal_baadan1.jpg";i:1;s:38:"images/mountains/ibb/jabal_baadan2.jpg";}s:10:"sort_order";i:36;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:36;a:17:{s:2:"id";i:214;s:7:"city_id";i:6;s:11:"external_id";s:12:"jabal-samara";s:4:"name";s:28:"منتزه جبل سمارة";s:7:"name_en";s:18:"Mount Samarah Park";s:11:"description";s:333:"جبل استراتيجي يقع على الطريق بين صنعاء وإب، ويشتهر بقمته التي تضم حصن سمارة التاريخي. [2] المنطقة المحيطة بالقمة تعتبر منتزهًا جبليًا طبيعيًا يوفر مناظر خلابة للوديان والقرى المجاورة.";s:14:"description_en";s:255:"A strategic mountain located on the road between Sana'a and Ibb, famous for its peak that houses the historic Samarah Fort. [2] The area surrounding the summit is a natural mountain park offering breathtaking views of the neighboring valleys and villages.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:10:"historical";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:12:"تاريخي";i:3;s:12:"إطلالة";}s:8:"latitude";d:14.18;s:9:"longitude";d:44.33;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/mountains/ibb/jabal_samara1.jpg";i:1;s:38:"images/mountains/ibb/jabal_samara2.jpg";}s:10:"sort_order";i:37;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:37;a:17:{s:2:"id";i:215;s:7:"city_id";i:6;s:11:"external_id";s:14:"jabal-al-adeen";s:4:"name";s:32:"منتزه جبال العدين";s:7:"name_en";s:23:"Al-Udayn Mountains Park";s:11:"description";s:347:"سلسلة جبلية خضراء تقع في مديرية العدين غرب إب. [3] تتميز بمدرجاتها الزراعية التي تغطي السفوح بالكامل، وتعتبر المنطقة وجهة مثالية للقيادة في الطرق الجبلية والاستمتاع بالمناظر الريفية الساحرة.";s:14:"description_en";s:244:"A green mountain range located in the Al-Udayn district west of Ibb. [3] Known for its agricultural terraces that fully cover the slopes, the area is an ideal destination for driving along mountain roads and enjoying the charming rural scenery.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:12:"scenic-drive";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:17:"طريق جبلي";i:3;s:10:"زراعي";}s:8:"latitude";d:13.77;s:9:"longitude";d:43.92;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/mountains/ibb/jabal_al_adeen1.jpg";i:1;s:40:"images/mountains/ibb/jabal_al_adeen2.jpg";}s:10:"sort_order";i:38;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:38;a:17:{s:2:"id";i:216;s:7:"city_id";i:6;s:11:"external_id";s:10:"jabal-rabi";s:4:"name";s:24:"منتزه جبل ربي";s:7:"name_en";s:16:"Mount Rabbi Park";s:11:"description";s:304:"جبل يقع غرب مدينة إب، ويطل على المدينة من جهة الغرب. [4] يعتبر من المنتزهات الجبلية القريبة من مركز المدينة، ويوفر إطلالات جميلة ومساحات طبيعية للتنزه والرحلات الخلوية.";s:14:"description_en";s:217:"A mountain situated west of Ibb city, overlooking the city from the west. [4] It is considered one of the mountain parks close to the city center, offering beautiful views and natural spaces for strolling and picnics.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:4:"park";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:10:"منتزه";i:3;s:12:"إطلالة";}s:8:"latitude";d:13.96;s:9:"longitude";d:44.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/mountains/ibb/jabal_rabi1.jpg";i:1;s:36:"images/mountains/ibb/jabal_rabi2.jpg";}s:10:"sort_order";i:39;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:39;a:17:{s:2:"id";i:217;s:7:"city_id";i:6;s:11:"external_id";s:14:"jabal-al-shaer";s:4:"name";s:30:"منتزه جبال الشعر";s:7:"name_en";s:25:"Ash Sha'ir Mountains Park";s:11:"description";s:311:"مجموعة من الجبال الخضراء التي تقع في مديرية الشعر، وتشتهر بخصوبتها وجمال طبيعتها. [5] توفر المنطقة العديد من الأماكن الهادئة للتخييم والاستمتاع بالريف اليمني في أبهى صوره.";s:14:"description_en";s:213:"A group of green mountains located in the Ash Sha'ir district, famous for their fertility and natural beauty. [5] The area provides many quiet spots for camping and experiencing the Yemeni countryside at its best.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:5:"rural";i:3;s:7:"camping";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:8:"ريفي";i:3;s:10:"تخييم";}s:8:"latitude";d:14.06;s:9:"longitude";d:44.55;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/mountains/ibb/jabal_al_shaer1.jpg";i:1;s:40:"images/mountains/ibb/jabal_al_shaer2.jpg";}s:10:"sort_order";i:40;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:40;a:17:{s:2:"id";i:218;s:7:"city_id";i:6;s:11:"external_id";s:17:"jabal-al-makhadir";s:4:"name";s:34:"منتزه جبال المخادر";s:7:"name_en";s:26:"Al-Makhadir Mountains Park";s:11:"description";s:311:"سلسلة جبلية تقع شمال مدينة إب في مديرية المخادر. [7] تتميز بارتفاعها ومناخها المعتدل، وتوفر إطلالات واسعة على المناطق المحيطة، وتعتبر مكانًا جيدًا للابتعاد عن صخب المدينة.";s:14:"description_en";s:233:"A mountain range located north of Ibb city in the Al-Makhadir district. [7] Distinguished by its elevation and moderate climate, it offers sweeping views of the surrounding areas and serves as a good place to escape the city's noise.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:9:"viewpoint";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:12:"إطلالة";i:3;s:12:"ترفيهي";}s:8:"latitude";d:14.09;s:9:"longitude";d:44.26;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/mountains/ibb/jabal_al_makhadir1.jpg";i:1;s:43:"images/mountains/ibb/jabal_al_makhadir2.jpg";}s:10:"sort_order";i:41;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:41;a:17:{s:2:"id";i:219;s:7:"city_id";i:6;s:11:"external_id";s:16:"jabal-al-sayyani";s:4:"name";s:34:"منتزه جبال السياني";s:7:"name_en";s:25:"Al-Sayyani Mountains Park";s:11:"description";s:328:"الجبال المحيطة بمديرية السياني، والتي تشتهر بشلالاتها ومياهها الجارية. [8] السفوح الخضراء لهذه الجبال تشكل منتزهات طبيعية يقصدها الناس للاستمتاع بجمال الشلالات والمناظر الطبيعية.";s:14:"description_en";s:240:"The mountains surrounding the Al-Sayyani district, famous for their waterfalls and flowing waters. [8] The green slopes of these mountains form natural parks frequented by people to enjoy the beauty of the waterfalls and natural landscapes.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:9:"waterfall";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:8:"شلال";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.87;s:9:"longitude";d:44.23;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/mountains/ibb/jabal_al_sayyani1.jpg";i:1;s:42:"images/mountains/ibb/jabal_al_sayyani2.jpg";}s:10:"sort_order";i:42;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:42;a:17:{s:2:"id";i:220;s:7:"city_id";i:6;s:11:"external_id";s:14:"jabal-al-qafar";s:4:"name";s:30:"منتزه جبال القفر";s:7:"name_en";s:22:"Al-Qafr Mountains Park";s:11:"description";s:283:"جبال تقع في مديرية القفر، وتتميز بطبيعتها الصخرية القاسية وجمالها البري. [9] توفر تجربة مختلفة عن جبال إب الخضراء، وتعتبر وجهة لهواة استكشاف الطبيعة الوعرة.";s:14:"description_en";s:233:"Mountains located in the Al-Qafr district, noted for their harsh rocky nature and wild beauty. [9] They offer an experience quite different from the green mountains of Ibb, acting as a destination for fans of exploring rugged nature.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:6:"hiking";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:17:"تنزه جبلي";i:3;s:14:"مغامرات";}s:8:"latitude";d:14.23;s:9:"longitude";d:44.18;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/mountains/ibb/jabal_al_qafar1.jpg";i:1;s:40:"images/mountains/ibb/jabal_al_qafar2.jpg";}s:10:"sort_order";i:43;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:43;a:17:{s:2:"id";i:221;s:7:"city_id";i:6;s:11:"external_id";s:11:"jabal-manar";s:4:"name";s:30:"منتزه جبل المنار";s:7:"name_en";s:19:"Mount Al-Manar Park";s:11:"description";s:328:"يقع في مديرية بعدان، وهو الجبل الذي تنبع منه شلالات المنار الشهيرة. [10] المنطقة عبارة عن منتزه جبلي غني بالمياه والخضرة، ويعتبر مثالياً للرحلات الاستكشافية والمشي في الطبيعة البكر.";s:14:"description_en";s:235:"Located in the Ba'dan district, this is the mountain from which the famous Al-Manar waterfalls originate. [10] The area is a mountain park rich in water and greenery, making it ideal for exploratory trips and hiking in pristine nature.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"nature";i:2;s:4:"park";i:3;s:9:"waterfall";}s:14:"category_names";a:4:{i:0;s:6:"جبل";i:1;s:10:"طبيعي";i:2;s:10:"منتزه";i:3;s:8:"شلال";}s:8:"latitude";d:13.998;s:9:"longitude";d:44.3;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/mountains/ibb/jabal_manar1.jpg";i:1;s:37:"images/mountains/ibb/jabal_manar2.jpg";}s:10:"sort_order";i:44;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:44;a:17:{s:2:"id";i:222;s:7:"city_id";i:6;s:11:"external_id";s:20:"al-sayani-waterfalls";s:4:"name";s:64:"شلالات السياني (شلالات وادي الجنات)";s:7:"name_en";s:49:"Al-Sayyani Waterfalls (Wadi Al-Jannat Waterfalls)";s:11:"description";s:357:"تقع في مديرية السياني، وهي عبارة عن مجموعة من الشلالات التي تتشكل في وادي الجنات. [1, 2] تعتبر من أجمل المناظر الطبيعية في المحافظة وتجذب الزوار للاستمتاع بتدفق المياه والمساحات الخضراء المحيطة. [1, 2]";s:14:"description_en";s:259:"Situated in the Al-Sayyani district, it is a collection of waterfalls formed in Wadi Al-Jannat. [1, 2] Rated among the most beautiful natural landscapes in the governorate, attracting visitors to enjoy the cascading waters and surrounding green spaces. [1, 2]";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"valley";i:2;s:12:"natural-park";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:8:"وادي";i:2;s:21:"منتزه طبيعي";i:3;s:23:"مناظر طبيعية";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:45;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:45;a:17:{s:2:"id";i:223;s:7:"city_id";i:6;s:11:"external_id";s:22:"wadi-al-durr-waterfall";s:4:"name";s:28:"شلال وادي الدُر";s:7:"name_en";s:21:"Wadi Al-Dur Waterfall";s:11:"description";s:268:"يقع في مديرية العُدين، وهو شلال جميل يتدفق في وادٍ خصب. [3] المنطقة المحيطة بالشلال تعتبر مكانًا مثاليًا للنزهات الخلوية والابتعاد عن صخب المدينة. [3]";s:14:"description_en";s:200:"Located in the Al-Udayn district, it is a lovely waterfall flowing through a fertile valley. [3] The area around the waterfall is an ideal spot for picnics and getting away from the city's hustle. [3]";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"valley";i:2;s:12:"natural-park";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:8:"وادي";i:2;s:21:"منتزه طبيعي";i:3;s:8:"هادئ";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:46;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:46;a:17:{s:2:"id";i:224;s:7:"city_id";i:6;s:11:"external_id";s:17:"jabal-baadan-area";s:4:"name";s:49:"منتزهات جبل بعدان الطبيعية";s:7:"name_en";s:26:"Mount Ba'dan Natural Parks";s:11:"description";s:416:"المنطقة الجبلية الشاسعة في مديرية بعدان، والتي تضم العديد من القرى المعلقة والمدرجات الزراعية الخضراء. [4] تعتبر المنطقة بأكملها منتزهًا طبيعيًا مفتوحًا، حيث يقصد الزوار مناطق مثل "حب" و"العكمة" للاستمتاع بالمناظر البانورامية. [4]";s:14:"description_en";s:270:"The vast mountainous region in the Ba'dan district, which encompasses many hanging villages and green agricultural terraces. [4] The entire area is considered an open natural park, where visitors head to areas like 'Habb' and 'Al-Akmah' to enjoy the panoramic views. [4]";s:10:"categories";a:4:{i:0;s:12:"natural-park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:21:"منتزه طبيعي";i:1;s:6:"جبل";i:2;s:6:"مطل";i:3;s:23:"مناظر طبيعية";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:47;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:47;a:17:{s:2:"id";i:225;s:7:"city_id";i:6;s:11:"external_id";s:20:"al-maqbana-waterfall";s:4:"name";s:29:"شلال المَقْبَنة";s:7:"name_en";s:21:"Al-Maqbanah Waterfall";s:11:"description";s:315:"يقع في مديرية حزم العُدين، وهو أحد الشلالات الموسمية التي تظهر بجمال أخاذ بعد هطول الأمطار. [5] يعتبر وجهة للسكان المحليين والمناطق المجاورة للاستمتاع بجمال الطبيعة البكر. [5]";s:14:"description_en";s:235:"Located in the Hazm Al-Udayn district, it is a seasonal waterfall that emerges with breathtaking beauty after rainfall. [5] It is a destination for locals and those from nearby areas looking to savor the beauty of untouched nature. [5]";s:10:"categories";a:3:{i:0;s:9:"waterfall";i:1;s:12:"natural-park";i:2;s:8:"seasonal";}s:14:"category_names";a:3:{i:0;s:8:"شلال";i:1;s:21:"منتزه طبيعي";i:2;s:10:"موسمي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:48;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:48;a:17:{s:2:"id";i:226;s:7:"city_id";i:6;s:11:"external_id";s:21:"al-nahari-park-jeblah";s:4:"name";s:36:"منتزه النهاري (جبلة)";s:7:"name_en";s:22:"Al-Nahari Park (Jibla)";s:11:"description";s:282:"منتزه خاص يقع في مدينة جبلة التاريخية، ويوفر إطلالة جميلة على المدينة. [6] يضم المنتزه استراحات عائلية ومطعمًا، ويجمع بين النزهة والاستمتاع بعبق التاريخ. [6]";s:14:"description_en";s:221:"A private park situated in the historical city of Jibla, providing a beautiful view over the city. [6] The park features family rest stops and a restaurant, combining picnicking with experiencing the aroma of history. [6]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"family";i:3;s:19:"historical-vicinity";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:10:"عائلي";i:3;s:21:"جوار تاريخي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:49;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:49;a:17:{s:2:"id";i:618;s:7:"city_id";i:6;s:11:"external_id";N;s:4:"name";s:12:"الامجد";s:7:"name_en";s:8:"Al-Amjad";s:11:"description";s:40:"اروع منتزه في مدينة اب";s:14:"description_en";s:43:"The most wonderful park in the city of Ibb.";s:10:"categories";a:1:{i:0;s:10:"historical";}s:14:"category_names";a:1:{i:0;s:10:"ثقافي";}s:8:"latitude";d:13.5746995;s:9:"longitude";d:44.0103913;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/ASSdAiYWX7VWvAzq6";s:6:"images";a:1:{i:0;s:54:"https://www.almotamar.net/photo/15-07-09-829663297.jpg";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-01T00:18:38.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:1;a:13:{s:2:"id";i:14;s:4:"slug";s:5:"abean";s:4:"name";s:8:"أبين";s:7:"name_en";s:5:"Abyan";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:17:"zinjibar_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:20;s:9:"landmarks";a:20:{i:0;a:17:{s:2:"id";i:349;s:7:"city_id";i:14;s:11:"external_id";s:11:"abyan-delta";s:4:"name";s:17:"دلتا أبين";s:7:"name_en";s:11:"Abyan Delta";s:11:"description";s:301:"تعتبر من أخصب الأراضي الزراعية في اليمن وتشتهر بزراعة الفواكه والخضروات والقطن طويل التيلة. [1, 10] تمثل الدلتا منظراً طبيعياً خلاباً وتعتبر سلة غذاء رئيسية للمنطقة. [1]";s:14:"description_en";s:228:"Considered one of the most fertile agricultural lands in Yemen, famous for cultivating fruits, vegetables, and long-staple cotton. [1, 10] The delta is a breathtaking natural landscape and a major breadbasket for the region. [1]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:11:"agriculture";i:2;s:6:"scenic";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"زراعة";i:2;s:21:"مناظر خلابة";}s:8:"latitude";d:13.1667;s:9:"longitude";d:45.3333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:350;s:7:"city_id";i:14;s:11:"external_id";s:11:"ahwar-coast";s:4:"name";s:17:"ساحل أحور";s:7:"name_en";s:11:"Ahwar Coast";s:11:"description";s:294:"يمتد على بحر العرب ويتميز بشواطئه الرملية الجميلة ومياهه الصافية. [11] يعتبر مقصداً للصيادين ومركزاً لتجمع الطيور المهاجرة، مما يجعله مهماً من الناحية البيئية. [11]";s:14:"description_en";s:224:"Stretching along the Arabian Sea, it is characterized by its beautiful sandy beaches and clear waters. [11] It is a destination for fishermen and a gathering center for migratory birds, making it ecologically important. [11]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:5:"beach";i:2;s:7:"coastal";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"شاطئ";i:2;s:10:"ساحلي";}s:8:"latitude";d:13.05;s:9:"longitude";d:46.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:351;s:7:"city_id";i:14;s:11:"external_id";s:14:"zinjibar-beach";s:4:"name";s:47:"ساحل زنجبار (شاطئ المسحال)";s:7:"name_en";s:32:"Zinjibar Coast (Al-Mashal Beach)";s:11:"description";s:385:"يعتبر الشريط الساحلي لمدينة زنجبار، عاصمة المحافظة، المتنفس الرئيسي والأكثر شعبية للسكان. [1, 2] يتميز الشاطئ برماله الناعمة وامتداده الواسع، ويقصده الزوار والعائلات للسباحة والنزهات والاستمتاع بمنظر البحر. [1, 2]";s:14:"description_en";s:246:"The coastal strip of Zinjibar, the provincial capital, is the primary and most popular retreat for residents. [1, 2] Featuring soft sands and vast expanses, the beach is visited by families for swimming, picnics, and enjoying the sea view. [1, 2]";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:12:"recreational";i:2;s:6:"family";i:3;s:8:"swimming";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:10:"سباحة";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:352;s:7:"city_id";i:14;s:11:"external_id";s:12:"khanfar-city";s:4:"name";s:38:"مدينة خنفر التاريخية";s:7:"name_en";s:24:"Historic City of Khanfar";s:11:"description";s:257:"إحدى المدن القديمة في أبين، وتضم بقايا قلعة تاريخية تُعرف بـ "حصن خنفر" الذي يقع على قمة جبل. [3, 9] كانت المدينة مركزاً مهماً في تاريخ المنطقة. [3]";s:14:"description_en";s:186:"An ancient city in Abyan, housing the ruins of a historic castle known as 'Khanfar Fort', situated on a mountaintop. [3, 9] The city was a significant center in the region's history. [3]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:5:"ruins";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:10:"أطلال";}s:8:"latitude";d:13.133;s:9:"longitude";d:45.283;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:353;s:7:"city_id";i:14;s:11:"external_id";s:22:"al-hisn-fortress-ja'ar";s:4:"name";s:30:"قلعة الحصن (جعار)";s:7:"name_en";s:22:"Al-Husn Castle (Ja'ar)";s:11:"description";s:246:"قلعة تاريخية تقع في مدينة جعار، ثاني أكبر مدن المحافظة. [9] تمثل القلعة شاهداً على التاريخ العسكري والإداري للمنطقة عبر العصور المختلفة.";s:14:"description_en";s:208:"A historical castle located in the city of Ja'ar, the second-largest city in the governorate. [9] The castle serves as a witness to the military and administrative history of the region across different eras.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";}s:8:"latitude";d:13.11;s:9:"longitude";d:45.28;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:354;s:7:"city_id";i:14;s:11:"external_id";s:9:"wadi-bana";s:4:"name";s:15:"وادي بنا";s:7:"name_en";s:10:"Wadi Banna";s:11:"description";s:320:"أحد أكبر وأهم الأودية في اليمن، ينبع من المرتفعات الوسطى ويصب في دلتا أبين. [1] يشكل الوادي مصدراً رئيسياً للمياه للزراعة في الدلتا، وتنتشر على ضفافه العديد من القرى والمزارع. [1]";s:14:"description_en";s:247:"One of the largest and most important valleys in Yemen, originating in the central highlands and emptying into the Abyan Delta. [1] The valley is a major water source for agriculture in the delta, with many villages and farms lining its banks. [1]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";}s:8:"latitude";d:13.25;s:9:"longitude";d:45.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:355;s:7:"city_id";i:14;s:11:"external_id";s:12:"lawdar-parks";s:4:"name";s:40:"متنفسات لودر الطبيعية";s:7:"name_en";s:22:"Lodar Natural Retreats";s:11:"description";s:344:"تقع مديرية لودر في المنطقة الجبلية من أبين، وتتميز بأوديتها ومناظرها الطبيعية. [9] تعتبر الأودية والمناطق الخضراء في لودر متنفسات طبيعية غير رسمية يقصدها السكان للرحلات والنزهات الجبلية. [9]";s:14:"description_en";s:237:"The Lodar district is located in the mountainous region of Abyan, known for its valleys and natural scenery. [9] The valleys and green areas in Lodar act as informal natural retreats where residents go for mountain trips and picnics. [9]";s:10:"categories";a:3:{i:0;s:12:"natural-area";i:1;s:8:"mountain";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:23:"منطقة طبيعية";i:1;s:8:"جبلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:356;s:7:"city_id";i:14;s:11:"external_id";s:14:"qarn-al-kalasi";s:4:"name";s:21:"قرن الكلاسي";s:7:"name_en";s:14:"Qarn Al-Kalasi";s:11:"description";s:291:"موقع أثري قديم يقع في مديرية مودية، ويعتقد أنه كان عاصمة مملكة أوسان القديمة. [2] يضم الموقع بقايا مبانٍ قديمة ونقوشاً أثرية تشير إلى الأهمية التاريخية للمكان. [2]";s:14:"description_en";s:254:"An ancient archaeological site located in the Mudiyah district, believed to have been the capital of the ancient Awsan Kingdom. [2] The site features remains of ancient buildings and archaeological inscriptions indicating its historical significance. [2]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:7:"ancient";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:8:"قديم";}s:8:"latitude";d:13.6;s:9:"longitude";d:46.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:357;s:7:"city_id";i:14;s:11:"external_id";s:12:"shuqra-beach";s:4:"name";s:17:"شاطئ شقرة";s:7:"name_en";s:12:"Shoqra Beach";s:11:"description";s:250:"مدينة ساحلية وميناء تاريخي مهم في محافظة أبين. [11] يتميز شاطئها بجماله الطبيعي وكان محطة تجارية رئيسية على الطريق الساحلي بين عدن وحضرموت.";s:14:"description_en";s:195:"A coastal city and important historical port in Abyan Governorate. [11] Its beach is noted for its natural beauty and was a major trading station on the coastal route between Aden and Hadhramaut.";s:10:"categories";a:3:{i:0;s:7:"coastal";i:1;s:5:"beach";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:10:"ساحلي";i:1;s:8:"شاطئ";i:2;s:12:"تاريخي";}s:8:"latitude";d:13.36;s:9:"longitude";d:45.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:358;s:7:"city_id";i:14;s:11:"external_id";s:11:"wadi-hassan";s:4:"name";s:17:"وادي حسان";s:7:"name_en";s:11:"Wadi Hassan";s:11:"description";s:256:"وادي زراعي خصب آخر يمر عبر محافظة أبين ويصب في البحر. [1] يشتهر بزراعة النخيل والموز والحمضيات، ويعتبر من المناطق الزراعية الهامة في المحافظة.";s:14:"description_en";s:238:"Another fertile agricultural valley passing through Abyan Governorate and emptying into the sea. [1] It is famous for cultivating palm trees, bananas, and citrus fruits, and is considered one of the key agricultural areas in the province.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";}s:8:"latitude";d:13.1;s:9:"longitude";d:45.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:359;s:7:"city_id";i:14;s:11:"external_id";s:17:"al-mahfad-reserve";s:4:"name";s:23:"محمية المحفد";s:7:"name_en";s:17:"Al-Mahfad Reserve";s:11:"description";s:306:"منطقة جبلية وعرة تقع في مديرية المحفد، وتتميز بتنوعها البيولوجي الفريد. [11] كانت تعتبر موطناً للوعل النوبي وأنواع أخرى من الحيوانات البرية، وتمثل أهمية طبيعية كبيرة. [11]";s:14:"description_en";s:217:"A rugged mountainous area in the Al-Mahfad district, characterized by its unique biodiversity. [11] It was considered a habitat for the Nubian ibex and other wild animals, representing great natural significance. [11]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:7:"reserve";i:2;s:8:"wildlife";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"محمية";i:2;s:17:"حياة برية";}s:8:"latitude";d:13.9;s:9:"longitude";d:46.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:17:{s:2:"id";i:360;s:7:"city_id";i:14;s:11:"external_id";s:10:"ja'ar-city";s:4:"name";s:19:"مدينة جعار";s:7:"name_en";s:13:"City of Ja'ar";s:11:"description";s:295:"تعتبر المركز التجاري الرئيسي في دلتا أبين وثاني أكبر مدينة في المحافظة بعد زنجبار. [9] تشتهر بأسواقها النشطة وتاريخها الحديث المرتبط بالتنمية الزراعية في المنطقة.";s:14:"description_en";s:222:"Considered the main commercial center in the Abyan Delta and the second-largest city in the governorate after Zinjibar. [9] Famous for its active markets and modern history linked to agricultural development in the region.";s:10:"categories";a:3:{i:0;s:4:"city";i:1;s:6:"market";i:2;s:7:"culture";}s:14:"category_names";a:3:{i:0;s:10:"مدينة";i:1;s:6:"سوق";i:2;s:10:"ثقافي";}s:8:"latitude";d:13.1167;s:9:"longitude";d:45.2833;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:17:{s:2:"id";i:361;s:7:"city_id";i:14;s:11:"external_id";s:16:"wadi-hassan-park";s:4:"name";s:43:"منتزه وادي حسان الطبيعي";s:7:"name_en";s:23:"Wadi Hassan Nature Park";s:11:"description";s:342:"وادي زراعي خصب يشتهر ببساتين النخيل والموز والحمضيات. [1] يعتبر الوادي منتزهاً طبيعياً يقصده السكان المحليون والزوار للنزهة والاستمتاع بالخضرة والمناظر الطبيعية الهادئة، خاصةً على ضفافه.";s:14:"description_en";s:240:"A fertile agricultural valley known for its palm, banana, and citrus orchards. [1] The valley serves as a natural park frequented by locals and visitors for picnics, enjoying the greenery and tranquil landscapes, especially along its banks.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:4:"park";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"منتزه";i:3;s:10:"زراعة";}s:8:"latitude";d:13.1;s:9:"longitude";d:45.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:17:{s:2:"id";i:362;s:7:"city_id";i:14;s:11:"external_id";s:16:"al-habilayn-park";s:4:"name";s:27:"منتزه الحبيلين";s:7:"name_en";s:16:"Al-Habilayn Park";s:11:"description";s:339:"يقع في مديرية رصد، وهي منطقة جبلية تتميز بأجوائها المعتدلة وطبيعتها الخضراء. [4] يعتبر منتزه الحبيلين متنفساً طبيعياً رئيسياً في المنطقة، ويشتهر بأشجاره الكثيفة ومناظره الجبلية الساحرة.";s:14:"description_en";s:225:"Located in the Rasd district, a mountainous area characterized by its moderate climate and green nature. [4] Al-Habilayn Park is a major natural retreat in the region, famous for its dense trees and charming mountain scenery.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.6;s:9:"longitude";d:45.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:17:{s:2:"id";i:363;s:7:"city_id";i:14;s:11:"external_id";s:25:"wadi-ahwar-seasonal-falls";s:4:"name";s:47:"شلالات وادي أحور الموسمية";s:7:"name_en";s:32:"Ahwar Valley Seasonal Waterfalls";s:11:"description";s:317:"وادي كبير يقع في المناطق الشرقية من أبين. [3] عند جريانه في مواسم الأمطار، يخلق مناظر طبيعية رائعة وشلالات مؤقتة على المنحدرات الصخرية، مما يجعله وجهة للمتنزهين ومحبي الطبيعة.";s:14:"description_en";s:239:"A large valley located in the eastern regions of Abyan. [3] When it flows during the rainy seasons, it creates wonderful natural landscapes and temporary waterfalls on rocky slopes, making it a destination for picnickers and nature lovers.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:9:"waterfall";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:8:"شلال";i:3;s:10:"موسمي";}s:8:"latitude";d:13.5;s:9:"longitude";d:46.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:15;a:17:{s:2:"id";i:364;s:7:"city_id";i:14;s:11:"external_id";s:22:"rasd-mountain-terraces";s:4:"name";s:36:"مدرجات رصد الزراعية";s:7:"name_en";s:26:"Rasd Agricultural Terraces";s:11:"description";s:351:"تعتبر المدرجات الزراعية في جبال رصد لوحة فنية طبيعية ومنتزهاً بحد ذاتها. [4] يمكن للزوار التجول بين هذه المدرجات التي تزرع فيها القهوة والحبوب، والاستمتاع بالإطلالات البانورامية والهواء النقي.";s:14:"description_en";s:236:"The agricultural terraces in the Rasd mountains are considered a natural masterpiece and a park in themselves. [4] Visitors can wander among these terraces, where coffee and grains are grown, and enjoy the panoramic views and fresh air.";s:10:"categories";a:4:{i:0;s:6:"scenic";i:1;s:11:"agriculture";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:21:"مناظر خلابة";i:1;s:10:"زراعة";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.55;s:9:"longitude";d:45.35;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:16;a:17:{s:2:"id";i:365;s:7:"city_id";i:14;s:11:"external_id";s:23:"al-mahfad-reserve-views";s:4:"name";s:34:"مطلات محمية المحفد";s:7:"name_en";s:28:"Al-Mahfad Reserve Viewpoints";s:11:"description";s:358:"منطقة جبلية وعرة تتميز بتنوعها البيولوجي. [3] توفر المرتفعات في المحفد إطلالات ومطلات طبيعية ساحرة على الوديان والمناطق المحيطة، وتعتبر وجهة مثالية لمحبي سياحة المغامرات والمناظر الطبيعية البرية.";s:14:"description_en";s:246:"A rugged mountainous area characterized by its biodiversity. [3] The highlands in Al-Mahfad offer charming natural viewpoints overlooking the valleys and surrounding areas, making it an ideal destination for adventure tourism and wild landscapes.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:7:"reserve";i:2;s:6:"scenic";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"محمية";i:2;s:21:"مناظر خلابة";i:3;s:8:"جبلي";}s:8:"latitude";d:13.9;s:9:"longitude";d:46.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:17;a:17:{s:2:"id";i:366;s:7:"city_id";i:14;s:11:"external_id";s:25:"wadi-al-wadih-green-areas";s:4:"name";s:47:"مناطق وادي الوضيع الخضراء";s:7:"name_en";s:25:"Wadi Al-Wadi' Green Areas";s:11:"description";s:318:"يقع في مديرية الوضيع، ويتميز بأراضيه الزراعية الخصبة التي تعتمد على المياه الجوفية والسيول. [3] تتحول أجزاء من الوادي إلى ما يشبه المنتزهات الطبيعية الخضراء بعد مواسم الأمطار.";s:14:"description_en";s:223:"Located in the Al-Wadi' district, it is distinguished by its fertile agricultural lands that rely on groundwater and floods. [3] Parts of the valley transform into what resembles green natural parks after the rainy seasons.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:10:"منتزه";}s:8:"latitude";d:13.45;s:9:"longitude";d:45.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:18;a:17:{s:2:"id";i:367;s:7:"city_id";i:14;s:11:"external_id";s:20:"sabah-mountain-views";s:4:"name";s:26:"مطلات جبل سباح";s:7:"name_en";s:22:"Mount Sibah Viewpoints";s:11:"description";s:347:"تقع مديرية سباح في منطقة مرتفعة، وتوفر جبالها إطلالات بانورامية على المناطق المحيطة. [4] تعتبر هذه المرتفعات بمثابة منتزهات طبيعية مفتوحة، وتتميز بأجوائها اللطيفة ومناظرها الطبيعية الجبلية.";s:14:"description_en";s:238:"The Sibah district is located in an elevated area, and its mountains offer panoramic views of the surrounding regions. [4] These highlands serve as open natural parks, characterized by their pleasant atmosphere and mountainous landscapes.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"scenic";i:2;s:7:"natural";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:8:"جبلي";i:1;s:21:"مناظر خلابة";i:2;s:10:"طبيعي";i:3;s:6:"مطل";}s:8:"latitude";d:13.7;s:9:"longitude";d:45.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:19;a:17:{s:2:"id";i:368;s:7:"city_id";i:14;s:11:"external_id";s:21:"khanfar-mountain-park";s:4:"name";s:26:"منتزه جبل خنفر";s:7:"name_en";s:18:"Mount Khanfar Park";s:11:"description";s:339:"الجبل الذي يطل على مدينة جعار ودلتا أبين. [3] بالإضافة إلى أهميته التاريخية لوجود قلعة خنفر، يعتبر الجبل ومنحدراته متنفساً طبيعياً يوفر إطلالات رائعة على المساحات الخضراء الشاسعة للدلتا.";s:14:"description_en";s:272:"The mountain that overlooks the city of Ja'ar and the Abyan Delta. [3] In addition to its historical significance due to the presence of Khanfar Castle, the mountain and its slopes are considered a natural retreat offering wonderful views of the delta's vast green spaces.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:9:"viewpoint";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:6:"مطل";i:3;s:12:"تاريخي";}s:8:"latitude";d:13.133;s:9:"longitude";d:45.283;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:2;a:13:{s:2:"id";i:17;s:4:"slug";s:5:"bayda";s:4:"name";s:14:"البيضاء";s:7:"name_en";s:8:"Al Bayda";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:17:"al_bayda_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:31;s:9:"landmarks";a:31:{i:0;a:17:{s:2:"id";i:420;s:7:"city_id";i:17;s:11:"external_id";s:20:"amiriya-school-radaa";s:4:"name";s:42:"المدرسة العامرية (رداع)";s:7:"name_en";s:24:"Amiriya Madrasa (Rada'a)";s:11:"description";s:416:"تحفة معمارية إسلامية فريدة تقع في مدينة رداع. بناها السلطان عامر بن عبدالوهاب الطاهري عام 1504م. [1, 2] تتميز بقبابها المزخرفة وكتاباتها ونقوشها الجصية الملونة، وتعتبر من أهم المعالم الإسلامية في اليمن وكانت مركزاً علمياً هاماً. [1, 2]";s:14:"description_en";s:331:"A unique Islamic architectural masterpiece located in the city of Rada'a. Built by Sultan Amir bin Abdulwahab Al-Tahir in 1504 AD. [1, 2] It features ornate domes, colorful stucco inscriptions, and carvings, and is considered one of the most important Islamic landmarks in Yemen, having been a significant scientific center. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:7:"islamic";i:3;s:6:"school";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:12:"إسلامي";i:3;s:10:"مدرسة";}s:8:"latitude";d:14.4147;s:9:"longitude";d:44.7731;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:421;s:7:"city_id";i:17;s:11:"external_id";s:12:"bayda-castle";s:4:"name";s:23:"قلعة البيضاء";s:7:"name_en";s:15:"Al Bayda Castle";s:11:"description";s:332:"قلعة تاريخية تقع على تلة صخرية تطل على مدينة البيضاء، عاصمة المحافظة. [3, 4] كانت القلعة حصناً منيعاً ومركزاً للحكم عبر العصور، وتوفر إطلالة بانورامية على المدينة والمناطق المحيطة بها.";s:14:"description_en";s:266:"A historic castle located on a rocky hill overlooking the city of Al Bayda, the capital of the governorate. [3, 4] The castle was an impregnable fortress and a center of governance throughout the ages, offering a panoramic view of the city and its surrounding areas.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:9:"viewpoint";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:6:"مطل";i:3;s:12:"معماري";}s:8:"latitude";d:13.975;s:9:"longitude";d:45.575;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:422;s:7:"city_id";i:17;s:11:"external_id";s:12:"radaa-castle";s:4:"name";s:17:"قلعة رداع";s:7:"name_en";s:13:"Rada'a Castle";s:11:"description";s:404:"قلعة تاريخية ضخمة تقع في مدينة رداع، وتعتبر من أقدم وأهم القلاع في المحافظة. [5] يعود تاريخها إلى فترة ما قبل الإسلام (الدولة الحميرية)، وشهدت العديد من الإضافات والتجديدات عبر العصور، وكانت مركزاً إدارياً وعسكرياً هاماً. [5]";s:14:"description_en";s:318:"A massive historical castle located in the city of Rada'a, considered one of the oldest and most important castles in the governorate. [5] Dating back to the pre-Islamic period (the Himyarite Kingdom), it witnessed many additions and renovations over the ages, and was a crucial administrative and military center. [5]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:7:"ancient";i:3;s:8:"military";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:8:"قديم";i:3;s:10:"عسكري";}s:8:"latitude";d:14.4167;s:9:"longitude";d:44.7667;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:17:{s:2:"id";i:423;s:7:"city_id";i:17;s:11:"external_id";s:19:"al-bayda-grand-park";s:4:"name";s:38:"حديقة البيضاء الكبرى";s:7:"name_en";s:19:"Al Bayda Grand Park";s:11:"description";s:342:"تعتبر الحديقة العامة الرئيسية في مدينة البيضاء، مركز المحافظة. [1, 2] تمثل المتنفس الأهم للعائلات داخل المدينة، وتضم مساحات خضراء وألعابًا للأطفال، وتشهد إقبالًا في الأعياد والمناسبات. [1, 2]";s:14:"description_en";s:267:"Considered the main public park in the city of Al Bayda, the center of the governorate. [1, 2] It represents the most important retreat for families within the city, featuring green spaces and children's games, and sees large crowds during holidays and events. [1, 2]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:17:{s:2:"id";i:424;s:7:"city_id";i:17;s:11:"external_id";s:10:"wadi-ahrar";s:4:"name";s:19:"وادي أحرار";s:7:"name_en";s:10:"Wadi Ahrar";s:11:"description";s:314:"أحد الأودية الخصبة والجميلة في مديرية السوادية. يشتهر بمياهه الجارية ومزارعه الخضراء، ويعتبر متنفساً طبيعياً للسكان والزوار، خاصة في مواسم الأمطار حيث تزداد خضرته وجماله.";s:14:"description_en";s:243:"One of the fertile and beautiful valleys in the As Sawadiyah district. Known for its running waters and green farms, it is a natural retreat for residents and visitors, especially during the rainy seasons when its lushness and beauty increase.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:14.2;s:9:"longitude";d:45.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:17:{s:2:"id";i:425;s:7:"city_id";i:17;s:11:"external_id";s:18:"sawadiyah-fortress";s:4:"name";s:23:"حصن السوادية";s:7:"name_en";s:17:"As Sawadiyah Fort";s:11:"description";s:315:"حصن تاريخي يقع في مديرية السوادية، ويتميز بموقعه الاستراتيجي على قمة جبل. [4] كان يستخدم كنقطة مراقبة وحماية للطرق التجارية القديمة، ويوفر إطلالات واسعة على المناطق المحيطة.";s:14:"description_en";s:225:"A historic fort located in the As Sawadiyah district, notable for its strategic position on a mountaintop. [4] It was used as a watchpoint and to protect ancient trade routes, offering sweeping views of the surrounding areas.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:10:"عسكري";i:3;s:6:"مطل";}s:8:"latitude";d:14.25;s:9:"longitude";d:45.15;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:17:{s:2:"id";i:426;s:7:"city_id";i:17;s:11:"external_id";s:11:"jabal-sawad";s:4:"name";s:19:"جبل السواد";s:7:"name_en";s:14:"Mount Al-Sawad";s:11:"description";s:324:"سلسلة جبلية بركانية تشتهر بصخورها السوداء التي أعطت المنطقة اسمها. [6] تعتبر المنطقة ذات أهمية جيولوجية وتاريخية، حيث توجد بها نقوش صخرية قديمة، وتوفر مناظر طبيعية فريدة ومختلفة.";s:14:"description_en";s:232:"A volcanic mountain range famous for its black rocks that gave the region its name. [6] The area is of geological and historical significance, containing ancient rock inscriptions and offering unique and distinct natural landscapes.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:10:"geological";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:14:"جيولوجي";i:3;s:12:"تاريخي";}s:8:"latitude";d:14.3;s:9:"longitude";d:45.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:17:{s:2:"id";i:427;s:7:"city_id";i:17;s:11:"external_id";s:13:"mukayras-city";s:4:"name";s:23:"مدينة مكيراس";s:7:"name_en";s:13:"Mukayras City";s:11:"description";s:285:"تقع على هضبة مرتفعة وتشتهر بأجوائها الباردة والمعتدلة صيفاً. [7] كانت مصيفاً شهيراً في الماضي، وتتميز بطبيعتها الجبلية الخلابة ومزارعها، خاصة زراعة اللوز. [7]";s:14:"description_en";s:229:"Situated on a high plateau, it is famous for its cold and moderate summer climate. [7] It was a popular summer resort in the past, characterized by its breathtaking mountainous nature and farms, especially almond cultivation. [7]";s:10:"categories";a:4:{i:0;s:4:"city";i:1;s:8:"mountain";i:2;s:7:"climate";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"مدينة";i:1;s:8:"جبلي";i:2;s:8:"مناخ";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.95;s:9:"longitude";d:45.66;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:8;a:17:{s:2:"id";i:428;s:7:"city_id";i:17;s:11:"external_id";s:21:"baghdad-village-ruins";s:4:"name";s:30:"أطلال قرية بغداد";s:7:"name_en";s:24:"Ruins of Baghdad Village";s:11:"description";s:286:"موقع أثري يقع في مديرية الطفة، ويعتقد أنه يعود إلى فترة ما قبل الإسلام. [8] يضم الموقع بقايا مبانٍ قديمة ونقوشاً حميرية، مما يدل على الأهمية التاريخية للمنطقة.";s:14:"description_en";s:233:"An archaeological site located in the At Taffah district, believed to date back to the pre-Islamic period. [8] The site contains remains of old buildings and Himyarite inscriptions, indicating the historical importance of the region.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:7:"ancient";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:8:"قديم";}s:8:"latitude";d:14.1;s:9:"longitude";d:45.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:9;a:17:{s:2:"id";i:429;s:7:"city_id";i:17;s:11:"external_id";s:14:"radaa-old-city";s:4:"name";s:34:"مدينة رداع القديمة";s:7:"name_en";s:18:"Old City of Rada'a";s:11:"description";s:331:"إلى جانب القلعة والمدرسة العامرية، تتميز مدينة رداع القديمة بأسوارها ومنازلها المبنية من الطين (الياجور) والمزينة بالزخارف الجصية. [5] التجول في أزقتها الضيقة يعتبر رحلة عبر التاريخ.";s:14:"description_en";s:249:"Alongside the castle and the Amiriya Madrasa, the old city of Rada'a is distinguished by its walls and houses built of fired mud bricks (Yajur) and decorated with stucco patterns. [5] Wandering through its narrow alleys is a journey through history.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:10:"ثقافي";}s:8:"latitude";d:14.41;s:9:"longitude";d:44.77;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:10;a:17:{s:2:"id";i:430;s:7:"city_id";i:17;s:11:"external_id";s:11:"jabal-arash";s:4:"name";s:17:"جبل العرش";s:7:"name_en";s:13:"Mount Al-Arsh";s:11:"description";s:287:"أحد الجبال الشاهقة في المحافظة، يقع في مديرية العرش. [4] يشتهر بحصونه التاريخية المنتشرة على قممه، ويوفر إطلالات بانورامية على مساحات واسعة من محافظة البيضاء.";s:14:"description_en";s:217:"One of the towering mountains in the governorate, located in the Al-Arsh district. [4] It is famous for the historic forts scattered across its peaks, providing panoramic views over vast areas of Al Bayda Governorate.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:10:"historical";i:2;s:9:"viewpoint";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"جبلي";i:1;s:12:"تاريخي";i:2;s:6:"مطل";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.2;s:9:"longitude";i:45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:11;a:17:{s:2:"id";i:431;s:7:"city_id";i:17;s:11:"external_id";s:19:"wadi-al-sabil-falls";s:4:"name";s:34:"شلالات وادي السبيل";s:7:"name_en";s:24:"Wadi Al-Sabil Waterfalls";s:11:"description";s:360:"يقع في مديرية الطفة، وهو من الأودية الجميلة التي تتشكل فيها شلالات موسمية رائعة بعد هطول الأمطار. [1] يعتبر الوادي ومحيطه متنفساً طبيعياً للسكان المحليين للاستمتاع بالمناظر الخضراء والمياه الجارية.";s:14:"description_en";s:242:"Located in the At Taffah district, it is a beautiful valley where magnificent seasonal waterfalls form after rainfall. [1] The valley and its surroundings serve as a natural retreat for locals to enjoy the green landscapes and running waters.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:8:"seasonal";i:3;s:6:"valley";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:10:"موسمي";i:3;s:8:"وادي";}s:8:"latitude";d:14.12;s:9:"longitude";d:45.35;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:12;a:17:{s:2:"id";i:432;s:7:"city_id";i:17;s:11:"external_id";s:23:"mukayras-highlands-park";s:4:"name";s:38:"منتزه مرتفعات مكيراس";s:7:"name_en";s:23:"Mukayras Highlands Park";s:11:"description";s:337:"تعتبر المنطقة الجبلية المحيطة بمدينة مكيراس منتزهاً طبيعياً بحد ذاتها. [2] تشتهر بأجوائها المعتدلة والباردة، ومزارع اللوز والفرسك (الخوخ)، وتوفر إطلالات بانورامية ومناطق هادئة للنزهات.";s:14:"description_en";s:213:"The mountainous area surrounding the city of Mukayras is considered a natural park in itself. [2] Known for its mild and cool climate, almond and peach farms, it offers panoramic views and quiet areas for picnics.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:13.95;s:9:"longitude";d:45.66;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:13;a:17:{s:2:"id";i:433;s:7:"city_id";i:17;s:11:"external_id";s:15:"wadi-bayan-park";s:4:"name";s:28:"منتزه وادي بيان";s:7:"name_en";s:15:"Wadi Bayan Park";s:11:"description";s:335:"أحد الأودية الهامة في المحافظة، يمر بالقرب من مدينة البيضاء. [3] يتميز الوادي بمساحاته الخضراء الواسعة التي تظهر بعد مواسم الأمطار، ويقصده الأهالي للرحلات الخلوية والاستمتاع بالطبيعة.";s:14:"description_en";s:239:"One of the important valleys in the governorate, passing near the city of Al Bayda. [3] The valley is characterized by its vast green spaces that appear after the rainy seasons, and residents visit it for outdoor trips and to enjoy nature.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:6:"valley";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:8:"وادي";i:3;s:10:"موسمي";}s:8:"latitude";i:14;s:9:"longitude";d:45.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:14;a:17:{s:2:"id";i:434;s:7:"city_id";i:17;s:11:"external_id";s:18:"sharyah-waterfalls";s:4:"name";s:38:"شلالات مديرية الشرية";s:7:"name_en";s:31:"Al-Shariyah District Waterfalls";s:11:"description";s:340:"تتميز مديرية الشرية بطبيعتها الجبلية، وتتشكل في أوديتها العديد من الشلالات الموسمية الصغيرة بعد تدفق السيول. [4] توفر هذه الشلالات مناظر طبيعية جميلة وتجذب المتنزهين من المناطق المجاورة.";s:14:"description_en";s:233:"The Al-Shariyah district is noted for its mountainous nature. Many small seasonal waterfalls form in its valleys after floods flow. [4] These waterfalls provide beautiful natural scenery and attract picnickers from neighboring areas.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:8:"seasonal";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:10:"موسمي";i:3;s:8:"جبلي";}s:8:"latitude";d:14.3;s:9:"longitude";d:45.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:15;a:17:{s:2:"id";i:435;s:7:"city_id";i:17;s:11:"external_id";s:18:"al-zaher-parklands";s:4:"name";s:47:"منتزهات آل حميقان (الزاهر)";s:7:"name_en";s:27:"Al Humiqan Parks (Az Zahir)";s:11:"description";s:316:"تضم منطقة الزاهر (آل حميقان) العديد من الأودية والمناطق الخضراء التي تصلح كمنتزهات طبيعية. [5] تشتهر المنطقة بخصوبتها وتنوعها الزراعي، وتوفر بيئة ريفية هادئة ومناسبة للنزهات.";s:14:"description_en";s:224:"The Az Zahir (Al Humiqan) area includes many valleys and green spaces suitable as natural parks. [5] The region is famous for its fertility and agricultural diversity, providing a quiet rural environment perfect for outings.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:13.85;s:9:"longitude";d:45.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:16;a:17:{s:2:"id";i:436;s:7:"city_id";i:17;s:11:"external_id";s:20:"wadi-al-malajim-park";s:4:"name";s:34:"منتزه وادي الملاجم";s:7:"name_en";s:20:"Wadi Al-Malajim Park";s:11:"description";s:314:"وادي واسع يقع في مديرية الملاجم، ويشتهر بأراضيه الزراعية التي تعتمد على مياه السيول. [4] بعد الأمطار، يتحول الوادي إلى مساحات خضراء شاسعة، مما يجعله منتزهاً طبيعياً مفتوحاً.";s:14:"description_en";s:210:"A wide valley located in the Al-Malajim district, famous for its agricultural lands that rely on floodwaters. [4] After the rains, the valley transforms into vast green expanses, making it an open natural park.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:6:"valley";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:8:"وادي";i:3;s:10:"موسمي";}s:8:"latitude";d:14.4;s:9:"longitude";d:45.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:17;a:17:{s:2:"id";i:437;s:7:"city_id";i:17;s:11:"external_id";s:24:"al-arsh-mountain-springs";s:4:"name";s:43:"عيون ومنتزهات جبل العرش";s:7:"name_en";s:34:"Springs and Parks of Mount Al-Arsh";s:11:"description";s:318:"بالإضافة إلى حصونه، يضم جبل العرش والمناطق المحيطة به عيون مياه طبيعية ومناطق رعوية خضراء. [6] تعتبر هذه المواقع بمثابة منتزهات طبيعية صغيرة توفر إطلالات رائعة ومكاناً للراحة.";s:14:"description_en";s:213:"In addition to its forts, Mount Al-Arsh and its surrounding areas feature natural water springs and green pastoral lands. [6] These sites serve as small natural parks providing wonderful views and a place to rest.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:6:"spring";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:10:"ينبوع";i:3;s:10:"منتزه";}s:8:"latitude";d:14.2;s:9:"longitude";i:45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:18;a:17:{s:2:"id";i:438;s:7:"city_id";i:17;s:11:"external_id";s:20:"radman-al-awad-falls";s:4:"name";s:53:"شلالات ردمان العواد الموسمية";s:7:"name_en";s:34:"Radman Al-Awad Seasonal Waterfalls";s:11:"description";s:333:"مديرية ردمان هي منطقة جبلية تاريخية، وتتشكل في أوديتها شلالات جميلة بعد هطول الأمطار. [4] تجذب هذه الشلالات المؤقتة السكان المحليين للاستمتاع بمنظر تدفق المياه في قلب الطبيعة الجبلية.";s:14:"description_en";s:239:"The Radman district is a historical mountainous region where beautiful waterfalls form in its valleys following rainfall. [4] These temporary waterfalls attract locals to enjoy the sight of flowing water in the heart of mountainous nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.35;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:19;a:17:{s:2:"id";i:439;s:7:"city_id";i:17;s:11:"external_id";s:17:"sabah-valley-park";s:4:"name";s:28:"منتزه وادي صباح";s:7:"name_en";s:15:"Wadi Sabah Park";s:11:"description";s:262:"يقع في مديرية صباح، ويتميز بطبيعته الهادئة وأراضيه الزراعية. [4] يعتبر الوادي وجهة للنزهات العائلية، خاصة خلال مواسم الخصوبة والاعتدال في الطقس.";s:14:"description_en";s:213:"Located in the Sabah district, it is characterized by its tranquil nature and agricultural lands. [4] The valley is a destination for family picnics, especially during the fertile seasons when the weather is mild.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:6:"valley";i:2;s:7:"natural";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"وادي";i:2;s:10:"طبيعي";i:3;s:10:"زراعة";}s:8:"latitude";d:13.9;s:9:"longitude";d:45.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:20;a:17:{s:2:"id";i:440;s:7:"city_id";i:17;s:11:"external_id";s:20:"dhi-naim-green-areas";s:4:"name";s:39:"مناطق ذي ناعم الخضراء";s:7:"name_en";s:21:"Dhi Na'im Green Areas";s:11:"description";s:323:"تشتهر مديرية ذي ناعم بخصوبة أراضيها ووفرة مياهها نسبياً. [4] تنتشر في المديرية العديد من المناطق الخضراء والبساتين التي تشكل منتزهات طبيعية صغيرة يقصدها الناس للراحة والاستجمام.";s:14:"description_en";s:243:"The Dhi Na'im district is renowned for the fertility of its land and the relative abundance of its waters. [4] Many green areas and orchards spread throughout the district, forming small natural parks that people visit for rest and recreation.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.1;s:9:"longitude";d:45.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:21;a:17:{s:2:"id";i:441;s:7:"city_id";i:17;s:11:"external_id";s:18:"wadi-hadekah-falls";s:4:"name";s:60:"شلالات وادي حمرة (مديرية الصومعة)";s:7:"name_en";s:45:"Wadi Humrah Waterfalls (As Sawma'ah District)";s:11:"description";s:279:"يقع في مديرية الصومعة، وهو وادٍ جبلي تنحدر فيه السيول مكونة شلالات جميلة على المنحدرات الصخرية. يعتبر منظراً طبيعياً جذاباً للسكان المحليين بعد الأمطار.";s:14:"description_en";s:212:"Located in the As Sawma'ah district, it is a mountain valley where floods descend, creating beautiful waterfalls on the rocky slopes. It acts as an attractive natural landscape for local residents after the rain.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.05;s:9:"longitude";d:45.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:22;a:17:{s:2:"id";i:442;s:7:"city_id";i:17;s:11:"external_id";s:26:"al-qurayshiyah-upper-falls";s:4:"name";s:40:"شلالات أعالي القريشية";s:7:"name_en";s:30:"Upper Al-Quraishyah Waterfalls";s:11:"description";s:319:"في المرتفعات الجبلية لمديرية القريشية، تتشكل العديد من الشلالات الصغيرة والمتوسطة التي تغذي وادي أحرار وغيره من الأودية. توفر هذه المناطق مناظر طبيعية بكر ومسارات للمغامرين.";s:14:"description_en";s:207:"In the mountainous highlands of the Al-Quraishyah district, many small and medium waterfalls form, feeding Wadi Ahrar and other valleys. These areas offer pristine natural scenery and trails for adventurers.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:12:"مغامرة";}s:8:"latitude";d:14.25;s:9:"longitude";d:45.05;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:23;a:17:{s:2:"id";i:443;s:7:"city_id";i:17;s:11:"external_id";s:25:"wadi-al-ghayl-falls-bayda";s:4:"name";s:49:"شلالات وادي الغيل (البيضاء)";s:7:"name_en";s:35:"Wadi Al-Ghayl Waterfalls (Al Bayda)";s:11:"description";s:294:"يوجد أكثر من وادٍ بهذا الاسم، وأحدها في البيضاء بمديرية مكيراس. يتميز هذا الوادي بتدفق المياه فيه بعد الأمطار، مما يخلق شلالات صغيرة وبرك مائية مناسبة للاستجمام.";s:14:"description_en";s:247:"There is more than one valley with this name, and one of them is in Al Bayda within the Mukayras district. This valley is distinguished by water flowing through it after the rains, creating small waterfalls and water pools suitable for recreation.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.9;s:9:"longitude";d:45.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:24;a:17:{s:2:"id";i:444;s:7:"city_id";i:17;s:11:"external_id";s:26:"maswarah-mountain-cascades";s:4:"name";s:32:"شلالات جبال مسورة";s:7:"name_en";s:29:"Maswarah Mountains Waterfalls";s:11:"description";s:284:"مديرية مسورة هي منطقة جبلية وعرة. تتسبب الأمطار الغزيرة في تدفق المياه بقوة عبر المنحدرات، مكونة سلسلة من الشلالات المتتالية (Cascades) التي توفر منظراً مهيباً.";s:14:"description_en";s:172:"The Maswarah district is a rugged mountainous area. Heavy rains cause water to flow powerfully down the slopes, creating a series of cascades that provide a majestic sight.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.45;s:9:"longitude";i:45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:25;a:17:{s:2:"id";i:445;s:7:"city_id";i:17;s:11:"external_id";s:15:"wadi-thah-falls";s:4:"name";s:28:"شلالات وادي ثاه";s:7:"name_en";s:20:"Wadi Thah Waterfalls";s:11:"description";s:260:"أحد الأودية الهامة في مديرية ناطع. عند جريان السيول، تتشكل فيه شلالات قوية نظراً للطبيعة الصخرية للمنطقة، مما يجذب السكان لمشاهدة قوة الطبيعة.";s:14:"description_en";s:200:"One of the important valleys in the Nati' district. When floods run through it, powerful waterfalls are formed due to the rocky nature of the area, attracting residents to witness the power of nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:6:"قوي";}s:8:"latitude";d:14.6;s:9:"longitude";d:45.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:26;a:17:{s:2:"id";i:446;s:7:"city_id";i:17;s:11:"external_id";s:22:"as-sawmaah-rocky-falls";s:4:"name";s:42:"شلالات الصومعة الصخرية";s:7:"name_en";s:28:"As Sawma'ah Rocky Waterfalls";s:11:"description";s:273:"تتميز مديرية الصومعة بتكويناتها الصخرية الفريدة. تنحت المياه المتدفقة طريقها عبر هذه الصخور لتشكل شلالات ذات طابع خاص، وتكون محاطة بالخضرة الموسمية.";s:14:"description_en";s:196:"The As Sawma'ah district is characterized by its unique rock formations. Flowing water carves its way through these rocks to form distinctive waterfalls, which are surrounded by seasonal greenery.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:5:"rocky";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"صخري";i:3;s:21:"مناظر خلابة";}s:8:"latitude";i:14;s:9:"longitude";d:45.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:27;a:17:{s:2:"id";i:447;s:7:"city_id";i:17;s:11:"external_id";s:21:"noman-valley-cascades";s:4:"name";s:32:"شلالات وادي نعمان";s:7:"name_en";s:22:"Wadi Na'man Waterfalls";s:11:"description";s:274:"يقع في مديرية نعمان، وهو وادٍ واسع تتجمع فيه مياه السيول من مناطق مختلفة. تتشكل على أطرافه شلالات صغيرة عند التقاء الروافد به، مما يضيف لجماله الطبيعي.";s:14:"description_en";s:185:"Located in the Na'man district, it is a wide valley where floodwaters gather from various areas. Small waterfalls form on its edges where tributaries meet, adding to its natural beauty.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.5;s:9:"longitude";d:45.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:28;a:17:{s:2:"id";i:448;s:7:"city_id";i:17;s:11:"external_id";s:16:"wadi-habun-falls";s:4:"name";s:30:"شلالات وادي حبون";s:7:"name_en";s:21:"Wadi Habun Waterfalls";s:11:"description";s:282:"يمر هذا الوادي في مديرية السوادية، ويشتهر بتدفقه القوي بعد الأمطار. تتكون فيه شلالات جميلة على طول مجراه، خاصة في المناطق التي يضيق فيها الوادي بين الجبال.";s:14:"description_en";s:214:"This valley passes through the As Sawadiyah district and is famous for its strong flow after rainfall. Beautiful waterfalls form along its course, especially in areas where the valley narrows between the mountains.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.22;s:9:"longitude";d:45.18;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:29;a:17:{s:2:"id";i:449;s:7:"city_id";i:17;s:11:"external_id";s:25:"al-malajim-mountain-falls";s:4:"name";s:36:"شلالات جبال الملاجم";s:7:"name_en";s:31:"Al-Malajim Mountains Waterfalls";s:11:"description";s:295:"المرتفعات الجبلية في مديرية الملاجم هي مصدر للعديد من السيول التي تغذي الأودية. تتشكل على هذه المرتفعات شلالات تنحدر بقوة نحو الأسفل، وتكون مشاهدتها تجربة فريدة.";s:14:"description_en";s:211:"The mountain highlands in the Al-Malajim district are the source of many floods that feed the valleys. Waterfalls form on these highlands, plunging forcefully downwards, making watching them a unique experience.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:6:"قوي";}s:8:"latitude";d:14.42;s:9:"longitude";d:45.35;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:30;a:17:{s:2:"id";i:450;s:7:"city_id";i:17;s:11:"external_id";s:18:"wadi-ar-rumh-falls";s:4:"name";s:32:"شلالات وادي الرمح";s:7:"name_en";s:23:"Wadi Al-Rumh Waterfalls";s:11:"description";s:258:"يقع في مديرية الطفة، ويتميز بوجود منحدرات صخرية حادة. عندما تتدفق مياه الأمطار، فإنها تسقط من هذه المنحدرات مكونة شلالات موسمية جميلة وجذابة.";s:14:"description_en";s:184:"Located in the At Taffah district, it is characterized by sharp rocky cliffs. When rainwater flows, it cascades down these cliffs, forming beautiful and attractive seasonal waterfalls.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:5:"rocky";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:8:"صخري";}s:8:"latitude";d:14.15;s:9:"longitude";d:45.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:3;a:13:{s:2:"id";i:29;s:4:"slug";s:6:"torbah";s:4:"name";s:12:"التربه";s:7:"name_en";s:9:"At Turbah";s:11:"description";s:388:"تعد مدينة التربة من أهم مدن محافظة تعز في اليمن، وتمثل المركز الإداري لمديرية الشمايتين. تُلقب بـ "المدينة المعلقة" نظراً لموقعها الجغرافي الفريد على حافة جبل ذبحان بارتفاع يصل إلى حوالي 1900 متر فوق مستوى سطح البحر.";s:14:"description_en";s:309:"At Turbah is one of the most important cities in Taiz Governorate in Yemen and represents the administrative center of Ash Shamayatayn District. It is nicknamed the "Hanging City" due to its unique geographical location on the edge of Mount Dhubhan, reaching an altitude of about 1,900 meters above sea level.";s:9:"image_url";s:59:"https://suhail.net/userimages/2024/08/1723404055blobid0.jpg";s:6:"status";s:9:"published";s:8:"category";s:19:"mountain historical";s:15:"landmarks_count";i:1;s:9:"landmarks";a:1:{i:0;a:17:{s:2:"id";i:621;s:7:"city_id";i:29;s:11:"external_id";N;s:4:"name";s:19:"هيجة العبد";s:7:"name_en";s:13:"Hayjat Al-Abd";s:11:"description";s:298:"تعد هيجة العبد أحد أهم الطرق الاستراتيجية والحيوية في اليمن، حيث تمثل الشريان البري الوحيد والرئيسي الذي يربط مدينة تعز المحاصرة بالمحافظات الجنوبية مثل لحج وعدن.";s:14:"description_en";s:215:"Hayjat Al-Abd is considered one of the most important and vital strategic roads in Yemen, representing the sole and main land artery connecting the besieged city of Taiz to southern governorates like Lahij and Aden.";s:10:"categories";a:1:{i:0;s:10:"historical";}s:14:"category_names";a:1:{i:0;s:12:"تاريخي";}s:8:"latitude";d:13.2113134;s:9:"longitude";d:44.1978578;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTq7fi5vEb2IHfnZA02jD81gkUlFbTZVsBMFw&s";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-05T21:12:07.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-04-05T21:06:07.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:4;a:13:{s:2:"id";i:20;s:4:"slug";s:6:"aljawf";s:4:"name";s:10:"الجوف";s:7:"name_en";s:7:"Al Jawf";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:16:"al_hazm_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:17;s:9:"landmarks";a:17:{i:0;a:17:{s:2:"id";i:501;s:7:"city_id";i:20;s:11:"external_id";s:21:"baraqish-ancient-city";s:4:"name";s:45:"مدينة براقش (يثل القديمة)";s:7:"name_en";s:34:"City of Baraqish (Ancient Yathill)";s:11:"description";s:395:"أشهر وأهم مدينة أثرية في الجوف، كانت عاصمة مملكة معين الدينية. [1, 2] تتميز بسورها العظيم وأبراجها الـ 57 التي لا تزال قائمة، وتضم بداخلها بقايا معابد وقصور ومنازل، وتعتبر من أكمل المدن الأثرية في شبه الجزيرة العربية. [1, 2]";s:14:"description_en";s:324:"The most famous and significant ancient city in Al-Jawf, it was the religious capital of the Minaean Kingdom. [1, 2] Known for its great wall and 57 towers that still stand, it houses the remains of temples, palaces, and homes inside. It is considered one of the most complete ancient cities in the Arabian Peninsula. [1, 2]";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:7:"ancient";i:3;s:4:"city";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"قديم";i:3;s:10:"مدينة";}s:8:"latitude";d:15.8333;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:1;a:17:{s:2:"id";i:502;s:7:"city_id";i:20;s:11:"external_id";s:20:"qarnawu-ancient-city";s:4:"name";s:36:"قرناو (معين القديمة)";s:7:"name_en";s:23:"Qarnawu (Ancient Ma'in)";s:11:"description";s:372:"العاصمة السياسية لمملكة معين، وتقع بالقرب من مدينة الحزم. [3, 4] على الرغم من أن الكثير منها مدفون تحت الرمال، إلا أن أطلالها لا تزال شاهدة على عظمتها، وقد عُثر فيها على العديد من النقوش والتماثيل الهامة. [3, 4]";s:14:"description_en";s:245:"The political capital of the Minaean Kingdom, located near the city of Al-Hazm. [3, 4] Although much of it is buried under sand, its ruins still testify to its greatness. Many important inscriptions and statues have been discovered there. [3, 4]";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:7:"capital";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:10:"عاصمة";}s:8:"latitude";i:16;s:9:"longitude";d:44.8167;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:2;a:17:{s:2:"id";i:503;s:7:"city_id";i:20;s:11:"external_id";s:21:"al-sawda-ancient-city";s:4:"name";s:38:"السوداء (نشن القديمة)";s:7:"name_en";s:25:"As-Sawda (Ancient Nashan)";s:11:"description";s:288:"مدينة أثرية هامة كانت إحدى مدن مملكة معين. [5, 6] تشتهر بمعبدها "بنات عاد" الذي لا تزال بعض أعمدته قائمة، وعُثر فيها على نقوش هامة تحكي عن تاريخ المدينة وقوانينها.";s:14:"description_en";s:248:"An important archaeological city that was one of the cities of the Minaean Kingdom. [5, 6] It is famous for its 'Banat Aad' temple, where some columns remain standing, and crucial inscriptions have been found recounting the city's history and laws.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:6:"temple";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:8:"معبد";}s:8:"latitude";d:15.9167;s:9:"longitude";d:44.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:17:{s:2:"id";i:504;s:7:"city_id";i:20;s:11:"external_id";s:21:"al-bayda-ancient-city";s:4:"name";s:38:"البيضاء (نشق القديمة)";s:7:"name_en";s:24:"Al-Bayda (Ancient Nashq)";s:11:"description";s:292:"مدينة معينية قديمة تقع إلى الجنوب الغربي من السوداء. [5, 7] كانت مدينة محصنة ومحطة هامة على طريق البخور، وتضم أطلال معابد ومبانٍ تدل على أهميتها التجارية والدينية.";s:14:"description_en";s:224:"An ancient Minaean city located southwest of As-Sawda. [5, 7] It was a fortified city and a significant stop on the Incense Route, housing ruins of temples and buildings that point to its commercial and religious importance.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:5:"trade";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:10:"تجارة";}s:8:"latitude";d:15.9;s:9:"longitude";d:44.73;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:17:{s:2:"id";i:505;s:7:"city_id";i:20;s:11:"external_id";s:19:"al-hazm-public-park";s:4:"name";s:34:"حديقة الحزم العامة";s:7:"name_en";s:19:"Al-Hazm Public Park";s:11:"description";s:331:"الحديقة العامة الرئيسية في مدينة الحزم، عاصمة المحافظة. [5] تمثل متنفسًا منظمًا للعائلات والأطفال داخل المدينة، وتضم بعض المساحات الخضراء والألعاب، وتعتبر مكانًا للراحة والترفيه. [5]";s:14:"description_en";s:231:"The main public park in Al-Hazm, the capital of the governorate. [5] It represents an organized retreat for families and children within the city, containing green spaces and games, making it a place for rest and entertainment. [5]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:17:{s:2:"id";i:506;s:7:"city_id";i:20;s:11:"external_id";s:14:"al-hazm-castle";s:4:"name";s:17:"قصر الحزم";s:7:"name_en";s:14:"Al-Hazm Palace";s:11:"description";s:289:"يقع في مدينة الحزم، عاصمة المحافظة. [8] هو قصر تاريخي يعود إلى فترة الإمامة، وكان يستخدم كمركز للحكم والإدارة في المنطقة. يتميز بطابعه المعماري الطيني التقليدي.";s:14:"description_en";s:262:"Located in the city of Al-Hazm, the capital of the governorate. [8] It is a historical palace dating back to the Imamate period and was used as a center for governance and administration in the area. It is characterized by its traditional mud-brick architecture.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:8:"mudbrick";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:6:"طين";}s:8:"latitude";d:15.96;s:9:"longitude";d:44.78;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:17:{s:2:"id";i:507;s:7:"city_id";i:20;s:11:"external_id";s:15:"kharibat-al-ali";s:4:"name";s:44:"خربة آل علي (هرم القديمة)";s:7:"name_en";s:30:"Khirbat Al-Ali (Ancient Haram)";s:11:"description";s:312:"موقع أثري يقع شرق مدينة الحزم، ويعتقد أنه مدينة "هرم" التي ورد ذكرها في النقوش. [9] يضم الموقع بقايا مستوطنة قديمة وتل أثري كبير يحتاج إلى المزيد من التنقيبات للكشف عن أسراره.";s:14:"description_en";s:258:"An archaeological site located east of Al-Hazm, believed to be the city of 'Haram' mentioned in inscriptions. [9] The site includes the remains of an ancient settlement and a large archaeological mound that requires further excavation to uncover its secrets.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:7:"ancient";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:8:"قديم";}s:8:"latitude";d:15.98;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:17:{s:2:"id";i:508;s:7:"city_id";i:20;s:11:"external_id";s:12:"wadi-al-jawf";s:4:"name";s:43:"وادي الجوف (وادي الخارد)";s:7:"name_en";s:29:"Wadi Al-Jawf (Wadi Al-Kharid)";s:11:"description";s:343:"الوادي الكبير الذي أعطى المحافظة اسمها. [10] هو شريان الحياة في المنطقة منذ العصور القديمة، وعلى ضفافه قامت الحضارات والممالك اليمنية. يعتبر منظراً طبيعياً فريداً يجمع بين الزراعة والصحراء.";s:14:"description_en";s:258:"The great valley that gave the governorate its name. [10] It has been the lifeline of the region since ancient times, with Yemeni civilizations and kingdoms rising on its banks. It is considered a unique natural landscape merging agriculture with the desert.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:10:"historical";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:12:"تاريخي";i:3;s:10:"زراعة";}s:8:"latitude";d:15.8;s:9:"longitude";i:45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:8;a:17:{s:2:"id";i:509;s:7:"city_id";i:20;s:11:"external_id";s:17:"maraziq-mountains";s:4:"name";s:25:"جبال المرازيق";s:7:"name_en";s:20:"Al-Maraziq Mountains";s:11:"description";s:293:"سلسلة جبلية تقع في مديرية خب والشعف، وتتميز بتكويناتها الصخرية الفريدة والنقوش والرسوم الصخرية القديمة التي تركها الإنسان القديم، وتعتبر سجلاً لتاريخ المنطقة.";s:14:"description_en";s:218:"A mountain range located in the Khabb wa ash Sha'af district, known for its unique rock formations and the ancient rock drawings and inscriptions left by early humans. It is considered a record of the region's history.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:14:"archaeological";i:3;s:8:"rock_art";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:8:"أثري";i:3;s:13:"فن صخري";}s:8:"latitude";d:16.3;s:9:"longitude";d:45.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:9;a:17:{s:2:"id";i:510;s:7:"city_id";i:20;s:11:"external_id";s:16:"al-matammah-city";s:4:"name";s:51:"مدينة المتون (كمنهو القديمة)";s:7:"name_en";s:32:"Al-Maton City (Ancient Kaminahu)";s:11:"description";s:283:"مدينة أثرية هامة كانت تعرف باسم "كمنهو" في النقوش القديمة. [5] كانت مركزاً لقبيلة "كمنة" القوية، وتضم أطلالاً لمعابد ومبانٍ ضخمة تدل على مكانتها في مملكة معين.";s:14:"description_en";s:252:"An important archaeological city that was known as 'Kaminahu' in ancient inscriptions. [5] It was the center of the powerful 'Kaminah' tribe and houses ruins of massive temples and buildings that signify its prominent status within the Minaean Kingdom.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:7:"ancient";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:8:"قديم";}s:8:"latitude";d:15.88;s:9:"longitude";d:44.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:10;a:17:{s:2:"id";i:511;s:7:"city_id";i:20;s:11:"external_id";s:20:"al-hazm-grand-mosque";s:4:"name";s:32:"جامع الحزم الكبير";s:7:"name_en";s:23:"Great Mosque of Al-Hazm";s:11:"description";s:340:"المسجد الرئيسي في مدينة الحزم، عاصمة المحافظة. يعتبر المركز الديني للمدينة وتقام فيه الصلوات والفعاليات الدينية الرئيسية. يتميز بتصميمه الحديث نسبياً الذي يخدم سكان المدينة المتزايدين.";s:14:"description_en";s:245:"The main mosque in the city of Al-Hazm, the governorate's capital. It serves as the religious center of the city where prayers and major religious events are held. It features a relatively modern design catering to the city's growing population.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:6:"mosque";i:2;s:11:"city_center";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:8:"مسجد";i:2;s:23:"مركز المدينة";i:3;s:12:"معماري";}s:8:"latitude";d:15.965;s:9:"longitude";d:44.785;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:11;a:17:{s:2:"id";i:512;s:7:"city_id";i:20;s:11:"external_id";s:24:"wadi-al-khard-banks-park";s:4:"name";s:54:"منتزه ضفاف وادي الخارد (الحزم)";s:7:"name_en";s:35:"Wadi Al-Kharid Banks Park (Al-Hazm)";s:11:"description";s:337:"يمر وادي الخارد (وادي الجوف) بالقرب من مدينة الحزم. تعتبر ضفافه، خاصة بعد مواسم الأمطار وعندما تخضر، منتزهاً طبيعياً مفتوحاً يقصده سكان المدينة للنزهة والاستمتاع بمنظر المياه والزراعة.";s:14:"description_en";s:235:"Wadi Al-Kharid (Wadi Al-Jawf) passes near Al-Hazm. Its banks, especially when they turn green after the rainy seasons, act as an open natural park frequented by city residents for picnics and enjoying the view of water and agriculture.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"valley";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:14:"استجمام";}s:8:"latitude";d:15.95;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:12;a:17:{s:2:"id";i:513;s:7:"city_id";i:20;s:11:"external_id";s:20:"qarnawu-nearby-ruins";s:4:"name";s:36:"أطلال قرناو القريبة";s:7:"name_en";s:23:"Nearby Ruins of Qarnawu";s:11:"description";s:353:"تقع أطلال مدينة قرناو، عاصمة مملكة معين، على بعد مسافة قصيرة جداً من الحزم. يمكن اعتبار زيارتها نزهة تاريخية وثقافية تنطلق من المدينة، حيث يمكن مشاهدة بقايا المدينة القديمة المدفونة تحت الرمال.";s:14:"description_en";s:263:"The ruins of Qarnawu, the capital of the Minaean Kingdom, lie a very short distance from Al-Hazm. Visiting it can be considered a historical and cultural outing starting from the city, where one can observe the remains of the ancient city buried beneath the sand.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:6:"nearby";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:8:"قريب";}s:8:"latitude";i:16;s:9:"longitude";d:44.8167;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:13;a:17:{s:2:"id";i:514;s:7:"city_id";i:20;s:11:"external_id";s:25:"kharibat-al-ali-viewpoint";s:4:"name";s:27:"مطل خربة آل علي";s:7:"name_en";s:24:"Khirbat Al-Ali Viewpoint";s:11:"description";s:323:"الموقع الأثري لخربة آل علي (مدينة هرم) يقع على تل مرتفع شرق الحزم. يوفر هذا التل إطلالة بانورامية (منتزه مطل) على وادي الجوف ومدينة الحزم، وهو مكان مثالي لمشاهدة المنطقة من الأعلى.";s:14:"description_en";s:235:"The archaeological site of Khirbat Al-Ali (the city of Haram) is perched on a high hill east of Al-Hazm. This hill provides a panoramic viewpoint over Wadi Al-Jawf and Al-Hazm, making it a perfect spot to observe the region from above.";s:10:"categories";a:4:{i:0;s:9:"viewpoint";i:1;s:4:"park";i:2;s:14:"archaeological";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:6:"مطل";i:1;s:10:"منتزه";i:2;s:8:"أثري";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.98;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:14;a:17:{s:2:"id";i:515;s:7:"city_id";i:20;s:11:"external_id";s:22:"al-hazm-farms-parkland";s:4:"name";s:32:"منتزه مزارع الحزم";s:7:"name_en";s:18:"Al-Hazm Farms Park";s:11:"description";s:346:"المزارع المحيطة بمدينة الحزم، والتي تروى من مياه وادي الجوف، تشكل حزاماً أخضر حول المدينة. تعتبر هذه المزارع بمثابة منتزهات ريفية يمكن للزوار التجول بالقرب منها والاستمتاع بالمنظر الزراعي.";s:14:"description_en";s:208:"The farms surrounding Al-Hazm, irrigated by the waters of Wadi Al-Jawf, form a green belt around the city. These farms serve as rural parks where visitors can stroll nearby and enjoy the agricultural scenery.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:11:"agriculture";i:2;s:7:"natural";i:3;s:11:"countryside";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"زراعة";i:2;s:10:"طبيعي";i:3;s:6:"ريف";}s:8:"latitude";d:15.95;s:9:"longitude";d:44.77;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:15;a:17:{s:2:"id";i:516;s:7:"city_id";i:20;s:11:"external_id";s:19:"al-hazm-old-quarter";s:4:"name";s:28:"حي الحزم القديم";s:7:"name_en";s:24:"Old Al-Hazm Neighborhood";s:11:"description";s:321:"بالإضافة إلى القصر، يوجد في الحزم حي قديم يضم بقايا المنازل الطينية التقليدية. التجول في هذا الجزء من المدينة يعطي فكرة عن شكل الحياة قبل التوسع الحديث، ويعتبر معلماً عمرانياً.";s:14:"description_en";s:242:"In addition to the palace, Al-Hazm has an old neighborhood that houses remnants of traditional mud houses. Walking through this part of the city gives an idea of what life was like before modern expansion, making it an architectural landmark.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"mudbrick";i:3;s:12:"neighborhood";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:6:"طين";i:3;s:4:"حي";}s:8:"latitude";d:15.96;s:9:"longitude";d:44.78;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:16;a:17:{s:2:"id";i:517;s:7:"city_id";i:20;s:11:"external_id";s:18:"dunes-near-al-hazm";s:4:"name";s:55:"منتزه الكثبان الرملية القريبة";s:7:"name_en";s:22:"Nearby Sand Dunes Park";s:11:"description";s:334:"تبدأ الكثبان الرملية بالظهور على بعد مسافة ليست بالبعيدة عن شرق وشمال الحزم. تعتبر هذه المناطق بداية الصحراء منتزهات طبيعية فريدة للتنزه بالسيارات (التطعيس) والاستمتاع بجمال الصحراء.";s:14:"description_en";s:208:"Sand dunes start appearing not far east and north of Al-Hazm. Marking the beginning of the desert, these areas act as unique natural parks for dune bashing (off-roading) and enjoying the beauty of the desert.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:6:"desert";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:10:"صحراء";i:3;s:12:"مغامرة";}s:8:"latitude";d:16.05;s:9:"longitude";d:44.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:5;a:13:{s:2:"id";i:32;s:4:"slug";s:7:"alhabil";s:4:"name";s:12:"الحبيل";s:7:"name_en";s:7:"AlHabil";s:11:"description";s:142:"مدينة تظاهي اجمل المدن في جمالها ومعماريتها وبيوتها الفاخره والمنقوشه بالذهب";s:14:"description_en";s:113:"A city that rivals the most beautiful cities in its beauty, architecture, and luxurious houses adorned with gold.";s:9:"image_url";s:90:"https://www.otlaat.com/wp-content/uploads/2020/03/%D8%A7%D9%84%D8%AE%D9%81%D8%AC%D9%8A.jpg";s:6:"status";s:9:"published";s:8:"category";s:6:"island";s:15:"landmarks_count";i:1;s:9:"landmarks";a:1:{i:0;a:17:{s:2:"id";i:624;s:7:"city_id";i:32;s:11:"external_id";N;s:4:"name";s:12:"الشعبه";s:7:"name_en";s:8:"AlShubah";s:11:"description";s:226:"من افضل المعالم في مدينة الحبيل تتميز بالطقس البارد صيفا المعتدل شتاء وتضم مجموعه نادره من الطيور البريه  والنباتات الزهريه";s:14:"description_en";s:185:"One of the best landmarks in Al-Habil city, it is characterized by its cool summer weather and mild winter weather, and it includes a rare collection of wild birds and flowering plants.";s:10:"categories";a:2:{i:0;s:10:"historical";i:1;s:8:"cultural";}s:14:"category_names";a:2:{i:0;s:12:"تاريخي";i:1;s:10:"ثقافي";}s:8:"latitude";d:13.460017;s:9:"longitude";d:44.1620024;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSTOoPhjGtrXGV_Cvdnggf6mkKs-Ysj21tBfw&s";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-23T22:32:16.000000Z";s:10:"updated_at";s:27:"2026-04-23T22:32:16.000000Z";}}s:10:"created_at";s:27:"2026-04-23T22:22:31.000000Z";s:10:"updated_at";s:27:"2026-04-23T22:22:31.000000Z";}i:6;a:13:{s:2:"id";i:4;s:4:"slug";s:8:"hodeidah";s:4:"name";s:14:"الحديدة";s:7:"name_en";s:11:"Al Hudaydah";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:20:"al_hodeidah_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:40;s:9:"landmarks";a:40:{i:0;a:17:{s:2:"id";i:116;s:7:"city_id";i:4;s:11:"external_id";s:17:"hodeidah-corniche";s:4:"name";s:27:"كورنيش الحديدة";s:7:"name_en";s:17:"Hodeidah Corniche";s:11:"description";s:253:"واجهة بحرية جميلة تمتد على طول ساحل البحر الأحمر في مدينة الحديدة. تعتبر متنفساً للسكان والزوار، وتضم العديد من المطاعم والمقاهي والحدائق.";s:14:"description_en";s:189:"A beautiful waterfront stretching along the Red Sea coast in the city of Al Hudaydah. It serves as a recreational area for locals and visitors, featuring many restaurants, cafes, and parks.";s:10:"categories";a:3:{i:0;s:7:"coastal";i:1;s:12:"recreational";i:2;s:6:"scenic";}s:14:"category_names";a:3:{i:0;s:10:"ساحلي";i:1;s:12:"ترفيهي";i:2;s:21:"مناظر خلابة";}s:8:"latitude";d:14.805556;s:9:"longitude";d:42.946389;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:48:"images/landmarks/hodeidah/hodeidah_corniche1.jpg";i:1;s:48:"images/landmarks/hodeidah/hodeidah_corniche2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:1;a:17:{s:2:"id";i:117;s:7:"city_id";i:4;s:11:"external_id";s:20:"hodeidah-fish-market";s:4:"name";s:34:"سوق السمك (المحوات)";s:7:"name_en";s:23:"Fish Market (Al-Mahwat)";s:11:"description";s:375:"أحد أكبر أسواق الأسماك في اليمن، يقع بالقرب من ميناء الحديدة. [2] يعرض السوق مجموعة هائلة ومتنوعة من الأسماك الطازجة والكائنات البحرية التي يتم اصطيادها من البحر الأحمر، ويعتبر تجربة ثقافية واقتصادية فريدة.";s:14:"description_en";s:239:"One of the largest fish markets in Yemen, situated near the port of Al Hudaydah. [2] The market displays a massive and diverse array of fresh fish and marine life caught from the Red Sea, offering a unique cultural and economic experience.";s:10:"categories";a:3:{i:0;s:6:"market";i:1;s:8:"cultural";i:2;s:7:"seafood";}s:14:"category_names";a:3:{i:0;s:6:"سوق";i:1;s:10:"ثقافي";i:2;s:25:"مأكولات بحرية";}s:8:"latitude";d:14.793333;s:9:"longitude";d:42.949722;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:51:"images/landmarks/hodeidah/hodeidah_fish_market1.jpg";i:1;s:51:"images/landmarks/hodeidah/hodeidah_fish_market2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:2;a:17:{s:2:"id";i:118;s:7:"city_id";i:4;s:11:"external_id";s:14:"al-kadan-beach";s:4:"name";s:19:"شاطئ الكدن";s:7:"name_en";s:14:"Al-Kadan Beach";s:11:"description";s:288:"شاطئ رملي واسع يقع جنوب مدينة الحديدة، ويتميز برماله الناعمة ومياهه الضحلة. [3] يعتبر وجهة شهيرة للنزهات العائلية والسباحة والاستمتاع بجمال ساحل البحر الأحمر.";s:14:"description_en";s:207:"A wide sandy beach located south of Al Hudaydah, characterized by its soft sand and shallow waters. [3] It is a popular destination for family picnics, swimming, and enjoying the beauty of the Red Sea coast.";s:10:"categories";a:3:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";}s:8:"latitude";d:15.013333;s:9:"longitude";d:42.846667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/hodeidah/al_kadan_beach1.jpg";i:1;s:45:"images/landmarks/hodeidah/al_kadan_beach2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:3;a:17:{s:2:"id";i:119;s:7:"city_id";i:4;s:11:"external_id";s:17:"hodeidah-old-city";s:4:"name";s:40:"مدينة الحديدة القديمة";s:7:"name_en";s:20:"Old City of Hodeidah";s:11:"description";s:306:"المركز التاريخي للمدينة، يضم أزقة ضيقة ومباني قديمة تتميز بطراز معماري فريد متأثر بالحقبة العثمانية. [4] تحتوي على مساجد تاريخية وأسواق شعبية تعكس تاريخ المدينة العريق.";s:14:"description_en";s:239:"The historical center of the city, featuring narrow alleys and old buildings with a unique architectural style influenced by the Ottoman era. [4] It houses historical mosques and traditional markets that reflect the city's ancient history.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"ثقافي";}s:8:"latitude";d:14.793056;s:9:"longitude";d:42.951389;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:48:"images/landmarks/hodeidah/hodeidah_old_city1.jpg";i:1;s:48:"images/landmarks/hodeidah/hodeidah_old_city2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:4;a:17:{s:2:"id";i:120;s:7:"city_id";i:4;s:11:"external_id";s:14:"kamaran-island";s:4:"name";s:21:"جزيرة كمران";s:7:"name_en";s:14:"Kamaran Island";s:11:"description";s:318:"أكبر الجزر اليمنية في البحر الأحمر، تقع قبالة ساحل الصليف شمال الحديدة. [5] تتميز بشواطئها البكر وغابات المانجروف (الشورى) وتاريخها الغني، وتعتبر وجهة مثالية للغوص والاسترخاء.";s:14:"description_en";s:242:"The largest Yemeni island in the Red Sea, located off the coast of As Salif, north of Al Hudaydah. [5] Distinguished by its pristine beaches, mangrove forests, and rich history, it is considered an ideal destination for diving and relaxation.";s:10:"categories";a:4:{i:0;s:6:"island";i:1;s:6:"nature";i:2;s:10:"historical";i:3;s:6:"diving";}s:14:"category_names";a:4:{i:0;s:10:"جزيرة";i:1;s:10:"طبيعي";i:2;s:12:"تاريخي";i:3;s:6:"غوص";}s:8:"latitude";d:15.366667;s:9:"longitude";d:42.566667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/hodeidah/kamaran_island1.jpg";i:1;s:45:"images/landmarks/hodeidah/kamaran_island2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:5;a:17:{s:2:"id";i:121;s:7:"city_id";i:4;s:11:"external_id";s:13:"hodeidah-port";s:4:"name";s:25:"ميناء الحديدة";s:7:"name_en";s:13:"Hodeidah Port";s:11:"description";s:337:"أحد أهم وأكبر الموانئ في اليمن، ويعتبر شريانًا اقتصاديًا حيويًا للبلاد. [6] على الرغم من طابعه الصناعي، إلا أن مشاهدة حركة السفن الضخمة والنشاط المستمر فيه يمثل معلمًا بارزًا في المدينة.";s:14:"description_en";s:251:"One of the most important and largest ports in Yemen, acting as a vital economic artery for the country. [6] Despite its industrial nature, watching the movement of massive ships and its continuous activity represents a prominent landmark in the city.";s:10:"categories";a:3:{i:0;s:10:"industrial";i:1;s:8:"maritime";i:2;s:8:"economic";}s:14:"category_names";a:3:{i:0;s:10:"صناعي";i:1;s:8:"بحري";i:2;s:14:"اقتصادي";}s:8:"latitude";d:14.845833;s:9:"longitude";d:42.934722;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/hodeidah/hodeidah_port1.jpg";i:1;s:44:"images/landmarks/hodeidah/hodeidah_port2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:6;a:17:{s:2:"id";i:122;s:7:"city_id";i:4;s:11:"external_id";s:24:"al-hodeidah-grand-mosque";s:4:"name";s:42:"الجامع الكبير بالحديدة";s:7:"name_en";s:24:"Great Mosque of Hodeidah";s:11:"description";s:271:"مسجد تاريخي يقع في المدينة القديمة، ويتميز بتصميمه المعماري الذي يجمع بين الطراز المحلي والعثماني. [7] يعتبر مركزًا دينيًا وثقافيًا هامًا في الحديدة.";s:14:"description_en";s:198:"A historic mosque located in the old city, distinguished by an architectural design that blends local and Ottoman styles. [7] It serves as a significant religious and cultural center in Al Hudaydah.";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:14.796389;s:9:"longitude";d:42.948333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/hodeidah/grand_mosque1.jpg";i:1;s:43:"images/landmarks/hodeidah/grand_mosque2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:7;a:17:{s:2:"id";i:123;s:7:"city_id";i:4;s:11:"external_id";s:19:"hodeidah-sand-dunes";s:4:"name";s:44:"الكثبان الرملية (الغراب)";s:7:"name_en";s:22:"Sand Dunes (Al-Ghurab)";s:11:"description";s:353:"منطقة صحراوية قريبة من المدينة تتميز بكثبانها الرملية الذهبية الشاسعة. [8] تعتبر وجهة شهيرة بين السكان المحليين لممارسة رياضة التزلج على الرمال والتخييم والاستمتاع بالمناظر الطبيعية الصحراوية.";s:14:"description_en";s:165:"A desert area near the city featuring vast golden sand dunes. [8] It is a popular destination among locals for sandboarding, camping, and enjoying desert landscapes.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:6:"desert";i:2;s:12:"recreational";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:12:"صحراوي";i:2;s:12:"ترفيهي";i:3;s:14:"مغامرات";}s:8:"latitude";d:14.781111;s:9:"longitude";d:42.956667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/hodeidah/sand_dunes1.jpg";i:1;s:41:"images/landmarks/hodeidah/sand_dunes2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:8;a:17:{s:2:"id";i:124;s:7:"city_id";i:4;s:11:"external_id";s:13:"al-salif-port";s:4:"name";s:23:"ميناء الصليف";s:7:"name_en";s:13:"As Salif Port";s:11:"description";s:325:"ميناء طبيعي عميق يقع شمال مدينة الحديدة، ويشتهر بتصدير الملح. [9] المنطقة المحيطة به تتميز بجمالها الطبيعي وتكويناتها الملحية الفريدة، وتعتبر نقطة انطلاق للرحلات إلى جزيرة كمران.";s:14:"description_en";s:221:"A deep natural port located north of Al Hudaydah, famous for salt exportation. [9] The surrounding area is noted for its natural beauty and unique salt formations, serving as a departure point for trips to Kamaran Island.";s:10:"categories";a:3:{i:0;s:8:"maritime";i:1;s:10:"industrial";i:2;s:6:"nature";}s:14:"category_names";a:3:{i:0;s:8:"بحري";i:1;s:10:"صناعي";i:2;s:10:"طبيعي";}s:8:"latitude";d:15.309444;s:9:"longitude";d:42.673889;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/hodeidah/al_salif_port1.jpg";i:1;s:44:"images/landmarks/hodeidah/al_salif_port2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:9;a:17:{s:2:"id";i:125;s:7:"city_id";i:4;s:11:"external_id";s:20:"hodeidah-public-park";s:4:"name";s:51:"حديقة الشعب (الحديقة العامة)";s:7:"name_en";s:28:"Al-Sha'ab Park (Public Park)";s:11:"description";s:291:"أكبر حديقة عامة في مدينة الحديدة، تقع بالقرب من الكورنيش. [10] توفر مساحات خضراء واسعة وأماكن للجلوس وألعاب للأطفال، وتعتبر متنفسًا عائليًا مهمًا في قلب المدينة.";s:14:"description_en";s:205:"The largest public park in Al Hudaydah, located near the Corniche. [10] It provides extensive green spaces, seating areas, and children's games, acting as a crucial family retreat in the heart of the city.";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";d:14.807778;s:9:"longitude";d:42.961111;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/hodeidah/hodeidah_park1.jpg";i:1;s:44:"images/landmarks/hodeidah/hodeidah_park2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:10;a:17:{s:2:"id";i:126;s:7:"city_id";i:4;s:11:"external_id";s:24:"kamaran-island-mangroves";s:4:"name";s:56:"غابات المانجروف في جزيرة كمران";s:7:"name_en";s:34:"Mangrove Forests in Kamaran Island";s:11:"description";s:342:"تضم جزيرة كمران غابات كثيفة من أشجار المانجروف (الشورى)، والتي تشكل نظامًا بيئيًا فريدًا. [2] تعتبر هذه المنطقة متنزهًا طبيعيًا لمحبي البيئة ومراقبة الطيور واستكشاف الطبيعة الساحلية البكر.";s:14:"description_en";s:207:"Kamaran Island features dense mangrove forests that create a unique ecosystem. [2] This area serves as a natural park for nature enthusiasts, bird watchers, and those exploring pristine coastal environments.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:6:"island";i:2;s:9:"ecosystem";i:3;s:13:"bird-watching";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"جزيرة";i:2;s:17:"نظام بيئي";i:3;s:25:"مراقبة الطيور";}s:8:"latitude";d:15.378333;s:9:"longitude";d:42.583056;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/parks/hodeidah/kamaran_mangroves1.jpg";i:1;s:44:"images/parks/hodeidah/kamaran_mangroves2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:11;a:17:{s:2:"id";i:127;s:7:"city_id";i:4;s:11:"external_id";s:24:"hodeidah-sand-dunes-park";s:4:"name";s:40:"متنزه الكثبان الرملية";s:7:"name_en";s:15:"Sand Dunes Park";s:11:"description";s:343:"منطقة صحراوية تتميز بكثبانها الرملية الذهبية الممتدة. [3] تعد متنزهًا طبيعيًا مفتوحًا لهواة المغامرات، حيث يمكن ممارسة التزلج على الرمال، وقيادة سيارات الدفع الرباعي، والتخييم تحت النجوم.";s:14:"description_en";s:202:"A desert area characterized by rolling golden sand dunes. [3] It serves as an open natural park for adventure lovers, offering activities like sandboarding, 4x4 off-roading, and camping under the stars.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:6:"desert";i:2;s:9:"adventure";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:12:"صحراوي";i:2;s:14:"مغامرات";i:3;s:12:"ترفيهي";}s:8:"latitude";d:14.782222;s:9:"longitude";d:42.958889;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/parks/hodeidah/sand_dunes_park1.jpg";i:1;s:42:"images/parks/hodeidah/sand_dunes_park2.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:12;a:17:{s:2:"id";i:128;s:7:"city_id";i:4;s:11:"external_id";s:12:"al-urj-beach";s:4:"name";s:19:"شاطئ العرج";s:7:"name_en";s:12:"Al-Arj Beach";s:11:"description";s:272:"يقع شمال الحديدة، وهو شاطئ هادئ يتميز بجماله الطبيعي وبقايا أشجار القرم. [4] يعتبر مكانًا مثاليًا للباحثين عن الهدوء والاسترخاء بعيدًا عن صخب المدينة.";s:14:"description_en";s:207:"Located north of Al Hudaydah, it is a quiet beach distinguished by its natural beauty and remains of mangrove trees. [4] It is an ideal spot for those seeking peace and relaxation away from the city's noise.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:10:"recreation";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";i:3;s:8:"هادئ";}s:8:"latitude";d:14.981389;s:9:"longitude";d:42.868889;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/parks/hodeidah/al_urj_beach1.jpg";i:1;s:39:"images/parks/hodeidah/al_urj_beach2.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:13;a:17:{s:2:"id";i:129;s:7:"city_id";i:4;s:11:"external_id";s:11:"wadi-surdud";s:4:"name";s:17:"وادي سردد";s:7:"name_en";s:11:"Wadi Surdud";s:11:"description";s:345:"أحد الأودية الهامة في منطقة تهامة، يقع شرق الحديدة. [5] بعد هطول الأمطار، يتحول الوادي إلى مساحات خضراء ومجاري مائية، ليصبح متنزهًا طبيعيًا يقصده السكان للنزهات والاستمتاع بالطبيعة الريفية.";s:14:"description_en";s:233:"One of the important valleys in the Tihamah region, located east of Al Hudaydah. [5] After rainfall, the valley turns into green expanses and waterways, becoming a natural park visited by locals for picnics and enjoying rural nature.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:10:"recreation";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";i:3;s:10:"زراعي";}s:8:"latitude";d:15.228056;s:9:"longitude";d:43.342778;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/parks/hodeidah/wadi_surdud1.jpg";i:1;s:38:"images/parks/hodeidah/wadi_surdud2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:14;a:17:{s:2:"id";i:130;s:7:"city_id";i:4;s:11:"external_id";s:17:"al-khawkhah-beach";s:4:"name";s:21:"شاطئ الخوخة";s:7:"name_en";s:17:"Al-Khawkhah Beach";s:11:"description";s:337:"يقع في مديرية الخوخة جنوب الحديدة، ويشتهر بنخيله الباسق الذي يمتد حتى الشاطئ. [6] يوفر هذا المزيج الفريد من الشاطئ الرملي وأشجار النخيل منظرًا استوائيًا خلابًا وظلالًا طبيعية للمتنزهين.";s:14:"description_en";s:267:"Located in the Al-Khawkhah district south of Al Hudaydah, it is famous for its towering palm trees that reach all the way to the shore. [6] This unique combination of a sandy beach and palm trees provides a breathtaking tropical view and natural shade for picnickers.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:12:"ترفيهي";}s:8:"latitude";d:13.784722;s:9:"longitude";d:43.250556;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/parks/hodeidah/al_khawkhah_beach1.jpg";i:1;s:44:"images/parks/hodeidah/al_khawkhah_beach2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:15;a:17:{s:2:"id";i:131;s:7:"city_id";i:4;s:11:"external_id";s:25:"hodeidah-corniche-gardens";s:4:"name";s:38:"حدائق كورنيش الحديدة";s:7:"name_en";s:23:"Hodeidah Corniche Parks";s:11:"description";s:317:"مجموعة من المساحات الخضراء والحدائق الصغيرة المنتشرة على طول الكورنيش. [7] تعمل هذه الحدائق كمتنزهات حضرية توفر أماكن للجلوس والاستمتاع بنسيم البحر الأحمر وإطلالاته الساحرة.";s:14:"description_en";s:192:"A series of green spaces and small parks scattered along the Corniche. [7] These parks serve as urban recreational areas providing seating to enjoy the Red Sea breeze and its enchanting views.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:10:"recreation";i:2;s:6:"family";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:10:"ساحلي";}s:8:"latitude";d:14.809444;s:9:"longitude";d:42.945833;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/parks/hodeidah/corniche_gardens1.jpg";i:1;s:43:"images/parks/hodeidah/corniche_gardens2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:16;a:17:{s:2:"id";i:132;s:7:"city_id";i:4;s:11:"external_id";s:17:"ras-isa-peninsula";s:4:"name";s:33:"شبه جزيرة رأس عيسى";s:7:"name_en";s:17:"Ras Isa Peninsula";s:11:"description";s:307:"منطقة ساحلية شمال الصليف، تتميز بشواطئها البكر ومياهها الصافية. [8] تعتبر متنزهًا طبيعيًا مفتوحًا ومثاليًا للتخييم، والسباحة، والغوص السطحي (السنوركلينج) في بيئة هادئة.";s:14:"description_en";s:196:"A coastal area north of As Salif, known for its pristine beaches and clear waters. [8] It is considered an open natural park, perfect for camping, swimming, and snorkeling in a serene environment.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:5:"beach";i:2;s:7:"camping";i:3;s:10:"snorkeling";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شاطئ";i:2;s:10:"تخييم";i:3;s:15:"غطس سطحي";}s:8:"latitude";d:15.1975;s:9:"longitude";d:42.747222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:34:"images/parks/hodeidah/ras_isa1.jpg";i:1;s:34:"images/parks/hodeidah/ras_isa2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:17;a:17:{s:2:"id";i:133;s:7:"city_id";i:4;s:11:"external_id";s:10:"wadi-zabid";s:4:"name";s:17:"وادي زبيد";s:7:"name_en";s:10:"Wadi Zabid";s:11:"description";s:311:"وادي تاريخي شهير يقع بالقرب من مدينة زبيد الأثرية. [9] عند جريان المياه فيه، تتحول ضفافه إلى أراضٍ خضراء خصبة، مما يجعله وجهة للتنزه والاستمتاع بالجمع بين الطبيعة والتاريخ.";s:14:"description_en";s:224:"A famous historical valley located near the ancient city of Zabid. [9] When water flows through it, its banks turn into fertile green lands, making it a destination for strolling and enjoying the blend of nature and history.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:10:"historical";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:12:"تاريخي";i:3;s:12:"ترفيهي";}s:8:"latitude";d:14.180278;s:9:"longitude";d:43.336111;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/parks/hodeidah/wadi_zabid1.jpg";i:1;s:37:"images/parks/hodeidah/wadi_zabid2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:18;a:17:{s:2:"id";i:134;s:7:"city_id";i:4;s:11:"external_id";s:22:"al-ashaer-mosque-zabid";s:4:"name";s:37:"جامع الأشاعر في زبيد";s:7:"name_en";s:26:"Al-Asha'ir Mosque in Zabid";s:11:"description";s:321:"أحد أقدم المساجد في الإسلام، يُقال إنه بني في عهد النبي محمد على يد الصحابي أبي موسى الأشعري. [2] يعتبر خامس مسجد بني في الإسلام، ويحتوي على جامعة تاريخية كانت مركزاً هاماً للعلم.";s:14:"description_en";s:266:"One of the oldest mosques in Islam, said to have been built during the era of Prophet Muhammad by his companion Abu Musa Al-Ash'ari. [2] It is considered the fifth mosque built in Islam and contains a historical university that was a significant center for learning.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:9:"religious";i:2;s:10:"historical";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:8:"ديني";i:2;s:12:"تاريخي";i:3;s:12:"إسلامي";}s:8:"latitude";d:14.195556;s:9:"longitude";d:43.315;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:52:"images/archaeological/hodeidah/al_ashaer_mosque1.jpg";i:1;s:52:"images/archaeological/hodeidah/al_ashaer_mosque2.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:19;a:17:{s:2:"id";i:135;s:7:"city_id";i:4;s:11:"external_id";s:18:"beit-al-faqih-town";s:4:"name";s:30:"مدينة بيت الفقيه";s:7:"name_en";s:18:"Bayt Al-Faqih City";s:11:"description";s:334:"بلدة تاريخية تشتهر بسوقها الأسبوعي الذي يعتبر من أقدم وأشهر الأسواق الشعبية في تهامة. [3] كانت المدينة مركزاً تجارياً مهماً على طريق القوافل، وتحتفظ بطابعها التقليدي ومبانيها القديمة.";s:14:"description_en";s:259:"A historical town famous for its weekly market, which is considered one of the oldest and most renowned traditional markets in Tihamah. [3] The city was a crucial commercial hub on the caravan route and retains its traditional character and ancient buildings.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:6:"market";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:6:"سوق";i:2;s:10:"ثقافي";}s:8:"latitude";d:14.515278;s:9:"longitude";d:43.303333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/archaeological/hodeidah/beit_al_faqih1.jpg";i:1;s:49:"images/archaeological/hodeidah/beit_al_faqih2.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:20;a:17:{s:2:"id";i:136;s:7:"city_id";i:4;s:11:"external_id";s:21:"al-faza-coastal-ruins";s:4:"name";s:34:"أطلال ميناء الفازة";s:7:"name_en";s:21:"Ruins of Al-Faza Port";s:11:"description";s:300:"موقع أثري لمدينة ساحلية قديمة تقع جنوب الحديدة. [4] كانت ميناءً هاماً في العصور الإسلامية المبكرة، ويمكن مشاهدة بقايا أساسات المباني والمنازل القديمة على طول الساحل.";s:14:"description_en";s:229:"An archaeological site of an ancient coastal city located south of Al Hudaydah. [4] It was a vital port in the early Islamic periods, and the foundational remains of ancient buildings and houses can still be seen along the coast.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:10:"ساحلي";}s:8:"latitude";d:14.15;s:9:"longitude";d:43.141667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/archaeological/hodeidah/al_faza_ruins1.jpg";i:1;s:49:"images/archaeological/hodeidah/al_faza_ruins2.jpg";}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:21;a:17:{s:2:"id";i:137;s:7:"city_id";i:4;s:11:"external_id";s:18:"hays-city-fortress";s:4:"name";s:26:"قلعة مدينة حيس";s:7:"name_en";s:16:"Hays City Castle";s:11:"description";s:280:"تقع في مدينة حيس التاريخية، المشهورة بصناعة الفخار. [5] القلعة هي حصن قديم كان يستخدم للدفاع عن المدينة، وتتميز مباني المدينة نفسها بطراز معماري طيني فريد.";s:14:"description_en";s:213:"Located in the historic city of Hays, famous for its pottery making. [5] The castle is an ancient fort used to defend the city, while the city's buildings themselves feature a unique mud-brick architectural style.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:12:"معماري";}s:8:"latitude";d:13.929167;s:9:"longitude";d:43.479167;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/archaeological/hodeidah/hays_fortress1.jpg";i:1;s:49:"images/archaeological/hodeidah/hays_fortress2.jpg";}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:22;a:17:{s:2:"id";i:138;s:7:"city_id";i:4;s:11:"external_id";s:29:"al-mahjam-archaeological-site";s:4:"name";s:34:"موقع المهجم الأثري";s:7:"name_en";s:29:"Al-Mahjam Archaeological Site";s:11:"description";s:303:"أطلال مدينة إسلامية قديمة كانت مزدهرة في العصور الوسطى، وتقع بالقرب من وادي سردد. [6] الموقع يضم بقايا مسجد كبير، ومنازل، ونظام ري متطور، مما يدل على أهميتها التاريخية.";s:14:"description_en";s:234:"The ruins of an ancient Islamic city that flourished in the Middle Ages, located near Wadi Surdud. [6] The site features the remains of a large mosque, houses, and an advanced irrigation system, indicating its historical significance.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:12:"إسلامي";}s:8:"latitude";d:15.333333;s:9:"longitude";d:43.316667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:50:"images/archaeological/hodeidah/al_mahjam_site1.jpg";i:1;s:50:"images/archaeological/hodeidah/al_mahjam_site2.jpg";}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:23;a:17:{s:2:"id";i:139;s:7:"city_id";i:4;s:11:"external_id";s:26:"ottoman-buildings-hodeidah";s:4:"name";s:53:"المباني العثمانية في الحديدة";s:7:"name_en";s:29:"Ottoman Buildings in Hodeidah";s:11:"description";s:318:"مجموعة من المباني الحكومية والثكنات العسكرية التي تعود لفترة الحكم العثماني الثاني في اليمن. [7] تنتشر هذه المباني في المدينة القديمة وتتميز بطرازها المعماري العثماني المميز.";s:14:"description_en";s:231:"A collection of government buildings and military barracks dating back to the second Ottoman rule in Yemen. [7] These structures are scattered throughout the old city and stand out for their distinctive Ottoman architectural style.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:7:"ottoman";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:12:"عثماني";}s:8:"latitude";d:14.797222;s:9:"longitude";d:42.951111;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:53:"images/archaeological/hodeidah/ottoman_buildings1.jpg";i:1;s:53:"images/archaeological/hodeidah/ottoman_buildings2.jpg";}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:24;a:17:{s:2:"id";i:140;s:7:"city_id";i:4;s:11:"external_id";s:15:"al-qanawis-fort";s:4:"name";s:21:"حصن القناوص";s:7:"name_en";s:15:"Al-Qanawis Fort";s:11:"description";s:284:"حصن تاريخي يقع في مديرية القناوص شمال مدينة الحديدة. [8] كان الحصن مركزاً إدارياً وعسكرياً للمنطقة، ويمثل نموذجاً للعمارة الدفاعية التقليدية في منطقة تهامة.";s:14:"description_en";s:231:"A historical fort located in the Al-Qanawis district north of Al Hudaydah. [8] The fort served as an administrative and military center for the region, representing a model of traditional defensive architecture in the Tihamah area.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:10:"عسكري";}s:8:"latitude";d:15.358333;s:9:"longitude";d:43.3;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:51:"images/archaeological/hodeidah/al_qanawis_fort1.jpg";i:1;s:51:"images/archaeological/hodeidah/al_qanawis_fort2.jpg";}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:25;a:17:{s:2:"id";i:141;s:7:"city_id";i:4;s:11:"external_id";s:13:"zabid-citadel";s:4:"name";s:17:"قلعة زبيد";s:7:"name_en";s:12:"Zabid Castle";s:11:"description";s:338:"حصن دفاعي ضخم يقع على طرف مدينة زبيد التاريخية. [10] كانت القلعة مقراً للحكام والسلاطين وتضم أسواراً وأبراجاً عالية، وهي جزء لا يتجزأ من النظام الدفاعي للمدينة المصنفة ضمن التراث العالمي.";s:14:"description_en";s:253:"A massive defensive fortress located at the edge of the historic city of Zabid. [10] The castle served as the seat for rulers and sultans, featuring high walls and towers. It is an integral part of the defensive system of the World Heritage-listed city.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:8:"fortress";i:2;s:10:"historical";i:3;s:6:"unesco";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:8:"قلعة";i:2;s:12:"تاريخي";i:3;s:12:"يونسكو";}s:8:"latitude";d:14.1975;s:9:"longitude";d:43.313889;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/archaeological/hodeidah/zabid_citadel1.jpg";i:1;s:49:"images/archaeological/hodeidah/zabid_citadel2.jpg";}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:26;a:17:{s:2:"id";i:142;s:7:"city_id";i:4;s:11:"external_id";s:10:"wadi-siham";s:4:"name";s:17:"وادي سهام";s:7:"name_en";s:10:"Wadi Siham";s:11:"description";s:340:"ينبع من المرتفعات الغربية لمحافظة صنعاء ويمر شمال جبال ريمة ليسقي أراضي المراوعة والقطيع. [4] يعتبر من الأودية الهامة في تهامة التي تساهم في دعم الزراعة وتوفير المياه للمناطق التي يمر بها.";s:14:"description_en";s:295:"Originates from the western highlands of Sana'a Governorate, passing north of the Raymah mountains to irrigate the lands of Al-Marawi'ah and Al-Qati'. [4] It is considered one of Tihamah's important valleys that contribute to supporting agriculture and providing water to the areas it traverses.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:12:"water-course";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:17:"مجرى مائي";i:3;s:10:"زراعي";}s:8:"latitude";d:14.811111;s:9:"longitude";d:43.146944;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/water/hodeidah/wadi_siham1.jpg";i:1;s:37:"images/water/hodeidah/wadi_siham2.jpg";}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:27;a:17:{s:2:"id";i:143;s:7:"city_id";i:4;s:11:"external_id";s:10:"wadi-rimaa";s:4:"name";s:17:"وادي رماع";s:7:"name_en";s:9:"Wadi Rima";s:11:"description";s:326:"وادي كبير ينحدر من مرتفعات آنس ووصاب وريمة، ويشق طريقه بين الجبال ليصب في البحر الأحمر. [4] يلعب دوراً حيوياً في ري الأراضي الزراعية في مديريات الجروبة والحسينية والمناطق المجاورة.";s:14:"description_en";s:268:"A large valley descending from the highlands of Anis, Wusab, and Raymah, carving its path through mountains to empty into the Red Sea. [4] It plays a vital role in irrigating agricultural lands in the Al-Jarubah and Al-Husseiniyah districts, as well as adjacent areas.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:8:"مائي";}s:8:"latitude";d:14.332778;s:9:"longitude";d:43.2725;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/water/hodeidah/wadi_rimaa1.jpg";i:1;s:37:"images/water/hodeidah/wadi_rimaa2.jpg";}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:28;a:17:{s:2:"id";i:144;s:7:"city_id";i:4;s:11:"external_id";s:13:"wadi-mawr-dam";s:4:"name";s:20:"سد وادي مور";s:7:"name_en";s:13:"Wadi Mawr Dam";s:11:"description";s:331:"سد رئيسي أقيم على وادي مور لتنظيم جريان المياه وتوزيعها على الأراضي الزراعية عبر شبكة من القنوات. [24] يعتبر مشروعاً مائياً استراتيجياً يهدف إلى تحقيق الاستفادة القصوى من مياه الوادي.";s:14:"description_en";s:223:"A primary dam built on Wadi Mawr to regulate water flow and distribute it to agricultural lands through a network of canals. [24] It is considered a strategic water project aimed at maximizing the use of the valley's water.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:16:"water-management";i:2;s:11:"agriculture";i:3;s:11:"engineering";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:19:"إدارة مياه";i:2;s:10:"زراعي";i:3;s:10:"هندسي";}s:8:"latitude";d:15.655833;s:9:"longitude";d:43.456389;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/water/hodeidah/wadi_mawr_dam1.jpg";i:1;s:40:"images/water/hodeidah/wadi_mawr_dam2.jpg";}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:29;a:17:{s:2:"id";i:145;s:7:"city_id";i:4;s:11:"external_id";s:17:"red-sea-coastline";s:4:"name";s:32:"ساحل البحر الأحمر";s:7:"name_en";s:13:"Red Sea Coast";s:11:"description";s:359:"تمتلك محافظة الحديدة شريطاً ساحلياً طويلاً يمتد لمئات الكيلومترات على البحر الأحمر. [4] يعتبر هذا الساحل مسطحاً مائياً ضخماً ومورداً طبيعياً للأسماك، وتنتشر على طوله الشواطئ الرملية وأشجار النخيل.";s:14:"description_en";s:230:"Al Hudaydah Governorate possesses a long coastal strip extending for hundreds of kilometers along the Red Sea. [4] This coastline is a massive body of water and a natural resource for fish, lined with sandy beaches and palm trees.";s:10:"categories";a:4:{i:0;s:3:"sea";i:1;s:7:"coastal";i:2;s:6:"nature";i:3;s:7:"fishing";}s:14:"category_names";a:4:{i:0;s:6:"بحر";i:1;s:10:"ساحلي";i:2;s:10:"طبيعي";i:3;s:6:"صيد";}s:8:"latitude";d:14.805278;s:9:"longitude";d:42.941667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/water/hodeidah/red_sea_coast1.jpg";i:1;s:40:"images/water/hodeidah/red_sea_coast2.jpg";}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:30;a:17:{s:2:"id";i:146;s:7:"city_id";i:4;s:11:"external_id";s:18:"al-salif-salt-pans";s:4:"name";s:25:"ملاحات الصليف";s:7:"name_en";s:18:"As Salif Salt Pans";s:11:"description";s:300:"أحواض مائية واسعة تستخدم في استخراج الملح الصخري عبر تبخير مياه البحر. [9] تشكل هذه الملاحات منظراً طبيعياً-صناعياً فريداً، وتعتبر من أكبر مواقع إنتاج الملح في اليمن.";s:14:"description_en";s:201:"Vast water basins used for extracting rock salt via the evaporation of seawater. [9] These salt pans form a unique natural-industrial landscape and are among the largest salt production sites in Yemen.";s:10:"categories";a:4:{i:0;s:5:"water";i:1;s:10:"industrial";i:2;s:15:"salt-extraction";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"مائي";i:1;s:10:"صناعي";i:2;s:21:"استخراج ملح";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.322222;s:9:"longitude";d:42.705833;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/water/hodeidah/al_salif_salt_pans1.jpg";i:1;s:45:"images/water/hodeidah/al_salif_salt_pans2.jpg";}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:31;a:17:{s:2:"id";i:147;s:7:"city_id";i:4;s:11:"external_id";s:11:"wadi-nakhla";s:4:"name";s:17:"وادي نخلة";s:7:"name_en";s:12:"Wadi Nakhlah";s:11:"description";s:288:"وادي ينحدر من المرتفعات الجبلية لمحافظة تعز ويمر بمدينة حيس التاريخية. [4] يروي الأراضي الزراعية في المناطق التي يمر بها قبل أن يصب في البحر الأحمر شمال الخوخة.";s:14:"description_en";s:217:"A valley descending from the mountainous highlands of Taiz Governorate, passing through the historic city of Hays. [4] It irrigates agricultural lands in its path before emptying into the Red Sea north of Al-Khawkhah.";s:10:"categories";a:3:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:12:"water-course";}s:14:"category_names";a:3:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:17:"مجرى مائي";}s:8:"latitude";d:14.077222;s:9:"longitude";d:43.618611;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/water/hodeidah/wadi_nakhla1.jpg";i:1;s:38:"images/water/hodeidah/wadi_nakhla2.jpg";}s:10:"sort_order";i:32;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:32;a:17:{s:2:"id";i:148;s:7:"city_id";i:4;s:11:"external_id";s:16:"hot-sand-therapy";s:4:"name";s:51:"حمامات الرمال الحارة (الدفن)";s:7:"name_en";s:28:"Hot Sand Baths (Sand Burial)";s:11:"description";s:332:"في المناطق ذات الكثبان الرملية الشاسعة، تُمارس عادة "الدفن في الرمال" كعلاج تقليدي. [2] يُعتقد أن حرارة الرمال الجافة تساعد على استرخاء العضلات وتخفيف آلام الروماتيزم والتهاب المفاصل.";s:14:"description_en";s:204:"In areas with vast sand dunes, 'sand burial' is practiced as a traditional treatment. [2] It is believed that the heat of the dry sand helps relax muscles and relieve the pain of rheumatism and arthritis.";s:10:"categories";a:4:{i:0;s:11:"therapeutic";i:1;s:7:"natural";i:2;s:12:"sand-therapy";i:3;s:10:"rheumatism";}s:14:"category_names";a:4:{i:0;s:10:"علاجي";i:1;s:10:"طبيعي";i:2;s:21:"علاج بالرمل";i:3;s:16:"روماتيزم";}s:8:"latitude";d:14.779444;s:9:"longitude";d:42.964444;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/therapeutic/hodeidah/hot_sand_therapy1.jpg";i:1;s:49:"images/therapeutic/hodeidah/hot_sand_therapy2.jpg";}s:10:"sort_order";i:33;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:33;a:17:{s:2:"id";i:149;s:7:"city_id";i:4;s:11:"external_id";s:22:"kamaran-island-seaweed";s:4:"name";s:32:"طحالب جزيرة كمران";s:7:"name_en";s:20:"Kamaran Island Algae";s:11:"description";s:350:"تنمو على سواحل جزيرة كمران أنواع مختلفة من الطحالب البحرية في بيئة نظيفة. [6] يستخدمها السكان المحليون في غذائهم وكعلاج موضعي لبعض الالتهابات الجلدية لاحتوائها على عناصر مغذية ومضادة للالتهاب.";s:14:"description_en";s:219:"Various types of marine algae grow on the clean coasts of Kamaran Island. [6] Locals use them in their diet and as a topical treatment for some skin infections, due to their nutritional and anti-inflammatory properties.";s:10:"categories";a:4:{i:0;s:11:"therapeutic";i:1;s:7:"natural";i:2;s:7:"seaweed";i:3;s:9:"skin-care";}s:14:"category_names";a:4:{i:0;s:10:"علاجي";i:1;s:10:"طبيعي";i:2;s:21:"طحالب بحرية";i:3;s:25:"عناية بالبشرة";}s:8:"latitude";d:15.385;s:9:"longitude";d:42.59;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:48:"images/therapeutic/hodeidah/kamaran_seaweed1.jpg";i:1;s:48:"images/therapeutic/hodeidah/kamaran_seaweed2.jpg";}s:10:"sort_order";i:34;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:34;a:17:{s:2:"id";i:150;s:7:"city_id";i:4;s:11:"external_id";s:23:"al-khawkhah-coconut-oil";s:4:"name";s:42:"زيت جوز الهند من الخوخة";s:7:"name_en";s:28:"Coconut Oil from Al-Khawkhah";s:11:"description";s:306:"تشتهر منطقة الخوخة بأشجار جوز الهند (النارجيل). [7] يُستخرج الزيت من الثمار ويُستخدم تقليدياً كمرطب للبشرة والشعر، ولعلاج حروق الشمس الطفيفة، وكمضاد للالتهابات الجلدية.";s:14:"description_en";s:215:"The Al-Khawkhah area is famous for its coconut trees. [7] The oil is extracted from the fruits and traditionally used as a moisturizer for skin and hair, for treating minor sunburns, and as a skin anti-inflammatory.";s:10:"categories";a:4:{i:0;s:11:"therapeutic";i:1;s:7:"natural";i:2;s:15:"herbal-medicine";i:3;s:9:"skin-care";}s:14:"category_names";a:4:{i:0;s:10:"علاجي";i:1;s:10:"طبيعي";i:2;s:15:"طب أعشاب";i:3;s:25:"عناية بالبشرة";}s:8:"latitude";d:13.785278;s:9:"longitude";d:43.251389;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/therapeutic/hodeidah/coconut_oil1.jpg";i:1;s:44:"images/therapeutic/hodeidah/coconut_oil2.jpg";}s:10:"sort_order";i:35;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:35;a:17:{s:2:"id";i:151;s:7:"city_id";i:4;s:11:"external_id";s:17:"tihama-sidr-honey";s:4:"name";s:32:"عسل السدر التهامي";s:7:"name_en";s:17:"Tihami Sidr Honey";s:11:"description";s:350:"يُنتج النحل عسلاً ذا جودة عالية من رحيق أشجار السدر المنتشرة في أودية تهامة. [8] يُعتبر عسل السدر مضاداً حيوياً طبيعياً ويستخدم في الطب الشعبي لتقوية المناعة وعلاج أمراض الجهاز التنفسي والجروح.";s:14:"description_en";s:244:"Bees produce high-quality honey from the nectar of Sidr trees spread across the valleys of Tihamah. [8] Sidr honey is considered a natural antibiotic and is used in folk medicine to strengthen immunity and treat respiratory diseases and wounds.";s:10:"categories";a:4:{i:0;s:11:"therapeutic";i:1;s:7:"natural";i:2;s:5:"honey";i:3;s:8:"wellness";}s:14:"category_names";a:4:{i:0;s:10:"علاجي";i:1;s:10:"طبيعي";i:2;s:6:"عسل";i:3;s:6:"صحة";}s:8:"latitude";d:14.532222;s:9:"longitude";d:43.312222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/therapeutic/hodeidah/sidr_honey1.jpg";i:1;s:43:"images/therapeutic/hodeidah/sidr_honey2.jpg";}s:10:"sort_order";i:36;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:36;a:17:{s:2:"id";i:152;s:7:"city_id";i:4;s:11:"external_id";s:17:"fish-oil-hodeidah";s:4:"name";s:30:"زيت السمك الطازج";s:7:"name_en";s:14:"Fresh Fish Oil";s:11:"description";s:325:"لكون الحديدة ميناء صيد رئيسي، يتوفر فيها زيت السمك الطازج المستخرج محلياً. [9] يُستخدم هذا الزيت الغني بالأوميجا 3 في التغذية لتقوية الجسم، ويُعتقد أنه يساعد في صحة المفاصل والقلب.";s:14:"description_en";s:226:"As Al Hudaydah is a major fishing port, locally extracted fresh fish oil is readily available. [9] Rich in Omega-3, this oil is used as a dietary supplement to strengthen the body and is believed to aid joint and heart health.";s:10:"categories";a:4:{i:0;s:11:"therapeutic";i:1;s:7:"natural";i:2;s:9:"nutrition";i:3;s:8:"wellness";}s:14:"category_names";a:4:{i:0;s:10:"علاجي";i:1;s:10:"طبيعي";i:2;s:10:"تغذية";i:3;s:6:"صحة";}s:8:"latitude";d:14.794444;s:9:"longitude";d:42.948333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/therapeutic/hodeidah/fish_oil1.jpg";i:1;s:41:"images/therapeutic/hodeidah/fish_oil2.jpg";}s:10:"sort_order";i:37;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:37;a:17:{s:2:"id";i:153;s:7:"city_id";i:4;s:11:"external_id";s:21:"al-hodeidah-land-park";s:4:"name";s:34:"منتزه الحديدة لاند";s:7:"name_en";s:18:"Hodeidah Land Park";s:11:"description";s:319:"يقع على شارع الكورنيش، وهو من أبرز الوجهات الترفيهية في المدينة. [3, 4] يضم المنتزه مجموعة متنوعة من الألعاب الحديثة ومساحات خضراء، ويستقطب عددًا كبيرًا من العائلات والشباب. [3, 4]";s:14:"description_en";s:220:"Located on Corniche Street, it is one of the most prominent recreational destinations in the city. [3, 4] The park features a variety of modern rides and green spaces, drawing a large number of families and youth. [3, 4]";s:10:"categories";a:3:{i:0;s:14:"amusement-park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"ملاهي";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";d:14.821111;s:9:"longitude";d:42.964444;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:38;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:38;a:17:{s:2:"id";i:154;s:7:"city_id";i:4;s:11:"external_id";s:25:"al-shaheed-al-sammad-park";s:4:"name";s:26:"حديقة 7 يوليو  )";s:7:"name_en";s:16:"7th of July Park";s:11:"description";s:285:"تقع في شارع جمال، وهي إحدى الحدائق الهامة في مدينة الحديدة. [5, 6] تم إعادة تأهيلها وتطويرها لتكون متنفسًا إضافيًا للسكان، وتضم مساحات خضراء ومناطق للجلوس. [5, 6]";s:14:"description_en";s:218:"Located on Gamal Street, it is one of the important parks in Al Hudaydah. [5, 6] It has been rehabilitated and developed to serve as an additional retreat for residents, featuring green spaces and seating areas. [5, 6]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";d:14.821389;s:9:"longitude";d:42.973333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:39;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:39;a:17:{s:2:"id";i:155;s:7:"city_id";i:4;s:11:"external_id";s:17:"al-durayhimi-park";s:4:"name";s:27:"حديقة الدريهمي";s:7:"name_en";s:17:"Al-Durayhimi Park";s:11:"description";s:314:"تقع في مديرية الدريهمي جنوب مدينة الحديدة، وتعتبر متنفسًا رئيسيًا لسكان المديرية. [8] عانت الحديقة من الأضرار ولكن هناك جهود ومناشدات لإعادة تأهيلها لخدمة المجتمع المحلي. [8]";s:14:"description_en";s:244:"Located in the Al-Durayhimi district south of Al Hudaydah, it is considered a primary retreat for the district's residents. [8] The park has suffered damage, but there are efforts and appeals to rehabilitate it to serve the local community. [8]";s:10:"categories";a:2:{i:0;s:4:"park";i:1;s:12:"neighborhood";}s:14:"category_names";a:2:{i:0;s:10:"حديقة";i:1;s:13:"حي سكني";}s:8:"latitude";d:14.63;s:9:"longitude";d:43.030556;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:40;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:7;a:13:{s:2:"id";i:13;s:4:"slug";s:5:"shihr";s:4:"name";s:10:"الشحر";s:7:"name_en";s:9:"Ash Shihr";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:17:"al_shihr_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:15;s:9:"landmarks";a:15:{i:0;a:17:{s:2:"id";i:334;s:7:"city_id";i:13;s:11:"external_id";s:22:"ash-shihr-grand-mosque";s:4:"name";s:38:"الجامع الكبير بالشحر";s:7:"name_en";s:25:"Great Mosque in Ash Shihr";s:11:"description";s:354:"يُعد أول مسجد بني في حضرموت في السنة العاشرة للهجرة. [4, 12] مر المسجد بالعديد من التجديدات والتوسعات عبر تاريخه الطويل، ويتميز بعمارته الإسلامية التقليدية، وكان مركزاً هاماً للعلم ونشر الدين. [4, 16]";s:14:"description_en";s:292:"Considered the first mosque built in Hadhramaut in the tenth year of Hijra. [4, 12] The mosque has undergone many renovations and expansions over its long history, characterized by its traditional Islamic architecture, and was an important center for knowledge and spreading religion. [4, 16]";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:14.754023;s:9:"longitude";d:49.605589;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:335;s:7:"city_id";i:13;s:11:"external_id";s:22:"al-shihr-public-garden";s:4:"name";s:34:"حديقة الشحر العامة";s:7:"name_en";s:21:"Ash Shihr Public Park";s:11:"description";s:285:"حديقة عامة تقع داخل المدينة، وتعتبر متنفسًا للأحياء السكنية. [6] على الرغم من أنها قد تحتاج إلى مزيد من الاهتمام، إلا أنها توفر مساحة خضراء للسكان المحليين. [6]";s:14:"description_en";s:182:"A public park located within the city, serving as a retreat for residential neighborhoods. [6] Although it may need more attention, it provides a green space for local residents. [6]";s:10:"categories";a:2:{i:0;s:4:"park";i:1;s:12:"neighborhood";}s:14:"category_names";a:2:{i:0;s:10:"حديقة";i:1;s:13:"حي سكني";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:336;s:7:"city_id";i:13;s:11:"external_id";s:17:"al-shihr-corniche";s:4:"name";s:23:"كورنيش الشحر";s:7:"name_en";s:18:"Ash Shihr Corniche";s:11:"description";s:436:"يمتد على طول الواجهة البحرية للمدينة، ويعتبر المتنفس الرئيسي والأكثر شعبية لسكان الشحر. [1, 2] يوفر الكورنيش مساحات مفتوحة للمشي والجلوس والاستمتاع بمنظر البحر، وتنتشر على طوله الاستراحات والمقاهي، ويشهد إقبالًا كبيرًا في فترات المساء. [1, 2]";s:14:"description_en";s:276:"Stretching along the city's waterfront, it is the main and most popular retreat for Ash Shihr's residents. [1, 2] The corniche offers open spaces for walking, sitting, and enjoying the sea view, lined with rest stops and cafes, and sees a large turnout in the evenings. [1, 2]";s:10:"categories";a:4:{i:0;s:8:"corniche";i:1;s:10:"waterfront";i:2;s:12:"recreational";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:12:"كورنيش";i:1;s:21:"واجهة بحرية";i:2;s:12:"ترفيهي";i:3;s:10:"عائلي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:337;s:7:"city_id";i:13;s:11:"external_id";s:20:"al-kud-al-aswad-park";s:4:"name";s:34:"منتزه الكود الأسود";s:7:"name_en";s:20:"Al-Kud Al-Aswad Park";s:11:"description";s:283:"منتزه يقع في منطقة الكود الأسود بمديرية الشحر، ويتميز بوجود مساحات خضراء وألعاب للأطفال. [3] يعتبر وجهة للعائلات الباحثة عن متنفس هادئ ومكان للعب الأطفال. [3]";s:14:"description_en";s:201:"A park located in the Al-Kud Al-Aswad area in Ash Shihr district, featuring green spaces and children's games. [3] It is a destination for families seeking a quiet retreat and a play area for kids. [3]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"منتزه";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:338;s:7:"city_id";i:13;s:11:"external_id";s:14:"al-horah-beach";s:4:"name";s:21:"شاطئ الحورة";s:7:"name_en";s:15:"Al-Hawrah Beach";s:11:"description";s:297:"أحد الشواطئ الجميلة في الشحر، ويقع بالقرب من ميناء الشحر السمكي. [4] يعتبر مكانًا للاستجمام والنزهات الشاطئية، ويقصده السكان المحليون للاستمتاع بالبحر والسباحة. [4]";s:14:"description_en";s:191:"One of the beautiful beaches in Ash Shihr, located near the Ash Shihr fishing port. [4] It is a place for relaxation and beach picnics, frequented by locals to enjoy the sea and swimming. [4]";s:10:"categories";a:3:{i:0;s:5:"beach";i:1;s:12:"recreational";i:2;s:8:"swimming";}s:14:"category_names";a:3:{i:0;s:8:"شاطئ";i:1;s:12:"ترفيهي";i:2;s:10:"سباحة";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:339;s:7:"city_id";i:13;s:11:"external_id";s:15:"al-aweyna-beach";s:4:"name";s:23:"شاطئ العوينة";s:7:"name_en";s:16:"Al-Uwaynah Beach";s:11:"description";s:301:"شاطئ يقع شرق مدينة الشحر، ويتميز بهدوئه وجمال طبيعته. [7] يعتبر وجهة مفضلة للباحثين عن الاسترخاء والابتعاد عن الأماكن المزدحمة، وهو مناسب للنزهات العائلية الهادئة. [7]";s:14:"description_en";s:222:"A beach located east of Ash Shihr city, known for its tranquility and natural beauty. [7] It is a favorite destination for those seeking relaxation away from crowded places, making it suitable for quiet family outings. [7]";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:5:"quiet";i:2;s:6:"family";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:8:"هادئ";i:2;s:10:"عائلي";i:3;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:340;s:7:"city_id";i:13;s:11:"external_id";s:15:"husn-bin-ayyash";s:4:"name";s:22:"حصن بن عيّاش";s:7:"name_en";s:15:"Bin Ayyash Fort";s:11:"description";s:316:"أحد أشهر المعالم الأثرية في الشحر، يقع وسط المدينة على تل مرتفع. [3, 10] شُيّد بين عامي 1868 و 1888م على الطراز الهندي التقليدي، ويتكون من عدة أدوار وسراديب كانت تستخدم للتخزين. [19, 24]";s:14:"description_en";s:239:"One of the most famous archaeological landmarks in Ash Shihr, situated on a high hill in the city center. [3, 10] Built between 1868 and 1888 in traditional Indian style, it consists of several floors and cellars used for storage. [19, 24]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";}s:8:"latitude";d:14.758;s:9:"longitude";d:49.605;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:341;s:7:"city_id";i:13;s:11:"external_id";s:18:"saddat-al-aydaroos";s:4:"name";s:23:"سدة العيدروس";s:7:"name_en";s:37:"Saddat Al-Aidaroos (Al-Aidaroos Gate)";s:11:"description";s:328:"تمثل البوابة الشمالية لسور مدينة الشحر القديم وتعتبر نموذجاً فريداً لبوابات المدن الإسلامية في اليمن. [14] سُميت بهذا الاسم لقربها من مسجد العيدروس، ويتكون مبناها من ثلاثة أدوار. [14]";s:14:"description_en";s:213:"It represents the northern gate of the old Ash Shihr city wall and is a unique model of Islamic city gates in Yemen. [14] Named for its proximity to Al-Aidaroos Mosque, its structure consists of three floors. [14]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:4:"gate";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"بوابة";i:2;s:12:"معماري";}s:8:"latitude";d:14.76;s:9:"longitude";d:49.606;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:342;s:7:"city_id";i:13;s:11:"external_id";s:18:"ash-shihr-old-port";s:4:"name";s:34:"ميناء الشحر القديم";s:7:"name_en";s:21:"Old Port of Ash Shihr";s:11:"description";s:349:"كان أحد أهم الموانئ التجارية على بحر العرب وبوابة حضرموت على المحيط الهندي لأكثر من ألف عام. [5, 8] اشتهر بتصدير اللبان والبخور، وكان محطة رئيسية للسفن التجارية المتجهة إلى الهند وشرق إفريقيا. [5]";s:14:"description_en";s:270:"It was one of the most important commercial ports on the Arabian Sea and Hadhramaut's gateway to the Indian Ocean for over a thousand years. [5, 8] Famous for exporting frankincense and incense, it was a major hub for merchant ships heading to India and East Africa. [5]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:4:"port";i:2;s:5:"trade";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"ميناء";i:2;s:10:"تجارة";}s:8:"latitude";d:14.75;s:9:"longitude";d:49.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:343;s:7:"city_id";i:13;s:11:"external_id";s:15:"dar-nasser-fort";s:4:"name";s:40:"حصن دار ناصر (قصر عبود)";s:7:"name_en";s:29:"Dar Naser Fort (Aboud Palace)";s:11:"description";s:313:"قصر أثري بناه الأمير ناصر بن ناجي بن بريك عام 1768م. [15] استُخدم في عهد السلطنة القعيطية كمقر لإدارة حاكم الشحر وضم دوائر حكومية مختلفة. [9, 15] للأسف، اندثرت معظم أجزائه اليوم. [15]";s:14:"description_en";s:285:"An archaeological palace built by Prince Naser bin Naji bin Brik in 1768. [15] Used during the Qu'aiti Sultanate as the administrative headquarters for the governor of Ash Shihr, housing various government departments. [9, 15] Unfortunately, most of its parts have vanished today. [15]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:5:"ruins";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:10:"أطلال";}s:8:"latitude";d:14.759;s:9:"longitude";d:49.605;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:344;s:7:"city_id";i:13;s:11:"external_id";s:12:"jabal-dabdab";s:4:"name";s:15:"جبل ضبضب";s:7:"name_en";s:14:"Mount Dhabdhab";s:11:"description";s:261:"يقع شمال شرق الشحر، وتوجد على قمته بقايا آثار حصن يعود للفترة الإسلامية. [3, 20] لم يتبق من الحصن سوى بعض الأساسات وصهريج كبير لحفظ مياه الأمطار. [20]";s:14:"description_en";s:177:"Located northeast of Ash Shihr, its summit holds the remains of an Islamic-era fort. [3, 20] Only some foundations and a large rainwater storage cistern remain of the fort. [20]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:7:"natural";i:2;s:14:"archaeological";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"طبيعي";i:2;s:8:"أثري";}s:8:"latitude";d:14.78;s:9:"longitude";d:49.63;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:17:{s:2:"id";i:345;s:7:"city_id";i:13;s:11:"external_id";s:18:"al-aydaroos-mosque";s:4:"name";s:25:"مسجد العيدروس";s:7:"name_en";s:18:"Al-Aidaroos Mosque";s:11:"description";s:372:"أحد أقدم وأشهر المساجد في المنطقة، يعود تأسيسه للقرن العاشر الهجري (السادس عشر الميلادي). [7] ارتبط اسمه بالإمام عبدالله بن أبي بكر العيدروس، وكان مركزاً لنشر تعاليم التصوف ويتميز بطرازه المعماري البسيط. [7]";s:14:"description_en";s:269:"One of the oldest and most famous mosques in the area, founded in the 10th century AH (16th century AD). [7] Associated with Imam Abdullah bin Abu Bakr Al-Aidaroos, it was a center for spreading Sufi teachings and is characterized by its simple architectural style. [7]";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:14.7605;s:9:"longitude";d:49.6063;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:17:{s:2:"id";i:346;s:7:"city_id";i:13;s:11:"external_id";s:17:"therapeutic-baths";s:4:"name";s:33:"الحمامات العلاجية";s:7:"name_en";s:17:"Therapeutic Baths";s:11:"description";s:342:"تنتشر في مديرية الشحر مواقع للمياه الحارة الطبيعية مثل حمام صويبر ومعيان باحميد وعين محدث. [9, 20] يقصدها الناس على مدار العام للاستشفاء من بعض الأمراض، ولكنها لا تزال تُستغل بطرق تقليدية. [20]";s:14:"description_en";s:250:"Natural hot water sites are scattered in the Ash Shihr district, such as Suwaybir Bath, Ma'yan Bahmeid, and Ain Muhaddith. [9, 20] People visit them year-round to heal from certain illnesses, although they are still utilized in traditional ways. [20]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"health";i:2;s:7:"tourism";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:6:"صحي";i:2;s:10:"سياحة";}s:8:"latitude";d:14.85;s:9:"longitude";d:49.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:17:{s:2:"id";i:347;s:7:"city_id";i:13;s:11:"external_id";s:19:"ash-shihr-city-wall";s:4:"name";s:28:"سور مدينة الشحر";s:7:"name_en";s:17:"Wall of Ash Shihr";s:11:"description";s:264:"كان يحيط بالمدينة من ثلاث جهات لحمايتها من الهجمات. [14] يعود تاريخ بناء آخر سور إلى عهد السلطنة القعيطية (1868-1888م)، وكانت تتخلله قلاع دفاعية ضخمة. [14]";s:14:"description_en";s:209:"It surrounded the city from three sides to protect it from attacks. [14] The construction of the last wall dates back to the Qu'aiti Sultanate era (1868-1888), interspersed with massive defensive castles. [14]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:9:"defensive";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"دفاعي";}s:8:"latitude";d:14.76;s:9:"longitude";d:49.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:17:{s:2:"id";i:348;s:7:"city_id";i:13;s:11:"external_id";s:15:"tabalah-village";s:4:"name";s:19:"قرية تبالة";s:7:"name_en";s:15:"Tabalah Village";s:11:"description";s:271:"تقع شمال الشحر على بعد حوالي 6 كيلومترات. [9, 20] تشتهر بمعالمها التاريخية مثل قلعة ابن الشيخ علي وحصن تبالة (حصن القعيطي) الذي كان سكناً لنائب السلطان. [9]";s:14:"description_en";s:220:"Located about 6 kilometers north of Ash Shihr. [9, 20] Famous for its historical landmarks such as the Castle of Ibn Al-Sheikh Ali and Tabalah Fort (Qu'aiti Fort), which served as a residence for the Sultan's deputy. [9]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:7:"village";i:2;s:8:"fortress";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"قرية";i:2;s:6:"حصن";}s:8:"latitude";d:14.8;s:9:"longitude";d:49.58;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:8;a:13:{s:2:"id";i:19;s:4:"slug";s:5:"dhale";s:4:"name";s:12:"الضالع";s:7:"name_en";s:8:"Ad Dhale";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:17:"al_dhale_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:20;s:9:"landmarks";a:20:{i:0;a:17:{s:2:"id";i:481;s:7:"city_id";i:19;s:11:"external_id";s:11:"jabal-jihaf";s:4:"name";s:15:"جبل جحاف";s:7:"name_en";s:11:"Mount Jihaf";s:11:"description";s:384:"أحد أشهر وأعلى الجبال في الضالع، وهو عبارة عن سلسلة جبلية واسعة تضم العديد من القرى والحصون. [1, 2] يشتهر بزراعة البن عالي الجودة، ومدرجاته الزراعية الخضراء، وأجوائه المعتدلة، ويعتبر محمية طبيعية وسياحية متكاملة.";s:14:"description_en";s:296:"One of the most famous and highest mountains in Ad Dhale, it is a broad mountain range comprising many villages and forts. [1, 2] It is renowned for cultivating high-quality coffee, its green agricultural terraces, and a moderate climate, rendering it a comprehensive natural and tourist reserve.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:13.75;s:9:"longitude";d:44.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:1;a:17:{s:2:"id";i:482;s:7:"city_id";i:19;s:11:"external_id";s:26:"dar-al-amir-qalat-al-dhale";s:4:"name";s:43:"دار الأمير (قلعة الضالع)";s:7:"name_en";s:29:"Dar Al-Amir (Ad Dhale Castle)";s:11:"description";s:316:"كانت القصر ومقر الحكم لأمراء إمارة الضالع. [3, 4] تقع القلعة على تلة تطل على مدينة الضالع، وتعتبر شاهداً على التاريخ السياسي والإداري للمنطقة، وتتميز بطابعها المعماري الدفاعي.";s:14:"description_en";s:272:"It was the palace and seat of governance for the emirs of the Ad Dhale Emirate. [3, 4] Located on a hill overlooking Ad Dhale city, the castle stands as a testament to the political and administrative history of the region, marked by its defensive architectural character.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:6:"palace";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:6:"قصر";i:3;s:12:"معماري";}s:8:"latitude";d:13.696;s:9:"longitude";d:44.729;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:2;a:17:{s:2:"id";i:483;s:7:"city_id";i:19;s:11:"external_id";s:16:"damt-hot-springs";s:4:"name";s:36:"حمامات دمت المعدنية";s:7:"name_en";s:18:"Damt Mineral Baths";s:11:"description";s:397:"مدينة دمت هي أشهر وجهة للسياحة العلاجية في اليمن. [5, 6] تضم المدينة العديد من الينابيع الكبريتية الحارة التي يقصدها الزوار من كل مكان للاستشفاء من أمراض المفاصل والجلد، وتتميز بتدفق مياهها الحارة التي تشكل شلالات صغيرة.";s:14:"description_en";s:268:"The city of Damt is the most famous destination for medical tourism in Yemen. [5, 6] The city holds numerous hot sulfur springs visited by people from everywhere to heal from joint and skin diseases. It is notable for its hot flowing waters that form small waterfalls.";s:10:"categories";a:4:{i:0;s:6:"health";i:1;s:7:"tourism";i:2;s:7:"natural";i:3;s:6:"spring";}s:14:"category_names";a:4:{i:0;s:6:"صحي";i:1;s:10:"سياحة";i:2;s:10:"طبيعي";i:3;s:10:"ينبوع";}s:8:"latitude";d:14.07;s:9:"longitude";d:44.68;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:17:{s:2:"id";i:484;s:7:"city_id";i:19;s:11:"external_id";s:20:"al-dhale-public-park";s:4:"name";s:36:"حديقة الضالع العامة";s:7:"name_en";s:20:"Ad Dhale Public Park";s:11:"description";s:325:"الحديقة العامة الرئيسية في مدينة الضالع، مركز المحافظة. [6] تمثل متنفسًا منظمًا للعائلات والأطفال داخل المدينة، وتضم بعض المساحات الخضراء والألعاب، وتشهد إقبالًا في المناسبات. [6]";s:14:"description_en";s:242:"The main public park in the city of Ad Dhale, the center of the governorate. [6] It represents an organized retreat for families and children within the city, containing some green spaces and games, and sees high turnout during occasions. [6]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:17:{s:2:"id";i:485;s:7:"city_id";i:19;s:11:"external_id";s:19:"juban-historic-city";s:4:"name";s:36:"مدينة جبن التاريخية";s:7:"name_en";s:22:"Historic City of Juban";s:11:"description";s:332:"مدينة تاريخية قديمة كانت عاصمة للدولة الطاهرية في فترة من الفترات. [7, 8] تشتهر بقلعتها التاريخية (حصن قرين) ومساجدها ومدارسها القديمة، وتعتبر مركزاً ثقافياً ودينياً هاماً في المحافظة.";s:14:"description_en";s:267:"An ancient historical city that was the capital of the Tahirid state during a certain period. [7, 8] It is famous for its historical castle (Qurayn Fort) and its old mosques and schools, and is considered an important cultural and religious center in the governorate.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:8:"fortress";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:6:"حصن";i:3;s:10:"ثقافي";}s:8:"latitude";d:13.93;s:9:"longitude";d:44.88;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:17:{s:2:"id";i:486;s:7:"city_id";i:19;s:11:"external_id";s:16:"khawlah-fortress";s:4:"name";s:15:"حصن خولة";s:7:"name_en";s:12:"Khawlah Fort";s:11:"description";s:305:"حصن تاريخي منيع يقع في مديرية الشعيب، مبني على قمة جبلية شاهقة. [9] يتميز الحصن بموقعه الاستراتيجي الذي يسيطر على المناطق المحيطة، ويعكس تاريخ المنطقة العسكري والدفاعي.";s:14:"description_en";s:253:"An impregnable historical fort located in the Ash Shu'ayb district, built on a towering mountain peak. [9] The fort is distinguished by its strategic location dominating the surrounding areas, reflecting the military and defensive history of the region.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:10:"عسكري";i:3;s:8:"جبلي";}s:8:"latitude";d:13.8;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:17:{s:2:"id";i:487;s:7:"city_id";i:19;s:11:"external_id";s:15:"wadi-bana-dhale";s:4:"name";s:30:"وادي بنا (الضالع)";s:7:"name_en";s:21:"Wadi Banna (Ad Dhale)";s:11:"description";s:345:"يمر الجزء الأعلى من وادي بنا الشهير عبر محافظة الضالع. [10] يتميز هذا الجزء من الوادي بمناظره الطبيعية الجبلية الخلابة ومياهه الجارية التي تشكل مصدراً رئيسياً للزراعة في المناطق التي يمر بها.";s:14:"description_en";s:262:"The upper part of the famous Wadi Banna passes through Ad Dhale Governorate. [10] This section of the valley is characterized by its breathtaking mountainous scenery and flowing waters, which constitute a primary source for agriculture in the areas it traverses.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:5:"water";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:8:"مائي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.9;s:9:"longitude";d:44.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:17:{s:2:"id";i:488;s:7:"city_id";i:19;s:11:"external_id";s:15:"al-hussein-city";s:4:"name";s:23:"مدينة الحصين";s:7:"name_en";s:15:"Al-Hussein City";s:11:"description";s:342:"عاصمة مديرية الحصين، وهي مدينة جبلية تتميز بقراها ومنازلها الحجرية المتناثرة على السفوح. [4] تشتهر المنطقة بطبيعتها الزراعية ووديانها الخصبة، وتعتبر نموذجاً للمستوطنات الجبلية في الضالع.";s:14:"description_en";s:260:"The capital of Al-Hussein district, a mountainous city distinguished by its villages and stone houses scattered across the slopes. [4] The region is known for its agricultural nature and fertile valleys, serving as a model for mountain settlements in Ad Dhale.";s:10:"categories";a:4:{i:0;s:4:"city";i:1;s:8:"mountain";i:2;s:7:"village";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:10:"مدينة";i:1;s:8:"جبلي";i:2;s:8:"قرية";i:3;s:12:"معماري";}s:8:"latitude";d:13.65;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:8;a:17:{s:2:"id";i:489;s:7:"city_id";i:19;s:11:"external_id";s:12:"qutabah-city";s:4:"name";s:21:"مدينة قعطبة";s:7:"name_en";s:14:"Qa'atabah City";s:11:"description";s:277:"مدينة حدودية وتجارية هامة، تقع على الطريق الرئيسي الذي يربط جنوب اليمن بشماله. [4] تشتهر بسوقها النشط وتاريخها كمركز تجاري ونقطة التقاء بين مناطق مختلفة.";s:14:"description_en";s:223:"An important border and commercial city located on the main road connecting the south of Yemen to its north. [4] It is famous for its bustling market and its history as a trade hub and a meeting point for different regions.";s:10:"categories";a:4:{i:0;s:4:"city";i:1;s:6:"market";i:2;s:10:"historical";i:3;s:5:"trade";}s:14:"category_names";a:4:{i:0;s:10:"مدينة";i:1;s:6:"سوق";i:2;s:12:"تاريخي";i:3;s:10:"تجارة";}s:8:"latitude";d:13.88;s:9:"longitude";d:44.68;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:9;a:17:{s:2:"id";i:490;s:7:"city_id";i:19;s:11:"external_id";s:18:"al-shuaib-terraces";s:4:"name";s:42:"مدرجات الشعيب الزراعية";s:7:"name_en";s:33:"Ash Shu'ayb Agricultural Terraces";s:11:"description";s:330:"تغطي المدرجات الزراعية سفوح الجبال في مديرية الشعيب، مكونة لوحة فنية خضراء. [9] تزرع في هذه المدرجات الحبوب والبن، وهي شاهد على قدرة الإنسان على تطويع البيئة الجبلية القاسية للزراعة.";s:14:"description_en";s:255:"Agricultural terraces cover the mountain slopes in Ash Shu'ayb district, creating a green artistic canvas. [9] Grains and coffee are cultivated on these terraces, acting as a testament to human ability to adapt harsh mountain environments for agriculture.";s:10:"categories";a:4:{i:0;s:11:"agriculture";i:1;s:6:"scenic";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"زراعة";i:1;s:21:"مناظر خلابة";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.85;s:9:"longitude";d:44.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:10;a:17:{s:2:"id";i:491;s:7:"city_id";i:19;s:11:"external_id";s:20:"juban-fortress-qarin";s:4:"name";s:24:"حصن قرين (جبن)";s:7:"name_en";s:19:"Qurayn Fort (Juban)";s:11:"description";s:293:"الحصن التاريخي الذي يطل على مدينة جبن. [7, 8] كان مركز السلطة والقيادة في المدينة، ويتميز ببنائه الحجري القوي وموقعه المسيطر، ويحتوي على بقايا مبانٍ ومرافق دفاعية.";s:14:"description_en";s:247:"The historical fort overlooking the city of Juban. [7, 8] It was the center of power and leadership in the city, distinguished by its strong stone construction and commanding location, and it contains remains of buildings and defensive facilities.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:9:"viewpoint";i:3;s:8:"military";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:6:"مطل";i:3;s:10:"عسكري";}s:8:"latitude";d:13.93;s:9:"longitude";d:44.88;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:11;a:17:{s:2:"id";i:492;s:7:"city_id";i:19;s:11:"external_id";s:21:"damt-travertine-falls";s:4:"name";s:34:"شلالات دمت الكلسية";s:7:"name_en";s:26:"Damt Travertine Waterfalls";s:11:"description";s:367:"بالإضافة إلى ينابيعها الحارة، تتميز دمت بظاهرة فريدة حيث تترسب المعادن من المياه الحارة لتشكل مدرجات وشلالات كلسية (Travertine) متجمدة. [1] توفر هذه التكوينات البيضاء منظراً طبيعياً فريداً يشبه شلالات الثلج.";s:14:"description_en";s:256:"In addition to its hot springs, Damt features a unique phenomenon where minerals from the hot waters precipitate to form frozen-looking travertine terraces and waterfalls. [1] These white formations provide a unique natural view resembling snow waterfalls.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:10:"geological";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:14:"جيولوجي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.07;s:9:"longitude";d:44.68;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:12;a:17:{s:2:"id";i:493;s:7:"city_id";i:19;s:11:"external_id";s:19:"wadi-al-shuaib-park";s:4:"name";s:32:"منتزه وادي الشعيب";s:7:"name_en";s:21:"Wadi Ash Shu'ayb Park";s:11:"description";s:353:"أحد الأودية الرئيسية في مديرية الشعيب، ويتميز بمناظره الطبيعية الخلابة ومياهه الجارية بعد الأمطار. [2] يعتبر الوادي والمناطق الخضراء المحيطة به منتزهاً طبيعياً يقصده الأهالي للنزهة والاستجمام.";s:14:"description_en";s:255:"One of the main valleys in the Ash Shu'ayb district, characterized by its breathtaking natural scenery and waters flowing after the rains. [2] The valley and its surrounding green areas serve as a natural park visited by locals for picnics and relaxation.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"valley";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.85;s:9:"longitude";d:44.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:13;a:17:{s:2:"id";i:494;s:7:"city_id";i:19;s:11:"external_id";s:22:"jihaf-mountain-springs";s:4:"name";s:41:"عيون ومنتزهات جبل جحاف";s:7:"name_en";s:32:"Springs and Parks of Mount Jihaf";s:11:"description";s:360:"يضم جبل جحاف الشاسع العديد من عيون المياه الطبيعية (الينابيع) والمناطق الخضراء التي لم تذكر. [3] تعتبر هذه المواقع بمثابة منتزهات طبيعية صغيرة توفر إطلالات رائعة ومكاناً هادئاً للراحة بين مزارع البن.";s:14:"description_en";s:208:"The vast Mount Jihaf encompasses many natural water springs and unmentioned green areas. [3] These sites serve as small natural parks providing wonderful views and quiet places to rest among the coffee farms.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:6:"spring";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:10:"ينبوع";i:3;s:8:"جبلي";}s:8:"latitude";d:13.75;s:9:"longitude";d:44.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:14;a:17:{s:2:"id";i:495;s:7:"city_id";i:19;s:11:"external_id";s:18:"wadi-nakhlah-falls";s:4:"name";s:30:"شلالات وادي نخلة";s:7:"name_en";s:23:"Wadi Nakhlah Waterfalls";s:11:"description";s:307:"يقع في مديرية الحشاء، وهو وادٍ جبلي تنحدر فيه السيول بقوة بعد الأمطار مكونة شلالات موسمية جميلة. [4] يشتهر الوادي بطبيعته البكر ومناظره الصخرية التي يتدفق من بينها الماء.";s:14:"description_en";s:246:"Located in the Al-Hasha district, it is a mountain valley where floods descend powerfully after rainfall, creating beautiful seasonal waterfalls. [4] The valley is famous for its pristine nature and rocky landscapes through which the water flows.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.8;s:9:"longitude";d:44.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:15;a:17:{s:2:"id";i:496;s:7:"city_id";i:19;s:11:"external_id";s:24:"al-azariq-highlands-park";s:4:"name";s:40:"منتزه مرتفعات الأزارق";s:7:"name_en";s:24:"Al-Azariq Highlands Park";s:11:"description";s:315:"تتميز مديرية الأزارق بمرتفعاتها الجبلية ومناظرها الطبيعية. [5] توفر هذه المرتفعات أماكن هادئة ومطلات طبيعية تصلح للنزهات والتخييم الخفيف، والاستمتاع بالهواء النقي والهدوء.";s:14:"description_en";s:231:"The Al-Azariq district is characterized by its mountainous highlands and natural landscapes. [5] These highlands offer quiet places and natural viewpoints suitable for picnics, light camping, and enjoying fresh air and tranquility.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.5;s:9:"longitude";d:44.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:16;a:17:{s:2:"id";i:497;s:7:"city_id";i:19;s:11:"external_id";s:19:"wadi-al-habil-falls";s:4:"name";s:43:"شلالات وادي الحبيل (جبن)";s:7:"name_en";s:33:"Wadi Al-Hubayl Waterfalls (Juban)";s:11:"description";s:289:"أحد الأودية الهامة في مديرية جبن، وتتشكل فيه شلالات موسمية جميلة بعد تدفق السيول من المرتفعات المحيطة. [6] يعتبر الوادي ومحيطه متنفساً طبيعياً للسكان المحليين.";s:14:"description_en";s:233:"One of the important valleys in the Juban district, where beautiful seasonal waterfalls form after floods stream down from the surrounding highlands. [6] The valley and its surroundings are a natural retreat for the local population.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.9;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:17;a:17:{s:2:"id";i:498;s:7:"city_id";i:19;s:11:"external_id";s:23:"al-dhale-city-view-park";s:4:"name";s:41:"منتزه مطل مدينة الضالع";s:7:"name_en";s:28:"Ad Dhale City Viewpoint Park";s:11:"description";s:357:"التلال والمرتفعات المحيطة بمدينة الضالع، خاصة تلك القريبة من دار الأمير، تعتبر منتزهات طبيعية. [7] توفر هذه المواقع إطلالات بانورامية على المدينة والوديان المجاورة، وهي مكان مفضل للسكان المحليين.";s:14:"description_en";s:227:"The hills and highlands surrounding Ad Dhale city, especially those near Dar Al-Amir, are considered natural parks. [7] These sites provide panoramic views over the city and adjacent valleys, and are a favorite spot for locals.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:4:"city";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:10:"مدينة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.7;s:9:"longitude";d:44.73;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:18;a:17:{s:2:"id";i:499;s:7:"city_id";i:19;s:11:"external_id";s:26:"al-hasha-mountain-cascades";s:4:"name";s:34:"شلالات جبال الحشاء";s:7:"name_en";s:29:"Al-Hasha Mountains Waterfalls";s:11:"description";s:314:"مديرية الحشاء هي منطقة جبلية وعرة. تتسبب الأمطار الغزيرة في تدفق المياه بقوة عبر المنحدرات، مكونة سلسلة من الشلالات المتتالية (Cascades) التي توفر منظراً طبيعياً قوياً وجذاباً.";s:14:"description_en";s:195:"The Al-Hasha district is a rugged mountainous region. Heavy rains cause water to flow forcefully over the slopes, forming a series of cascades that provide a powerful and attractive natural view.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:6:"قوي";}s:8:"latitude";d:13.85;s:9:"longitude";d:44.55;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:19;a:17:{s:2:"id";i:500;s:7:"city_id";i:19;s:11:"external_id";s:15:"wadi-yaram-park";s:4:"name";s:28:"منتزه وادي يرام";s:7:"name_en";s:15:"Wadi Yaram Park";s:11:"description";s:287:"وادي خصب يقع بين مديريتي قعطبة والحشاء. [4] بعد مواسم الأمطار، يتحول الوادي إلى مساحات خضراء شاسعة، مما يجعله منتزهاً طبيعياً مفتوحاً ومكاناً مثالياً للرحلات.";s:14:"description_en";s:215:"A fertile valley located between the Qa'atabah and Al-Hasha districts. [4] Following the rainy seasons, the valley transforms into vast green expanses, making it an open natural park and an ideal location for trips.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"valley";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:10:"موسمي";}s:8:"latitude";d:13.9;s:9:"longitude";d:44.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:9;a:13:{s:2:"id";i:16;s:4:"slug";s:6:"mahwit";s:4:"name";s:14:"المحويت";s:7:"name_en";s:9:"Al Mahwit";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:18:"al_mahwit_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:21;s:9:"landmarks";a:21:{i:0;a:17:{s:2:"id";i:399;s:7:"city_id";i:16;s:11:"external_id";s:15:"shibam-kawkaban";s:4:"name";s:32:"مدينة شبام كوكبان";s:7:"name_en";s:20:"Shibam Kawkaban City";s:11:"description";s:422:"مدينة تاريخية فريدة تتكون من جزأين: شبام التي تقع أسفل الجبل، وكوكبان المدينة المحصنة على قمته. [1, 2] ترتبطان بطريق مشاة صخري متدرج، وتشتهر كوكبان بحصونها ومنازلها الشاهقة ومساجدها التاريخية، وتوفر إطلالات بانورامية لا مثيل لها. [1, 2]";s:14:"description_en";s:323:"A unique historical city consisting of two parts: Shibam, located at the foot of the mountain, and Kawkaban, the fortified city on its summit. [1, 2] They are connected by a stepped rocky pedestrian path. Kawkaban is famous for its forts, towering houses, and historic mosques, offering unparalleled panoramic views. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:8:"mountain";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:8:"جبلي";i:3;s:12:"معماري";}s:8:"latitude";d:15.5136;s:9:"longitude";d:43.8819;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:400;s:7:"city_id";i:16;s:11:"external_id";s:15:"al-mahweet-city";s:4:"name";s:25:"مدينة المحويت";s:7:"name_en";s:14:"Al Mahwit City";s:11:"description";s:368:"عاصمة المحافظة، وهي مدينة معلقة على سفوح الجبال ومحاطة بالمدرجات الزراعية الخضراء. [4, 5] تتميز بمنازلها الحجرية التقليدية التي تبدو وكأنها جزء من الجبل، وأجوائها المعتدلة ومناظرها الطبيعية الساحرة. [4, 5]";s:14:"description_en";s:272:"The capital of the governorate, a city suspended on mountain slopes and surrounded by green agricultural terraces. [4, 5] It is characterized by its traditional stone houses that seem to be part of the mountain, its moderate climate, and enchanting natural scenery. [4, 5]";s:10:"categories";a:4:{i:0;s:4:"city";i:1;s:6:"scenic";i:2;s:8:"mountain";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:10:"مدينة";i:1;s:21:"مناظر خلابة";i:2;s:8:"جبلي";i:3;s:12:"معماري";}s:8:"latitude";d:15.47;s:9:"longitude";d:43.54;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:401;s:7:"city_id";i:16;s:11:"external_id";s:15:"husn-al-tawilah";s:4:"name";s:21:"حصن الطويلة";s:7:"name_en";s:15:"Al-Tawilah Fort";s:11:"description";s:390:"حصن تاريخي منيع يقع في مدينة الطويلة، مبني على قمة جبل صخري شاهق. [3, 6] يعتبر من أهم الحصون في اليمن، ويتميز بتصميمه الدفاعي الفريد الذي يندمج مع التكوين الصخري للجبل، ويحتوي على مساجد ومدافن مياه منحوتة في الصخر. [3, 6]";s:14:"description_en";s:328:"An impregnable historical fort located in the city of Al-Tawilah, built on the peak of a towering rocky mountain. [3, 6] Considered one of the most important forts in Yemen, it features a unique defensive design that merges with the mountain's rock formation, and contains mosques and water cisterns carved into the rock. [3, 6]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";i:3;s:8:"military";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";i:3;s:10:"عسكري";}s:8:"latitude";d:15.3969;s:9:"longitude";d:43.7658;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:402;s:7:"city_id";i:16;s:11:"external_id";s:20:"al-mahweet-city-park";s:4:"name";s:38:"حديقة المحويت العامة";s:7:"name_en";s:21:"Al Mahwit Public Park";s:11:"description";s:286:"الحديقة العامة الرئيسية في مدينة المحويت، مركز المحافظة. [6] توفر متنفسًا منظمًا للعائلات والأطفال داخل المدينة، وتضم بعض المساحات الخضراء وألعابًا بسيطة. [6]";s:14:"description_en";s:200:"The main public park in Al Mahwit city, the center of the governorate. [6] It provides an organized retreat for families and children within the city, featuring some green spaces and simple games. [6]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:403;s:7:"city_id";i:16;s:11:"external_id";s:10:"wadi-saraa";s:4:"name";s:15:"وادي سرع";s:7:"name_en";s:10:"Wadi Suru'";s:11:"description";s:343:"أحد الأودية الخصبة والجميلة في المحافظة، يقع بالقرب من مدينة المحويت. [7] يشتهر بمياهه الجارية وبساتين البن والموز، ويعتبر متنفساً طبيعياً يقصده الزوار للاستمتاع بالخضرة والأجواء الهادئة.";s:14:"description_en";s:265:"One of the fertile and beautiful valleys in the governorate, located near the city of Al Mahwit. [7] Famous for its running waters and coffee and banana plantations, it is considered a natural retreat visited by people to enjoy the greenery and peaceful atmosphere.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.45;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:404;s:7:"city_id";i:16;s:11:"external_id";s:17:"jabal-bilad-ghail";s:4:"name";s:22:"جبل بلاد غيل";s:7:"name_en";s:17:"Mount Bilad Ghayl";s:11:"description";s:347:"منطقة جبلية تقع في مديرية حفاش، وتشتهر بمدرجاتها الزراعية الكثيفة التي تكسوها الخضرة معظم أيام السنة. [8] تعتبر المنطقة لوحة فنية طبيعية، وتوفر مناظر بانورامية ساحرة للوديان والجبال المحيطة.";s:14:"description_en";s:250:"A mountainous area located in the Hafash district, famous for its dense agricultural terraces covered in green most days of the year. [8] The area is a natural masterpiece, offering enchanting panoramic views of the surrounding valleys and mountains.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:15.2;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:405;s:7:"city_id";i:16;s:11:"external_id";s:19:"al-qanaqir-fortress";s:4:"name";s:21:"حصن القرانع";s:7:"name_en";s:15:"Al-Qarani' Fort";s:11:"description";s:318:"حصن تاريخي آخر يقع في مدينة شبام كوكبان، ويعتبر جزءاً من تحصيناتها. [2] يتميز بعمارته الحجرية القوية وموقعه الاستراتيجي الذي يوفر إطلالة رائعة على المناطق المحيطة بمدينة شبام.";s:14:"description_en";s:255:"Another historical fort located in the city of Shibam Kawkaban, serving as part of its fortifications. [2] It is distinguished by its strong stone architecture and strategic location, providing a wonderful view of the areas surrounding the city of Shibam.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";i:3;s:6:"مطل";}s:8:"latitude";d:15.51;s:9:"longitude";d:43.88;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:406;s:7:"city_id";i:16;s:11:"external_id";s:13:"wadi-al-ahjer";s:4:"name";s:21:"وادي الأهجر";s:7:"name_en";s:13:"Wadi Al-Ahjur";s:11:"description";s:367:"وادي ساحر يقع بالقرب من شبام كوكبان، ويشتهر بقرية الأهجر المعلقة على حافته. [9] يتميز الوادي بجسوره الحجرية القديمة ومياهه الجارية ومزارع البن، ويعتبر وجهة مثالية لمحبي المشي لمسافات طويلة (الهايكنج). [9]";s:14:"description_en";s:235:"A charming valley near Shibam Kawkaban, famous for the village of Al-Ahjur hanging on its edge. [9] The valley features ancient stone bridges, running waters, and coffee farms, making it an ideal destination for hiking enthusiasts. [9]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:7:"village";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:8:"قرية";i:3;s:12:"هايكنج";}s:8:"latitude";d:15.45;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:407;s:7:"city_id";i:16;s:11:"external_id";s:13:"jabal-al-dila";s:4:"name";s:33:"جبل الظل (جبل حفاش)";s:7:"name_en";s:28:"Mount Al-Zill (Mount Hafash)";s:11:"description";s:338:"أحد أعلى القمم الجبلية في المحافظة، ويقع في مديرية حفاش. [8] يشتهر بأجوائه الباردة والضباب الذي يلفه معظم الأوقات، وتغطيه مدرجات زراعية خضراء، مما يجعله وجهة فريدة لمحبي الطبيعة الجبلية.";s:14:"description_en";s:276:"One of the highest mountain peaks in the governorate, located in the Hafash district. [8] It is famous for its cold atmosphere and the fog that engulfs it most of the time, covered with green agricultural terraces, making it a unique destination for lovers of mountain nature.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:6:"scenic";i:3;s:7:"climate";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:21:"مناظر خلابة";i:3;s:8:"مناخ";}s:8:"latitude";d:15.25;s:9:"longitude";d:43.55;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:408;s:7:"city_id";i:16;s:11:"external_id";s:15:"al-tawilah-city";s:4:"name";s:25:"مدينة الطويلة";s:7:"name_en";s:15:"Al-Tawilah City";s:11:"description";s:359:"مدينة تاريخية تقع على طريق صنعاء - المحويت، وتشتهر بحصنها المنيع وسوقها التقليدي. [6] تتميز المدينة بمبانيها الحجرية القديمة ومساجدها التاريخية، وتعتبر مركزاً إدارياً وثقافياً مهماً في المحافظة. [6]";s:14:"description_en";s:284:"A historical city located on the Sana'a - Al Mahwit road, famous for its impregnable fort and traditional market. [6] The city is characterized by its old stone buildings and historical mosques, and is considered an important administrative and cultural center in the governorate. [6]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:6:"market";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:6:"سوق";i:3;s:12:"معماري";}s:8:"latitude";d:15.39;s:9:"longitude";d:43.76;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:409;s:7:"city_id";i:16;s:11:"external_id";s:18:"bani-saad-terraces";s:4:"name";s:43:"مدرجات بني سعد الزراعية";s:7:"name_en";s:31:"Bani Sa'd Agricultural Terraces";s:11:"description";s:363:"تقع في مديرية بني سعد، وهي منطقة تشتهر بزراعة البن اليمني عالي الجودة. [10] تشكل المدرجات الزراعية التي تغطي سفوح الجبال لوحة فنية خضراء، وتعتبر مثالاً رائعاً على تكيف الإنسان مع البيئة الجبلية الصعبة.";s:14:"description_en";s:276:"Located in the Bani Sa'd district, an area famous for cultivating high-quality Yemeni coffee. [10] The agricultural terraces covering the mountain slopes form a green artistic canvas, representing a wonderful example of human adaptation to a difficult mountainous environment.";s:10:"categories";a:4:{i:0;s:11:"agriculture";i:1;s:6:"scenic";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"زراعة";i:1;s:21:"مناظر خلابة";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.2;s:9:"longitude";d:43.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:17:{s:2:"id";i:410;s:7:"city_id";i:16;s:11:"external_id";s:17:"wadi-hafash-falls";s:4:"name";s:30:"شلالات وادي حفاش";s:7:"name_en";s:22:"Wadi Hafash Waterfalls";s:11:"description";s:286:"يقع في مديرية حفاش، وهي منطقة جبلية خضراء. بعد هطول الأمطار، تتشكل في الوادي شلالات موسمية جميلة تنحدر من بين المدرجات الزراعية، مما يخلق مناظر طبيعية خلابة.";s:14:"description_en";s:208:"Located in the Hafash district, a green mountainous area. After rainfall, beautiful seasonal waterfalls form in the valley, cascading down between agricultural terraces, creating breathtaking natural scenery.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:8:"seasonal";i:3;s:6:"valley";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:10:"موسمي";i:3;s:8:"وادي";}s:8:"latitude";d:15.22;s:9:"longitude";d:43.53;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:17:{s:2:"id";i:411;s:7:"city_id";i:16;s:11:"external_id";s:21:"al-ahjer-village-park";s:4:"name";s:32:"منتزه قرية الأهجر";s:7:"name_en";s:21:"Al-Ahjur Village Park";s:11:"description";s:333:"تعتبر قرية الأهجر نفسها منتزهاً طبيعياً فريداً. تقع القرية على حافة وادٍ سحيق، وتوفر إطلالات مذهلة ومسارات للمشي (هايكنج) عبر الجسر الحجري القديم وصولاً إلى بساتين البن في قاع الوادي.";s:14:"description_en";s:232:"The village of Al-Ahjur itself is considered a unique natural park. Perched on the edge of a deep valley, it offers stunning views and hiking trails across the ancient stone bridge down to the coffee plantations at the valley floor.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"village";i:2;s:6:"scenic";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"قرية";i:2;s:21:"مناظر خلابة";i:3;s:12:"هايكنج";}s:8:"latitude";d:15.45;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:17:{s:2:"id";i:412;s:7:"city_id";i:16;s:11:"external_id";s:21:"wadi-al-ghuzayl-falls";s:4:"name";s:36:"شلالات وادي الغُزيل";s:7:"name_en";s:26:"Wadi Al-Ghuzayl Waterfalls";s:11:"description";s:302:"أحد الأودية الفرعية في مديرية بني سعد، ويشتهر بمناظره الطبيعية الخلابة. تتكون فيه شلالات صغيرة وعيون مياه جارية، خاصة في مواسم الأمطار، مما يجعله وجهة مفضلة للنزهات.";s:14:"description_en";s:222:"A sub-valley in the Bani Sa'd district, famous for its breathtaking natural scenery. Small waterfalls and flowing water springs form in it, especially during the rainy seasons, making it a favorite destination for picnics.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:6:"valley";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:8:"وادي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.25;s:9:"longitude";d:43.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:17:{s:2:"id";i:413;s:7:"city_id";i:16;s:11:"external_id";s:19:"jabal-kawkaban-park";s:4:"name";s:30:"منتزه جبل كوكبان";s:7:"name_en";s:19:"Mount Kawkaban Park";s:11:"description";s:374:"المنطقة المحيطة بمدينة كوكبان التاريخية تعتبر منتزهاً طبيعياً. يمكن للزوار الاستمتاع بالمشي على الطريق الصخري القديم الذي يربط شبام بكوكبان، والتمتع بالإطلالات البانورامية على الوديان والمناطق المحيطة.";s:14:"description_en";s:232:"The area surrounding the historical city of Kawkaban is considered a natural park. Visitors can enjoy walking on the old rocky path connecting Shibam to Kawkaban, and take in the panoramic views of the valleys and surrounding areas.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:12:"تاريخي";}s:8:"latitude";d:15.5136;s:9:"longitude";d:43.8819;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:15;a:17:{s:2:"id";i:414;s:7:"city_id";i:16;s:11:"external_id";s:14:"wadi-nawa-park";s:4:"name";s:26:"منتزه وادي نوا";s:7:"name_en";s:14:"Wadi Nawa Park";s:11:"description";s:310:"يقع في مديرية الخبت، وهو وادٍ واسع يتميز بأراضيه الزراعية الخصبة. يعتبر الوادي متنفساً طبيعياً لسكان المنطقة، ويوفر مساحات خضراء واسعة مناسبة للرحلات العائلية والنزهات.";s:14:"description_en";s:222:"Located in the Al Khabt district, it is a wide valley known for its fertile agricultural lands. The valley is a natural retreat for the region's residents, providing vast green spaces suitable for family trips and picnics.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:6:"valley";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:8:"وادي";i:3;s:10:"زراعة";}s:8:"latitude";d:15.4;s:9:"longitude";d:43.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:16;a:17:{s:2:"id";i:415;s:7:"city_id";i:16;s:11:"external_id";s:25:"al-tawilah-mountain-views";s:4:"name";s:42:"مطلات ومنتزهات الطويلة";s:7:"name_en";s:31:"Al-Tawilah Viewpoints and Parks";s:11:"description";s:341:"المنحدرات الجبلية المحيطة بمدينة الطويلة وحصنها التاريخي توفر إطلالات رائعة وتعتبر منتزهات طبيعية. يمكن للزوار الجلوس والاستمتاع بمشاهدة المدرجات الزراعية والقرى المتناثرة في الوديان.";s:14:"description_en";s:239:"The mountain slopes surrounding the city of Al-Tawilah and its historical fort offer wonderful views and are considered natural parks. Visitors can sit and enjoy watching the agricultural terraces and villages scattered across the valleys.";s:10:"categories";a:4:{i:0;s:9:"viewpoint";i:1;s:4:"park";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:6:"مطل";i:1;s:10:"منتزه";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.39;s:9:"longitude";d:43.76;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:17;a:17:{s:2:"id";i:416;s:7:"city_id";i:16;s:11:"external_id";s:21:"wadi-al-khams-mahweet";s:4:"name";s:36:"وادي الخمس (المحويت)";s:7:"name_en";s:25:"Wadi Al-Khams (Al Mahwit)";s:11:"description";s:314:"يقع في مديرية ملحان، وهو وادٍ جبلي يتميز بانحداره الشديد وطبيعته البكر. تتشكل فيه شلالات موسمية رائعة أثناء وبعد هطول الأمطار، ويعتبر وجهة لمحبي المغامرات والطبيعة الصعبة.";s:14:"description_en";s:241:"Located in the Milhan district, it is a mountain valley characterized by its steep slopes and pristine nature. Magnificent seasonal waterfalls form during and after rainfall, making it a destination for lovers of adventure and rugged nature.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:9:"waterfall";i:2;s:8:"seasonal";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"شلال";i:2;s:10:"موسمي";i:3;s:12:"مغامرة";}s:8:"latitude";d:15.3;s:9:"longitude";d:43.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:18;a:17:{s:2:"id";i:417;s:7:"city_id";i:16;s:11:"external_id";s:20:"jabal-malhan-reserve";s:4:"name";s:39:"منتزه محمية جبل ملحان";s:7:"name_en";s:25:"Mount Milhan Reserve Park";s:11:"description";s:340:"جبل ملحان هو محمية طبيعية تتميز بتنوعها البيولوجي الفريد ونباتاتها النادرة. تعتبر المنطقة بأكملها منتزهاً طبيعياً مثالياً للمشي لمسافات طويلة ومراقبة الطيور والاستمتاع بالطبيعة البكر.";s:14:"description_en";s:193:"Mount Milhan is a nature reserve characterized by its unique biodiversity and rare plants. The entire area is an ideal natural park for hiking, bird watching, and enjoying the untouched nature.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:7:"reserve";i:2;s:4:"park";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"محمية";i:2;s:10:"منتزه";i:3;s:12:"هايكنج";}s:8:"latitude";d:15.35;s:9:"longitude";d:43.45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:19;a:17:{s:2:"id";i:418;s:7:"city_id";i:16;s:11:"external_id";s:18:"wadi-laaah-mahweet";s:4:"name";s:34:"وادي لاعة (المحويت)";s:7:"name_en";s:22:"Wadi La'ah (Al Mahwit)";s:11:"description";s:305:"يمر جزء من وادي لاعة الشهير في محافظة المحويت، وتحديداً في مديرية بني سعد. يتميز هذا الجزء بمناظره الجبلية الخلابة ومياهه الجارية التي تشكل بركاً صغيرة مناسبة للسباحة.";s:14:"description_en";s:236:"A part of the famous Wadi La'ah passes through Al Mahwit Governorate, specifically in the Bani Sa'd district. This section is distinguished by its stunning mountain scenery and running waters that form small pools suitable for swimming.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:7:"natural";i:2;s:4:"park";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"منتزه";i:3;s:8:"مائي";}s:8:"latitude";d:15.25;s:9:"longitude";d:43.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:20;a:17:{s:2:"id";i:419;s:7:"city_id";i:16;s:11:"external_id";s:21:"al-khabt-green-plains";s:4:"name";s:45:"منتزه سهول الخبت الخضراء";s:7:"name_en";s:26:"Al Khabt Green Plains Park";s:11:"description";s:328:"تتميز مديرية الخبت بوجود بعض السهول والهضاب المتموجة التي تتحول إلى بساط أخضر بعد مواسم الأمطار. تعتبر هذه السهول منتزهات طبيعية مفتوحة ومكاناً مثالياً للرحلات والنزهات العائلية.";s:14:"description_en";s:201:"The Al Khabt district features rolling plains and plateaus that turn into a green carpet after the rainy seasons. These plains act as open natural parks and an ideal place for family trips and picnics.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"park";i:2;s:6:"scenic";i:3;s:5:"plain";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"منتزه";i:2;s:21:"مناظر خلابة";i:3;s:6:"سهل";}s:8:"latitude";d:15.42;s:9:"longitude";d:43.45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:10;a:13:{s:2:"id";i:5;s:4:"slug";s:7:"mukalla";s:4:"name";s:12:"المكلا";s:7:"name_en";s:10:"Al Mukalla";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:19:"al_mukalla_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:22;s:9:"landmarks";a:22:{i:0;a:17:{s:2:"id";i:156;s:7:"city_id";i:5;s:11:"external_id";s:12:"mukalla-khor";s:4:"name";s:19:"خور المكلا";s:7:"name_en";s:15:"Khor Al Mukalla";s:11:"description";s:369:"لسان بحري طبيعي يتوغل في قلب مدينة المكلا، ويعتبر الواجهة البحرية الأجمل وروح المدينة. [1] تحيط به المباني القديمة والحديثة، وتصطف على جوانبه القوارب التقليدية، وهو مكان مثالي للتنزه والاستمتاع بالمنظر.";s:14:"description_en";s:289:"A natural marine inlet penetrating the heart of Al Mukalla city, considered the most beautiful waterfront and the soul of the city. [1] It is surrounded by both old and modern buildings, with traditional boats lining its sides, making it a perfect spot for strolling and enjoying the view.";s:10:"categories";a:4:{i:0;s:7:"coastal";i:1;s:12:"recreational";i:2;s:6:"scenic";i:3;s:8:"landmark";}s:14:"category_names";a:4:{i:0;s:10:"ساحلي";i:1;s:12:"ترفيهي";i:2;s:21:"مناظر خلابة";i:3;s:8:"معلم";}s:8:"latitude";d:14.535;s:9:"longitude";d:49.13;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/mukalla/mukalla_khor1.jpg";i:1;s:42:"images/landmarks/mukalla/mukalla_khor2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:1;a:17:{s:2:"id";i:157;s:7:"city_id";i:5;s:11:"external_id";s:20:"khor-al-mukalla-park";s:4:"name";s:30:"متنزه خور المكلا";s:7:"name_en";s:20:"Khor Al Mukalla Park";s:11:"description";s:359:"الواجهة البحرية والحدائق المحيطة بخور المكلا، والتي أصبحت مقصدًا رئيسيًا للعائلات. [20] يجمع المتنزه بين جمال المنظر البحري للخور والمساحات الخضراء وأماكن الترفيه، مما يجعله متنزهًا حضريًا فريدًا.";s:14:"description_en";s:247:"The waterfront and gardens surrounding Khor Al Mukalla, which have become a primary destination for families. [20] The park combines the beauty of the estuary's marine views with green spaces and entertainment areas, making it a unique urban park.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:10:"recreation";i:2;s:6:"family";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:10:"ساحلي";}s:8:"latitude";d:14.535;s:9:"longitude";d:49.13;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:35:"images/parks/mukalla/khor_park1.jpg";i:1;s:35:"images/parks/mukalla/khor_park2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:2;a:17:{s:2:"id";i:158;s:7:"city_id";i:5;s:11:"external_id";s:15:"al-ghwayzi-fort";s:4:"name";s:21:"حصن الغويزي";s:7:"name_en";s:16:"Al-Ghuwayzi Fort";s:11:"description";s:343:"حصن تاريخي شهير يقع على صخرة ضخمة عند المدخل الشمالي الشرقي لمدينة المكلا. [2] يعود تاريخه إلى القرن الثامن عشر، وكان يستخدم للحماية ومراقبة القادمين إلى المدينة، ويعتبر اليوم رمزاً للمكلا.";s:14:"description_en";s:243:"A famous historical fortress perched on a massive rock at the northeastern entrance of Al Mukalla. [2] Dating back to the 18th century, it was used for protection and monitoring arrivals to the city, and stands today as a symbol of Al Mukalla.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";i:3;s:8:"landmark";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:12:"معماري";i:3;s:8:"معلم";}s:8:"latitude";d:14.551;s:9:"longitude";d:49.145;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/mukalla/al_ghwayzi_fort1.jpg";i:1;s:45:"images/landmarks/mukalla/al_ghwayzi_fort2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:3;a:17:{s:2:"id";i:159;s:7:"city_id";i:5;s:11:"external_id";s:23:"al-quaiti-sultan-palace";s:4:"name";s:36:"قصر السلطان القعيطي";s:7:"name_en";s:24:"Al-Qu'aiti Sultan Palace";s:11:"description";s:315:"قصر تاريخي فخم يطل على خور المكلا، كان مقراً لسلاطين الدولة القعيطية. [3] يتميز بتصميمه المعماري الفريد الذي يدمج الطابع الهندي والأوروبي واليمني، ويضم حالياً المتحف الوطني.";s:14:"description_en";s:227:"A luxurious historical palace overlooking Khor Al Mukalla, once the seat of the Qu'aiti sultans. [3] It boasts a unique architectural design merging Indian, European, and Yemeni styles, and currently houses the National Museum.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:6:"museum";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:8:"متحف";i:3;s:12:"معماري";}s:8:"latitude";d:14.534;s:9:"longitude";d:49.128;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/landmarks/mukalla/al_quaiti_palace1.jpg";i:1;s:46:"images/landmarks/mukalla/al_quaiti_palace2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:4;a:17:{s:2:"id";i:160;s:7:"city_id";i:5;s:11:"external_id";s:16:"mukalla-old-city";s:4:"name";s:27:"المكلا القديمة";s:7:"name_en";s:14:"Old Al Mukalla";s:11:"description";s:341:"القلب التاريخي للمدينة، تتميز بأزقتها الضيقة ومبانيها البيضاء ذات الطراز الحضرمي الفريد والنوافذ الخشبية المزخرفة (الروشان). [4] التجول فيها يعطي لمحة عن تاريخ المكلا العريق وحياة سكانها.";s:14:"description_en";s:265:"The historical heart of the city, characterized by narrow alleys and white buildings with unique Hadhrami architecture and ornate wooden windows (Rawshan). [4] Strolling through it offers a glimpse into Al Mukalla's ancient history and the lives of its inhabitants.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"cultural";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"ثقافي";i:2;s:12:"معماري";}s:8:"latitude";d:14.533;s:9:"longitude";d:49.125;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/landmarks/mukalla/mukalla_old_city1.jpg";i:1;s:46:"images/landmarks/mukalla/mukalla_old_city2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:5;a:17:{s:2:"id";i:161;s:7:"city_id";i:5;s:11:"external_id";s:19:"omar-mosque-mukalla";s:4:"name";s:39:"مسجد عمر (جامع المكلا)";s:7:"name_en";s:31:"Omar Mosque (Al Mukalla Mosque)";s:11:"description";s:290:"أحد أقدم وأكبر المساجد في المكلا، يقع في المدينة القديمة. [5] يتميز بمئذنته الشاهقة وتصميمه البسيط والأنيق، ويعتبر مركزاً دينياً واجتماعياً رئيسياً في المدينة.";s:14:"description_en";s:206:"One of the oldest and largest mosques in Al Mukalla, situated in the old city. [5] It features a towering minaret and a simple yet elegant design, serving as a major religious and social center in the city.";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:14.534;s:9:"longitude";d:49.126;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/mukalla/omar_mosque1.jpg";i:1;s:41:"images/landmarks/mukalla/omar_mosque2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:6;a:17:{s:2:"id";i:162;s:7:"city_id";i:5;s:11:"external_id";s:21:"burum-coastal-village";s:4:"name";s:17:"ساحل بروم";s:7:"name_en";s:11:"Borum Coast";s:11:"description";s:285:"منطقة ساحلية وقرية صيد تاريخية تقع غرب المكلا. [6] تشتهر بشواطئها الجميلة ومينائها الطبيعي الذي كان يستخدم في تجارة البخور قديماً، وتعتبر ميناء قنا التاريخي.";s:14:"description_en";s:215:"A coastal area and historic fishing village located west of Al Mukalla. [6] Famous for its beautiful beaches and natural harbor that was used in the ancient incense trade, and is linked to the historic port of Qana.";s:10:"categories";a:4:{i:0;s:7:"coastal";i:1;s:10:"historical";i:2;s:7:"village";i:3;s:5:"beach";}s:14:"category_names";a:4:{i:0;s:10:"ساحلي";i:1;s:12:"تاريخي";i:2;s:8:"قرية";i:3;s:8:"شاطئ";}s:8:"latitude";d:14.35;s:9:"longitude";d:48.98;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/mukalla/burum_coast1.jpg";i:1;s:41:"images/landmarks/mukalla/burum_coast2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:7;a:17:{s:2:"id";i:163;s:7:"city_id";i:5;s:11:"external_id";s:13:"jabal-al-qara";s:4:"name";s:19:"جبل القارة";s:7:"name_en";s:14:"Jabal Al-Qarah";s:11:"description";s:328:"سلسلة جبلية تشرف على مدينة المكلا من جهة الشمال، وتوفر إطلالات بانورامية مذهلة على المدينة والبحر. [7] يمكن الوصول إلى أجزاء منها بالسيارة، وهي وجهة مفضلة لمشاهدة المدينة من الأعلى.";s:14:"description_en";s:208:"A mountain range overlooking Al Mukalla from the north, offering stunning panoramic views of the city and the sea. [7] Parts of it are accessible by car, making it a favorite spot to view the city from above.";s:10:"categories";a:3:{i:0;s:6:"nature";i:1;s:9:"viewpoint";i:2;s:8:"mountain";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:12:"إطلالة";i:2;s:6:"جبل";}s:8:"latitude";d:14.56;s:9:"longitude";d:49.13;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/mukalla/jabal_al_qara1.jpg";i:1;s:43:"images/landmarks/mukalla/jabal_al_qara2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:8;a:17:{s:2:"id";i:164;s:7:"city_id";i:5;s:11:"external_id";s:15:"al-rayyan-beach";s:4:"name";s:21:"شاطئ الريان";s:7:"name_en";s:14:"Al-Riyan Beach";s:11:"description";s:294:"شاطئ واسع ونظيف يقع بالقرب من مطار الريان الدولي شرق المكلا. [8] يتميز برماله البيضاء ومياهه الصافية، ويعتبر مكاناً مثالياً للسباحة والاسترخاء والنزهات العائلية.";s:14:"description_en";s:194:"A wide, clean beach located near Al-Riyan International Airport, east of Al Mukalla. [8] With its white sands and clear waters, it is an ideal place for swimming, relaxation, and family outings.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:12:"recreational";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";i:3;s:10:"عائلي";}s:8:"latitude";d:14.65;s:9:"longitude";d:49.35;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/mukalla/al_rayyan_beach1.jpg";i:1;s:45:"images/landmarks/mukalla/al_rayyan_beach2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:9;a:17:{s:2:"id";i:165;s:7:"city_id";i:5;s:11:"external_id";s:20:"al-rayyan-beach-park";s:4:"name";s:32:"متنزه شاطئ الريان";s:7:"name_en";s:19:"Al-Riyan Beach Park";s:11:"description";s:267:"شاطئ رملي أبيض واسع ومفتوح يقع شرق المكلا. [8] يعد متنزهًا طبيعيًا مثاليًا للسباحة والرياضات الشاطئية والتخييم، ويتميز بهدوئه وبعده عن صخب المدينة.";s:14:"description_en";s:212:"A wide and open white sandy beach located east of Al Mukalla. [8] It serves as a perfect natural park for swimming, beach sports, and camping, characterized by its tranquility and distance from the city's hustle.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:10:"recreation";i:3;s:7:"camping";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";i:3;s:10:"تخييم";}s:8:"latitude";d:14.65;s:9:"longitude";d:49.35;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/parks/mukalla/al_rayyan_park1.jpg";i:1;s:40:"images/parks/mukalla/al_rayyan_park2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:10;a:17:{s:2:"id";i:166;s:7:"city_id";i:5;s:11:"external_id";s:21:"al-salam-park-mukalla";s:4:"name";s:23:"منتزه السلام";s:7:"name_en";s:13:"Al-Salam Park";s:11:"description";s:272:"حديقة عامة ومنتزه ترفيهي يقع في منطقة فوه غرب المكلا. [9] يضم مساحات خضراء وألعاب للأطفال ومرافق ترفيهية، ويعتبر متنفساً هاماً للعائلات وسكان المدينة.";s:14:"description_en";s:231:"A public garden and recreational park located in the Fuwah district, west of Al Mukalla. [9] It features green spaces, children's rides, and entertainment facilities, serving as an important retreat for families and city residents.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";i:3;s:13:"entertainment";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:10:"تسلية";}s:8:"latitude";d:14.55;s:9:"longitude";d:49.08;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/mukalla/al_salam_park1.jpg";i:1;s:43:"images/landmarks/mukalla/al_salam_park2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:11;a:17:{s:2:"id";i:167;s:7:"city_id";i:5;s:11:"external_id";s:14:"hisn-al-eiddah";s:4:"name";s:17:"حصن العدة";s:7:"name_en";s:13:"Al-Iddah Fort";s:11:"description";s:323:"حصن تاريخي آخر يقع على تلة تشرف على المكلا القديمة من جهة الغرب. [10] إلى جانب حصن الغويزي، كان يشكل جزءاً من النظام الدفاعي للمدينة، ويوفر إطلالة رائعة على المدينة القديمة والخور.";s:14:"description_en";s:229:"Another historic fortress situated on a hill overlooking Old Al Mukalla from the west. [10] Along with Al-Ghuwayzi Fort, it formed part of the city's defensive system and offers a magnificent view of the old city and the estuary.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:9:"viewpoint";i:3;s:5:"ruins";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:12:"إطلالة";i:3;s:10:"أطلال";}s:8:"latitude";d:14.538;s:9:"longitude";d:49.122;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/mukalla/hisn_al_eiddah1.jpg";i:1;s:44:"images/landmarks/mukalla/hisn_al_eiddah2.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:12;a:17:{s:2:"id";i:168;s:7:"city_id";i:5;s:11:"external_id";s:10:"wadi-dawan";s:4:"name";s:17:"وادي دوعن";s:7:"name_en";s:10:"Wadi Dawan";s:11:"description";s:377:"أحد أشهر وأجمل الأودية في حضرموت، يتفرع إلى واديين أيمن وأيسر. [5, 6] يشتهر بقرى الطين المعلقة على سفوح الجبال، ومناحل العسل الدوعني الشهير، وبساتين النخيل الكثيفة، مما يجعله متحفاً طبيعياً وتاريخياً مفتوحاً.";s:14:"description_en";s:273:"One of the most famous and beautiful valleys in Hadhramaut, branching into a right and a left wadi. [5, 6] It is famous for its mud villages hanging on mountain slopes, renowned Dawan honey apiaries, and dense palm orchards, making it an open natural and historical museum.";s:10:"categories";a:5:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:10:"historical";i:3;s:6:"scenic";i:4;s:7:"village";}s:14:"category_names";a:5:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:12:"تاريخي";i:3;s:21:"مناظر خلابة";i:4;s:8:"قرية";}s:8:"latitude";d:15.03;s:9:"longitude";d:48.38;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/parks/mukalla/wadi_dawan1.jpg";i:1;s:36:"images/parks/mukalla/wadi_dawan2.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:13;a:17:{s:2:"id";i:169;s:7:"city_id";i:5;s:11:"external_id";s:21:"sharmah-beach-reserve";s:4:"name";s:28:"محمية شاطئ شرمة";s:7:"name_en";s:20:"Sharma Beach Reserve";s:11:"description";s:327:"تقع شرق المكلا، وهي محمية طبيعية ذات أهمية عالمية. [10] تعتبر من أهم مواقع تعشيش السلاحف البحرية الخضراء النادرة، وتتميز بشواطئها البكر ومياهها الصافية وتنوعها البيولوجي البحري. [17]";s:14:"description_en";s:245:"Located east of Al Mukalla, it is a globally significant nature reserve. [10] Considered one of the most important nesting sites for rare green sea turtles, it is distinguished by its pristine beaches, clear waters, and marine biodiversity. [17]";s:10:"categories";a:4:{i:0;s:14:"nature-reserve";i:1;s:5:"beach";i:2;s:8:"wildlife";i:3;s:7:"turtles";}s:14:"category_names";a:4:{i:0;s:23:"محمية طبيعية";i:1;s:8:"شاطئ";i:2;s:17:"حياة برية";i:3;s:10:"سلاحف";}s:8:"latitude";d:14.82;s:9:"longitude";d:49.95;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/parks/mukalla/sharmah_beach1.jpg";i:1;s:39:"images/parks/mukalla/sharmah_beach2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:14;a:17:{s:2:"id";i:170;s:7:"city_id";i:5;s:11:"external_id";s:16:"mukalla-corniche";s:4:"name";s:47:"كورنيش المحضار وشواطئ خلف";s:7:"name_en";s:38:"Al-Mihdhar Corniche and Khalaf Beaches";s:11:"description";s:321:"يمتد على طول منطقة خلف، ويعتبر المتنفس البحري الرئيسي الحديث في المكلا. [26] يرتاده السكان والزوار للنزهات المسائية والاستمتاع بنسيم البحر، وتنتشر على طوله المقاهي والاستراحات.";s:14:"description_en";s:213:"Stretching along the Khalaf area, it is considered the main modern marine promenade in Al Mukalla. [26] Frequented by locals and visitors for evening strolls and sea breezes, it is lined with cafes and rest stops.";s:10:"categories";a:4:{i:0;s:7:"coastal";i:1;s:10:"recreation";i:2;s:6:"family";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:10:"ساحلي";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:10:"متنزه";}s:8:"latitude";d:14.525;s:9:"longitude";d:49.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/parks/mukalla/mukalla_corniche1.jpg";i:1;s:42:"images/parks/mukalla/mukalla_corniche2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:15;a:17:{s:2:"id";i:171;s:7:"city_id";i:5;s:11:"external_id";s:11:"burum-coast";s:4:"name";s:28:"متنزه ساحل بروم";s:7:"name_en";s:16:"Borum Coast Park";s:11:"description";s:335:"منطقة ساحلية تاريخية غرب المكلا، تتميز بشواطئها الرملية الهادئة وأشجار النخيل. [6] تعتبر مكانًا مثاليًا للرحلات العائلية والسباحة والاسترخاء، مع الاستمتاع بمنظر قرية الصيد التقليدية.";s:14:"description_en";s:215:"A historic coastal area west of Al Mukalla, featuring quiet sandy beaches and palm trees. [6] It is an ideal spot for family trips, swimming, and relaxing while taking in the view of the traditional fishing village.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:10:"recreation";i:3;s:7:"village";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:12:"ترفيهي";i:3;s:8:"قرية";}s:8:"latitude";d:14.35;s:9:"longitude";d:48.98;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/parks/mukalla/burum_coast_park1.jpg";i:1;s:42:"images/parks/mukalla/burum_coast_park2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:16;a:17:{s:2:"id";i:172;s:7:"city_id";i:5;s:11:"external_id";s:23:"jabal-al-qara-viewpoint";s:4:"name";s:37:"متنزه مطل جبل القارة";s:7:"name_en";s:29:"Jabal Al-Qarah Viewpoint Park";s:11:"description";s:348:"يوفر جبل القارة المشرف على المكلا نقاط مشاهدة طبيعية تعتبر بمثابة متنزهات. [7] يقصدها الزوار للاستمتاع بالإطلالات البانورامية الساحرة للمدينة والخور والبحر العربي، خاصة عند شروق وغروب الشمس.";s:14:"description_en";s:231:"Jabal Al-Qarah, overlooking Al Mukalla, provides natural vantage points that serve as parks. [7] Visitors come to enjoy the enchanting panoramic views of the city, the estuary, and the Arabian Sea, especially at sunrise and sunset.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:9:"viewpoint";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:12:"إطلالة";i:2;s:6:"جبل";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.56;s:9:"longitude";d:49.13;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/parks/mukalla/jabal_al_qara_view1.jpg";i:1;s:44:"images/parks/mukalla/jabal_al_qara_view2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:17;a:17:{s:2:"id";i:173;s:7:"city_id";i:5;s:11:"external_id";s:21:"ghayl-bawazir-springs";s:4:"name";s:28:"عيون غيل باوزير";s:7:"name_en";s:21:"Ghayl Bawazir Springs";s:11:"description";s:353:"واحة خضراء تقع شمال شرق المكلا، تشتهر بينابيعها المائية العذبة وكثافة أشجار النخيل. [8] تعتبر متنزهًا ريفيًا طبيعيًا، حيث يقصدها الناس للاستحمام في مياه العيون الجارية والاستمتاع بالظل والهدوء.";s:14:"description_en";s:233:"A green oasis located northeast of Al Mukalla, renowned for its fresh water springs and dense palm trees. [8] It acts as a natural rural park, where people go to bathe in the flowing spring waters and enjoy the shade and tranquility.";s:10:"categories";a:4:{i:0;s:5:"oasis";i:1;s:6:"nature";i:2;s:12:"water-spring";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:8:"واحة";i:1;s:10:"طبيعي";i:2;s:13:"عين ماء";i:3;s:12:"ترفيهي";}s:8:"latitude";d:14.77;s:9:"longitude";d:49.38;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/parks/mukalla/ghayl_bawazir1.jpg";i:1;s:39:"images/parks/mukalla/ghayl_bawazir2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:18;a:17:{s:2:"id";i:174;s:7:"city_id";i:5;s:11:"external_id";s:11:"wadi-al-ain";s:4:"name";s:19:"وادي العين";s:7:"name_en";s:11:"Wadi Al-Ayn";s:11:"description";s:322:"أحد الأودية الخصبة والهامة في حضرموت، يشتهر بمزارعه الخضراء وقراه الطينية الجميلة. يعتبر متنزهًا طبيعيًا ريفيًا يعرض جمال الحياة الزراعية في حضرموت ومناظرها الطبيعية الهادئة.";s:14:"description_en";s:237:"One of the important and fertile valleys in Hadhramaut, famous for its green farms and beautiful mud villages. It is considered a rural nature park that showcases the beauty of agricultural life in Hadhramaut and its tranquil landscapes.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:7:"village";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:8:"قرية";}s:8:"latitude";d:15.25;s:9:"longitude";d:48.75;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/parks/mukalla/wadi_al_ain1.jpg";i:1;s:37:"images/parks/mukalla/wadi_al_ain2.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:19;a:17:{s:2:"id";i:175;s:7:"city_id";i:5;s:11:"external_id";s:11:"yalkh-beach";s:4:"name";s:15:"شاطئ يلخ";s:7:"name_en";s:11:"Yalkh Beach";s:11:"description";s:327:"موقع بحري هادئ وخلاب يقع في مديرية بروم ميفع. [13] يجذب الزوار بفضل جماله الطبيعي وشواطئه النظيفة وتكويناته الصخرية الفريدة، وهو مكان ممتاز للاسترخاء والابتعاد عن الأماكن المزدحمة.";s:14:"description_en";s:234:"A quiet and picturesque coastal site located in the Borum Mayfa'ah district. [13] It attracts visitors with its natural beauty, clean beaches, and unique rock formations, making it an excellent place to relax and escape crowded areas.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:8:"هادئ";}s:8:"latitude";d:14.4;s:9:"longitude";d:49.02;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/parks/mukalla/yalkh_beach1.jpg";i:1;s:37:"images/parks/mukalla/yalkh_beach2.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:20;a:17:{s:2:"id";i:176;s:7:"city_id";i:5;s:11:"external_id";s:16:"mukalla-fun-park";s:4:"name";s:54:"منتزه المكلا للالعاب (فن بارك)";s:7:"name_en";s:36:"Al Mukalla Amusement Park (Fun Park)";s:11:"description";s:282:"مدينة ملاهي تقع في منطقة خلف بالمكلا، وتعتبر وجهة ترفيهية رئيسية للأطفال والعائلات. [4, 5] تضم مجموعة متنوعة من الألعاب الكهربائية والإلكترونية الحديثة. [4, 5]";s:14:"description_en";s:210:"An amusement park located in the Khalaf area of Al Mukalla, considered a primary entertainment destination for children and families. [4, 5] It features a variety of modern electric and electronic rides. [4, 5]";s:10:"categories";a:3:{i:0;s:14:"amusement-park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"ملاهي";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:21;a:17:{s:2:"id";i:177;s:7:"city_id";i:5;s:11:"external_id";s:16:"khalf-beach-park";s:4:"name";s:26:"منتزه شاطئ خلف";s:7:"name_en";s:17:"Khalaf Beach Park";s:11:"description";s:339:"منتزه مفتوح يقع على امتداد شاطئ خلف، وهو أحد أجمل شواطئ المكلا. [6] يوفر مساحات للجلوس والاستمتاع بمنظر البحر، بالإضافة إلى وجود استراحات ومقاهٍ قريبة، ويعتبر مكانًا مثاليًا للاستجمام. [6]";s:14:"description_en";s:235:"An open park running along Khalaf Beach, which is one of the most beautiful beaches in Al Mukalla. [6] It provides seating areas to enjoy the sea view, alongside nearby rest stops and cafes, making it an ideal place for recreation. [6]";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:4:"park";i:2;s:10:"waterfront";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"منتزه";i:2;s:21:"واجهة بحرية";i:3;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:11;a:13:{s:2:"id";i:23;s:4:"slug";s:6:"mahrah";s:4:"name";s:12:"المهرة";s:7:"name_en";s:9:"Al Mahrah";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:18:"al_mahrah_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:31;s:9:"landmarks";a:31:{i:0;a:17:{s:2:"id";i:581;s:7:"city_id";i:23;s:11:"external_id";s:19:"hawf-forest-reserve";s:4:"name";s:34:"محمية حوف الطبيعية";s:7:"name_en";s:19:"Hawf Nature Reserve";s:11:"description";s:481:"أهم وأشهر معلم في المهرة، وهي أكبر غابة موسمية في شبه الجزيرة العربية. [1, 2] خلال موسم الخريف (من يونيو إلى سبتمبر)، تتحول جبالها إلى بساط أخضر كثيف يغطيه الضباب، وتتدفق فيها الشلالات، مما يخلق منظراً استوائياً فريداً. وهي مدرجة ضمن مواقع التراث العالمي لليونسكو. [1, 2]";s:14:"description_en";s:361:"The most important and famous landmark in Al Mahrah, being the largest seasonal forest in the Arabian Peninsula. [1, 2] During the Khareef (monsoon) season (from June to September), its mountains turn into a dense green carpet blanketed in fog, with cascading waterfalls, creating a unique tropical scene. It is inscribed as a UNESCO World Heritage site. [1, 2]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:7:"reserve";i:2;s:6:"forest";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"محمية";i:2;s:8:"غابة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:16.65;s:9:"longitude";d:53.05;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:1;a:17:{s:2:"id";i:582;s:7:"city_id";i:23;s:11:"external_id";s:19:"qishn-sultan-palace";s:4:"name";s:33:"قصر السلطان في قشن";s:7:"name_en";s:24:"Sultan's Palace in Qishn";s:11:"description";s:315:"كان المقر التاريخي لسلاطين المهرة وسقطرى. [3, 4] يقع في مدينة قشن التاريخية، ويعتبر شاهداً على التاريخ السياسي للمنطقة، ويتميز بطابعه المعماري الفريد الذي يعكس تاريخ السلطنة.";s:14:"description_en";s:257:"It was the historical residence of the Sultans of Al Mahrah and Socotra. [3, 4] Located in the historic city of Qishn, it serves as a witness to the political history of the area and features a unique architectural character reflecting the sultanate's past.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:10:"ثقافي";}s:8:"latitude";d:15.42;s:9:"longitude";d:51.68;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:2;a:17:{s:2:"id";i:583;s:7:"city_id";i:23;s:11:"external_id";s:12:"nishtun-port";s:4:"name";s:21:"ميناء نشطون";s:7:"name_en";s:12:"Nishtun Port";s:11:"description";s:335:"الميناء البحري الرئيسي لمحافظة المهرة وبوابتها التجارية على بحر العرب. [5] يتميز الميناء بموقعه الطبيعي المحمي، ويعتبر مركزاً حيوياً للاقتصاد المحلي ونشاط الصيد، وتحيط به شواطئ جميلة.";s:14:"description_en";s:266:"The primary seaport of Al Mahrah Governorate and its commercial gateway to the Arabian Sea. [5] The port is distinguished by its naturally sheltered location, acting as a vital hub for the local economy and fishing activities, and is surrounded by beautiful beaches.";s:10:"categories";a:4:{i:0;s:4:"port";i:1;s:8:"economic";i:2;s:7:"coastal";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"ميناء";i:1;s:14:"اقتصادي";i:2;s:10:"ساحلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:16.25;s:9:"longitude";d:52.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:3;a:17:{s:2:"id";i:584;s:7:"city_id";i:23;s:11:"external_id";s:15:"al-ghaydah-city";s:4:"name";s:23:"مدينة الغيضة";s:7:"name_en";s:15:"Al-Ghaydah City";s:11:"description";s:297:"عاصمة محافظة المهرة ومركزها الإداري والتجاري الحديث. [6] تتميز بسوقها المركزي الذي يعرض المنتجات المحلية، وتعتبر نقطة انطلاق لاستكشاف بقية معالم المحافظة الساحرة.";s:14:"description_en";s:249:"The capital of Al Mahrah Governorate and its modern administrative and commercial center. [6] It is noted for its central market that showcases local products, acting as a starting point to explore the rest of the governorate's enchanting landmarks.";s:10:"categories";a:4:{i:0;s:4:"city";i:1;s:7:"capital";i:2;s:6:"market";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:10:"مدينة";i:1;s:10:"عاصمة";i:2;s:6:"سوق";i:3;s:10:"ثقافي";}s:8:"latitude";d:16.208;s:9:"longitude";d:52.176;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:4;a:17:{s:2:"id";i:585;s:7:"city_id";i:23;s:11:"external_id";s:22:"al-ghaydah-public-park";s:4:"name";s:36:"حديقة الغيضة العامة";s:7:"name_en";s:22:"Al-Ghaydah Public Park";s:11:"description";s:308:"حديقة عامة تقع داخل مدينة الغيضة، وتوفر متنفسًا إضافيًا للعائلات. [9] تضم الحديقة بعض الألعاب للأطفال ومساحات للجلوس، وتساهم في توفير أماكن ترفيهية منظمة داخل العاصمة. [9]";s:14:"description_en";s:221:"A public park located within the city of Al-Ghaydah, providing an extra retreat for families. [9] The park includes children's rides and seating areas, contributing to organized recreational spaces within the capital. [9]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:5;a:17:{s:2:"id";i:586;s:7:"city_id";i:23;s:11:"external_id";s:10:"ras-fartak";s:4:"name";s:33:"رأس فرتك (حصن فرتك)";s:7:"name_en";s:24:"Ras Fartak (Fartak Fort)";s:11:"description";s:301:"رأس صخري شاهق يبرز في بحر العرب، ويعتبر من أهم المعالم الجغرافية على الساحل اليمني. [7] توجد على قمته بقايا حصن قديم، ويوفر إطلالات بانورامية مذهلة على الساحل والمحيط.";s:14:"description_en";s:248:"A towering rocky promontory jutting into the Arabian Sea, considered one of the most prominent geographical landmarks on the Yemeni coast. [7] The remains of an ancient fort sit atop it, offering stunning panoramic views of the coast and the ocean.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"viewpoint";i:2;s:10:"historical";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:6:"مطل";i:2;s:12:"تاريخي";i:3;s:10:"ساحلي";}s:8:"latitude";d:15.6;s:9:"longitude";d:52.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:6;a:17:{s:2:"id";i:587;s:7:"city_id";i:23;s:11:"external_id";s:15:"wadi-al-masilah";s:4:"name";s:23:"وادي المسيلة";s:7:"name_en";s:15:"Wadi Al-Masilah";s:11:"description";s:294:"أحد أطول الأودية في اليمن، ويمتد الجزء الشرقي منه في محافظة المهرة. [8] يتميز الوادي بواحات النخيل والقرى المتناثرة على ضفافه، ويعتبر شريان حياة للمناطق الداخلية.";s:14:"description_en";s:222:"One of the longest valleys in Yemen, with its eastern segment extending into Al Mahrah Governorate. [8] The valley features palm oases and scattered villages along its banks, serving as a lifeline for the interior regions.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:5:"oasis";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:8:"واحة";}s:8:"latitude";d:15.8;s:9:"longitude";d:51.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:7;a:17:{s:2:"id";i:588;s:7:"city_id";i:23;s:11:"external_id";s:14:"damqut-village";s:4:"name";s:19:"قرية دمقوت";s:7:"name_en";s:14:"Damqut Village";s:11:"description";s:301:"قرية ساحلية تقع على الحدود مع سلطنة عمان، وتعتبر آخر نقطة مأهولة في شرق اليمن. [9] تشتهر بشاطئها الجميل ومينائها الصغير، وتعتبر مثالاً للقرى المهرية الساحلية الهادئة.";s:14:"description_en";s:224:"A coastal village located on the border with the Sultanate of Oman, marking the last inhabited point in eastern Yemen. [9] Famous for its beautiful beach and small port, it is an archetype of tranquil coastal Mahri villages.";s:10:"categories";a:4:{i:0;s:7:"village";i:1;s:7:"coastal";i:2;s:6:"border";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"قرية";i:1;s:10:"ساحلي";i:2;s:10:"حدودي";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.58;s:9:"longitude";d:53.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:8;a:17:{s:2:"id";i:589;s:7:"city_id";i:23;s:11:"external_id";s:16:"huswain-fortress";s:4:"name";s:17:"حصن حصوين";s:7:"name_en";s:12:"Huswayn Fort";s:11:"description";s:282:"حصن تاريخي يقع في مديرية حصوين، مبني على تلة مرتفعة تطل على الساحل. [10] كان يستخدم للمراقبة والدفاع، ويعكس الأهمية الاستراتيجية للمنطقة الساحلية في المهرة.";s:14:"description_en";s:208:"A historical fort situated in the Huswayn district, built on an elevated hill overlooking the coast. [10] Used for surveillance and defense, it reflects the strategic importance of Al Mahrah's coastal region.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:10:"عسكري";i:3;s:6:"مطل";}s:8:"latitude";d:15.9;s:9:"longitude";d:52.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:9;a:17:{s:2:"id";i:590;s:7:"city_id";i:23;s:11:"external_id";s:18:"frankincense-trail";s:4:"name";s:32:"مواقع طريق اللبان";s:7:"name_en";s:24:"Frankincense Trail Sites";s:11:"description";s:351:"تنتشر في المهرة العديد من المواقع الأثرية والأشجار التي كانت جزءاً من طريق اللبان التاريخي. [11] تعتبر المحافظة الموطن الأصلي لأجود أنواع أشجار اللبان، وزيارة هذه المناطق هي رحلة في عبق التاريخ.";s:14:"description_en";s:272:"Numerous archaeological sites and trees that were part of the historic Frankincense Trail are scattered across Al Mahrah. [11] The governorate is the original homeland for the finest frankincense trees, making a visit to these areas a journey through the aroma of history.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:5:"trade";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:10:"تجارة";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.7;s:9:"longitude";d:52.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:10;a:17:{s:2:"id";i:591;s:7:"city_id";i:23;s:11:"external_id";s:25:"empty-quarter-edge-mahrah";s:4:"name";s:49:"أطراف الربع الخالي (المهرة)";s:7:"name_en";s:38:"Edges of the Empty Quarter (Al Mahrah)";s:11:"description";s:335:"تشكل صحراء الربع الخالي الجزء الشمالي الشاسع من المحافظة. [12] توفر هذه المنطقة مناظر طبيعية صحراوية بكر وكثباناً رملية هائلة، وهي وجهة مثالية لعشاق المغامرات الصحراوية والهدوء المطلق.";s:14:"description_en";s:255:"The Rub' al Khali (Empty Quarter) desert comprises the vast northern part of the governorate. [12] This area provides pristine desert landscapes and colossal sand dunes, making it a perfect destination for desert adventure lovers and absolute tranquility.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"desert";i:2;s:9:"adventure";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"صحراء";i:2;s:12:"مغامرة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:17.5;s:9:"longitude";d:51.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:11;a:17:{s:2:"id";i:592;s:7:"city_id";i:23;s:11:"external_id";s:20:"hawf-grand-waterfall";s:4:"name";s:28:"شلال حوف الكبير";s:7:"name_en";s:20:"Great Hawf Waterfall";s:11:"description";s:365:"أحد أكبر وأشهر الشلالات الموسمية في محمية حوف. [1] يتكون بعد هطول الأمطار الغزيرة في موسم الخريف، وينحدر من ارتفاع شاهق وسط الغابات الكثيفة، مما يخلق منظراً طبيعياً استوائياً يأسر الألباب ويجذب الزوار.";s:14:"description_en";s:255:"One of the largest and most renowned seasonal waterfalls in the Hawf Reserve. [1] Formed after heavy rains during the Khareef season, it plunges from a staggering height amid dense forests, creating a captivating tropical landscape that attracts visitors.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"scenic";i:3;s:6:"forest";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:21:"مناظر خلابة";i:3;s:8:"غابة";}s:8:"latitude";d:16.64;s:9:"longitude";d:53.05;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:12;a:17:{s:2:"id";i:593;s:7:"city_id";i:23;s:11:"external_id";s:18:"wadi-al-jiza-falls";s:4:"name";s:32:"شلالات وادي الجزع";s:7:"name_en";s:24:"Wadi Al-Jiza' Waterfalls";s:11:"description";s:392:"وادي الجزع هو أحد الأودية الرئيسية داخل محمية حوف. [2] خلال موسم الخريف، يمتلئ الوادي بالمياه وتتشكل على طول مجراه سلسلة من الشلالات الصغيرة والمتوسطة والبرك المائية، مما يجعله وجهة مثالية للمشي والاستمتاع بالطبيعة.";s:14:"description_en";s:260:"Wadi Al-Jiza' is a principal valley inside the Hawf Reserve. [2] During the Khareef season, the valley fills with water, and a series of small to medium waterfalls and pools form along its course, making it an ideal destination for walking and enjoying nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:12:"هايكنج";}s:8:"latitude";d:16.66;s:9:"longitude";d:53.03;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:13;a:17:{s:2:"id";i:594;s:7:"city_id";i:23;s:11:"external_id";s:18:"ayn-al-barak-falls";s:4:"name";s:32:"شلالات عين البراك";s:7:"name_en";s:24:"Ain Al-Barrak Waterfalls";s:11:"description";s:346:"منطقة في محمية حوف تشتهر بعيونها المائية التي يزداد تدفقها في موسم الخريف. [3] تتسبب غزارة المياه في تكوين شلالات جميلة تنحدر على الصخور المغطاة بالخضرة، وتعتبر من المناظر المميزة في المحمية.";s:14:"description_en";s:240:"An area in the Hawf Reserve famed for its water springs that experience increased flow during the Khareef season. [3] The abundance of water produces beautiful waterfalls sliding over greenery-covered rocks, a standout scene in the reserve.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"spring";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:10:"ينبوع";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.63;s:9:"longitude";d:53.06;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:14;a:17:{s:2:"id";i:595;s:7:"city_id";i:23;s:11:"external_id";s:13:"manarat-falls";s:4:"name";s:21:"شلالات منعر";s:7:"name_en";s:17:"Man'ar Waterfalls";s:11:"description";s:294:"تقع في منطقة منعر الجبلية داخل محمية حوف. [4] تتميز هذه الشلالات الموسمية بمرورها عبر تضاريس وعرة، مما يخلق تدفقات مائية قوية ومناظر طبيعية بكر تجذب محبي المغامرة.";s:14:"description_en";s:236:"Located in the mountainous Man'ar region within the Hawf Reserve. [4] These seasonal waterfalls are characterized by cutting through rugged terrain, generating powerful water flows and pristine natural scenes that lure adventure lovers.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:12:"مغامرة";}s:8:"latitude";d:16.67;s:9:"longitude";i:53;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:15;a:17:{s:2:"id";i:596;s:7:"city_id";i:23;s:11:"external_id";s:16:"al-ghaydah-beach";s:4:"name";s:21:"شاطئ الغيضة";s:7:"name_en";s:16:"Al-Ghaydah Beach";s:11:"description";s:381:"الشاطئ الممتد على طول الواجهة البحرية لمدينة الغيضة، عاصمة المحافظة. [5] يعتبر المتنفس الرئيسي لسكان المدينة، ويتميز برماله الناعمة وأمواجه الهادئة، وهو مكان مثالي للنزهات العائلية وممارسة الرياضات الشاطئية.";s:14:"description_en";s:245:"The beach stretching along the waterfront of Al-Ghaydah city, the provincial capital. [5] Acting as the main retreat for the city's inhabitants, it features soft sands and calm waves, making it an ideal place for family outings and beach sports.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:4:"city";i:2;s:10:"recreation";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"مدينة";i:2;s:14:"استجمام";i:3;s:10:"ساحلي";}s:8:"latitude";d:16.18;s:9:"longitude";d:52.18;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:16;a:17:{s:2:"id";i:597;s:7:"city_id";i:23;s:11:"external_id";s:11:"qishn-beach";s:4:"name";s:15:"شاطئ قشن";s:7:"name_en";s:11:"Qishn Beach";s:11:"description";s:296:"الشاطئ المحاذي لمدينة قشن التاريخية. [6] يجمع هذا الشاطئ بين جمال الطبيعة الساحلية وعبق التاريخ المتمثل في قصر السلطان القريب. يتميز بهدوئه ورماله الذهبية الممتدة.";s:14:"description_en";s:232:"The beach adjacent to the historic city of Qishn. [6] This beach merges the beauty of coastal nature with the aura of history embodied in the nearby Sultan's Palace. It is characterized by its tranquility and expansive golden sands.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:10:"historical";i:2;s:6:"scenic";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:12:"تاريخي";i:2;s:21:"مناظر خلابة";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.41;s:9:"longitude";d:51.68;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:17;a:17:{s:2:"id";i:598;s:7:"city_id";i:23;s:11:"external_id";s:13:"haswayn-beach";s:4:"name";s:19:"شاطئ حصوين";s:7:"name_en";s:13:"Huswayn Beach";s:11:"description";s:348:"شاطئ طويل وبكر يقع في مديرية حصوين. [7] يشتهر بنقائه الشديد وبعده عن التجمعات السكانية الكبيرة، مما يجعله وجهة مثالية للباحثين عن الهدوء والاسترخاء والاستمتاع بالطبيعة الساحلية في أنقى صورها.";s:14:"description_en";s:253:"A long, pristine beach located in the Huswayn district. [7] Well-known for its extreme purity and distance from large populated areas, it is the perfect destination for those seeking peace, relaxation, and experiencing coastal nature in its purest form.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:7:"natural";i:2;s:8:"pristine";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:6:"بكر";i:3;s:8:"هادئ";}s:8:"latitude";d:15.88;s:9:"longitude";d:52.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:18;a:17:{s:2:"id";i:599;s:7:"city_id";i:23;s:11:"external_id";s:19:"fartak-cape-beaches";s:4:"name";s:26:"شواطئ رأس فرتك";s:7:"name_en";s:18:"Ras Fartak Beaches";s:11:"description";s:290:"الخلجان والشواطئ الصغيرة المتناثرة حول قاعدة رأس فرتك الصخري. [8] توفر هذه الشواطئ المحمية أماكن رائعة للسباحة والغوص، مع منظر مهيب للرأس الشاهق الذي يطل عليها.";s:14:"description_en";s:232:"The coves and small beaches scattered around the base of the rocky Ras Fartak promontory. [8] These sheltered shores offer wonderful spots for swimming and diving, alongside a majestic view of the towering headland overlooking them.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"scenic";i:2;s:3:"bay";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:21:"مناظر خلابة";i:2;s:8:"خليج";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.6;s:9:"longitude";d:52.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:19;a:17:{s:2:"id";i:600;s:7:"city_id";i:23;s:11:"external_id";s:12:"damqut-beach";s:4:"name";s:19:"شاطئ دمقوت";s:7:"name_en";s:12:"Damqut Beach";s:11:"description";s:331:"يقع في أقصى شرق اليمن على الحدود مع عمان. [9] يتميز هذا الشاطئ بكونه نقطة التقاء الجبال بالبحر، ويوفر منظراً طبيعياً دراماتيكياً، ويعتبر وجهة للصيادين ومحبي الأماكن الحدودية الفريدة.";s:14:"description_en";s:241:"Located in the far east of Yemen on the border with Oman. [9] This beach is notable as a meeting point where mountains crash into the sea, providing a dramatic landscape. It is a destination for fishermen and fans of unique border locations.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"border";i:2;s:6:"scenic";i:3;s:7:"fishing";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"حدودي";i:2;s:21:"مناظر خلابة";i:3;s:6:"صيد";}s:8:"latitude";d:16.58;s:9:"longitude";d:53.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:20;a:17:{s:2:"id";i:601;s:7:"city_id";i:23;s:11:"external_id";s:13:"khalfut-beach";s:4:"name";s:19:"شاطئ خلفوت";s:7:"name_en";s:13:"Khalfut Beach";s:11:"description";s:313:"شاطئ جميل يقع بالقرب من منطقة نشطون. [10] يشتهر برماله البيضاء ومياهه الصافية، ويعتبر مكاناً مفضلاً لدى السكان المحليين للنزهات ورحلات الصيد والاستمتاع بجمال الساحل المهري.";s:14:"description_en";s:212:"A beautiful beach located near the Nishtun area. [10] Famous for its white sands and crystal-clear waters, it is a favored spot among locals for picnics, fishing trips, and enjoying the beauty of the Mahri coast.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:5:"local";i:2;s:7:"natural";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:8:"محلي";i:2;s:10:"طبيعي";i:3;s:14:"استجمام";}s:8:"latitude";d:16.3;s:9:"longitude";d:52.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:21;a:17:{s:2:"id";i:602;s:7:"city_id";i:23;s:11:"external_id";s:17:"wadi-shaghit-park";s:4:"name";s:28:"منتزه وادي شغيظ";s:7:"name_en";s:18:"Wadi Shaghidh Park";s:11:"description";s:397:"أحد الأودية القريبة من مدينة الغيضة، ويعتبر المتنفس البري الرئيسي لسكان العاصمة. [1] بعد هطول الأمطار، تجري فيه المياه وتخضر ضفافه، فيقصده الناس بكثرة للنزهات العائلية والرحلات الخلوية (الكشتات) والطبخ في الهواء الطلق.";s:14:"description_en";s:244:"One of the valleys near Al-Ghaydah city, acting as the main wilderness retreat for the capital's residents. [1] Following rains, its waters flow and its banks turn green, attracting large crowds for family outings, picnics, and outdoor cooking.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"valley";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:14:"استجمام";}s:8:"latitude";d:16.25;s:9:"longitude";d:52.15;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:22;a:17:{s:2:"id";i:603;s:7:"city_id";i:23;s:11:"external_id";s:19:"al-ghaydah-corniche";s:4:"name";s:25:"كورنيش الغيضة";s:7:"name_en";s:19:"Al-Ghaydah Corniche";s:11:"description";s:422:"الواجهة البحرية المجهزة على طول شاطئ الغيضة. [2] يعتبر هذا الكورنيش المنتزه الرسمي والأكثر شعبية داخل المدينة، حيث تتجمع العائلات والأصدقاء في المساء، وتوجد به أماكن للجلوس وأكشاك صغيرة، وهو مكان مثالي للمشي والاستمتاع بنسيم البحر.";s:14:"description_en";s:276:"The developed waterfront along Al-Ghaydah Beach. [2] This corniche is the official and most popular park within the city, where families and friends gather in the evening. It features seating areas and small kiosks, offering an ideal spot to stroll and take in the sea breeze.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"corniche";i:2;s:4:"city";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:12:"كورنيش";i:2;s:10:"مدينة";i:3;s:14:"استجمام";}s:8:"latitude";d:16.18;s:9:"longitude";d:52.18;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:23;a:17:{s:2:"id";i:604;s:7:"city_id";i:23;s:11:"external_id";s:19:"hawf-fog-viewpoints";s:4:"name";s:50:"منتزهات مطلات الضباب في حوف";s:7:"name_en";s:25:"Hawf Fog Viewpoints Parks";s:11:"description";s:371:"خلال موسم الخريف، تتحول الطرق الجبلية المتعرجة في محمية حوف إلى منتزهات بحد ذاتها. [3] يتوقف الناس بسياراتهم عند المطلات الرئيسية للاستمتاع بمنظر الضباب وهو يغطي كل شيء بالأسفل، في مشهد ساحر وفريد من نوعه.";s:14:"description_en";s:246:"During the Khareef season, the winding mountain roads in the Hawf Reserve turn into parks in their own right. [3] People park their cars at the main viewpoints to watch the fog blanketing everything below, creating a magical and unique spectacle.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"scenic";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:21:"مناظر خلابة";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.65;s:9:"longitude";i:53;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:24;a:17:{s:2:"id";i:605;s:7:"city_id";i:23;s:11:"external_id";s:21:"wadi-al-masilah-oases";s:4:"name";s:45:"منتزه واحات وادي المسيلة";s:7:"name_en";s:26:"Wadi Al-Masilah Oases Park";s:11:"description";s:355:"تعتبر واحات النخيل الكثيفة في وادي المسيلة منتزهات طبيعية شهيرة لسكان المناطق الداخلية. [4] توفر هذه الواحات الظل والبرودة والجمال، وتعتبر مكاناً مثالياً للراحة والاستجمام بعيداً عن حرارة الشمس.";s:14:"description_en";s:237:"The dense palm oases in Wadi Al-Masilah act as popular natural parks for residents of the interior regions. [4] These oases provide shade, coolness, and beauty, representing an ideal place to rest and relax away from the heat of the sun.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:5:"oasis";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"واحة";i:3;s:10:"زراعة";}s:8:"latitude";d:15.8;s:9:"longitude";d:51.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:25;a:17:{s:2:"id";i:606;s:7:"city_id";i:23;s:11:"external_id";s:22:"nishtun-port-viewpoint";s:4:"name";s:39:"منتزه مطل ميناء نشطون";s:7:"name_en";s:27:"Nishtun Port Viewpoint Park";s:11:"description";s:372:"التلال والمرتفعات المحيطة بميناء نشطون توفر إطلالة بانورامية رائعة على الميناء وحركة السفن والساحل الممتد. [5] يقصد الناس هذه المنطقة كمنتزه للاستمتاع بالمنظر الفريد الذي يجمع بين الطبيعة والنشاط البشري.";s:14:"description_en";s:245:"The hills and highlands surrounding Nishtun Port provide a wonderful panoramic view of the port, ship movements, and the sweeping coastline. [5] People visit this area as a park to marvel at the unique scene combining nature with human activity.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:4:"port";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:10:"ميناء";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:16.25;s:9:"longitude";d:52.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:26;a:17:{s:2:"id";i:607;s:7:"city_id";i:23;s:11:"external_id";s:27:"al-faydami-hot-springs-area";s:4:"name";s:58:"منتزه منطقة عيون الفيدمي الحارة";s:7:"name_en";s:27:"Al-Faydami Hot Springs Park";s:11:"description";s:341:"تقع في مديرية المسيلة، وهي منطقة تشتهر بوجود عيون مياه كبريتية حارة. [6] المنطقة المحيطة بالعيون تعتبر منتزهاً طبيعياً وعلاجياً، يقصده الناس للاستشفاء والاستمتاع بالطبيعة الفريدة للموقع.";s:14:"description_en";s:244:"Located in the Al-Masilah district, this area is known for its hot sulfurous water springs. [6] The surroundings of the springs are a natural and therapeutic park, visited by people seeking healing while taking in the site's distinctive nature.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:6:"health";i:2;s:6:"spring";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"صحي";i:2;s:10:"ينبوع";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.7;s:9:"longitude";d:51.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:27;a:17:{s:2:"id";i:608;s:7:"city_id";i:23;s:11:"external_id";s:22:"qishn-countryside-park";s:4:"name";s:28:"منتزه أرياف قشن";s:7:"name_en";s:22:"Qishn Countryside Park";s:11:"description";s:317:"المناطق الريفية والمزارع الصغيرة المحيطة بمدينة قشن التاريخية تعتبر منتزهات طبيعية للسكان. [7] توفر هذه الأرياف بيئة هادئة ومناظر جميلة تجمع بين أشجار النخيل والبحر في الأفق.";s:14:"description_en";s:235:"The rural areas and small farms surrounding the historic city of Qishn are considered natural parks for the locals. [7] This countryside provides a peaceful environment and pretty scenes blending palm trees with the sea on the horizon.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:11:"countryside";i:2;s:11:"agriculture";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"ريف";i:2;s:10:"زراعة";i:3;s:12:"تاريخي";}s:8:"latitude";d:15.45;s:9:"longitude";d:51.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:28;a:17:{s:2:"id";i:609;s:7:"city_id";i:23;s:11:"external_id";s:20:"sayhut-mangrove-area";s:4:"name";s:56:"منتزه منطقة أشجار القرم (سيحوت)";s:7:"name_en";s:28:"Mangrove Trees Park (Sayhut)";s:11:"description";s:352:"توجد بالقرب من مدينة سيحوت الساحلية مناطق تنمو فيها أشجار القرم (المانغروف). [8] تعتبر هذه النظم البيئية الفريدة منتزهات طبيعية هامة، وهي وجهة لمراقبة الطيور والتعرف على التنوع البيولوجي البحري.";s:14:"description_en";s:212:"Areas where mangrove trees grow are found near the coastal city of Sayhut. [8] These unique ecosystems serve as significant natural parks, and are destinations for bird watching and exploring marine biodiversity.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:9:"ecosystem";i:3;s:5:"birds";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:17:"نظام بيئي";i:3;s:8:"طيور";}s:8:"latitude";d:15.2;s:9:"longitude";d:51.25;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:29;a:17:{s:2:"id";i:610;s:7:"city_id";i:23;s:11:"external_id";s:25:"shihin-border-market-area";s:4:"name";s:50:"منتزه منطقة سوق شحن الحدودي";s:7:"name_en";s:25:"Shehun Border Market Park";s:11:"description";s:386:"منفذ شحن الحدودي مع سلطنة عمان ليس مجرد نقطة عبور، بل هو منطقة حيوية. [9] المنطقة المحيطة بالمنفذ والسوق الملحق به تعتبر منتزهاً اجتماعياً وتجارياً فريداً، حيث يختلط الناس من البلدين، مما يخلق جواً ثقافياً مميزاً.";s:14:"description_en";s:270:"The Shehun border crossing with Oman is not merely a transit point, but a bustling hub. [9] The area around the crossing and its attached market forms a unique social and commercial park where people from both countries mingle, generating a distinct cultural atmosphere.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:6:"market";i:2;s:6:"border";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"سوق";i:2;s:10:"حدودي";i:3;s:10:"ثقافي";}s:8:"latitude";d:17.17;s:9:"longitude";d:52.45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:30;a:17:{s:2:"id";i:611;s:7:"city_id";i:23;s:11:"external_id";s:15:"wadi-arakh-park";s:4:"name";s:26:"منتزه وادي أرخ";s:7:"name_en";s:14:"Wadi Arkh Park";s:11:"description";s:341:"أحد الأودية الصحراوية في شمال المهرة. بعد الأمطار النادرة، يتحول إلى منتزه طبيعي يقصده سكان البادية والمناطق المجاورة. [10] يتميز باتساعه وهدوئه الشديد، وهو مكان مثالي لتجربة جمال الصحراء.";s:14:"description_en";s:260:"One of the desert valleys in northern Al Mahrah. After the rare rains, it turns into a natural park visited by desert nomads and neighboring inhabitants. [10] Noted for its vastness and utter silence, it is an ideal spot to experience the beauty of the desert.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"desert";i:3;s:6:"valley";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:10:"صحراء";i:3;s:8:"وادي";}s:8:"latitude";d:16.8;s:9:"longitude";d:51.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:12;a:13:{s:2:"id";i:30;s:4:"slug";s:7:"baaadan";s:4:"name";s:12:"بعداان";s:7:"name_en";s:7:"baaadan";s:11:"description";s:128:"من اجمل مدن مدينة اب وهي مدين مغتربين امريكا وتتميز بانها خضراء كالجنة";s:14:"description_en";s:141:"One of the most beautiful cities in the city of Ab is the city of American expatriates, and it is distinguished by being green like paradise.";s:9:"image_url";s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRL6y35VmcqvhdHKeyjIZXx2ae4T2Uf-wjfBQ&s";s:6:"status";s:9:"published";s:8:"category";s:8:"mountain";s:15:"landmarks_count";i:0;s:9:"landmarks";a:0:{}s:10:"created_at";s:27:"2026-04-23T21:22:43.000000Z";s:10:"updated_at";s:27:"2026-04-23T21:51:42.000000Z";}i:13;a:13:{s:2:"id";i:3;s:4:"slug";s:4:"taiz";s:4:"name";s:6:"تعز";s:7:"name_en";s:4:"Taiz";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:13:"taiz_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:55;s:9:"landmarks";a:55:{i:0;a:17:{s:2:"id";i:64;s:7:"city_id";i:3;s:11:"external_id";s:17:"taiz-cairo-castle";s:4:"name";s:23:"قلعة القاهرة";s:7:"name_en";s:31:"Cairo Castle (Qal'at al-Qahira)";s:11:"description";s:352:"قلعة تاريخية تقع على قمة جبل صبر المطل على مدينة تعز. بنيت في العصر الأيوبي وتوسعت في العصر الرسولي. تتميز بموقعها الاستراتيجي الذي يوفر إطلالة بانورامية رائعة على المدينة والمناطق المحيطة بها.";s:14:"description_en";s:269:"A historic castle perched atop Mount Sabir overlooking the city of Taiz. It was built during the Ayyubid era and expanded during the Rasulid era. It is distinguished by its strategic location, offering a magnificent panoramic view of the city and its surrounding areas.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"عسكري";}s:8:"latitude";d:13.4760496;s:9:"longitude";d:44.1550492;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/hArKot7C9xKnJL8g8";s:6:"images";a:2:{i:0;s:44:"images/landmarks/taiz/taiz_cairo_castle1.jpg";i:1;s:44:"images/landmarks/taiz/taiz_cairo_castle2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:1;a:17:{s:2:"id";i:65;s:7:"city_id";i:3;s:11:"external_id";s:23:"taiz-muzaffariya-school";s:4:"name";s:31:"المدرسة المظفرية";s:7:"name_en";s:23:"Al-Mudhaffariya Madrasa";s:11:"description";s:541:"تعد من أقدم المدارس المعلقة في اليمن، أسسها السلطان المظفر يوسف بن عمر في العصر الرسولي. تتميز بقبابها البيضاء المتعددة وتصميمها المعماري الذي يجمع بين وظيفتي المسجد والمدرسة، وتعتبر نموذجاً للعمارة الرسولية. خضعت للعديد من الإضافات والترميمات عبر العصور، مما جعلها سجلاً حافلاً بالفن الإسلامي.";s:14:"description_en";s:405:"Considered one of the oldest hanging madrasas in Yemen, founded by Sultan Al-Mudhaffar Yusuf bin Umar during the Rasulid era. It features multiple white domes and an architectural design that combines the functions of a mosque and a school, serving as a prime example of Rasulid architecture. It has undergone numerous additions and restorations over the centuries, making it a rich record of Islamic art.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:9:"religious";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"ديني";i:2;s:12:"معماري";}s:8:"latitude";d:13.575971;s:9:"longitude";d:44.018442;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:85:"https://cdn.al-ain.com/images/2022/5/12/173-221838-mudhafari-school-yemen_700x400.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:2;a:17:{s:2:"id";i:66;s:7:"city_id";i:3;s:11:"external_id";s:21:"taiz-ashrafiya-school";s:4:"name";s:31:"المدرسة الأشرفية";s:7:"name_en";s:20:"Al-Ashrafiya Madrasa";s:11:"description";s:483:"تحفة معمارية من العصر الرسولي، أمر ببنائها السلطان الأشرف الثاني إسماعيل. تشتهر بجمال زخارفها ونقوشها الملونة التي تزين قبابها وجدرانها، وتضم مسجداً ومدرسة وقبوراً للسلطان وأبنائه. لها مئذنتان متطابقتان تضيفان إلى روعتها وتعتبر من أهم المعالم الإسلامية في اليمن.";s:14:"description_en";s:405:"An architectural masterpiece from the Rasulid era, commissioned by Sultan Al-Ashraf II Isma'il. It is renowned for the beauty of its colorful ornaments and inscriptions that adorn its domes and walls. It encompasses a mosque, a madrasa, and tombs for the Sultan and his sons. It boasts two identical minarets that add to its splendor and is considered one of the most important Islamic landmarks in Yemen.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:9:"religious";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"ديني";i:2;s:12:"معماري";}s:8:"latitude";d:13.575121;s:9:"longitude";d:44.019554;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:74:"https://www.al-bayan.com/polopoly_fs/1.3736783.1577543999!/image/image.jpg";i:1;s:52:"https://i.ytimg.com/vi/e9_L_v4Y-8o/maxresdefault.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:3;a:17:{s:2:"id";i:67;s:7:"city_id";i:3;s:11:"external_id";s:20:"taiz-national-museum";s:4:"name";s:25:"المتحف الوطني";s:7:"name_en";s:15:"National Museum";s:11:"description";s:519:"كان في الأصل قصراً للإمام أحمد حميد الدين، وقد تم بناؤه في العهد العثماني كمستشفى عسكري. بعد عام 1967، تم تحويله إلى متحف يعرض مقتنيات الإمام وأسرته، بالإضافة إلى قطع أثرية وأسلحة قديمة وصور توثق تاريخ اليمن في تلك الفترة. تعرض لأضرار كبيرة ولكنه لا يزال شاهداً على حقبة مهمة من تاريخ تعز.";s:14:"description_en";s:402:"Originally the palace of Imam Ahmad Hamid ed-Din, it was built during the Ottoman era as a military hospital. After 1967, it was converted into a museum displaying the belongings of the Imam and his family, along with ancient artifacts, weapons, and photographs documenting Yemen's history during that period. It sustained significant damage but remains a witness to an important era in Taiz's history.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:6:"museum";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"متحف";i:2;s:10:"ثقافي";}s:8:"latitude";d:13.579468;s:9:"longitude";d:44.018042;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"https://mapio.net/images-p/114357888.jpg";i:1;s:52:"https://i.ytimg.com/vi/95Ea-2a2gqA/maxresdefault.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:4;a:17:{s:2:"id";i:68;s:7:"city_id";i:3;s:11:"external_id";s:19:"taiz-saber-mountain";s:4:"name";s:13:"جبل صبر";s:7:"name_en";s:11:"Mount Sabir";s:11:"description";s:533:"أحد أعلى الجبال في اليمن والجزيرة العربية، يبلغ ارتفاعه حوالي 3070 متراً عن سطح البحر. يحتضن مدينة تعز ويوفر إطلالات خلابة ومناظر طبيعية ساحرة، ويعتبر متنفساً طبيعياً رئيسياً لسكان المدينة وزوارها. يشتهر بمدرجاته الزراعية الخضراء وقراه المعلقة التي تعكس قدرة الإنسان اليمني على تطويع الطبيعة.";s:14:"description_en";s:406:"One of the highest mountains in Yemen and the Arabian Peninsula, reaching an altitude of about 3,070 meters above sea level. It embraces the city of Taiz, offering breathtaking views and enchanting natural scenery, and acts as a major natural retreat for residents and visitors. It is famous for its green agricultural terraces and hanging villages that reflect the Yemeni people's ability to adapt nature.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:7:"tourism";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"سياحي";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.528258;s:9:"longitude";d:44.020126;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/iLBBGAJJ9Yv9rYPV9";s:6:"images";a:2:{i:0;s:119:"https://www.aa.com.tr/uploads/userfiles/a9298453-9574-43cb-84ef-518f48348a2f/2021/1506/20210615_2_48689591_65538576.jpg";i:1;s:66:"https://yemen-monitor.com/user_images/news/14-04-2024-90531675.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:5;a:17:{s:2:"id";i:69;s:7:"city_id";i:3;s:11:"external_id";s:13:"taiz-bab-musa";s:4:"name";s:15:"باب موسى";s:7:"name_en";s:20:"Bab Musa (Musa Gate)";s:11:"description";s:435:"أحد الأبواب التاريخية المتبقية لسور مدينة تعز القديمة. سُمي نسبة إلى الشيخ موسى بن أحمد، وكان في الأصل باباً صغيراً قبل أن يوسعه الوالي العثماني محمود باشا. يعتبر مدخلاً رئيسياً للمدينة القديمة ويؤدي إلى أسواقها التاريخية مثل سوق الشنيني.";s:14:"description_en";s:293:"One of the remaining historical gates of the old city wall of Taiz. Named after Sheikh Musa bin Ahmad, it was originally a small door before being expanded by the Ottoman governor Mahmud Pasha. It serves as a main entrance to the old city, leading to its historic markets like Souq Al-Shanini.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:4:"gate";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"بوابة";}s:8:"latitude";d:13.575217;s:9:"longitude";d:44.015091;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:88:"https://www.al-shareroad.com/thumb/1200x675/uploads/images/2020/01/23/5e2970729402e.jpeg";i:1;s:46:"https://almahriah.net/media/img/1645362953.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:6;a:17:{s:2:"id";i:70;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-bab-al-kabeer";s:4:"name";s:23:"الباب الكبير";s:7:"name_en";s:33:"Al-Bab Al-Kabeer (The Great Gate)";s:11:"description";s:381:"هو المدخل الرئيسي والتجاري لمدينة تعز القديمة، ويُعرف أيضاً بـ "عمدة الأسواق". يعد مع باب موسى من أبرز الأبواب التي لا تزال قائمة من سور المدينة التاريخي. يؤدي إلى أسواق شعبية وتراثية حافظت على طابعها عبر الزمن.";s:14:"description_en";s:289:"It is the main and commercial entrance to the old city of Taiz, also known as the 'Mayor of Markets'. Along with Bab Musa, it is one of the most prominent surviving gates from the historical city wall. It leads to popular and heritage markets that have preserved their character over time.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:4:"gate";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"بوابة";}s:8:"latitude";d:13.576889;s:9:"longitude";d:44.017778;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:52:"https://i.ytimg.com/vi/4_a9l9Y-1_E/maxresdefault.jpg";i:1;s:52:"https://i.ytimg.com/vi/q_7z7o7z7_k/maxresdefault.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:7;a:17:{s:2:"id";i:71;s:7:"city_id";i:3;s:11:"external_id";s:19:"taiz-shanini-market";s:4:"name";s:21:"سوق الشنيني";s:7:"name_en";s:15:"Souq Al-Shanini";s:11:"description";s:498:"من أقدم وأهم الأسواق الشعبية في تعز، يقع بين باب موسى والباب الكبير. اشتهر تاريخياً بكونه مركزاً للمنتجات الشعبية والحرف اليدوية مثل البن والجبن البلدي والأواني الفخارية والأدوات الزراعية. يحتفظ السوق بطابعه التاريخي ويعتبر وجهة للمتسوقين والباحثين عن المنتجات التراثية.";s:14:"description_en";s:362:"One of the oldest and most important traditional markets in Taiz, located between Bab Musa and Al-Bab Al-Kabeer. It has historically been famous as a hub for popular goods and handicrafts such as coffee, local cheese, pottery, and agricultural tools. The market retains its historical character and is a destination for shoppers and seekers of heritage products.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:6:"market";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:6:"سوق";i:2;s:10:"ثقافي";}s:8:"latitude";d:13.576135;s:9:"longitude";d:44.016391;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:88:"https://www.alayyam.info/Upload/Photo/2019/5/7509c261-2358-4033-b108-1546738592-9999.jpg";i:1;s:74:"https://www.al-bayan.com/polopoly_fs/1.3567084.1558371363!/image/image.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:8;a:17:{s:2:"id";i:72;s:7:"city_id";i:3;s:11:"external_id";s:15:"dream-land-park";s:4:"name";s:28:"حديقة دريم لاند";s:7:"name_en";s:14:"Dreamland Park";s:11:"description";s:294:"يقع في منطقة الحوبان ويعتبر من الوجهات الترفيهية الهامة في تعز. [3] يضم المنتزه مسابح وألعابًا متنوعة ويستقطب عددًا كبيرًا من الزوار، خاصة فئة الشباب والعائلات. [3]";s:14:"description_en";s:233:"Located in the Al-Hawban area, it is considered one of the important recreational destinations in Taiz. [3] The park features swimming pools and various rides, attracting a large number of visitors, especially youth and families. [3]";s:10:"categories";a:4:{i:0;s:14:"amusement-park";i:1;s:12:"recreational";i:2;s:6:"family";i:3;s:8:"swimming";}s:14:"category_names";a:4:{i:0;s:10:"ملاهي";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:10:"سباحة";}s:8:"latitude";d:13.585721;s:9:"longitude";d:44.032243;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:9;a:17:{s:2:"id";i:73;s:7:"city_id";i:3;s:11:"external_id";s:14:"al-taawon-park";s:4:"name";s:58:" (21 سبتمبر)حديقة التعاون السياحي";s:7:"name_en";s:38:"Al-Ta'awun Tourist Park (September 21)";s:11:"description";s:288:"يقع في مفرق ماوية بالحوبان، وهو أحد المشاريع السياحية التي توفر متنفسًا للسكان. [4] يضم مساحات خضراء ومرافق ترفيهية متنوعة ويعتبر وجهة للعائلات في المنطقة. [4, 5]";s:14:"description_en";s:253:"Located at the Mawiayh junction in Al-Hawban, it is one of the tourism projects that provides a recreational space for residents. [4] It includes green areas and various entertainment facilities, serving as a destination for families in the area. [4, 5]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"منتزه";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";d:13.576088;s:9:"longitude";d:44.004122;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:10;a:17:{s:2:"id";i:74;s:7:"city_id";i:3;s:11:"external_id";s:16:"jabal-saber-park";s:4:"name";s:24:"منتزه جبل صبر";s:7:"name_en";s:16:"Mount Sabir Park";s:11:"description";s:326:"منتزه طبيعي يقع على جبل صبر المطل على مدينة تعز. [6] يشتهر بمدرجاته الزراعية الخضراء وأجوائه المعتدلة ومناظره الطبيعية الخلابة، مما يجعله وجهة مفضلة للرحلات والنزهات الطبيعية. [6, 7]";s:14:"description_en";s:247:"A natural park located on Mount Sabir, overlooking the city of Taiz. [6] It is famous for its green agricultural terraces, moderate atmosphere, and breathtaking natural scenery, making it a favorite destination for trips and nature picnics. [6, 7]";s:10:"categories";a:3:{i:0;s:12:"natural-park";i:1;s:8:"mountain";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:21:"منتزه طبيعي";i:1;s:8:"جبلي";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.538555;s:9:"longitude";d:44.025424;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:11;a:17:{s:2:"id";i:75;s:7:"city_id";i:3;s:11:"external_id";s:13:"al-janad-park";s:4:"name";s:21:"حديقة الجند";s:7:"name_en";s:13:"Al-Janad Park";s:11:"description";s:217:"تقع بالقرب من جامع الجند التاريخي، وتعتبر متنفسًا لسكان المنطقة، على الرغم من أنها قد عانت من الإهمال في فترات معينة. [8]";s:14:"description_en";s:162:"Located near the historic Al-Janad Mosque, it serves as a recreational area for local residents, although it has suffered from neglect during certain periods. [8]";s:10:"categories";a:2:{i:0;s:4:"park";i:1;s:19:"historical-vicinity";}s:14:"category_names";a:2:{i:0;s:10:"حديقة";i:1;s:21:"جوار تاريخي";}s:8:"latitude";d:13.682352;s:9:"longitude";d:44.175116;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:12;a:17:{s:2:"id";i:76;s:7:"city_id";i:3;s:11:"external_id";s:13:"fun-city-taiz";s:4:"name";s:20:"فن سيتي تعز";s:7:"name_en";s:13:"Fun City Taiz";s:11:"description";s:199:"مدينة ملاهي تقع في منطقة الحوبان، وتوفر مجموعة من الألعاب الترفيهية التي تجذب الأطفال والعائلات بشكل كبير. [9]";s:14:"description_en";s:135:"An amusement park located in the Al-Hawban area, offering a range of entertaining rides that heavily attract children and families. [9]";s:10:"categories";a:3:{i:0;s:14:"amusement-park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"ملاهي";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.593254;s:9:"longitude";d:44.035443;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:13;a:17:{s:2:"id";i:77;s:7:"city_id";i:3;s:11:"external_id";s:20:"taiz-husayniyah-dome";s:4:"name";s:23:"قبة الحسينية";s:7:"name_en";s:21:"Qubbat Al-Husseiniyah";s:11:"description";s:481:"قبة أثرية بنيت في العصر العثماني عام 1581م لتضم ضريح الوالي العثماني حسين بن حسن باشا. تتميز بنمطها المعماري الفريد الذي يجمع بين الفن اليمني والتركي. تقع بالقرب من باب موسى وتعتبر من المعالم العثمانية البارزة في المدينة، على الرغم من تعرضها للإهمال وحاجتها للترميم.";s:14:"description_en";s:346:"An archaeological dome built during the Ottoman era in 1581 AD to house the tomb of the Ottoman governor Hussein bin Hassan Pasha. It features a unique architectural style that blends Yemeni and Turkish art. Situated near Bab Musa, it is considered a prominent Ottoman landmark in the city, despite suffering from neglect and needing restoration.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:9:"religious";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"ديني";i:2;s:12:"معماري";}s:8:"latitude";d:13.576911;s:9:"longitude";d:44.018212;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:70:"https://www.hespress.com/wp-content/uploads/2014/03/Taiz_650231487.jpg";i:1;s:52:"https://i.ytimg.com/vi/j5f5j5f5j5s/maxresdefault.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:14;a:17:{s:2:"id";i:78;s:7:"city_id";i:3;s:11:"external_id";s:22:"taiz-sheikh-zayed-park";s:4:"name";s:30:"منتزه الشيخ زايد";s:7:"name_en";s:17:"Sheikh Zayed Park";s:11:"description";s:467:"يقع في أعلى قمة جبل صبر، ويعد من أهم المعالم السياحية والجمالية في تعز. تم بناؤه بتمويل من الشيخ زايد بن سلطان آل نهيان، رحمه الله، ويوفر إطلالة رائعة على المدينة. يعتبر مقصداً رئيسياً للأسر والعائلات للتنزه والاستمتاع بالطبيعة، رغم تأثره بالأحداث الأخيرة.";s:14:"description_en";s:367:"Located at the highest peak of Mount Sabir, it is one of the most important tourist and aesthetic landmarks in Taiz. Built with funding from Sheikh Zayed bin Sultan Al Nahyan, may he rest in peace, it offers a magnificent view of the city. It remains a major destination for families and households to stroll and enjoy nature, despite being affected by recent events.";s:10:"categories";a:3:{i:0;s:12:"recreational";i:1;s:7:"tourism";i:2;s:4:"park";}s:14:"category_names";a:3:{i:0;s:12:"ترفيهي";i:1;s:10:"سياحي";i:2;s:10:"منتزه";}s:8:"latitude";d:13.558296;s:9:"longitude";d:44.017367;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:84:"https://al-ain.com/images/2018/7/16/123-144200-zayed-park-recreation-taiz-houth.jpeg";i:1;s:72:"https://www.albayan.ae/polopoly_fs/1.3270035.1527014269!/image/image.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:15;a:17:{s:2:"id";i:79;s:7:"city_id";i:3;s:11:"external_id";s:19:"taiz-aljanad-mosque";s:4:"name";s:32:"جامع ومدرسة الجند";s:7:"name_en";s:27:"Al-Janad Mosque and Madrasa";s:11:"description";s:521:"يعتبر من أقدم المساجد في الإسلام، حيث بناه الصحابي معاذ بن جبل في السنة السادسة للهجرة بأمر من النبي محمد (ص). يقع في منطقة الجند شمال شرق تعز، وسمي نسبة إلى "سوق الجند" الذي كان من أسواق العرب الشهيرة قبل الإسلام. يمثل قيمة تاريخية ودينية عظيمة، ويعد مركزاً للعلم والعبادة منذ فجر الإسلام.";s:14:"description_en";s:405:"Considered one of the oldest mosques in Islam, built by the companion Muadh bin Jabal in the sixth year of the Hijra by the order of Prophet Muhammad (PBUH). Located in the Al-Janad area northeast of Taiz, it was named after 'Souq Al-Janad', which was a famous Arab market before Islam. It holds immense historical and religious value, serving as a center for learning and worship since the dawn of Islam.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:9:"religious";i:2;s:7:"islamic";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"ديني";i:2;s:12:"إسلامي";}s:8:"latitude";d:13.682685;s:9:"longitude";d:44.174351;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:104:"https://upload.wikimedia.org/wikipedia/commons/thumb/1/18/Al-Janad_Mosque.jpg/1200px-Al-Janad_Mosque.jpg";i:1;s:50:"https://yemen-nic.info/contents/gallery/Taiz/2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:16;a:17:{s:2:"id";i:80;s:7:"city_id";i:3;s:11:"external_id";s:25:"taiz-bani-omar-waterfalls";s:4:"name";s:50:"شلالات بني عمر (وادي الضباب)";s:7:"name_en";s:34:"Bani Umar Waterfalls (Wadi Dhabab)";s:11:"description";s:449:"تعتبر من أشهر الشلالات في اليمن، تقع في وادي الضباب غرب مدينة تعز. تتدفق المياه من أعالي الجبال مكونة منظراً طبيعياً ساحراً، خاصة خلال موسم الأمطار. المنطقة المحيطة بالشلالات خضراء وتجذب الزوار للاستمتاع بجمال الطبيعة والسباحة في البرك المتكونة.";s:14:"description_en";s:341:"Considered among the most famous waterfalls in Yemen, located in Wadi Dhabab west of Taiz city. Water flows from the high mountains creating a magical natural landscape, especially during the rainy season. The area surrounding the waterfalls is lush green, attracting visitors to enjoy nature's beauty and swim in the naturally formed pools.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:7:"tourism";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:10:"سياحي";}s:8:"latitude";d:13.521255;s:9:"longitude";d:43.961445;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:72:"https://www.alyemenialyoum.com/user_images/news/03-08-2020-562177570.jpg";i:1;s:46:"https://yemen-press.net/photos/1659280302.jpeg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:17;a:17:{s:2:"id";i:81;s:7:"city_id";i:3;s:11:"external_id";s:16:"taiz-aden-valley";s:4:"name";s:15:"وادي عدن";s:7:"name_en";s:9:"Wadi Aden";s:11:"description";s:460:"وادٍ زراعي خصب يقع في مديرية شرعب السلام، يشتهر بجماله الطبيعي ومياهه الجارية على مدار العام. يعد الوادي مصدراً رئيسياً للمنتجات الزراعية المتنوعة مثل الموز والمانجو والبن. يتميز بمناظره الخلابة التي تجمع بين الجبال الشاهقة والمساحات الخضراء الواسعة.";s:14:"description_en";s:319:"A fertile agricultural valley located in the Shara'b As Salam district, famous for its natural beauty and running waters year-round. The valley is a major source of various agricultural products like bananas, mangoes, and coffee. It features breathtaking scenery that merges towering mountains with vast green expanses.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:12:"agricultural";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعي";}s:8:"latitude";d:13.581232;s:9:"longitude";d:44.053123;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/E9p6q-oXMAI5s_W.jpg";i:1;s:47:"https://pbs.twimg.com/media/D-2q2X_XoAA2h-M.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:18;a:17:{s:2:"id";i:82;s:7:"city_id";i:3;s:11:"external_id";s:25:"taiz-saber-mountain-baths";s:4:"name";s:43:"حمامات جبل صبر الطبيعية";s:7:"name_en";s:25:"Mount Sabir Natural Baths";s:11:"description";s:397:"مجموعة من الينابيع والبرك المائية الطبيعية المتناثرة في قرى جبل صبر. تتكون هذه الحمامات من تجمع مياه الأمطار والينابيع في تجاويف صخرية، وتوفر أماكن منعشة للسباحة والاستجمام للسكان المحليين والزوار، خاصة في فصل الصيف.";s:14:"description_en";s:294:"A collection of natural springs and water pools scattered throughout the villages of Mount Sabir. These baths are formed by the accumulation of rainwater and springs in rocky hollows, providing refreshing places for swimming and relaxation for locals and visitors, especially during the summer.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"spring";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"ينبوع";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.541255;s:9:"longitude";d:44.021556;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:67:"https://www.voice-yemen.com/user_images/news/28-04-20-992298587.jpg";i:1;s:47:"https://pbs.twimg.com/media/EaY-w2oWoAAG1gS.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:19;a:17:{s:2:"id";i:83;s:7:"city_id";i:3;s:11:"external_id";s:21:"taiz-alburkani-valley";s:4:"name";s:25:"وادي البركاني";s:7:"name_en";s:15:"Wadi Al-Burkani";s:11:"description";s:358:"يقع في مديرية المواسط، وهو وادٍ ساحر يتميز بتدفق المياه فيه معظم أيام السنة، مما يجعله وجهة مفضلة للرحلات والنزهات. تحيط بالوادي مدرجات زراعية خضراء وجبال شاهقة، مما يخلق لوحة فنية طبيعية متكاملة.";s:14:"description_en";s:301:"Located in the Al-Mawasit district, it is a charming valley characterized by water flowing through it most days of the year, making it a favorite destination for trips and picnics. The valley is surrounded by green agricultural terraces and towering mountains, creating a complete natural masterpiece.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:7:"tourism";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"سياحي";}s:8:"latitude";d:13.435556;s:9:"longitude";d:43.974444;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/E9qJ-XgX0AQs-4l.jpg";i:1;s:47:"https://pbs.twimg.com/media/D-2q2X-WwAA2h-M.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:20;a:17:{s:2:"id";i:84;s:7:"city_id";i:3;s:11:"external_id";s:8:"taiz-zoo";s:4:"name";s:38:"حديقة الحيوانات بتعز";s:7:"name_en";s:8:"Taiz Zoo";s:11:"description";s:476:"تعتبر من أقدم حدائق الحيوان في اليمن، وتقع عند سفح قلعة القاهرة. تضم مجموعة متنوعة من الحيوانات البرية والمفترسة، بما في ذلك الأسود والنمور العربية النادرة. على الرغم من التحديات التي واجهتها، لا تزال الحديقة معلماً ترفيهياً مهماً ومتنفساً للعائلات في المدينة.";s:14:"description_en";s:302:"Considered one of the oldest zoos in Yemen, located at the foot of Cairo Castle. It houses a variety of wild and predatory animals, including rare Arabian leopards and lions. Despite the challenges it has faced, the zoo remains an important recreational landmark and a retreat for families in the city.";s:10:"categories";a:3:{i:0;s:12:"recreational";i:1;s:4:"park";i:2;s:3:"zoo";}s:14:"category_names";a:3:{i:0;s:12:"ترفيهي";i:1;s:10:"حديقة";i:2;s:21:"حديقة حيوان";}s:8:"latitude";d:13.59954;s:9:"longitude";d:44.062832;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"https://www.dw.com/image/19043188_303.jpg";i:1;s:94:"https://www.aljazeera.net/wp-content/uploads/2016/02/a43a34f1-1576-496a-a28a-79878233e53c.jpeg";}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:21;a:17:{s:2:"id";i:85;s:7:"city_id";i:3;s:11:"external_id";s:21:"taiz-habashi-mountain";s:4:"name";s:15:"جبل حبشي";s:7:"name_en";s:13:"Jabal Habashi";s:11:"description";s:436:"سلسلة جبلية تقع غرب تعز، وتشتهر بجمالها الطبيعي الأخاذ ومدرجاتها الزراعية التي تزرع فيها أجود أنواع البن اليمني. تتميز المنطقة بأجوائها المعتدلة ومناظرها البانورامية، وتضم العديد من القرى المعلقة التي تحافظ على طابعها المعماري التقليدي.";s:14:"description_en";s:292:"A mountain range located west of Taiz, famous for its breathtaking natural beauty and agricultural terraces where the finest Yemeni coffee is grown. The region features a moderate climate, panoramic views, and numerous hanging villages that preserve their traditional architectural character.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:12:"agricultural";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:6:"جبل";i:2;s:10:"زراعي";}s:8:"latitude";d:13.533333;s:9:"longitude";d:43.916667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/FvT-T3_aYAAf-eW.jpg";i:1;s:47:"https://pbs.twimg.com/media/E9qJ-XgX0AQs-4l.jpg";}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:22;a:17:{s:2:"id";i:86;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-rasyan-valley";s:4:"name";s:19:"وادي رسيان";s:7:"name_en";s:11:"Wadi Rasyan";s:11:"description";s:427:"يقع في مديرية مقبنة، وهو من الأودية الجميلة التي تتميز بجريان المياه والغابات الكثيفة. يعد الوادي موطناً لتنوع بيولوجي غني، وتنتشر على ضفافه أشجار النخيل والعديد من النباتات البرية، مما يجعله مكاناً مثالياً لمحبي الطبيعة والمغامرات.";s:14:"description_en";s:279:"Located in the Maqbanah district, it is a beautiful valley distinguished by flowing water and dense forests. The valley is home to rich biodiversity, with palm trees and various wild plants spreading along its banks, making it a perfect spot for nature and adventure enthusiasts.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:6:"forest";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:8:"غابة";}s:8:"latitude";d:13.598212;s:9:"longitude";d:43.854322;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/E9p6q-oXMAI5s_W.jpg";i:1;s:47:"https://pbs.twimg.com/media/D-2q2X_XoAA2h-M.jpg";}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:23;a:17:{s:2:"id";i:87;s:7:"city_id";i:3;s:11:"external_id";s:19:"al-salam-park-turba";s:4:"name";s:23:"منتزه السلام";s:7:"name_en";s:13:"Al-Salam Park";s:11:"description";s:388:"أحد أبرز وأقدم المنتزهات في مدينة التربة، ويقع على قمة تل يوفر إطلالة بانورامية على المدينة والمناطق المحيطة بها. [1, 2] يضم المنتزه مساحات خضراء، ومطعمًا، وألعابًا للأطفال، ويعتبر وجهة رئيسية للعائلات والزوار. [1, 2]";s:14:"description_en";s:295:"One of the most prominent and oldest parks in the city of At Turbah, situated on a hilltop that offers a panoramic view of the city and its surroundings. [1, 2] The park includes green spaces, a restaurant, and children's games, serving as a primary destination for families and visitors. [1, 2]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"family";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:10:"عائلي";i:3;s:12:"ترفيهي";}s:8:"latitude";d:13.204556;s:9:"longitude";d:44.032222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/mukalla/al_salam_park1.jpg";i:1;s:43:"images/landmarks/mukalla/al_salam_park2.jpg";}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:24;a:17:{s:2:"id";i:88;s:7:"city_id";i:3;s:11:"external_id";s:20:"al-sokoon-park-turba";s:4:"name";s:23:"منتزه السكون";s:7:"name_en";s:13:"Al-Sukun Park";s:11:"description";s:415:"منتزه يقع في مدينة التربة ويتميز بأجوائه الهادئة وتصميمه الذي يوفر خصوصية للعائلات. [3, 4] يحتوي على شاليهات ومجلس للرجال وآخر للنساء، بالإضافة إلى مساحات خضراء وألعاب للأطفال، مما يجعله مناسبًا للمناسبات والتجمعات العائلية. [3, 4]";s:14:"description_en";s:297:"A park located in the city of At Turbah, distinguished by its peaceful atmosphere and a design that offers privacy for families. [3, 4] It contains chalets, separate lounges for men and women, along with green areas and children's games, making it suitable for events and family gatherings. [3, 4]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:7:"chalets";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"عائلي";i:2;s:14:"شاليهات";i:3;s:8:"هادئ";}s:8:"latitude";d:13.203112;s:9:"longitude";d:44.031556;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:25;a:17:{s:2:"id";i:89;s:7:"city_id";i:3;s:11:"external_id";s:19:"taiz-munif-fortress";s:4:"name";s:35:"حصن جبل منيف (الصلو)";s:7:"name_en";s:26:"Jabal Munif Fort (As Silw)";s:11:"description";s:441:"يقع على قمة جبل منيف في مديرية الصلو، وهو حصن تاريخي يمتزج بالطبيعة المحيطة به. يوفر الموقع إطلالات بانورامية مذهلة على الوديان والجبال المجاورة. المنطقة المحيطة بالحصن تتميز بجمالها الطبيعي وتعتبر وجهة للمشي لمسافات طويلة واستكشاف الطبيعة.";s:14:"description_en";s:317:"Perched atop Mount Munif in the As Silw district, it is a historic fortress that blends with the surrounding nature. The site offers stunning panoramic views of the neighboring valleys and mountains. The area around the fort is known for its natural beauty and serves as a destination for hiking and exploring nature.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:10:"historical";i:2;s:8:"mountain";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:12:"تاريخي";i:2;s:6:"جبل";}s:8:"latitude";d:13.385433;s:9:"longitude";d:44.116544;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/FvT-T3_aYAAf-eW.jpg";i:1;s:47:"https://pbs.twimg.com/media/E9qJ-XgX0AQs-4l.jpg";}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:26;a:17:{s:2:"id";i:90;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-aqroudh-ghayl";s:4:"name";s:38:"غيل الأقروض (المواسط)";s:7:"name_en";s:28:"Ghayl Al-Aqrudh (Al-Mawasit)";s:11:"description";s:394:"منطقة طبيعية ساحرة في مديرية المواسط، تشتهر بينابيعها المائية (الغيول) التي تتدفق بين الصخور وتصب في برك طبيعية. تعد المنطقة متنفساً طبيعياً يقصده الناس للسباحة والاستمتاع بجمال الطبيعة البكر، خاصة في مواسم الأمطار.";s:14:"description_en";s:287:"A charming natural area in the Al-Mawasit district, famous for its water springs (Ghayls) that flow between rocks and pour into natural pools. The area is a natural getaway frequented by people for swimming and enjoying the beauty of pristine nature, especially during the rainy seasons.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:6:"spring";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"ينبوع";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.411122;s:9:"longitude";d:44.045667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/EaY-w2oWoAAG1gS.jpg";i:1;s:67:"https://www.voice-yemen.com/user_images/news/28-04-20-992298587.jpg";}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:27;a:17:{s:2:"id";i:91;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-aroos-heights";s:4:"name";s:43:"مرتفعات العروس (جبل صبر)";s:7:"name_en";s:30:"Al-Aroos Heights (Mount Sabir)";s:11:"description";s:455:"أعلى قمة في جبل صبر، وتعرف بـ "جبل العروس". توفر هذه المرتفعات إطلالة لا مثيل لها على مدينة تعز والمناطق المحيطة بها، حيث يمكن رؤية السحب وهي تعانق قمم الجبال. تعتبر وجهة رئيسية للسياح ومتسلقي الجبال الباحثين عن المناظر الطبيعية الخلابة والهواء النقي.";s:14:"description_en";s:300:"The highest peak on Mount Sabir, known as 'Jabal Al-Aroos'. These heights offer an unparalleled view of Taiz city and the surrounding areas, where clouds can be seen hugging the mountain tops. It is a prime destination for tourists and mountain climbers seeking breathtaking landscapes and fresh air.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:9:"viewpoint";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:6:"جبل";i:2;s:6:"مطل";}s:8:"latitude";d:13.518333;s:9:"longitude";d:44.044167;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:72:"https://www.alyemenialyoum.com/user_images/news/03-08-2020-562177570.jpg";i:1;s:46:"https://yemen-press.net/photos/1659280302.jpeg";}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:28;a:17:{s:2:"id";i:92;s:7:"city_id";i:3;s:11:"external_id";s:32:"taiz-aljanad-archaeological-city";s:4:"name";s:36:"مدينة الجند الأثرية";s:7:"name_en";s:28:"Al-Janad Archaeological City";s:11:"description";s:548:"تعتبر من أهم المواقع الأثرية الإسلامية المبكرة. تأسست كمركز عسكري وإداري في عهد الخليفة عمر بن الخطاب. تضم الموقع بقايا جامع الجند التاريخي الذي بناه معاذ بن جبل، بالإضافة إلى بقايا أسوار ومبانٍ قديمة تعود إلى فترات مختلفة، مما يجعلها شاهداً على الأدوار المتعاقبة التي لعبتها المنطقة منذ فجر الإسلام.";s:14:"description_en";s:432:"Considered one of the most important early Islamic archaeological sites. It was established as a military and administrative center during the reign of Caliph Umar bin Al-Khattab. The site includes the ruins of the historic Al-Janad Mosque built by Muadh bin Jabal, along with remnants of walls and old buildings dating to different periods, making it a witness to the successive roles the region has played since the dawn of Islam.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:7:"islamic";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:12:"إسلامي";}s:8:"latitude";d:13.682894;s:9:"longitude";d:44.174111;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:60:"https://www.sabanew.net/upload/thumbs/162635483565554977.jpg";i:1;s:56:"https://www.almotamar.net/photo/10-07-2006-938194741.jpg";}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:29;a:17:{s:2:"id";i:93;s:7:"city_id";i:3;s:11:"external_id";s:31:"taiz-thabat-archaeological-city";s:4:"name";s:36:"مدينة ثعبات الأثرية";s:7:"name_en";s:27:"Thu'bat Archaeological City";s:11:"description";s:459:"مدينة أثرية تقع شرق تعز، كانت عاصمة للدولة الصليحية في فترة من الفترات. تشتهر بقصورها ومساجدها التي بنيت على قمم الجبال، ومن أبرز معالمها بقايا قصر "دار العز" ومسجد الملكة أروى. الموقع يكشف عن نظام هندسي ومعماري متقدم يعكس قوة الدولة الصليحية وازدهارها.";s:14:"description_en";s:389:"An archaeological city located east of Taiz, it was once the capital of the Sulayhid dynasty. It is renowned for its palaces and mosques built on mountain peaks. Among its most prominent landmarks are the ruins of 'Dar Al-Izz' palace and Queen Arwa's mosque. The site reveals an advanced architectural and engineering system that reflects the strength and prosperity of the Sulayhid state.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";}s:8:"latitude";d:13.565443;s:9:"longitude";d:44.032121;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:63:"https://al-mawqeapost.net/uploads/2021/08/16/611a5b8a5319a.jpeg";i:1;s:47:"https://pbs.twimg.com/media/E9p6q-oXMAI5s_W.jpg";}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:30;a:17:{s:2:"id";i:94;s:7:"city_id";i:3;s:11:"external_id";s:22:"taiz-damlouah-fortress";s:4:"name";s:21:"حصن الدملؤة";s:7:"name_en";s:16:"Al-Dumluwah Fort";s:11:"description";s:503:"حصن تاريخي منيع يقع في مديرية الصلو، ويعتبر من أقدم الحصون في اليمن. يعود تاريخه إلى فترات ما قبل الإسلام، وتعاقبت عليه العديد من الدول مثل الصليحيين والأيوبيين والرسوليين. اشتهر الحصن بأنه كان خزنة للدولة الصليحية، ويتميز بتصميمه المحكم فوق قمة جبل شاهق، مما جعله صعب المنال.";s:14:"description_en";s:416:"An impregnable historical fortress located in the As Silw district, considered one of the oldest forts in Yemen. Its history dates back to pre-Islamic periods, and several states successively controlled it, including the Sulayhids, Ayyubids, and Rasulids. The fort was famous as the treasury of the Sulayhid state and is distinguished by its tight design atop a towering mountain peak, making it highly inaccessible.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"عسكري";}s:8:"latitude";d:13.407555;s:9:"longitude";d:44.120222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:50:"https://yemen-nic.info/contents/gallery/Taiz/1.jpg";i:1;s:65:"https://www.bawabatii.net/user_images/news/28-06-20-675211536.jpg";}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:31;a:17:{s:2:"id";i:95;s:7:"city_id";i:3;s:11:"external_id";s:20:"wadi-al-qadhi-alsalu";s:4:"name";s:32:"وادي موقعة (الصلو)";s:7:"name_en";s:23:"Wadi Mawqa'ah (As Silw)";s:11:"description";s:410:"أحد أشهر الأودية في ريف تعز الجنوبي، ويمر عبر مديرية الصلو. [1, 2] يشتهر الوادي بجماله الطبيعي الخلاب، وينابيعه المائية العذبة، ومساحاته الخضراء، ويعتبر وجهة رئيسية للسياحة الداخلية والنزهات لسكان الصلو والمناطق المجاورة. [1, 2]";s:14:"description_en";s:334:"One of the most famous valleys in the southern countryside of Taiz, passing through the As Silw district. [1, 2] The valley is renowned for its stunning natural beauty, fresh water springs, and green expanses. It serves as a major destination for domestic tourism and picnics for the residents of As Silw and neighboring areas. [1, 2]";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:12:"natural-park";i:2;s:12:"recreational";i:3;s:7:"springs";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:21:"منتزه طبيعي";i:2;s:12:"ترفيهي";i:3;s:12:"ينابيع";}s:8:"latitude";d:13.411444;s:9:"longitude";d:44.112222;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:32;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:32;a:17:{s:2:"id";i:96;s:7:"city_id";i:3;s:11:"external_id";s:24:"taiz-dar-alhajar-alwasit";s:4:"name";s:34:"دار الحجر (المواسط)";s:7:"name_en";s:25:"Dar Al-Hajar (Al-Mawasit)";s:11:"description";s:413:"ليس دار الحجر الشهير في صنعاء، بل هو موقع أثري في مديرية المواسط بتعز. يعتقد أنه يعود إلى فترة ما قبل الإسلام، ويحتوي على نقوش صخرية وكتابات بخط المسند. الموقع بحاجة إلى المزيد من التنقيب والدراسة للكشف عن أسراره وتاريخه الكامل.";s:14:"description_en";s:340:"Not to be confused with the famous Dar Al-Hajar in Sana'a, this is an archaeological site in the Al-Mawasit district of Taiz. It is believed to date back to the pre-Islamic era and contains rock carvings and inscriptions in the Musnad script. The site requires further excavation and study to fully uncover its secrets and complete history.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"rock_art";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:13:"فن صخري";}s:8:"latitude";d:13.355212;s:9:"longitude";d:44.021334;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/FvT-T3_aYAAf-eW.jpg";i:1;s:47:"https://pbs.twimg.com/media/E9qJ-XgX0AQs-4l.jpg";}s:10:"sort_order";i:33;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:33;a:17:{s:2:"id";i:97;s:7:"city_id";i:3;s:11:"external_id";s:26:"taiz-jewish-cemetery-saber";s:4:"name";s:32:"مقبرة اليهود (صبر)";s:7:"name_en";s:23:"Jewish Cemetery (Sabir)";s:11:"description";s:449:"موقع أثري يقع في جبل صبر، وهو عبارة عن مقبرة قديمة للطائفة اليهودية التي كانت تعيش في المنطقة. تضم المقبرة شواهد قبور تحمل نقوشاً وكتابات باللغة العبرية، وتعتبر دليلاً على التاريخ الطويل للتعايش الديني في تعز، وشاهداً على الوجود اليهودي في اليمن.";s:14:"description_en";s:344:"An archaeological site located on Mount Sabir, representing an ancient cemetery for the Jewish community that once lived in the area. The cemetery includes tombstones bearing engravings and Hebrew inscriptions. It serves as evidence of the long history of religious coexistence in Taiz and stands as a testament to the Jewish presence in Yemen.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"cemetery";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"مقبرة";}s:8:"latitude";d:13.543211;s:9:"longitude";d:44.022132;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:88:"https://www.alayyam.info/Upload/Photo/2019/5/7509c261-2358-4033-b108-1546738592-9999.jpg";i:1;s:74:"https://www.al-bayan.com/polopoly_fs/1.3567084.1558371363!/image/image.jpg";}s:10:"sort_order";i:34;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:34;a:17:{s:2:"id";i:98;s:7:"city_id";i:3;s:11:"external_id";s:22:"taiz-ahl-alkahf-mosque";s:4:"name";s:26:"مسجد أهل الكهف";s:7:"name_en";s:32:"Mosque of the People of the Cave";s:11:"description";s:457:"يقع في قرية المعقاب بمديرية صبر الموادم، وهو موقع يعتقد السكان المحليون أنه مرتبط بقصة أهل الكهف. يضم الموقع مسجداً قديماً وكهفاً صغيراً. على الرغم من أن ارتباطه بالقصة القرآنية غير مثبت علمياً، إلا أنه يمثل معلماً أثرياً ودينياً ذا أهمية محلية كبيرة.";s:14:"description_en";s:370:"Located in the village of Al-Ma'qab in the Sabir Al-Mawadim district, it is a site that locals believe is connected to the story of the People of the Cave. The site encompasses an old mosque and a small cave. Although its association with the Quranic story is not scientifically proven, it represents an archaeological and religious landmark of great local significance.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:9:"religious";i:2;s:12:"mythological";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:8:"ديني";i:2;s:12:"أسطوري";}s:8:"latitude";d:13.581444;s:9:"longitude";d:44.014222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:52:"https://i.ytimg.com/vi/qY_U_b-i0qY/maxresdefault.jpg";i:1;s:74:"https://www.al-bayan.com/polopoly_fs/1.3745711.1578512398!/image/image.jpg";}s:10:"sort_order";i:35;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:35;a:17:{s:2:"id";i:99;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-old-city-wall";s:4:"name";s:26:"سور تعز القديم";s:7:"name_en";s:13:"Old Taiz Wall";s:11:"description";s:451:"سور تاريخي كان يحيط بمدينة تعز القديمة، بني في عهد الدولة الرسولية وتم توسيعه في العهد العثماني. كان للسور عدة أبواب لم يتبق منها سوى الباب الكبير وباب موسى. لا تزال أجزاء من السور قائمة حتى اليوم، شاهدة على تاريخ المدينة العريق ودورها كعاصمة محصنة.";s:14:"description_en";s:328:"A historic wall that used to surround the old city of Taiz, built during the Rasulid dynasty and expanded in the Ottoman era. The wall had several gates, of which only Al-Bab Al-Kabeer and Bab Musa remain. Sections of the wall still stand today, bearing witness to the city's ancient history and its role as a fortified capital.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:13.578111;s:9:"longitude";d:44.015222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:88:"https://www.al-shareroad.com/thumb/1200x675/uploads/images/2020/01/23/5e2970729402e.jpeg";i:1;s:46:"https://almahriah.net/media/img/1645362953.jpg";}s:10:"sort_order";i:36;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:36;a:17:{s:2:"id";i:100;s:7:"city_id";i:3;s:11:"external_id";s:21:"taiz-maqatirah-castle";s:4:"name";s:25:"قلعة المقاطرة";s:7:"name_en";s:19:"Al-Maqatirah Castle";s:11:"description";s:447:"حصن تاريخي يقع في مديرية المقاطرة، جنوب تعز. يعود تاريخه إلى فترات قديمة، ولعب دوراً عسكرياً مهماً في تأمين الطرق التجارية بين تعز والمناطق الجنوبية. يتميز الحصن بموقعه الاستراتيجي على قمة جبلية، وتصميمه الدفاعي الذي يضم أبراجاً وأسواراً متينة.";s:14:"description_en";s:329:"A historic fortress located in the Al-Maqatirah district, south of Taiz. Dating back to ancient periods, it played a crucial military role in securing trade routes between Taiz and the southern regions. The fort is notable for its strategic location on a mountain peak and its defensive design, featuring sturdy towers and walls.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"عسكري";}s:8:"latitude";d:13.161222;s:9:"longitude";d:44.135333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/FvT-T3_aYAAf-eW.jpg";i:1;s:47:"https://pbs.twimg.com/media/E9qJ-XgX0AQs-4l.jpg";}s:10:"sort_order";i:37;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:37;a:17:{s:2:"id";i:101;s:7:"city_id";i:3;s:11:"external_id";s:31:"taiz-alsawa-archaeological-site";s:4:"name";s:34:"موقع السواء الأثري";s:7:"name_en";s:27:"Al-Sawa Archaeological Site";s:11:"description";s:450:"يقع في مديرية السواء، وهو موقع أثري يعود إلى عصور ما قبل الإسلام. عُثر فيه على بقايا مستوطنات قديمة ونقوش بخط المسند، مما يدل على أنه كان مركزاً حضارياً مهماً في جنوب شبه الجزيرة العربية. الموقع بحاجة ماسة للحماية والتنقيب للكشف عن كنوزه التاريخية.";s:14:"description_en";s:369:"Located in the Al-Sawa district, it is an archaeological site dating back to pre-Islamic eras. Remains of ancient settlements and inscriptions in the Musnad script were discovered here, indicating that it was an important civilization center in the southern Arabian Peninsula. The site is in urgent need of protection and excavation to uncover its historical treasures.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:11:"pre-islamic";i:2;s:5:"ruins";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:26:"ما قبل الإسلام";i:2;s:10:"أطلال";}s:8:"latitude";d:13.416222;s:9:"longitude";d:44.016333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:60:"https://www.sabanew.net/upload/thumbs/162635483565554977.jpg";i:1;s:56:"https://www.almotamar.net/photo/10-07-2006-938194741.jpg";}s:10:"sort_order";i:38;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:38;a:17:{s:2:"id";i:102;s:7:"city_id";i:3;s:11:"external_id";s:19:"taiz-mutabiyah-dome";s:4:"name";s:23:"قبة المعتبية";s:7:"name_en";s:20:"Qubbat Al-Mu'tabiyah";s:11:"description";s:465:"ضريح ومسجد تاريخي يعود إلى العصر الرسولي، بني للأميرة "جهة الطواشي معتب" زوجة السلطان المظفر. تتميز القبة بزخارفها الجصية الرائعة وكتاباتها الكوفية التي تزين جدرانها، وتعتبر نموذجاً فريداً للعمارة الجنائزية في تلك الفترة. تقع في حارة المسبح بتعز القديمة.";s:14:"description_en";s:357:"A historic mausoleum and mosque dating back to the Rasulid era, built for Princess 'Jihat Al-Tawashi Mu'tab', wife of Sultan Al-Mudhaffar. The dome features magnificent stucco decorations and Kufic inscriptions adorning its walls, making it a unique example of funerary architecture from that period. It is located in the Al-Masbah neighborhood in old Taiz.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:13.576888;s:9:"longitude";d:44.017555;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:52:"https://i.ytimg.com/vi/e9_L_v4Y-8o/maxresdefault.jpg";i:1;s:74:"https://www.al-bayan.com/polopoly_fs/1.3736783.1577543999!/image/image.jpg";}s:10:"sort_order";i:39;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:39;a:17:{s:2:"id";i:103;s:7:"city_id";i:3;s:11:"external_id";s:17:"taiz-alhisami-dam";s:4:"name";s:43:"سد الحصامي (شرعب السلام)";s:7:"name_en";s:32:"Al-Hasami Dam (Shara'b As Salam)";s:11:"description";s:411:"سد مائي يقع في منطقة الحصامي بمديرية شرعب السلام، تم بناؤه لحجز مياه الأمطار والاستفادة منها في الزراعة وتغذية المياه الجوفية. يشكل السد بحيرة صناعية جميلة وسط الجبال، مما يجعله منظراً طبيعياً جذاباً ومكاناً مناسباً للنزهات.";s:14:"description_en";s:294:"A water dam located in the Al-Hasami area of the Shara'b As Salam district, built to capture rainwater for agricultural use and to recharge groundwater. The dam forms a beautiful artificial lake amidst the mountains, rendering it an attractive natural landscape and a suitable spot for picnics.";s:10:"categories";a:3:{i:0;s:3:"dam";i:1;s:4:"lake";i:2;s:12:"agricultural";}s:14:"category_names";a:3:{i:0;s:4:"سد";i:1;s:10:"بحيرة";i:2;s:10:"زراعي";}s:8:"latitude";d:13.821444;s:9:"longitude";d:43.916333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/E9p6q-oXMAI5s_W.jpg";i:1;s:47:"https://pbs.twimg.com/media/D-2q2X_XoAA2h-M.jpg";}s:10:"sort_order";i:40;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:40;a:17:{s:2:"id";i:104;s:7:"city_id";i:3;s:11:"external_id";s:19:"taiz-warazan-valley";s:4:"name";s:30:"وادي ورزان (خدير)";s:7:"name_en";s:20:"Wadi Warzan (Khadir)";s:11:"description";s:390:"يقع في مديرية خدير، وهو من الأودية الخصبة التي تشتهر بجريان المياه فيها بعد هطول الأمطار. تنتشر على ضفاف الوادي أشجار النخيل والمزارع المتنوعة، ويوفر مناظر طبيعية جميلة وأجواء هادئة للاسترخاء والاستمتاع بالطبيعة.";s:14:"description_en";s:246:"Located in the Khadir district, it is a fertile valley known for its flowing waters after rainfall. Palm trees and diverse farms line the riverbanks, offering beautiful natural scenery and a tranquil atmosphere for relaxation and enjoying nature.";s:10:"categories";a:3:{i:0;s:6:"valley";i:1;s:7:"natural";i:2;s:12:"agricultural";}s:14:"category_names";a:3:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";}s:8:"latitude";d:13.421555;s:9:"longitude";d:44.156777;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:52:"https://i.ytimg.com/vi/qY_U_b-i0qY/maxresdefault.jpg";i:1;s:74:"https://www.al-bayan.com/polopoly_fs/1.3745711.1578512398!/image/image.jpg";}s:10:"sort_order";i:41;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:41;a:17:{s:2:"id";i:105;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-saber-springs";s:4:"name";s:45:"حمامات وعيون صبر المائية";s:7:"name_en";s:29:"Sabir Water Springs and Baths";s:11:"description";s:421:"مجموعة من الينابيع والبرك المائية الطبيعية المتناثرة في قرى جبل صبر الشاهق. تتكون هذه الحمامات من تجمع مياه الأمطار والعيون الجبلية في تجاويف صخرية، وتوفر أماكن منعشة للسباحة والاستجمام للسكان المحليين والزوار، خاصة في فصل الصيف.";s:14:"description_en";s:293:"A series of natural springs and water pools scattered across the villages of the towering Mount Sabir. These baths form from the pooling of rainwater and mountain springs in rocky hollows, offering refreshing swimming and recreational spots for locals and visitors alike, especially in summer.";s:10:"categories";a:3:{i:0;s:6:"spring";i:1;s:12:"natural_pool";i:2;s:8:"mountain";}s:14:"category_names";a:3:{i:0;s:10:"ينبوع";i:1;s:21:"بركة طبيعية";i:2;s:8:"جبلي";}s:8:"latitude";d:13.541333;s:9:"longitude";d:44.021333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:67:"https://www.voice-yemen.com/user_images/news/28-04-20-992298587.jpg";i:1;s:47:"https://pbs.twimg.com/media/EaY-w2oWoAAG1gS.jpg";}s:10:"sort_order";i:42;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:42;a:17:{s:2:"id";i:106;s:7:"city_id";i:3;s:11:"external_id";s:28:"taiz-hanna-valley-waterfalls";s:4:"name";s:41:"شلالات وادي حنا (مقبنة)";s:7:"name_en";s:32:"Wadi Hanna Waterfalls (Maqbanah)";s:11:"description";s:370:"مجموعة من الشلالات الموسمية التي تتشكل في وادي حنا بمديرية مقبنة خلال موسم الأمطار. تتميز المنطقة بطبيعتها الصخرية الوعرة التي تخلق مساقط مائية جميلة، وتعتبر وجهة لهواة المغامرة واستكشاف الطبيعة البكر.";s:14:"description_en";s:281:"A series of seasonal waterfalls that form in Wadi Hanna in the Maqbanah district during the rainy season. The area is characterized by its rugged, rocky terrain which creates beautiful water cascades, serving as a destination for adventure seekers and explorers of pristine nature.";s:10:"categories";a:3:{i:0;s:9:"waterfall";i:1;s:6:"valley";i:2;s:7:"natural";}s:14:"category_names";a:3:{i:0;s:8:"شلال";i:1;s:8:"وادي";i:2;s:10:"طبيعي";}s:8:"latitude";d:13.513333;s:9:"longitude";d:43.766667;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:72:"https://www.alyemenialyoum.com/user_images/news/03-08-2020-562177570.jpg";i:1;s:46:"https://yemen-press.net/photos/1659280302.jpeg";}s:10:"sort_order";i:43;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:43;a:17:{s:2:"id";i:107;s:7:"city_id";i:3;s:11:"external_id";s:15:"taiz-mawqah-dam";s:4:"name";s:33:"سد موقعه (جبل حبشي)";s:7:"name_en";s:28:"Mawqa'ah Dam (Jabal Habashi)";s:11:"description";s:355:"سد مائي يقع في منطقة موقعه بمديرية جبل حبشي، أنشئ بهدف تجميع مياه السيول للاستفادة منها في ري المدرجات الزراعية التي تشتهر بزراعة البن. تشكل بحيرة السد منظراً جميلاً يمتزج مع خضرة الجبال المحيطة.";s:14:"description_en";s:268:"A water dam located in the Mawqa'ah area of the Jabal Habashi district. It was built to collect floodwaters for irrigating the agricultural terraces famous for coffee cultivation. The dam's lake forms a beautiful vista that blends with the green surrounding mountains.";s:10:"categories";a:3:{i:0;s:3:"dam";i:1;s:4:"lake";i:2;s:8:"mountain";}s:14:"category_names";a:3:{i:0;s:4:"سد";i:1;s:10:"بحيرة";i:2;s:8:"جبلي";}s:8:"latitude";d:13.535211;s:9:"longitude";d:43.921333;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/E9p6q-oXMAI5s_W.jpg";i:1;s:47:"https://pbs.twimg.com/media/D-2q2X_XoAA2h-M.jpg";}s:10:"sort_order";i:44;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:44;a:17:{s:2:"id";i:108;s:7:"city_id";i:3;s:11:"external_id";s:18:"taiz-dhabab-valley";s:4:"name";s:21:"وادي الضباب";s:7:"name_en";s:11:"Wadi Dhabab";s:11:"description";s:428:"أحد أشهر الأودية في تعز، يشتهر بمناظره الطبيعية الخلابة ومياهه الجارية التي تشكل شلالات بني عمر الشهيرة. يكتنف الوادي الضباب في كثير من الأحيان، مما يضفي عليه جواً ساحراً. يعد الوادي بأكمله وجهة سياحية متكاملة للتمتع بالطبيعة والمياه.";s:14:"description_en";s:304:"One of the most famous valleys in Taiz, renowned for its breathtaking natural landscapes and running waters that form the famous Bani Umar Waterfalls. Fog often shrouds the valley, lending it a magical atmosphere. The entire valley serves as a comprehensive tourist destination to enjoy nature and water.";s:10:"categories";a:3:{i:0;s:6:"valley";i:1;s:7:"natural";i:2;s:7:"tourism";}s:14:"category_names";a:3:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"سياحي";}s:8:"latitude";d:13.522222;s:9:"longitude";d:43.965556;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:119:"https://www.aa.com.tr/uploads/userfiles/a9298453-9574-43cb-84ef-518f48348a2f/2021/1506/20210615_2_48689591_65538576.jpg";i:1;s:66:"https://yemen-monitor.com/user_images/news/14-04-2024-90531675.jpg";}s:10:"sort_order";i:45;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:45;a:17:{s:2:"id";i:109;s:7:"city_id";i:3;s:11:"external_id";s:23:"taiz-mokha-port-beaches";s:4:"name";s:34:"ميناء وشواطئ المخا";s:7:"name_en";s:22:"Mocha Port and Beaches";s:11:"description";s:398:"على الرغم من أن الجزء الأكبر من تعز جبلي، إلا أنها تطل على البحر الأحمر عبر مديرية المخا. تشتهر المخا بمينائها التاريخي الذي كان مركزاً لتصدير البن، وتمتلك شواطئ رملية جميلة توفر فرصة للاستجمام وممارسة الأنشطة البحرية.";s:14:"description_en";s:286:"Although the majority of Taiz is mountainous, it overlooks the Red Sea through the Mocha district. Mocha is famous for its historical port, which was a hub for coffee export. It possesses beautiful sandy beaches that offer an opportunity for relaxation and practicing marine activities.";s:10:"categories";a:3:{i:0;s:5:"beach";i:1;s:3:"sea";i:2;s:4:"port";}s:14:"category_names";a:3:{i:0;s:8:"شاطئ";i:1;s:6:"بحر";i:2;s:10:"ميناء";}s:8:"latitude";d:13.318889;s:9:"longitude";d:43.245278;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"https://www.dw.com/image/19043188_303.jpg";i:1;s:94:"https://www.aljazeera.net/wp-content/uploads/2016/02/a43a34f1-1576-496a-a28a-79878233e53c.jpeg";}s:10:"sort_order";i:46;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:46;a:17:{s:2:"id";i:110;s:7:"city_id";i:3;s:11:"external_id";s:16:"taiz-rasyan-bath";s:4:"name";s:32:"حمام رسيان (مقبنة)";s:7:"name_en";s:22:"Rasyan Bath (Maqbanah)";s:11:"description";s:365:"حمام مائي طبيعي يقع في وادي رسيان بمديرية مقبنة. مياهه دافئة وليست حارة كحمام علي، ويقصدها السكان المحليون للاستحمام والاستشفاء من بعض الأمراض الجلدية وللاسترخاء. يتميز بوجوده وسط طبيعة خضراء وخلابة.";s:14:"description_en";s:281:"A natural water bath located in Wadi Rasyan in the Maqbanah district. Its waters are warm, not scalding like Hammam Ali, and it is frequented by locals for bathing, healing from certain skin diseases, and relaxation. It is notable for being nestled amidst lush, picturesque nature.";s:10:"categories";a:3:{i:0;s:11:"therapeutic";i:1;s:11:"warm_spring";i:2;s:7:"natural";}s:14:"category_names";a:3:{i:0;s:10:"علاجي";i:1;s:17:"حمام دافئ";i:2;s:10:"طبيعي";}s:8:"latitude";d:13.595222;s:9:"longitude";d:43.851222;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"https://pbs.twimg.com/media/E9p6q-oXMAI5s_W.jpg";i:1;s:47:"https://pbs.twimg.com/media/D-2q2X_XoAA2h-M.jpg";}s:10:"sort_order";i:47;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:47;a:17:{s:2:"id";i:111;s:7:"city_id";i:3;s:11:"external_id";s:12:"wadi-al-sahi";s:4:"name";s:37:"وادي الصهي (بني حماد)";s:7:"name_en";s:26:"Wadi Al-Sahi (Bani Hammad)";s:11:"description";s:303:"يقع في منطقة بني حماد القريبة من التربة، وهو وادٍ خصب يشتهر بمياهه الجارية ومناظره الطبيعية. [3] يعتبر وجهة للسكان المحليين للنزهة والاستجمام، خاصة في مواسم الأمطار. [3]";s:14:"description_en";s:230:"Located in the Bani Hammad area near At Turbah, it is a fertile valley renowned for its flowing waters and natural landscapes. [3] It serves as a destination for locals to picnic and relax, especially during the rainy seasons. [3]";s:10:"categories";a:3:{i:0;s:6:"valley";i:1;s:12:"natural-park";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:8:"وادي";i:1;s:21:"منتزه طبيعي";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.303333;s:9:"longitude";d:44.041667;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:48;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:48;a:17:{s:2:"id";i:112;s:7:"city_id";i:3;s:11:"external_id";s:11:"yefres-area";s:4:"name";s:19:"منطقة يفرس";s:7:"name_en";s:11:"Yafrus Area";s:11:"description";s:394:"تقع في مديرية جبل حبشي ولكنها قريبة جدًا من التربة، وتشتهر بجمالها الطبيعي وإطلالاتها المرتفعة. [4] المنطقة المحيطة بضريح الشيخ "أحمد بن علوان" تعتبر وجهة روحانية وسياحية، وتتميز بأجوائها المعتدلة ومناظرها الخلابة. [4]";s:14:"description_en";s:305:"Located in the Jabal Habashi district but very close to At Turbah, it is renowned for its natural beauty and elevated views. [4] The area surrounding the shrine of Sheikh 'Ahmad bin Alwan' is considered a spiritual and tourist destination, characterized by a moderate climate and breathtaking scenery. [4]";s:10:"categories";a:3:{i:0;s:12:"natural-area";i:1;s:13:"mountain-view";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:23:"منطقة طبيعية";i:1;s:23:"إطلالة جبلية";i:2;s:12:"تاريخي";}s:8:"latitude";d:13.498333;s:9:"longitude";d:43.940556;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:49;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:49;a:17:{s:2:"id";i:113;s:7:"city_id";i:3;s:11:"external_id";s:18:"al-areef-waterfall";s:4:"name";s:21:"شلال العريف";s:7:"name_en";s:18:"Al-Arrif Waterfall";s:11:"description";s:354:"أحد الشلالات الجميلة في مديرية حيفان، ويقع في منطقة العريف. [3] يتدفق الشلال بغزارة خلال مواسم الأمطار، مكونًا منظرًا طبيعيًا ساحرًا يجذب الزوار للاستمتاع بجماله والسباحة في البرك التي يكونها. [3]";s:14:"description_en";s:259:"One of the beautiful waterfalls in the Hayfan district, located in the Al-Arrif area. [3] The waterfall flows abundantly during the rainy seasons, creating a charming natural scene that attracts visitors to enjoy its beauty and swim in the pools it forms. [3]";s:10:"categories";a:3:{i:0;s:9:"waterfall";i:1;s:12:"natural-park";i:2;s:8:"swimming";}s:14:"category_names";a:3:{i:0;s:8:"شلال";i:1;s:21:"منتزه طبيعي";i:2;s:10:"سباحة";}s:8:"latitude";d:13.386222;s:9:"longitude";d:43.963111;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:50;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:50;a:17:{s:2:"id";i:114;s:7:"city_id";i:3;s:11:"external_id";s:14:"al-ahkoom-park";s:4:"name";s:25:"منتزه الأحكوم";s:7:"name_en";s:13:"Al-Ahkum Park";s:11:"description";s:402:"منتزه يقع في منطقة الأحكوم بمديرية حيفان، ويتميز بإطلالاته البانورامية على الأودية والجبال المحيطة. [4] يعتبر مكانًا مناسبًا للنزهات العائلية والاستمتاع بالهواء النقي والمناظر الطبيعية الخلابة التي تشتهر بها المنطقة. [4]";s:14:"description_en";s:265:"A park located in the Al-Ahkum area in the Hayfan district, noted for its panoramic views of the surrounding valleys and mountains. [4] It is an ideal spot for family outings to enjoy the fresh air and stunning natural landscapes for which the region is famous. [4]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"family";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:10:"عائلي";i:3;s:12:"ترفيهي";}s:8:"latitude";d:13.254111;s:9:"longitude";d:44.103222;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:51;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:51;a:17:{s:2:"id";i:115;s:7:"city_id";i:3;s:11:"external_id";s:19:"ayn-al-jabal-hayfan";s:4:"name";s:17:"عين الجبل";s:7:"name_en";s:12:"Ain Al-Jabal";s:11:"description";s:339:"عين مياه عذبة تقع في إحدى مناطق حيفان الجبلية، وتعتبر مصدرًا للمياه ومكانًا للاستراحة والاستجمام. [5] يقصدها السكان المحليون والزوار للاستمتاع ببرودة مياهها وجمال الطبيعة المحيطة بها. [5]";s:14:"description_en";s:229:"A freshwater spring located in one of Hayfan's mountainous areas, serving as a water source and a place for rest and relaxation. [5] Locals and visitors frequent it to enjoy its cool waters and the surrounding natural beauty. [5]";s:10:"categories";a:3:{i:0;s:6:"spring";i:1;s:12:"natural-area";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"ينبوع";i:1;s:23:"منطقة طبيعية";i:2;s:12:"ترفيهي";}s:8:"latitude";d:13.256222;s:9:"longitude";d:44.241333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:52;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:52;a:17:{s:2:"id";i:623;s:7:"city_id";i:3;s:11:"external_id";N;s:4:"name";s:10:"موحجه";s:7:"name_en";s:7:"Mohajha";s:11:"description";s:80:"تعد من افضل معالم اليمن بسبب الجو البارد فيه";s:14:"description_en";s:71:"It is considered one of Yemen's best landmarks due to its cool weather.";s:10:"categories";a:2:{i:0;s:10:"historical";i:1;s:8:"cultural";}s:14:"category_names";a:2:{i:0;s:12:"تاريخي";i:1;s:10:"ثقافي";}s:8:"latitude";d:13.4535926;s:9:"longitude";d:44.1813151;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSMiiVvm8GynRFCkmAL6udQZB0VNvL6HLZEkw&s";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-23T21:15:25.000000Z";s:10:"updated_at";s:27:"2026-04-23T21:15:25.000000Z";}i:53;a:17:{s:2:"id";i:616;s:7:"city_id";i:3;s:11:"external_id";N;s:4:"name";s:20:"المجوووودي";s:7:"name_en";s:10:"Al-Majoudi";s:11:"description";s:69:"حصن المجوووودي افضل حصن بالوطن العربي";s:14:"description_en";s:49:"Al-Majoudi Fort, the best fort in the Arab world.";s:10:"categories";a:1:{i:0;s:10:"طبيعي";}s:14:"category_names";a:1:{i:0;s:10:"سياحي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-30T22:18:28.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:54;a:17:{s:2:"id";i:622;s:7:"city_id";i:3;s:11:"external_id";N;s:4:"name";s:12:"الصرام";s:7:"name_en";N;s:11:"description";s:73:"وادي الصرام يتنوع بالزراعة ووفرة المياه";s:14:"description_en";N;s:10:"categories";a:1:{i:0;s:10:"historical";}s:14:"category_names";a:1:{i:0;s:10:"ثقافي";}s:8:"latitude";d:13.4417712;s:9:"longitude";d:44.1282684;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSnPJJF82BifabWJHUubquQFtWXi6YPZ1byMg&s";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-23T20:33:24.000000Z";s:10:"updated_at";s:27:"2026-04-23T20:33:24.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:14;a:13:{s:2:"id";i:15;s:4:"slug";s:6:"hajjah";s:4:"name";s:6:"حجة";s:7:"name_en";s:6:"Hajjah";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:15:"hajjah_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:30;s:9:"landmarks";a:30:{i:0;a:17:{s:2:"id";i:369;s:7:"city_id";i:15;s:11:"external_id";s:21:"qalat-alqahira-hajjah";s:4:"name";s:32:"قلعة القاهرة (حجة)";s:7:"name_en";s:21:"Cairo Castle (Hajjah)";s:11:"description";s:401:"من أبرز القلاع التاريخية في اليمن، تقع على قمة جبل وتطل على مدينة حجة. [1, 2] يعود تاريخها إلى القرن الحادي عشر الميلادي، وكانت حصناً استراتيجياً ومركزاً للحكم، وتتميز بعمارتها العسكرية الفريدة وإطلالاتها البانورامية. [1, 2]";s:14:"description_en";s:287:"One of the most prominent historical castles in Yemen, located atop a mountain overlooking the city of Hajjah. [1, 2] Dating back to the 11th century AD, it was a strategic fortress and a center of governance, distinguished by its unique military architecture and panoramic views. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";i:3;s:6:"مطل";}s:8:"latitude";d:15.6897;s:9:"longitude";d:43.5975;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:370;s:7:"city_id";i:15;s:11:"external_id";s:20:"shaharah-bridge-area";s:4:"name";s:43:"منتزه جسر شهارة الطبيعي";s:7:"name_en";s:28:"Shaharah Bridge Natural Park";s:11:"description";s:393:"يقع في مديرية شهارة المجاورة لحجة (والتابعة إداريًا لمحافظة عمران)، ولكنه وجهة رئيسية لزوار حجة. [8] المنطقة المحيطة بالجسر المعلق الشهير تعتبر منتزهًا جبليًا فريدًا، وتوفر مناظر طبيعية مذهلة وتجربة سياحية لا تنسى. [8]";s:14:"description_en";s:331:"Located in the Shaharah district adjacent to Hajjah (and administratively belonging to Amran Governorate), but it is a major destination for visitors to Hajjah. [8] The area surrounding the famous suspension bridge is considered a unique mountain park, offering stunning natural scenery and an unforgettable tourist experience. [8]";s:10:"categories";a:4:{i:0;s:6:"bridge";i:1;s:15:"historical-site";i:2;s:8:"mountain";i:3;s:7:"tourism";}s:14:"category_names";a:4:{i:0;s:6:"جسر";i:1;s:21:"موقع تاريخي";i:2;s:6:"جبل";i:3;s:10:"سياحة";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:371;s:7:"city_id";i:15;s:11:"external_id";s:18:"hajjah-public-park";s:4:"name";s:30:"حديقة حجة العامة";s:7:"name_en";s:18:"Hajjah Public Park";s:11:"description";s:308:"الحديقة العامة المنظمة داخل مدينة حجة، والتي تمثل متنفسًا للعائلات والأطفال. [9] تضم الحديقة بعض الألعاب والمساحات الخضراء، وتوفر مكانًا للراحة والترفيه داخل المدينة. [9]";s:14:"description_en";s:217:"The organized public park within the city of Hajjah, serving as a retreat for families and children. [9] The park includes some games and green spaces, providing a place for rest and entertainment within the city. [9]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:372;s:7:"city_id";i:15;s:11:"external_id";s:22:"wadi-sharas-waterfalls";s:4:"name";s:28:"شلالات وادي شرس";s:7:"name_en";s:22:"Wadi Sharas Waterfalls";s:11:"description";s:385:"يقع في مديرية شرس التي تتميز بطبيعتها الخضراء ومدرجاتها الزراعية. [3, 4] يعتبر الوادي موطناً لشلالات دائمة الجريان تنبع من أعالي الجبال، مما يجعله منتجعاً طبيعياً يقصده الزوار للاستجمام والتمتع بجمال الطبيعة. [3, 4]";s:14:"description_en";s:301:"Located in the Sharas district, which is characterized by its green nature and agricultural terraces. [3, 4] The valley is home to continuously flowing waterfalls originating from the high mountains, making it a natural resort visited by people for recreation and enjoying the beauty of nature. [3, 4]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:6:"scenic";i:3;s:6:"valley";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:21:"مناظر خلابة";i:3;s:8:"وادي";}s:8:"latitude";d:15.83;s:9:"longitude";d:43.45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:373;s:7:"city_id";i:15;s:11:"external_id";s:15:"kawkaban-shibam";s:4:"name";s:32:"مدينة كوكبان (حجة)";s:7:"name_en";s:22:"Kawkaban City (Hajjah)";s:11:"description";s:313:"مدينة تاريخية محصنة تقع على قمة جبل، وتختلف عن شبام كوكبان في المحويت. [2] تشتهر بأسوارها وحصونها ومنازلها الحجرية القديمة، وكانت مركزاً علمياً ودينياً مهماً عبر التاريخ. [2]";s:14:"description_en";s:240:"A fortified historical city located on a mountaintop, distinct from Shibam Kawkaban in Al Mahwit. [2] It is famous for its walls, fortresses, and old stone houses, and was an important scientific and religious center throughout history. [2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:9:"fortified";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:10:"محصنة";}s:8:"latitude";d:15.51;s:9:"longitude";d:43.88;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:374;s:7:"city_id";i:15;s:11:"external_id";s:21:"midi-island-and-coast";s:4:"name";s:26:"ساحل وجزر ميدي";s:7:"name_en";s:22:"Midi Coast and Islands";s:11:"description";s:348:"تمثل الواجهة البحرية لمحافظة حجة على البحر الأحمر. [9] تشتهر بسواحلها الرملية وأشجار المانجروف، وتضم أرخبيلاً من الجزر التي تتميز بتنوعها البيولوجي والبحري، وتعتبر منطقة هامة لصيد الأسماك. [9]";s:14:"description_en";s:259:"It represents the maritime front of Hajjah Governorate on the Red Sea. [9] Famous for its sandy coasts and mangrove trees, it includes an archipelago of islands distinguished by marine and biological diversity, and is considered an important fishing area. [9]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:7:"coastal";i:2;s:6:"island";i:3;s:5:"beach";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"ساحلي";i:2;s:10:"جزيرة";i:3;s:8:"شاطئ";}s:8:"latitude";d:16.31;s:9:"longitude";d:42.76;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:375;s:7:"city_id";i:15;s:11:"external_id";s:15:"naatan-fortress";s:4:"name";s:17:"حصن نعمان";s:7:"name_en";s:11:"Na'man Fort";s:11:"description";s:310:"حصن تاريخي منيع يقع في مديرية المفتاح. [2] بني على قمة جبل شاهق، وكان له دور دفاعي كبير عبر العصور. يتميز الحصن بتصميمه الهندسي الذي يتلاءم مع التضاريس الصخرية المحيطة به. [2]";s:14:"description_en";s:248:"An impregnable historical fort located in the Al-Miftah district. [2] Built on a towering mountaintop, it played a major defensive role throughout the ages. The fort features an architectural design that adapts to the surrounding rocky terrain. [2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:10:"عسكري";i:3;s:12:"معماري";}s:8:"latitude";d:15.75;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:376;s:7:"city_id";i:15;s:11:"external_id";s:16:"al-jāhilī-fort";s:4:"name";s:21:"حصن الجاهلي";s:7:"name_en";s:14:"Al-Jahili Fort";s:11:"description";s:333:"يقع في مديرية كشر، وهو حصن قديم يعود تاريخه إلى فترات ما قبل الإسلام. [2] يدلل على العمق التاريخي للمنطقة، ويحتوي على بقايا مبانٍ ونقوش أثرية تشير إلى الحضارات التي تعاقبت على المكان. [2]";s:14:"description_en";s:286:"Located in the Kushar district, it is an ancient fort dating back to pre-Islamic periods. [2] It demonstrates the historical depth of the region and contains the remains of buildings and archaeological inscriptions indicating the civilizations that succeeded each other in the area. [2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:8:"fortress";i:3;s:5:"ruins";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:6:"حصن";i:3;s:10:"أطلال";}s:8:"latitude";d:16.05;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:377;s:7:"city_id";i:15;s:11:"external_id";s:15:"maswar-fortress";s:4:"name";s:15:"حصن مسور";s:7:"name_en";s:11:"Miswar Fort";s:11:"description";s:334:"أحد الحصون التاريخية الهامة في مديرية مبين. [2] يتميز بموقعه الحصين على قمة جبلية، ويحتوي على عدد من المباني والمدافن الصخرية (خزانات مياه) التي تدل على براعة الهندسة اليمنية القديمة. [2]";s:14:"description_en";s:271:"One of the important historical forts in the Mabyan district. [2] It is distinguished by its fortified location on a mountain peak, and contains a number of buildings and rock-carved silos (water cisterns) that demonstrate the ingenuity of ancient Yemeni engineering. [2]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:6:"حصن";i:2;s:12:"معماري";}s:8:"latitude";d:15.78;s:9:"longitude";d:43.63;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:378;s:7:"city_id";i:15;s:11:"external_id";s:11:"wadi-laa'ah";s:4:"name";s:17:"وادي لاعة";s:7:"name_en";s:10:"Wadi La'ah";s:11:"description";s:330:"من الأودية الخصبة والجميلة في حجة، يشتهر بمياهه الجارية ومزارعه الخضراء التي تنتج أنواعاً مختلفة من الفواكه والخضروات. [10] يعتبر الوادي متنفساً طبيعياً ومقصداً للرحلات والنزهات. [10]";s:14:"description_en";s:244:"One of the fertile and beautiful valleys in Hajjah, famous for its running waters and green farms that produce various types of fruits and vegetables. [10] The valley is considered a natural retreat and a destination for trips and picnics. [10]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.9;s:9:"longitude";d:43.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:379;s:7:"city_id";i:15;s:11:"external_id";s:13:"shaharah-city";s:4:"name";s:21:"مدينة شهارة";s:7:"name_en";s:13:"Shaharah City";s:11:"description";s:348:"مدينة تاريخية محصنة تقع على قمة جبل شاهق، وتشتهر بجسرها المعلق. [6] تتميز المدينة بمنازلها الحجرية التقليدية وأسوارها وأبوابها القديمة، وتعتبر مثالاً رائعاً للمدن الجبلية المحصنة في اليمن. [6]";s:14:"description_en";s:257:"A fortified historical city located on a towering mountain peak, famous for its suspension bridge. [6] The city is characterized by its traditional stone houses, ancient walls, and gates, and is a wonderful example of fortified mountain cities in Yemen. [6]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:8:"mountain";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:8:"جبلي";i:3;s:12:"معماري";}s:8:"latitude";d:16.16;s:9:"longitude";d:43.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:17:{s:2:"id";i:380;s:7:"city_id";i:15;s:11:"external_id";s:14:"wadi-mour-park";s:4:"name";s:41:"منتزه وادي مور الطبيعي";s:7:"name_en";s:22:"Wadi Mawr Natural Park";s:11:"description";s:364:"أحد أكبر الأودية في اليمن، ويمر جزء كبير منه عبر محافظة حجة. [1, 2] تتميز ضفافه بالخضرة الدائمة والمياه الجارية، مما يجعله أكبر منتزه طبيعي مفتوح في المنطقة، ومقصداً رئيسياً للسكان للسباحة والنزهات. [1, 2]";s:14:"description_en";s:297:"One of the largest valleys in Yemen, a large part of which passes through Hajjah Governorate. [1, 2] Its banks are characterized by evergreen vegetation and running waters, making it the largest open natural park in the region and a major destination for residents for swimming and picnics. [1, 2]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:4:"park";i:3;s:5:"river";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"منتزه";i:3;s:6:"نهر";}s:8:"latitude";d:15.8;s:9:"longitude";d:43.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:17:{s:2:"id";i:381;s:7:"city_id";i:15;s:11:"external_id";s:18:"ayn-ali-waterfalls";s:4:"name";s:26:"شلالات عين علي";s:7:"name_en";s:18:"Ain Ali Waterfalls";s:11:"description";s:389:"تقع في عزلة عين علي بمديرية مبين، وهي من أشهر الوجهات السياحية في حجة. [4, 5] تتميز بمياهها المتدفقة على مدار العام تقريباً، وتحيط بها مدرجات زراعية خضراء ومناظر طبيعية ساحرة، مما يجعلها منتجعاً طبيعياً متكاملاً. [4, 5]";s:14:"description_en";s:311:"Located in the Ain Ali sub-district of Mabyan district, they are among the most famous tourist destinations in Hajjah. [4, 5] Distinguished by their almost year-round flowing waters, they are surrounded by green agricultural terraces and enchanting natural scenery, making them a complete natural resort. [4, 5]";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:6:"scenic";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:21:"مناظر خلابة";i:3;s:10:"منتزه";}s:8:"latitude";d:15.85;s:9:"longitude";d:43.65;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:17:{s:2:"id";i:382;s:7:"city_id";i:15;s:11:"external_id";s:17:"wadi-al-qour-park";s:4:"name";s:30:"منتزه وادي القور";s:7:"name_en";s:17:"Wadi Al-Qawr Park";s:11:"description";s:352:"يقع في مديرية كحلان عفار، ويشتهر بمياهه العذبة الجارية ومناظره الطبيعية الخلابة. [3] يعتبر الوادي متنفساً للسكان المحليين والزوار، حيث يوفر أماكن هادئة للنزهة والاستمتاع بجمال الطبيعة الريفية.";s:14:"description_en";s:243:"Located in the Kuhlan 'Affar district, it is famous for its flowing fresh waters and breathtaking natural scenery. [3] The valley is a retreat for locals and visitors, providing quiet places for picnics and enjoying the beauty of rural nature.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:4:"park";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"منتزه";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.95;s:9:"longitude";d:43.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:17:{s:2:"id";i:383;s:7:"city_id";i:15;s:11:"external_id";s:23:"al-maghrabah-waterfalls";s:4:"name";s:27:"شلالات المغربة";s:7:"name_en";s:23:"Al-Maghrabah Waterfalls";s:11:"description";s:323:"مجموعة من الشلالات الجميلة التي تقع في مديرية كشر. [3] تنحدر المياه من أعالي الجبال مكونةً شلالات تتدفق بين الصخور والمدرجات الزراعية، وتوفر منظراً بديعاً خاصة بعد مواسم الأمطار.";s:14:"description_en";s:247:"A group of beautiful waterfalls located in the Kushar district. [3] The water cascades from the high mountains forming waterfalls that flow between rocks and agricultural terraces, providing a magnificent sight, especially after the rainy seasons.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:6:"scenic";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:21:"مناظر خلابة";i:3;s:8:"جبلي";}s:8:"latitude";d:16.05;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:15;a:17:{s:2:"id";i:384;s:7:"city_id";i:15;s:11:"external_id";s:16:"wadi-nawhan-park";s:4:"name";s:41:"منتزه وادي نشوان (نحان)";s:7:"name_en";s:25:"Wadi Nashwan (Nihan) Park";s:11:"description";s:325:"وادي خصب يقع في مديرية أفلح الشام، ويتميز بمياهه الجارية وطبيعته الخضراء. [3] يعتبر الوادي وجهة مثالية للرحلات العائلية والاستمتاع بالأجواء الريفية الهادئة بعيداً عن ضوضاء المدن.";s:14:"description_en";s:240:"A fertile valley located in the Aflah Al-Sham district, distinguished by its running waters and green nature. [3] The valley is an ideal destination for family trips and enjoying the quiet rural atmosphere away from the noise of the cities.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:4:"park";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"منتزه";i:3;s:10:"زراعة";}s:8:"latitude";d:16.1;s:9:"longitude";d:43.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:16;a:17:{s:2:"id";i:385;s:7:"city_id";i:15;s:11:"external_id";s:22:"bani-al-awwam-terraces";s:4:"name";s:43:"منتزه مدرجات بني العوام";s:7:"name_en";s:26:"Bani Al-Awam Terraces Park";s:11:"description";s:324:"تشكل المدرجات الزراعية الخضراء التي تغطي جبال مديرية بني العوام منتزهاً طبيعياً مفتوحاً. [3] تشتهر المنطقة بزراعة البن والقات، وتوفر إطلالات بانورامية ومسارات للمشي بين المزارع.";s:14:"description_en";s:228:"The green agricultural terraces that cover the mountains of the Bani Al-Awam district form an open natural park. [3] The area is famous for cultivating coffee and qat, offering panoramic views and walking trails among the farms.";s:10:"categories";a:4:{i:0;s:6:"scenic";i:1;s:11:"agriculture";i:2;s:8:"mountain";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:21:"مناظر خلابة";i:1;s:10:"زراعة";i:2;s:8:"جبلي";i:3;s:10:"منتزه";}s:8:"latitude";d:15.6;s:9:"longitude";d:43.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:17;a:17:{s:2:"id";i:386;s:7:"city_id";i:15;s:11:"external_id";s:23:"wadi-sharas-upper-falls";s:4:"name";s:50:"الشلالات العليا في وادي شرس";s:7:"name_en";s:31:"Upper Waterfalls in Wadi Sharas";s:11:"description";s:359:"بالإضافة إلى الشلالات الرئيسية، يضم وادي شرس في مناطقه العليا العديد من الشلالات الصغيرة والعيون المائية المتدفقة. [3, 4] هذه المناطق توفر أماكن أكثر هدوءاً وعزلة للزوار الباحثين عن الاسترخاء التام.";s:14:"description_en";s:217:"In addition to the main waterfalls, the upper areas of Wadi Sharas feature many small waterfalls and flowing water springs. [3, 4] These areas offer more quiet and secluded spots for visitors seeking total relaxation.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:6:"scenic";i:3;s:6:"valley";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:21:"مناظر خلابة";i:3;s:8:"وادي";}s:8:"latitude";d:15.85;s:9:"longitude";d:43.48;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:18;a:17:{s:2:"id";i:387;s:7:"city_id";i:15;s:11:"external_id";s:17:"al-ashmor-valleys";s:4:"name";s:40:"منتزهات أودية الأشمور";s:7:"name_en";s:23:"Al-Ashmur Valleys Parks";s:11:"description";s:357:"منطقة الأشمور في مديرية كحلان الشرف غنية بالأودية الصغيرة والمتنزهات الطبيعية. [3] تتميز هذه الأودية بخصوبتها ومياهها الجارية، وتعتبر أماكن مثالية للنزهات الخلوية والاستمتاع بجمال الطبيعة البكر.";s:14:"description_en";s:253:"The Al-Ashmur area in the Kuhlan Ash Sharaf district is rich in small valleys and natural parks. [3] These valleys are known for their fertility and running waters, making them ideal places for outdoor picnics and enjoying the beauty of pristine nature.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:4:"park";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"منتزه";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.9;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:19;a:17:{s:2:"id";i:388;s:7:"city_id";i:15;s:11:"external_id";s:15:"wadi-einas-park";s:4:"name";s:30:"منتزه وادي عِناس";s:7:"name_en";s:14:"Wadi Inas Park";s:11:"description";s:294:"يقع في مديرية المفتاح، وهو وادٍ جميل يتميز بمناظره الطبيعية الخضراء ومياهه التي تجري في مواسم الأمطار. [3] يوفر الوادي بيئة هادئة ومناسبة للرحلات والتخييم الخفيف.";s:14:"description_en";s:234:"Located in the Al-Miftah district, it is a beautiful valley characterized by its green natural landscapes and waters that flow during the rainy seasons. [3] The valley provides a quiet environment suitable for trips and light camping.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:4:"park";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"منتزه";i:3;s:10:"موسمي";}s:8:"latitude";d:15.7;s:9:"longitude";d:43.55;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:20;a:17:{s:2:"id";i:389;s:7:"city_id";i:15;s:11:"external_id";s:25:"shaharah-mountain-springs";s:4:"name";s:43:"عيون ومنتزهات جبل شهارة";s:7:"name_en";s:35:"Springs and Parks of Mount Shaharah";s:11:"description";s:346:"إلى جانب الجسر والمدينة التاريخية، يشتهر جبل شهارة بوجود العديد من عيون الماء والمناطق الخضراء على سفوحه. [6] تعتبر هذه المناطق بمثابة منتزهات طبيعية صغيرة توفر إطلالات رائعة ومكاناً للراحة.";s:14:"description_en";s:215:"Besides the bridge and the historic city, Mount Shaharah is famous for the many water springs and green areas on its slopes. [6] These areas serve as small natural parks offering wonderful views and a place to rest.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:6:"spring";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:10:"ينبوع";i:3;s:10:"منتزه";}s:8:"latitude";d:16.16;s:9:"longitude";d:43.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:21;a:17:{s:2:"id";i:390;s:7:"city_id";i:15;s:11:"external_id";s:16:"sadd-al-abadilah";s:4:"name";s:21:"سد الأباعلة";s:7:"name_en";s:15:"Al-Aba'alah Dam";s:11:"description";s:392:"يقع في مديرية كحلان الشرف، وهو سد حديث نسبياً تم بناؤه للاستفادة من مياه الأمطار في الري وتغذية المياه الجوفية. [1, 2] أصبحت بحيرة السد منظراً طبيعياً جميلاً يجذب الزوار للنزهة والاستمتاع بمنظر المياه المحاطة بالجبال.";s:14:"description_en";s:289:"Located in the Kuhlan Ash Sharaf district, it is a relatively modern dam built to utilize rainwater for irrigation and groundwater recharge. [1, 2] The dam's lake has become a beautiful natural landscape that attracts visitors to picnic and enjoy the view of water surrounded by mountains.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:6:"scenic";i:3;s:11:"engineering";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:21:"مناظر خلابة";i:3;s:10:"هندسي";}s:8:"latitude";d:15.93;s:9:"longitude";d:43.58;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:22;a:17:{s:2:"id";i:391;s:7:"city_id";i:15;s:11:"external_id";s:13:"wadi-al-khams";s:4:"name";s:19:"وادي الخمس";s:7:"name_en";s:13:"Wadi Al-Khams";s:11:"description";s:291:"أحد الأودية الهامة في مديرية حرض الحدودية. [3] يشتهر بأراضيه الزراعية الخصبة التي تعتمد على مياهه، ويعتبر شرياناً حيوياً للمنطقة، خاصة في زراعة الحبوب والأعلاف.";s:14:"description_en";s:233:"One of the important valleys in the border district of Harad. [3] It is famous for its fertile agricultural lands that rely on its waters, and is considered a vital artery for the region, especially for cultivating grains and fodder.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.4;s:9:"longitude";i:43;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:23;a:17:{s:2:"id";i:392;s:7:"city_id";i:15;s:11:"external_id";s:11:"wadi-haydan";s:4:"name";s:19:"وادي حيران";s:7:"name_en";s:11:"Wadi Hayran";s:11:"description";s:348:"وادي رئيسي يقع في مديرية حيران، ويصب في وادي مور. [3] يلعب دوراً مهماً في دعم الزراعة في المنطقة، وتتحول ضفافه إلى مناطق خضراء جميلة بعد مواسم الأمطار، مما يجعله مكاناً مناسباً للرحلات الخلوية.";s:14:"description_en";s:256:"A major valley located in the Hayran district, flowing into Wadi Mawr. [3] It plays an important role in supporting agriculture in the area, and its banks turn into beautiful green areas after the rainy seasons, making it a suitable spot for outdoor trips.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"موسمي";}s:8:"latitude";d:16.2;s:9:"longitude";d:43.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:24;a:17:{s:2:"id";i:393;s:7:"city_id";i:15;s:11:"external_id";s:14:"sadd-bani-qays";s:4:"name";s:18:"سد بني قيس";s:7:"name_en";s:13:"Bani Qais Dam";s:11:"description";s:309:"يقع في مديرية بني قيس الجبلية، وهو سد محلي يهدف إلى تجميع مياه السيول لاستخدامها في الزراعة. [4] يمثل السد وبحيرته الصغيرة منظراً جميلاً يضاف إلى الطبيعة الخلابة للمديرية.";s:14:"description_en";s:230:"Located in the mountainous Bani Qais district, it is a local dam aimed at collecting floodwaters for agricultural use. [4] The dam and its small lake represent a beautiful scene that adds to the picturesque nature of the district.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:8:"جبلي";}s:8:"latitude";d:15.7;s:9:"longitude";d:43.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:25;a:17:{s:2:"id";i:394;s:7:"city_id";i:15;s:11:"external_id";s:13:"wadi-al-asfal";s:4:"name";s:21:"وادي الأسفل";s:7:"name_en";s:13:"Wadi Al-Asfal";s:11:"description";s:286:"أحد روافد وادي مور، يمر في مديرية أفلح اليمن. [3] يشتهر بخصوبته ومياهه الجارية التي تدعم زراعة متنوعة، ويعتبر من الأودية الجميلة التي تتميز بمناظرها الطبيعية.";s:14:"description_en";s:247:"One of the tributaries of Wadi Mawr, passing through the Aflah Al-Yaman district. [3] It is famous for its fertility and running waters that support diverse agriculture, and is considered one of the beautiful valleys known for its natural scenery.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"طبيعي";}s:8:"latitude";i:16;s:9:"longitude";d:43.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:26;a:17:{s:2:"id";i:395;s:7:"city_id";i:15;s:11:"external_id";s:12:"ayn-al-hadab";s:4:"name";s:19:"عين الهضاب";s:7:"name_en";s:37:"Ain Al-Hidad (Spring of the Plateaus)";s:11:"description";s:262:"عين مياه طبيعية (ينبوع) تقع في مديرية كحلان عفار. [5] تعتبر مصدراً مهماً للمياه للسكان المحليين وللأغراض الزراعية، وتتميز بمياهها العذبة والنقية.";s:14:"description_en";s:193:"A natural water spring located in the Kuhlan 'Affar district. [5] It is an important source of water for the local population and for agricultural purposes, known for its fresh and pure waters.";s:10:"categories";a:4:{i:0;s:6:"spring";i:1;s:5:"water";i:2;s:7:"natural";i:3;s:6:"source";}s:14:"category_names";a:4:{i:0;s:10:"ينبوع";i:1;s:8:"مائي";i:2;s:10:"طبيعي";i:3;s:8:"مصدر";}s:8:"latitude";d:15.9;s:9:"longitude";d:43.65;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:27;a:17:{s:2:"id";i:396;s:7:"city_id";i:15;s:11:"external_id";s:16:"wadi-sharis-dams";s:4:"name";s:52:"السدود التحويلية في وادي شرس";s:7:"name_en";s:29:"Diversion Dams in Wadi Sharas";s:11:"description";s:396:"بالإضافة إلى شلالاته، يضم وادي شرس عدداً من السدود والحواجز المائية التقليدية والحديثة. [6] تهدف هذه السدود إلى تحويل المياه لري المدرجات الزراعية الخضراء التي تشتهر بها المديرية، وهي مثال على الهندسة المائية الريفية.";s:14:"description_en";s:274:"In addition to its waterfalls, Wadi Sharas includes a number of traditional and modern dams and water barriers. [6] These dams aim to divert water to irrigate the green agricultural terraces for which the district is famous, serving as an example of rural water engineering.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:11:"engineering";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"هندسي";}s:8:"latitude";d:15.83;s:9:"longitude";d:43.45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:28;a:17:{s:2:"id";i:397;s:7:"city_id";i:15;s:11:"external_id";s:12:"wadi-mustaba";s:4:"name";s:21:"وادي مستباء";s:7:"name_en";s:12:"Wadi Mustaba";s:11:"description";s:271:"وادي يقع في مديرية مستباء، ويتميز بأهميته الزراعية للمنطقة. [3] تنشط فيه الزراعة بشكل كبير بعد تدفق السيول الموسمية، مما يحوله إلى مساحات خضراء واسعة.";s:14:"description_en";s:200:"A valley located in the Mustaba district, known for its agricultural importance to the region. [3] Farming becomes highly active after the flow of seasonal floods, turning it into vast green expanses.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"موسمي";}s:8:"latitude";i:16;s:9:"longitude";d:43.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:29;a:17:{s:2:"id";i:398;s:7:"city_id";i:15;s:11:"external_id";s:16:"sadd-al-mahjarah";s:4:"name";s:19:"سد المحجرة";s:7:"name_en";s:15:"Al-Mahjarah Dam";s:11:"description";s:342:"سد صغير يقع في مديرية مبين، تم بناؤه بمبادرات مجتمعية لحصاد مياه الأمطار. [4] على الرغم من صغر حجمه، إلا أنه يلعب دوراً حيوياً في توفير المياه للمزارع المحيطة ويشكل معلماً مائياً في المنطقة.";s:14:"description_en";s:231:"A small dam located in the Mabyan district, built through community initiatives to harvest rainwater. [4] Despite its small size, it plays a vital role in providing water to surrounding farms and forms a water landmark in the area.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:9:"community";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:12:"مجتمعي";i:3;s:10:"زراعة";}s:8:"latitude";d:15.78;s:9:"longitude";d:43.63;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:15;a:13:{s:2:"id";i:24;s:4:"slug";s:6:"hadibo";s:4:"name";s:10:"حديبو";s:7:"name_en";s:6:"Hadibu";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:15:"hadibo_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:1;s:9:"landmarks";a:1:{i:0;a:17:{s:2:"id";i:612;s:7:"city_id";i:24;s:11:"external_id";s:14:"shabwah-castle";s:4:"name";s:17:"قلعة شبوة";s:7:"name_en";s:14:"Shabwah Castle";s:11:"description";s:236:"قلعة تاريخية تقع في محافظة شبوة، تتميز بموقعها الاستراتيجي وعمارتها الدفاعية المميزة. تعتبر من أهم المعالم التاريخية في المنطقة.";s:14:"description_en";s:209:"A historic castle situated in Shabwah Governorate, distinguished by its strategic location and distinctive defensive architecture. It is considered one of the most important historical landmarks in the region.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"عسكري";}s:8:"latitude";d:14.53;s:9:"longitude";i:47;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/shabwah/shabwah_castle1.jpg";i:1;s:44:"images/landmarks/shabwah/shabwah_castle2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:16;a:13:{s:2:"id";i:10;s:4:"slug";s:6:"dhamar";s:4:"name";s:8:"ذمار";s:7:"name_en";s:6:"Dhamar";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";N;s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:29;s:9:"landmarks";a:29:{i:0;a:17:{s:2:"id";i:277;s:7:"city_id";i:10;s:11:"external_id";s:19:"dhamar-grand-mosque";s:4:"name";s:36:"الجامع الكبير بذمار";s:7:"name_en";s:22:"Great Mosque of Dhamar";s:11:"description";s:363:"أحد أقدم المساجد في اليمن، يُقال إن أساساته تعود إلى فترة معاذ بن جبل. [1] يتميز بتصميمه الذي يجمع بين الأصالة والزخارف الإسلامية، وبمكتبته التي تضم مخطوطات نادرة، ويعتبر قلب المدينة الروحي والتاريخي.";s:14:"description_en";s:295:"One of the oldest mosques in Yemen, its foundations are said to date back to the time of Muadh bin Jabal. [1] It is characterized by its design combining authenticity with Islamic decorations, and its library housing rare manuscripts. It serves as the spiritual and historical heart of the city.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";i:3;s:12:"إسلامي";}s:8:"latitude";d:14.553;s:9:"longitude";d:44.405;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:48:"images/landmarks/dhamar/dhamar_grand_mosque1.jpg";i:1;s:48:"images/landmarks/dhamar/dhamar_grand_mosque2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:278;s:7:"city_id";i:10;s:11:"external_id";s:17:"dhamar-grand-park";s:4:"name";s:33:"حديقة ذمار الكبرى ";s:7:"name_en";s:17:"Dhamar Grand Park";s:11:"description";s:415:"تعتبر الحديقة العامة الأكبر والرئيسية في مدينة ذمار، وتقع في منطقة هرّان. [1, 2] تمثل المتنفس الأهم للعائلات داخل المدينة، وتضم مساحات خضراء واسعة، وألعابًا للأطفال، ومرافق للزوار، وتشهد إقبالًا كبيرًا في الأعياد والمناسبات. [1, 2]";s:14:"description_en";s:319:"Considered the largest and primary public park in Dhamar city, located in the Harran area. [1, 2] It represents the most important retreat for families within the city, boasting extensive green spaces, children's playgrounds, and visitor facilities. It draws massive crowds during holidays and special occasions. [1, 2]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:279;s:7:"city_id";i:10;s:11:"external_id";s:10:"dhamar-zoo";s:4:"name";s:34:"حديقة حيوانات ذمار";s:7:"name_en";s:10:"Dhamar Zoo";s:11:"description";s:292:"حديقة حيوانات صغيرة تقع في مدينة ذمار، وتعتبر وجهة ترفيهية وتعليمية للأطفال والعائلات. [8] تضم مجموعة من الحيوانات والطيور، وتعد متنفسًا إضافيًا داخل المدينة. [8]";s:14:"description_en";s:239:"A small zoo located in the city of Dhamar, considered an educational and recreational destination for children and families. [8] It houses a collection of animals and birds and serves as an additional recreational spot within the city. [8]";s:10:"categories";a:4:{i:0;s:3:"zoo";i:1;s:6:"family";i:2;s:12:"recreational";i:3;s:11:"educational";}s:14:"category_names";a:4:{i:0;s:21:"حديقة حيوان";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";i:3;s:12:"تعليمي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:280;s:7:"city_id";i:10;s:11:"external_id";s:26:"baynun-archaeological-site";s:4:"name";s:36:"مدينة بينون الأثرية";s:7:"name_en";s:27:"Bainoun Archaeological City";s:11:"description";s:331:"أطلال مدينة حميرية قديمة كانت من أهم المدن في مملكة حمير. [2] تشتهر ببقايا قصر بينون ونفقها الصخري الشهير الذي كان جزءاً من نظام دفاعي وهندسي متطور، وهي شاهد على عظمة الحضارة الحميرية.";s:14:"description_en";s:316:"The ruins of an ancient Himyarite city that was one of the most important in the Himyarite Kingdom. [2] It is famous for the remains of Bainoun Palace and its renowned rock tunnel, which was part of an advanced defensive and engineering system, standing as a testament to the greatness of the Himyarite civilization.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:9:"himyarite";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:10:"حميري";}s:8:"latitude";d:14.65;s:9:"longitude";d:44.55;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/dhamar/baynun_site1.jpg";i:1;s:40:"images/landmarks/dhamar/baynun_site2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:281;s:7:"city_id";i:10;s:11:"external_id";s:23:"dhamar-ali-yahbur-ruins";s:4:"name";s:35:"أطلال ذمار علي يهبر";s:7:"name_en";s:26:"Ruins of Dhamar Ali Yahbur";s:11:"description";s:310:"موقع أثري يعتقد أنه كان من العواصم القديمة لمملكة سبأ وذي ريدان. [3] يضم الموقع نقوشاً مسندية وبقايا مبانٍ ضخمة، وهو دليل على الأهمية التاريخية لمنطقة ذمار في اليمن القديم.";s:14:"description_en";s:279:"An archaeological site believed to have been one of the ancient capitals of the Kingdom of Saba and Dhu Raydan. [3] The site contains Musnad inscriptions and the remains of massive buildings, serving as evidence of the historical importance of the Dhamar region in ancient Yemen.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:7:"sabaean";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:8:"سبئي";}s:8:"latitude";d:14.58;s:9:"longitude";d:44.42;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/landmarks/dhamar/dhamar_ali_yahbur1.jpg";i:1;s:46:"images/landmarks/dhamar/dhamar_ali_yahbur2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:282;s:7:"city_id";i:10;s:11:"external_id";s:24:"al-amiriya-school-dhamar";s:4:"name";s:59:"المدرسة الشمسية (العامرية بذمار)";s:7:"name_en";s:39:"Al-Shamsiya Madrasa (Amiriya in Dhamar)";s:11:"description";s:326:"مدرسة تاريخية تعود إلى العصر الطاهري، بناها السلطان عامر بن عبدالوهاب. [4] تتميز بتصميمها المعماري الإسلامي الفريد وقبابها المتعددة، وكانت مركزاً هاماً للعلم والتعليم في المنطقة.";s:14:"description_en";s:244:"A historical school dating back to the Tahirid era, built by Sultan Amir bin Abdulwahab. [4] It is distinguished by its unique Islamic architectural design and multiple domes, and was an important center for science and education in the region.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:7:"islamic";i:2;s:13:"architectural";i:3;s:6:"school";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:12:"إسلامي";i:2;s:12:"معماري";i:3;s:10:"مدرسة";}s:8:"latitude";d:14.554;s:9:"longitude";d:44.406;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/landmarks/dhamar/al_amiriya_dhamar1.jpg";i:1;s:46:"images/landmarks/dhamar/al_amiriya_dhamar2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:283;s:7:"city_id";i:10;s:11:"external_id";s:22:"dhamar-regional-museum";s:4:"name";s:34:"متحف ذمار الإقليمي";s:7:"name_en";s:22:"Dhamar Regional Museum";s:11:"description";s:340:"يحتوي على مجموعة واسعة من القطع الأثرية التي تمثل مختلف الحقب التاريخية لمحافظة ذمار، من العصور الحجرية إلى العصور الإسلامية. [5] يعتبر نافذة هامة للتعرف على تاريخ المنطقة الغني والمتنوع.";s:14:"description_en";s:246:"It contains a wide collection of artifacts representing the various historical eras of Dhamar Governorate, from the Stone Age to the Islamic eras. [5] It is considered an important window to learn about the rich and diverse history of the region.";s:10:"categories";a:4:{i:0;s:6:"museum";i:1;s:14:"archaeological";i:2;s:10:"historical";i:3;s:8:"cultural";}s:14:"category_names";a:4:{i:0;s:8:"متحف";i:1;s:8:"أثري";i:2;s:12:"تاريخي";i:3;s:10:"ثقافي";}s:8:"latitude";d:14.56;s:9:"longitude";d:44.41;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/dhamar/dhamar_museum1.jpg";i:1;s:42:"images/landmarks/dhamar/dhamar_museum2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:284;s:7:"city_id";i:10;s:11:"external_id";s:11:"hiran-ruins";s:4:"name";s:23:"أطلال هِجران";s:7:"name_en";s:15:"Ruins of Hijran";s:11:"description";s:300:"موقع أثري قديم يقع في منطقة آنس، ويحتوي على بقايا مدينة حميرية محصنة. [6] يتميز الموقع بوجود صهاريج مياه منحوتة في الصخر ومقابر صخرية، مما يدل على استيطان قديم ومتقدم.";s:14:"description_en";s:222:"An ancient archaeological site located in the Anis area, containing the remains of a fortified Himyarite city. [6] The site features rock-carved water cisterns and rock tombs, indicating an ancient and advanced settlement.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:9:"himyarite";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:10:"حميري";}s:8:"latitude";d:14.75;s:9:"longitude";d:44.25;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/dhamar/hiran_ruins1.jpg";i:1;s:40:"images/landmarks/dhamar/hiran_ruins2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:285;s:7:"city_id";i:10;s:11:"external_id";s:15:"dhamar-old-city";s:4:"name";s:34:"مدينة ذمار القديمة";s:7:"name_en";s:18:"Old City of Dhamar";s:11:"description";s:368:"النسيج الحضري التاريخي للمدينة، الذي يضم أحياء وحارات قديمة. [7] على الرغم من تأثرها بالتوسع الحديث، لا تزال تحتفظ ببعض ملامحها التقليدية من خلال مساجدها القديمة وبعض المنازل ذات الطابع المعماري المميز.";s:14:"description_en";s:267:"The historical urban fabric of the city, which includes old neighborhoods and alleys. [7] Despite being affected by modern expansion, it still retains some of its traditional features through its old mosques and some houses with a distinctive architectural character.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";}s:8:"latitude";d:14.55;s:9:"longitude";d:44.4;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/dhamar/dhamar_old_city1.jpg";i:1;s:44:"images/landmarks/dhamar/dhamar_old_city2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:286;s:7:"city_id";i:10;s:11:"external_id";s:19:"dawr-an-hot-springs";s:4:"name";s:30:"حمامات ضوران آنس";s:7:"name_en";s:18:"Dawran Aness Baths";s:11:"description";s:390:"مجموعة من الينابيع المعدنية الحارة الطبيعية التي تقع في مديرية ضوران آنس. [8] تعتبر من أشهر مواقع السياحة العلاجية في اليمن، حيث يقصدها الزوار للاستشفاء بمياهها الكبريتية التي يعتقد أنها تعالج أمراض الجلد والمفاصل.";s:14:"description_en";s:269:"A group of natural hot mineral springs located in the Dawran Aness district. [8] They are considered one of the most famous medical tourism sites in Yemen, visited by people seeking healing from its sulfurous waters, which are believed to treat skin and joint diseases.";s:10:"categories";a:4:{i:0;s:11:"therapeutic";i:1;s:7:"natural";i:2;s:10:"hot-spring";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:10:"علاجي";i:1;s:10:"طبيعي";i:2;s:17:"ينبوع حار";i:3;s:8:"مائي";}s:8:"latitude";d:14.85;s:9:"longitude";d:44.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/landmarks/dhamar/dawran_hot_springs1.jpg";i:1;s:47:"images/landmarks/dhamar/dawran_hot_springs2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:287;s:7:"city_id";i:10;s:11:"external_id";s:26:"yislah-archaeological-site";s:4:"name";s:30:"موقع يسلح الأثري";s:7:"name_en";s:26:"Yaslah Archaeological Site";s:11:"description";s:324:"موقع تاريخي يقع على الطريق بين صنعاء وذمار، وكان مركزاً دينياً هاماً في فترة ما قبل الإسلام. [9] يضم بقايا معبد قديم ونقوشاً مسندية، وكان أحد المراكز الهامة على طريق البخور القديم.";s:14:"description_en";s:272:"A historical site located on the road between Sana'a and Dhamar, which was an important religious center in the pre-Islamic period. [9] It contains the remains of an ancient temple and Musnad inscriptions, and was one of the important centers on the ancient Incense Route.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:9:"religious";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:8:"ديني";}s:8:"latitude";d:15.05;s:9:"longitude";d:44.3;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/dhamar/yislah_site1.jpg";i:1;s:40:"images/landmarks/dhamar/yislah_site2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:17:{s:2:"id";i:288;s:7:"city_id";i:10;s:11:"external_id";s:12:"jabal-dawran";s:4:"name";s:24:"جبل ضوران آنس";s:7:"name_en";s:18:"Mount Dawran Aness";s:11:"description";s:309:"جبل بركاني شاهق يطل على منطقة ضوران آنس. [10] يعتبر معلماً طبيعياً بارزاً، وتنتشر على سفوحه القرى الجميلة والمدرجات الزراعية، ويوفر إطلالات بانورامية على المنطقة المحيطة.";s:14:"description_en";s:227:"A towering volcanic mountain overlooking the Dawran Aness area. [10] It is a prominent natural landmark, with beautiful villages and agricultural terraces spread on its slopes, providing panoramic views of the surrounding area.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:8:"volcanic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:6:"جبل";i:2;s:12:"إطلالة";i:3;s:12:"بركاني";}s:8:"latitude";d:14.86;s:9:"longitude";d:44.14;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/dhamar/jabal_dawran1.jpg";i:1;s:41:"images/landmarks/dhamar/jabal_dawran2.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:17:{s:2:"id";i:289;s:7:"city_id";i:10;s:11:"external_id";s:17:"wadi-rimaa-source";s:4:"name";s:28:"منابع وادي رماع";s:7:"name_en";s:20:"Sources of Wadi Rima";s:11:"description";s:321:"أحد أكبر أودية اليمن، تنبع روافده الرئيسية من مرتفعات آنس ووصاب العالي في محافظة ذمار. [2] تتميز منطقة المنابع بجمالها الطبيعي الأخاذ وتدفق المياه الذي يغذي مساحات زراعية واسعة.";s:14:"description_en";s:261:"One of the largest valleys in Yemen, its main tributaries originate from the highlands of Anis and Wusab Al-Ali in Dhamar Governorate. [2] The source area is distinguished by its breathtaking natural beauty and water flow that irrigates vast agricultural lands.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:12:"water-source";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:17:"منبع مائي";i:3;s:10:"زراعي";}s:8:"latitude";d:14.65;s:9:"longitude";d:44.1;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/water/dhamar/wadi_rimaa_source1.jpg";i:1;s:42:"images/water/dhamar/wadi_rimaa_source2.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:17:{s:2:"id";i:290;s:7:"city_id";i:10;s:11:"external_id";s:12:"dhamar-plain";s:4:"name";s:35:"قاع جهران (سهل ذمار)";s:7:"name_en";s:25:"Qa' Jahran (Dhamar Plain)";s:11:"description";s:315:"سهل واسع وخصب يقع شمال مدينة ذمار، ويعتبر من أهم المناطق الزراعية في المرتفعات اليمنية. [3] تتجمع فيه مياه الأمطار والسيول، مما يجعله حوضاً مائياً طبيعياً ضخماً يدعم الزراعة.";s:14:"description_en";s:241:"A wide and fertile plain located north of Dhamar city, considered one of the most important agricultural areas in the Yemeni highlands. [3] Rainwater and floods gather in it, making it a massive natural water basin that supports agriculture.";s:10:"categories";a:4:{i:0;s:5:"plain";i:1;s:11:"agriculture";i:2;s:11:"water-basin";i:3;s:6:"nature";}s:14:"category_names";a:4:{i:0;s:6:"سهل";i:1;s:10:"زراعي";i:2;s:15:"حوض مائي";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.7;s:9:"longitude";d:44.35;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/water/dhamar/jahran_plain1.jpg";i:1;s:37:"images/water/dhamar/jahran_plain2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:17:{s:2:"id";i:291;s:7:"city_id";i:10;s:11:"external_id";s:17:"wadi-al-hayat-dam";s:4:"name";s:26:"سد وادي الحياة";s:7:"name_en";s:17:"Wadi Al-Hayat Dam";s:11:"description";s:287:"سد يقع في منطقة وصاب، بني بهدف حصاد مياه الأمطار وتوفير المياه للزراعة. [5] شكل السد بحيرة صغيرة أضافت منظراً جمالياً للمنطقة وساهمت في دعم المزارعين المحليين.";s:14:"description_en";s:217:"A dam located in the Wusab area, built to harvest rainwater and provide water for agriculture. [5] The dam formed a small lake that added an aesthetic landscape to the area and contributed to supporting local farmers.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:16:"water-management";i:2;s:11:"agriculture";i:3;s:4:"lake";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:19:"إدارة مياه";i:2;s:10:"زراعي";i:3;s:10:"بحيرة";}s:8:"latitude";d:14.45;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/water/dhamar/wadi_al_hayat_dam1.jpg";i:1;s:42:"images/water/dhamar/wadi_al_hayat_dam2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:15;a:17:{s:2:"id";i:292;s:7:"city_id";i:10;s:11:"external_id";s:20:"otmah-nature-reserve";s:4:"name";s:36:"محمية عتمة الطبيعية";s:7:"name_en";s:20:"Utmah Nature Reserve";s:11:"description";s:307:"منطقة جبلية ذات غطاء نباتي كثيف وتنوع بيولوجي فريد، وتعتبر محمية طبيعية. [6] تتخلل المحمية العديد من الينابيع والشلالات الموسمية الصغيرة، وهي مصدر هام للمياه في المنطقة.";s:14:"description_en";s:233:"A mountainous area with dense vegetation cover and unique biodiversity, considered a nature reserve. [6] The reserve is interspersed with many springs and small seasonal waterfalls, serving as an important water source in the region.";s:10:"categories";a:4:{i:0;s:14:"nature-reserve";i:1;s:6:"forest";i:2;s:12:"water-spring";i:3;s:12:"biodiversity";}s:14:"category_names";a:4:{i:0;s:23:"محمية طبيعية";i:1;s:8:"غابة";i:2;s:13:"عين ماء";i:3;s:17:"تنوع حيوي";}s:8:"latitude";d:14.4;s:9:"longitude";d:44.05;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/water/dhamar/otmah_reserve1.jpg";i:1;s:38:"images/water/dhamar/otmah_reserve2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:16;a:17:{s:2:"id";i:293;s:7:"city_id";i:10;s:11:"external_id";s:11:"wadi-kharif";s:4:"name";s:17:"وادي خارف";s:7:"name_en";s:11:"Wadi Kharif";s:11:"description";s:262:"وادي يقع في مديرية جهران، ويتميز بأراضيه الزراعية الخصبة. [7] يعتبر مجرى هاماً للسيول الموسمية التي تغذي الآبار والمياه الجوفية في سهل قاع جهران.";s:14:"description_en";s:197:"A valley located in the Jahran district, characterized by its fertile agricultural lands. [7] It is an important channel for seasonal floods that feed wells and groundwater in the Qa' Jahran plain.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:12:"water-course";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:17:"مجرى مائي";}s:8:"latitude";d:14.72;s:9:"longitude";d:44.45;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/water/dhamar/wadi_kharif1.jpg";i:1;s:36:"images/water/dhamar/wadi_kharif2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:17;a:17:{s:2:"id";i:294;s:7:"city_id";i:10;s:11:"external_id";s:23:"ancient-cisterns-dhamar";s:4:"name";s:48:"الصهاريج الحميرية القديمة";s:7:"name_en";s:26:"Ancient Himyarite Cisterns";s:11:"description";s:297:"تنتشر في العديد من المواقع الأثرية بذمار، مثل هجران وبينون، صهاريج (برك) مياه قديمة منحوتة في الصخر. [8] تمثل هذه الصهاريج نظام إدارة مياه متطور يعود لعصر مملكة حمير.";s:14:"description_en";s:242:"Spread across many archaeological sites in Dhamar, such as Hijran and Bainoun, are ancient water cisterns (pools) carved into the rock. [8] These cisterns represent an advanced water management system dating back to the Himyarite Kingdom era.";s:10:"categories";a:4:{i:0;s:7:"cistern";i:1;s:14:"archaeological";i:2;s:10:"historical";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:10:"صهريج";i:1;s:8:"أثري";i:2;s:12:"تاريخي";i:3;s:8:"مائي";}s:8:"latitude";d:14.75;s:9:"longitude";d:44.25;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/water/dhamar/ancient_cisterns1.jpg";i:1;s:41:"images/water/dhamar/ancient_cisterns2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:18;a:17:{s:2:"id";i:295;s:7:"city_id";i:10;s:11:"external_id";s:9:"dabaa-dam";s:4:"name";s:13:"سد ضبعة";s:7:"name_en";s:11:"Daba'ah Dam";s:11:"description";s:289:"سد صغير يقع في مديرية عنس، تم بناؤه لحصاد مياه الأمطار. [10] على الرغم من صغر حجمه، إلا أنه يلعب دوراً في توفير المياه للمزارع المحيطة ويشكل منظراً مائياً هادئاً.";s:14:"description_en";s:182:"A small dam located in the Ans district, built to harvest rainwater. [10] Despite its small size, it plays a role in providing water to surrounding farms and forms a calm waterscape.";s:10:"categories";a:3:{i:0;s:3:"dam";i:1;s:16:"water-management";i:2;s:11:"agriculture";}s:14:"category_names";a:3:{i:0;s:4:"سد";i:1;s:19:"إدارة مياه";i:2;s:10:"زراعي";}s:8:"latitude";d:14.58;s:9:"longitude";d:44.58;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:34:"images/water/dhamar/dabaa_dam1.jpg";i:1;s:34:"images/water/dhamar/dabaa_dam2.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:19;a:17:{s:2:"id";i:296;s:7:"city_id";i:10;s:11:"external_id";s:23:"al-dhil-waterfall-otmah";s:4:"name";s:30:"شلال الذيل (عتمة)";s:7:"name_en";s:26:"Al-Thail Waterfall (Utmah)";s:11:"description";s:276:"أشهر شلالات محمية عتمة، يتدفق بغزارة من جرف صخري مرتفع وسط غطاء نباتي كثيف. [1] يعتبر رمزاً للجمال الطبيعي في المديرية ووجهة رئيسية للزوار ومحبي الطبيعة.";s:14:"description_en";s:235:"The most famous waterfall in the Utmah Reserve, flowing abundantly from a high rocky cliff amidst dense vegetation. [1] It is considered a symbol of natural beauty in the district and a major destination for visitors and nature lovers.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:14:"nature-reserve";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:23:"محمية طبيعية";}s:8:"latitude";d:14.41;s:9:"longitude";d:44.06;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/waterfalls/dhamar/al_dhil_waterfall1.jpg";i:1;s:47:"images/waterfalls/dhamar/al_dhil_waterfall2.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:20;a:17:{s:2:"id";i:297;s:7:"city_id";i:10;s:11:"external_id";s:23:"wadi-al-ahjer-waterfall";s:4:"name";s:54:"شلال وادي الأحجر (وصاب العالي)";s:7:"name_en";s:38:"Wadi Al-Ahjar Waterfall (Wusab Al-Ali)";s:11:"description";s:285:"شلال هادر وقوي يقع في وادي الأحجر، يتميز بارتفاعه وقوة تدفقه خصوصاً في مواسم الأمطار. [2] يصب في بركة مائية كبيرة، مما يجعله مكاناً مثالياً للمغامرة والسباحة.";s:14:"description_en";s:231:"A roaring and powerful waterfall located in Wadi Al-Ahjar, characterized by its height and strong flow, especially during the rainy seasons. [2] It pours into a large water pool, making it an ideal place for adventure and swimming.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:8:"powerful";i:3;s:8:"swimming";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:6:"قوي";i:3;s:10:"سباحة";}s:8:"latitude";d:14.49;s:9:"longitude";d:43.78;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:53:"images/waterfalls/dhamar/wadi_al_ahjer_waterfall1.jpg";i:1;s:53:"images/waterfalls/dhamar/wadi_al_ahjer_waterfall2.jpg";}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:21;a:17:{s:2:"id";i:298;s:7:"city_id";i:10;s:11:"external_id";s:28:"otmah-nature-reserve-springs";s:4:"name";s:45:"ينابيع ومساقط محمية عتمة";s:7:"name_en";s:37:"Springs and Cascades of Utmah Reserve";s:11:"description";s:319:"بالإضافة للشلالات الكبيرة، تزخر محمية عتمة بشبكة من الينابيع العذبة والمساقط المائية الصغيرة التي تتدفق بين الصخور والمدرجات، مما يجعل المحمية بأكملها حديقة مائية طبيعية. [3]";s:14:"description_en";s:209:"In addition to the large waterfalls, the Utmah Reserve is full of a network of fresh springs and small water cascades that flow between rocks and terraces, making the entire reserve a natural water garden. [3]";s:10:"categories";a:4:{i:0;s:14:"nature-reserve";i:1;s:12:"water-spring";i:2;s:6:"forest";i:3;s:12:"biodiversity";}s:14:"category_names";a:4:{i:0;s:23:"محمية طبيعية";i:1;s:13:"عين ماء";i:2;s:8:"غابة";i:3;s:17:"تنوع حيوي";}s:8:"latitude";d:14.4;s:9:"longitude";d:44.05;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/water/dhamar/otmah_reserve1.jpg";i:1;s:38:"images/water/dhamar/otmah_reserve2.jpg";}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:22;a:17:{s:2:"id";i:299;s:7:"city_id";i:10;s:11:"external_id";s:24:"wusab-general-waterfalls";s:4:"name";s:59:"شلالات وصابين الموسمية المتعددة";s:7:"name_en";s:40:"Multiple Seasonal Waterfalls of Wusabain";s:11:"description";s:344:"تتميز جبال وصابين (العالي والسافل) بانحدارها الشديد، مما يؤدي إلى تشكل العشرات من الشلالات المؤقتة بعد هطول الأمطار. [4] تخلق هذه الشلالات لوحات طبيعية مائية بديعة على امتداد السفوح الجبلية.";s:14:"description_en";s:250:"The mountains of Wusabain (Al-Ali and Al-Safil) are characterized by their steep slopes, leading to the formation of dozens of temporary waterfalls after rainfall. [4] These waterfalls create magnificent natural waterscapes along the mountain slopes.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"nature";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:10:"طبيعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.48;s:9:"longitude";d:43.8;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/water/dhamar/wusab_waterfalls1.jpg";i:1;s:41:"images/water/dhamar/wusab_waterfalls2.jpg";}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:23;a:17:{s:2:"id";i:300;s:7:"city_id";i:10;s:11:"external_id";s:25:"al-sharab-waterfall-otmah";s:4:"name";s:32:"شلال الشارب (عتمة)";s:7:"name_en";s:27:"Al-Sharib Waterfall (Utmah)";s:11:"description";s:276:"شلال جميل في محمية عتمة، سُمي بذلك لشكله الفريد عند تدفقه على الصخور. [5] يوفر بفضل موقعه المنعزل تجربة هادئة للاستمتاع بخرير المياه وجمال الطبيعة البكر.";s:14:"description_en";s:232:"A beautiful waterfall in the Utmah Reserve, named for its unique shape as it flows over the rocks. [5] Thanks to its secluded location, it offers a peaceful experience to enjoy the murmuring waters and the beauty of pristine nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:8:"secluded";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:10:"منعزل";}s:8:"latitude";d:14.43;s:9:"longitude";d:44.04;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/waterfalls/dhamar/al_sharab_waterfall1.jpg";i:1;s:49:"images/waterfalls/dhamar/al_sharab_waterfall2.jpg";}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:24;a:17:{s:2:"id";i:301;s:7:"city_id";i:10;s:11:"external_id";s:21:"wadi-zabid-headwaters";s:4:"name";s:50:"منابع وادي زبيد (وصاب وعتمة)";s:7:"name_en";s:39:"Sources of Wadi Zabid (Wusab and Utmah)";s:11:"description";s:300:"تعتبر مرتفعات وصابين وعتمة هي المصدر الرئيسي لمياه وادي زبيد الشهير. [6] تتميز هذه المناطق بأوديتها العميقة الخضراء ومياهها الجارية التي تشكل بداية هذا الوادي الهام.";s:14:"description_en";s:233:"The highlands of Wusabain and Utmah are considered the main source of water for the famous Wadi Zabid. [6] These areas are distinguished by their deep green valleys and flowing waters that form the beginning of this important valley.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:12:"water-source";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:17:"منبع مائي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.3;s:9:"longitude";d:43.95;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/water/dhamar/wadi_zabid_source1.jpg";i:1;s:42:"images/water/dhamar/wadi_zabid_source2.jpg";}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:25;a:17:{s:2:"id";i:302;s:7:"city_id";i:10;s:11:"external_id";s:21:"bani-fakhri-waterfall";s:4:"name";s:48:"شلال بني فخري (وصاب السافل)";s:7:"name_en";s:38:"Bani Fakhri Waterfall (Wusab Al-Safil)";s:11:"description";s:233:"شلال موسمي بديع يتدفق عبر المدرجات الزراعية الخضراء في منطقة بني فخري، راسماً لوحة فنية تجمع بين إبداع الإنسان وجمال الطبيعة. [7]";s:14:"description_en";s:191:"A marvelous seasonal waterfall flowing through the green agricultural terraces in the Bani Fakhri area, painting an artistic scene that combines human creativity and the beauty of nature. [7]";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:8:"seasonal";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:10:"موسمي";i:3;s:10:"زراعي";}s:8:"latitude";d:14.35;s:9:"longitude";d:43.75;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:51:"images/waterfalls/dhamar/bani_fakhri_waterfall1.jpg";i:1;s:51:"images/waterfalls/dhamar/bani_fakhri_waterfall2.jpg";}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:26;a:17:{s:2:"id";i:303;s:7:"city_id";i:10;s:11:"external_id";s:19:"al-mawhab-waterfall";s:4:"name";s:32:"شلال الموهب (عتمة)";s:7:"name_en";s:27:"Al-Mawhib Waterfall (Utmah)";s:11:"description";s:226:"شلال بارز في عزلة الموهب بمديرية عتمة، يشتهر بارتفاعه وجمال محيطه الطبيعي، ويعتبر متنفساً هاماً للسكان المحليين والزوار. [8]";s:14:"description_en";s:192:"A prominent waterfall in the Al-Mawhib sub-district of Utmah district, famous for its height and the beauty of its natural surroundings. It is an important retreat for locals and visitors. [8]";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:12:"ترفيهي";}s:8:"latitude";d:14.38;s:9:"longitude";d:44.08;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/waterfalls/dhamar/al_mawhab_waterfall1.jpg";i:1;s:49:"images/waterfalls/dhamar/al_mawhab_waterfall2.jpg";}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:27;a:17:{s:2:"id";i:304;s:7:"city_id";i:10;s:11:"external_id";s:19:"al-jabin-waterfalls";s:4:"name";s:62:"شلالات ومساقط الجبين (وصاب العالي)";s:7:"name_en";s:50:"Waterfalls and Cascades of Al-Jabin (Wusab Al-Ali)";s:11:"description";s:248:"مجموعة من المساقط المائية المتفرقة التي تظهر في منطقة الجبين بعد الأمطار، محولة المنطقة إلى منظر طبيعي ريفي هادئ تتخلله أصوات المياه. [9]";s:14:"description_en";s:171:"A group of scattered water cascades that appear in the Al-Jabin area after rainfall, turning the region into a quiet rural landscape punctuated by the sounds of water. [9]";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:5:"rural";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:8:"ريفي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.51;s:9:"longitude";d:43.82;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/waterfalls/dhamar/al_jabin_waterfalls1.jpg";i:1;s:49:"images/waterfalls/dhamar/al_jabin_waterfalls2.jpg";}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:28;a:17:{s:2:"id";i:305;s:7:"city_id";i:10;s:11:"external_id";s:23:"al-sada-waterfall-otmah";s:4:"name";s:32:"شلال السادة (عتمة)";s:7:"name_en";s:26:"Al-Sadah Waterfall (Utmah)";s:11:"description";s:240:"شلال جميل يقع في وادٍ خصب، ويتطلب الوصول إليه بعض المشي، مما يجعله مكافأة رائعة لمحبي التنزه واستكشاف المسارات الطبيعية البعيدة. [10]";s:14:"description_en";s:183:"A beautiful waterfall located in a fertile valley, requiring a bit of a hike to reach, making it a wonderful reward for hiking enthusiasts and explorers of remote natural trails. [10]";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:6:"hiking";i:3;s:4:"wadi";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:17:"تنزه جبلي";i:3;s:8:"وادي";}s:8:"latitude";d:14.45;s:9:"longitude";d:44.02;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/waterfalls/dhamar/al_sada_waterfall1.jpg";i:1;s:47:"images/waterfalls/dhamar/al_sada_waterfall2.jpg";}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:17;a:13:{s:2:"id";i:28;s:4:"slug";s:7:"saaaada";s:4:"name";s:8:"سعده";s:7:"name_en";s:7:"sadddda";s:11:"description";s:97:"مدينة ساحليه رهيبة جدا جدا ,وهي بلاد السلطان العليسيس";s:14:"description_en";s:73:"A very, very awesome coastal city, and it is the land of Sultan Al-Alisi.";s:9:"image_url";s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT3AoG4tFGOf2ntoxY1jdoDVml8i8MALlAbqQ&s";s:6:"status";s:9:"published";s:8:"category";s:7:"coastal";s:15:"landmarks_count";i:2;s:9:"landmarks";a:2:{i:0;a:17:{s:2:"id";i:619;s:7:"city_id";i:28;s:11:"external_id";N;s:4:"name";s:14:"الشعوبة";s:7:"name_en";s:11:"Al-Sha'ubah";s:11:"description";s:70:"معلم ساحلي يضم انواع اسماك بحريه هائلة";s:14:"description_en";s:62:"A coastal landmark featuring a massive variety of marine fish.";s:10:"categories";a:1:{i:0;s:10:"historical";}s:14:"category_names";a:1:{i:0;s:12:"تاريخي";}s:8:"latitude";d:13.3172308;s:9:"longitude";d:44.2815429;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/q1JVBvDXHQ6drASJ6";s:6:"images";a:1:{i:0;s:148:"https://skylifeholidays.com/wp-content/uploads/2024/08/%D8%A7%D9%84%D8%B3%D9%8A%D8%A7%D8%AD%D8%A9-%D9%81%D9%8A-%D8%B7%D9%88%D9%83%D9%8A%D9%88-4.webp";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-01T21:43:35.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:1;a:17:{s:2:"id";i:620;s:7:"city_id";i:28;s:11:"external_id";N;s:4:"name";s:14:"السقيعي";s:7:"name_en";s:10:"Al-Suqay'i";s:11:"description";s:48:"من افضل السدود في المديريه";s:14:"description_en";s:37:"One of the best dams in the district.";s:10:"categories";a:1:{i:0;s:10:"historical";}s:14:"category_names";a:1:{i:0;s:12:"تاريخي";}s:8:"latitude";d:13.3172308;s:9:"longitude";d:44.2815429;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/DbL9gtg9LZJoynjq6";s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTtNsEN1D2OVyFQSjQG8dDnEYnyWotkEW1Yqw&s";}s:10:"sort_order";i:999;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-04-01T22:19:35.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-04-01T21:37:46.000000Z";s:10:"updated_at";s:27:"2026-04-27T18:34:13.000000Z";}i:18;a:13:{s:2:"id";i:8;s:4:"slug";s:7:"socotra";s:4:"name";s:10:"سقطرى";s:7:"name_en";s:7:"Socotra";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:18:"socotra_island.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:29;s:9:"landmarks";a:29:{i:0;a:17:{s:2:"id";i:237;s:7:"city_id";i:8;s:11:"external_id";s:19:"socotra-dragon-tree";s:4:"name";s:28:"شجرة دم الأخوين";s:7:"name_en";s:17:"Dragon Blood Tree";s:11:"description";s:318:"من أشهر الأشجار النادرة في جزيرة سقطرى، تتميز بشكلها الفريد الذي يشبه المظلة وعصارتها الحمراء التي تستخدم في الطب التقليدي. [1] تعتبر رمزاً للتنوع البيولوجي الفريد في الجزيرة.";s:14:"description_en";s:207:"One of the most famous rare trees on Socotra Island, characterized by its unique umbrella-like shape and its red sap used in traditional medicine. [1] It is a symbol of the island's exceptional biodiversity.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:9:"botanical";i:2;s:6:"unique";i:3;s:6:"iconic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"نباتي";i:2;s:8:"فريد";i:3;s:12:"أيقوني";}s:8:"latitude";d:12.475;s:9:"longitude";d:54.02;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/landmarks/socotra/socotra_dragon_tree1.jpg";i:1;s:49:"images/landmarks/socotra/socotra_dragon_tree2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:1;a:17:{s:2:"id";i:238;s:7:"city_id";i:8;s:11:"external_id";s:16:"qulansiyah-beach";s:4:"name";s:21:"شاطئ قلنسية";s:7:"name_en";s:16:"Qalansiyah Beach";s:11:"description";s:316:"أحد أجمل الشواطئ في العالم، يقع في الجزء الغربي من الجزيرة. [2] يتميز برماله البيضاء الناعمة كالبودرة ومياهه الفيروزية الصافية، وتتناثر على أطرافه التكوينات الصخرية الفريدة.";s:14:"description_en";s:210:"One of the most beautiful beaches in the world, located in the western part of the island. [2] It boasts powder-soft white sand and clear turquoise waters, with unique rock formations scattered along its edges.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:12:"ترفيهي";}s:8:"latitude";d:12.665;s:9:"longitude";d:53.485;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/landmarks/socotra/qulansiyah_beach1.jpg";i:1;s:46:"images/landmarks/socotra/qulansiyah_beach2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:2;a:17:{s:2:"id";i:239;s:7:"city_id";i:8;s:11:"external_id";s:13:"dixam-plateau";s:4:"name";s:17:"هضبة دكسم";s:7:"name_en";s:14:"Diksam Plateau";s:11:"description";s:334:"هضبة واسعة تعتبر الموطن الرئيسي لأشجار دم الأخوين، حيث تشكل غابات صغيرة منها. [3] توفر الهضبة إطلالات مذهلة على وادي درهور العميق، وتعتبر من أهم المناطق لمشاهدة التنوع النباتي للجزيرة.";s:14:"description_en";s:253:"A vast plateau considered the primary habitat for Dragon Blood trees, forming small forests of them. [3] The plateau offers breathtaking views of the deep Wadi Dirhur and is one of the most important areas for observing the island's botanical diversity.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:7:"plateau";i:2;s:9:"botanical";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"هضبة";i:2;s:10:"نباتي";i:3;s:12:"إطلالة";}s:8:"latitude";d:12.48;s:9:"longitude";d:53.98;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/socotra/dixam_plateau1.jpg";i:1;s:43:"images/landmarks/socotra/dixam_plateau2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:3;a:17:{s:2:"id";i:240;s:7:"city_id";i:8;s:11:"external_id";s:11:"shoab-beach";s:4:"name";s:17:"شاطئ شعُب";s:7:"name_en";s:11:"Shuab Beach";s:11:"description";s:318:"شاطئ منعزل لا يمكن الوصول إليه إلا عن طريق القوارب من قلنسية. [4] الرحلة إليه غالباً ما تصاحبها مشاهدة الدلافين، ويتميز الشاطئ بجماله البكر وهدوئه المطل، مما يجعله تجربة فريدة.";s:14:"description_en";s:229:"A secluded beach accessible only by boat from Qalansiyah. [4] The boat trip is often accompanied by dolphin sightings, and the beach is distinguished by its pristine beauty and absolute tranquility, making it a unique experience.";s:10:"categories";a:5:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:8:"secluded";i:3;s:7:"boating";i:4;s:8:"wildlife";}s:14:"category_names";a:5:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:10:"منعزل";i:3;s:10:"قوارب";i:4;s:17:"حياة برية";}s:8:"latitude";d:12.62;s:9:"longitude";d:53.38;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/socotra/shoab_beach1.jpg";i:1;s:41:"images/landmarks/socotra/shoab_beach2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:4;a:17:{s:2:"id";i:241;s:7:"city_id";i:8;s:11:"external_id";s:14:"al-ghurfa-park";s:4:"name";s:23:"منتزه الغرفة";s:7:"name_en";s:16:"Al-Ghurafah Park";s:11:"description";s:330:"يقع في بلدة الغرفة المجاورة لشبام، وهو أحد المنتزهات القليلة المنظمة في المنطقة. [6] يضم المنتزه ألعابًا للأطفال ومساحات للجلوس، ويعتبر وجهة للعائلات من شبام والمناطق المحيطة بها. [6]";s:14:"description_en";s:237:"Located in the town of Al-Ghurafah, adjacent to Shibam, it is one of the few organized parks in the area. [6] Featuring children's rides and seating spaces, it acts as a destination for families from Shibam and the surrounding areas. [6]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"منتزه";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:5;a:17:{s:2:"id";i:242;s:7:"city_id";i:8;s:11:"external_id";s:16:"shibam-viewpoint";s:4:"name";s:41:"مطل شبام (نقطة التصوير)";s:7:"name_en";s:29:"Shibam Viewpoint (Photo Spot)";s:11:"description";s:344:"منطقة مرتفعة تقع قبالة المدينة، وتوفر أفضل إطلالة بانورامية على ناطحات السحاب الطينية. [7] تعتبر هذه النقطة وجهة أساسية للسياح والمصورين، وهي بمثابة منتزه طبيعي للاستمتاع بالمنظر الفريد. [7]";s:14:"description_en";s:251:"An elevated area situated opposite the city, providing the best panoramic view of the mud-brick skyscrapers. [7] This spot is a quintessential destination for tourists and photographers, serving as a natural park to marvel at the unique landscape. [7]";s:10:"categories";a:3:{i:0;s:9:"viewpoint";i:1;s:7:"tourism";i:2;s:6:"scenic";}s:14:"category_names";a:3:{i:0;s:6:"مطل";i:1;s:10:"سياحة";i:2;s:23:"مناظر طبيعية";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:6;a:17:{s:2:"id";i:243;s:7:"city_id";i:8;s:11:"external_id";s:8:"hoq-cave";s:4:"name";s:13:"كهف حوق";s:7:"name_en";s:8:"Hoq Cave";s:11:"description";s:326:"أكبر وأشهر كهوف سقطرى، يمتد لعمق يصل إلى 3 كيلومترات. [5] يتميز بتكويناته الكلسية المذهلة من الصواعد والنوازل، ويحتوي على بحيرة صغيرة ونقوش قديمة، مما يجعله مغامرة استكشافية رائعة.";s:14:"description_en";s:261:"The largest and most famous cave in Socotra, extending to a depth of up to 3 kilometers. [5] It features spectacular limestone formations of stalactites and stalagmites, holding a small lake and ancient inscriptions, making it a fantastic exploratory adventure.";s:10:"categories";a:4:{i:0;s:4:"cave";i:1;s:6:"nature";i:2;s:9:"adventure";i:3;s:10:"geological";}s:14:"category_names";a:4:{i:0;s:6:"كهف";i:1;s:10:"طبيعي";i:2;s:14:"مغامرات";i:3;s:14:"جيولوجي";}s:8:"latitude";d:12.6;s:9:"longitude";d:54.35;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/landmarks/socotra/hoq_cave1.jpg";i:1;s:38:"images/landmarks/socotra/hoq_cave2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:7;a:17:{s:2:"id";i:244;s:7:"city_id";i:8;s:11:"external_id";s:16:"arher-sand-dunes";s:4:"name";s:34:"كثبان عرهر الرملية";s:7:"name_en";s:16:"Arher Sand Dunes";s:11:"description";s:300:"كثبان رملية بيضاء ضخمة تتكئ على جروف جرانيتية سوداء، وتلتقي بمياه البحر الفيروزية. [6] يتدفق من أسفلها ينبوع مياه عذبة، مما يخلق منظراً طبيعياً استثنائياً لا مثيل له.";s:14:"description_en";s:201:"Massive white sand dunes leaning against black granite cliffs, meeting the turquoise sea waters. [6] A fresh water spring flows from their base, creating an unparalleled, exceptional natural landscape.";s:10:"categories";a:5:{i:0;s:6:"nature";i:1;s:10:"sand-dunes";i:2;s:5:"beach";i:3;s:6:"unique";i:4;s:6:"scenic";}s:14:"category_names";a:5:{i:0;s:10:"طبيعي";i:1;s:21:"كثبان رملية";i:2;s:8:"شاطئ";i:3;s:8:"فريد";i:4;s:21:"مناظر خلابة";}s:8:"latitude";d:12.63;s:9:"longitude";d:54.48;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/socotra/arher_dunes1.jpg";i:1;s:41:"images/landmarks/socotra/arher_dunes2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:8;a:17:{s:2:"id";i:245;s:7:"city_id";i:8;s:11:"external_id";s:21:"homhil-protected-area";s:4:"name";s:23:"محمية حومهيل";s:7:"name_en";s:21:"Homhil Nature Reserve";s:11:"description";s:310:"منطقة محمية تتميز بتنوعها النباتي الفريد، حيث تضم غابات من أشجار دم الأخوين واللبان وشجرة الزجاجة. [7] تحتوي على مسبح طبيعي (infinity pool) يطل على المحيط، مما يوفر منظراً ساحراً.";s:14:"description_en";s:221:"A protected area characterized by its unique botanical diversity, containing forests of Dragon Blood, Frankincense, and Bottle trees. [7] It includes a natural infinity pool overlooking the ocean, offering a magical view.";s:10:"categories";a:4:{i:0;s:14:"nature-reserve";i:1;s:9:"botanical";i:2;s:9:"viewpoint";i:3;s:12:"natural-pool";}s:14:"category_names";a:4:{i:0;s:23:"محمية طبيعية";i:1;s:10:"نباتي";i:2;s:12:"إطلالة";i:3;s:19:"مسبح طبيعي";}s:8:"latitude";d:12.58;s:9:"longitude";d:54.3;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/socotra/homhil_reserve1.jpg";i:1;s:44:"images/landmarks/socotra/homhil_reserve2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:9;a:17:{s:2:"id";i:246;s:7:"city_id";i:8;s:11:"external_id";s:11:"bottle-tree";s:4:"name";s:41:"شجرة الزجاجة (شجرة كرش)";s:7:"name_en";s:25:"Bottle Tree (Desert Rose)";s:11:"description";s:323:"شجرة غريبة الشكل تشبه زجاجة منتفخة، وتعتبر من النباتات المستوطنة في سقطرى. [8] تنتشر في مناطق مختلفة من الجزيرة، وتزهر بأزهار وردية جميلة، وتضيف إلى غرابة المشهد الطبيعي للجزيرة.";s:14:"description_en";s:242:"A bizarrely shaped tree resembling a swollen bottle, considered an endemic plant to Socotra. [8] Scattered across various parts of the island, it blooms with beautiful pink flowers, adding to the strangeness of the island's natural landscape.";s:10:"categories";a:3:{i:0;s:6:"nature";i:1;s:9:"botanical";i:2;s:6:"unique";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:10:"نباتي";i:2;s:8:"فريد";}s:8:"latitude";d:12.55;s:9:"longitude";d:54.1;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/socotra/bottle_tree1.jpg";i:1;s:41:"images/landmarks/socotra/bottle_tree2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:10;a:17:{s:2:"id";i:247;s:7:"city_id";i:8;s:11:"external_id";s:18:"wadi-dirhur-canyon";s:4:"name";s:19:"وادي درهور";s:7:"name_en";s:11:"Wadi Dirhur";s:11:"description";s:304:"وادي عميق يشق طريقه عبر هضبة دكسم، ويوفر مناظر درامية ومذهلة. [9] يمكن مشاهدة روعته من حافة الهضبة، وتنمو على جوانبه أشجار النخيل، ويعتبر مكاناً رائعاً للتصوير والتنزه.";s:14:"description_en";s:244:"A deep canyon slicing through the Diksam Plateau, providing dramatic and astonishing views. [9] Its magnificence can be seen from the edge of the plateau. Palm trees grow along its sides, making it a spectacular spot for photography and hiking.";s:10:"categories";a:5:{i:0;s:4:"wadi";i:1;s:6:"canyon";i:2;s:6:"nature";i:3;s:6:"scenic";i:4;s:9:"viewpoint";}s:14:"category_names";a:5:{i:0;s:8:"وادي";i:1;s:10:"أخدود";i:2;s:10:"طبيعي";i:3;s:21:"مناظر خلابة";i:4;s:12:"إطلالة";}s:8:"latitude";d:12.46;s:9:"longitude";d:53.99;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/socotra/wadi_dirhur1.jpg";i:1;s:41:"images/landmarks/socotra/wadi_dirhur2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:11;a:17:{s:2:"id";i:248;s:7:"city_id";i:8;s:11:"external_id";s:22:"dihamri-marine-reserve";s:4:"name";s:36:"محمية دهمري البحرية";s:7:"name_en";s:22:"Dihamri Marine Reserve";s:11:"description";s:311:"أفضل مكان لممارسة رياضة الغوص السطحي (السنوركلينج) والغوص في سقطرى. [10] تتميز المحمية بتنوع هائل من الشعاب المرجانية والأسماك الملونة، مما يجعلها جنة تحت الماء للمستكشفين.";s:14:"description_en";s:181:"The best place for snorkeling and diving in Socotra. [10] The reserve features a tremendous variety of coral reefs and colorful fish, making it an underwater paradise for explorers.";s:10:"categories";a:4:{i:0;s:14:"marine-reserve";i:1;s:10:"snorkeling";i:2;s:6:"diving";i:3;s:10:"coral-reef";}s:14:"category_names";a:4:{i:0;s:21:"محمية بحرية";i:1;s:15:"غطس سطحي";i:2;s:6:"غوص";i:3;s:23:"شعاب مرجانية";}s:8:"latitude";d:12.65;s:9:"longitude";d:54.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/socotra/dihamri_reserve1.jpg";i:1;s:45:"images/landmarks/socotra/dihamri_reserve2.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:12;a:17:{s:2:"id";i:249;s:7:"city_id";i:8;s:11:"external_id";s:10:"omak-beach";s:4:"name";s:15:"شاطئ عمق";s:7:"name_en";s:10:"Aomq Beach";s:11:"description";s:346:"يقع على الساحل الجنوبي للجزيرة المطل على المحيط الهندي. [1] يتميز برماله الذهبية الناعمة وأمواجه القوية، ويعتبر مكانًا مثاليًا للاستمتاع بالمناظر البحرية الشاسعة ومشاهدة الصيادين المحليين.";s:14:"description_en";s:221:"Located on the island's southern coast overlooking the Indian Ocean. [1] It is characterized by its soft golden sands and strong waves, making it a perfect spot to enjoy expansive marine views and observe local fishermen.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:10:"ocean-view";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:32:"إطلالة على المحيط";i:3;s:12:"ترفيهي";}s:8:"latitude";d:12.35;s:9:"longitude";d:53.95;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/beaches/socotra/omak_beach1.jpg";i:1;s:38:"images/beaches/socotra/omak_beach2.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:13;a:17:{s:2:"id";i:250;s:7:"city_id";i:8;s:11:"external_id";s:21:"kalysan-canyons-pools";s:4:"name";s:55:"وادي كليسان (المسابح الطبيعية)";s:7:"name_en";s:28:"Wadi Kalisan (Natural Pools)";s:11:"description";s:327:"وادي مذهل يشتهر بمسابحه الطبيعية ذات المياه العذبة الصافية المتكونة بين الصخور الجيرية البيضاء. [2] يعتبر مكانًا رائعًا للسباحة والاسترخاء في بيئة طبيعية فريدة ومختلفة عن الشواطئ.";s:14:"description_en";s:207:"A stunning valley famous for its natural freshwater pools formed amidst white limestone rocks. [2] It is a wonderful place for swimming and relaxing in a unique natural environment distinct from the beaches.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:12:"natural-pool";i:2;s:8:"swimming";i:3;s:6:"canyon";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:19:"مسبح طبيعي";i:2;s:10:"سباحة";i:3;s:10:"أخدود";}s:8:"latitude";d:12.45;s:9:"longitude";d:54.1;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/beaches/socotra/kalysan_pools1.jpg";i:1;s:41:"images/beaches/socotra/kalysan_pools2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:14;a:17:{s:2:"id";i:251;s:7:"city_id";i:8;s:11:"external_id";s:16:"zahek-sand-dunes";s:4:"name";s:34:"كثبان زاحق الرملية";s:7:"name_en";s:16:"Zahek Sand Dunes";s:11:"description";s:352:"تُعرف أيضًا بـ "الكثبان الرملية الناعمة"، وهي منطقة واسعة من الرمال البيضاء النقية في جنوب الجزيرة. [3] تلتقي هذه الكثبان بالبحر، مما يخلق منظرًا طبيعيًا خلابًا ومكانًا مثاليًا للتصوير والتخييم.";s:14:"description_en";s:222:"Also known as the 'Smooth Sand Dunes', this is a vast area of pure white sand in the south of the island. [3] These dunes meet the sea, generating a breathtaking landscape and an ideal location for photography and camping.";s:10:"categories";a:4:{i:0;s:10:"sand-dunes";i:1;s:5:"beach";i:2;s:6:"nature";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:21:"كثبان رملية";i:1;s:8:"شاطئ";i:2;s:10:"طبيعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:12.33;s:9:"longitude";d:53.85;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/beaches/socotra/zahek_dunes1.jpg";i:1;s:39:"images/beaches/socotra/zahek_dunes2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:15;a:17:{s:2:"id";i:252;s:7:"city_id";i:8;s:11:"external_id";s:13:"detwah-lagoon";s:4:"name";s:38:"بحيرة ديتوا الشاطئية";s:7:"name_en";s:13:"Detwah Lagoon";s:11:"description";s:357:"بحيرة ساحلية (لاجون) رائعة تقع بالقرب من قلنسية، وهي منطقة محمية. [4] تتميز بمياهها الضحلة الهادئة وتنوعها البيولوجي الغني، حيث يمكن مشاهدة الأخطبوط والأسماك الصغيرة، وتعتبر منظرًا طبيعيًا ساحرًا.";s:14:"description_en";s:232:"A magnificent coastal lagoon situated near Qalansiyah and a protected area. [4] It features calm, shallow waters and rich biodiversity, where octopuses and small fish can be spotted. It is considered an enchanting natural spectacle.";s:10:"categories";a:4:{i:0;s:6:"lagoon";i:1;s:14:"nature-reserve";i:2;s:5:"beach";i:3;s:8:"wildlife";}s:14:"category_names";a:4:{i:0;s:23:"بحيرة شاطئية";i:1;s:23:"محمية طبيعية";i:2;s:8:"شاطئ";i:3;s:17:"حياة برية";}s:8:"latitude";d:12.68;s:9:"longitude";d:53.5;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/beaches/socotra/detwah_lagoon1.jpg";i:1;s:41:"images/beaches/socotra/detwah_lagoon2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:16;a:17:{s:2:"id";i:253;s:7:"city_id";i:8;s:11:"external_id";s:10:"ras-irusyl";s:4:"name";s:15:"رأس إرسل";s:7:"name_en";s:11:"Ras Erissel";s:11:"description";s:271:"أقصى نقطة في شرق جزيرة سقطرى، حيث يلتقي بحر العرب بالمحيط الهندي. [5] المنطقة عبارة عن شاطئ بري يضم قرية صيد صغيرة، وتعتبر موقعًا مهمًا لتعشيش السلاحف.";s:14:"description_en";s:201:"The easternmost point of Socotra Island, where the Arabian Sea meets the Indian Ocean. [5] The area is a wild beach that includes a small fishing village and serves as an important turtle nesting site.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:7:"coastal";i:2;s:8:"wildlife";i:3;s:7:"turtles";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"ساحلي";i:2;s:17:"حياة برية";i:3;s:10:"سلاحف";}s:8:"latitude";d:12.64;s:9:"longitude";d:54.53;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/beaches/socotra/ras_irusyl1.jpg";i:1;s:38:"images/beaches/socotra/ras_irusyl2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:17;a:17:{s:2:"id";i:254;s:7:"city_id";i:8;s:11:"external_id";s:13:"delisha-beach";s:4:"name";s:21:"شاطئ ديليشة";s:7:"name_en";s:13:"Delisha Beach";s:11:"description";s:299:"شاطئ جميل يقع بالقرب من العاصمة حديبو، مما يجعله سهل الوصول. [6] يتميز بوجود كثبان رملية صغيرة ومياه هادئة، وهو مكان جيد للاسترخاء والسباحة وقضاء فترة ما بعد الظهيرة.";s:14:"description_en";s:199:"A lovely beach located near the capital, Hadibu, making it easily accessible. [6] It boasts small sand dunes and calm waters, making it a good spot for relaxing, swimming, and spending the afternoon.";s:10:"categories";a:3:{i:0;s:5:"beach";i:1;s:12:"recreational";i:2;s:8:"swimming";}s:14:"category_names";a:3:{i:0;s:8:"شاطئ";i:1;s:12:"ترفيهي";i:2;s:10:"سباحة";}s:8:"latitude";d:12.66;s:9:"longitude";d:54.08;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/beaches/socotra/delisha_beach1.jpg";i:1;s:41:"images/beaches/socotra/delisha_beach2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:18;a:17:{s:2:"id";i:255;s:7:"city_id";i:8;s:11:"external_id";s:19:"ayhaft-canyon-pools";s:4:"name";s:19:"وادي عيهفت";s:7:"name_en";s:11:"Wadi Ayhaft";s:11:"description";s:338:"وادي خصب يعتبر حديقة نباتية طبيعية، ويحتوي على العديد من المسابح الصخرية الصغيرة ذات المياه العذبة. [7] يعتبر مكانًا رائعًا للاستمتاع بالطبيعة ومراقبة الطيور والسباحة في المياه الباردة.";s:14:"description_en";s:195:"A fertile valley regarded as a natural botanical garden, containing numerous small rocky pools with fresh water. [7] It is a wonderful place to enjoy nature, watch birds, and swim in cool waters.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:12:"natural-pool";i:2;s:6:"nature";i:3;s:13:"bird-watching";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:19:"مسبح طبيعي";i:2;s:10:"طبيعي";i:3;s:25:"مراقبة الطيور";}s:8:"latitude";d:12.62;s:9:"longitude";d:53.98;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/beaches/socotra/ayhaft_canyon1.jpg";i:1;s:41:"images/beaches/socotra/ayhaft_canyon2.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:19;a:17:{s:2:"id";i:256;s:7:"city_id";i:8;s:11:"external_id";s:12:"shuqra-beach";s:4:"name";s:17:"شاطئ شقرة";s:7:"name_en";s:12:"Shoqra Beach";s:11:"description";s:278:"شاطئ طويل ومنعزل يقع في جنوب الجزيرة، ويتميز بتكويناته الصخرية الفريدة ورماله الذهبية. [8] نظرًا لبعده، فإنه يوفر تجربة هادئة وبكر لمحبي الطبيعة والعزلة.";s:14:"description_en";s:218:"A long, secluded beach located in the south of the island, noted for its unique rock formations and golden sands. [8] Due to its remoteness, it offers a serene and pristine experience for lovers of nature and solitude.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"nature";i:2;s:8:"secluded";i:3;s:10:"geological";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:10:"منعزل";i:3;s:14:"جيولوجي";}s:8:"latitude";d:12.32;s:9:"longitude";d:54.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/beaches/socotra/shuqra_beach1.jpg";i:1;s:40:"images/beaches/socotra/shuqra_beach2.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:20;a:17:{s:2:"id";i:257;s:7:"city_id";i:8;s:11:"external_id";s:26:"abd-al-kuri-island-beaches";s:4:"name";s:41:"شواطئ جزيرة عبد الكوري";s:7:"name_en";s:26:"Abd al Kuri Island Beaches";s:11:"description";s:325:"ثاني أكبر جزيرة في الأرخبيل، وتتميز بشواطئها البيضاء النقية التي لم تمسها يد الإنسان تقريبًا. [9] زيارتها تتطلب رحلة بحرية خاصة، وتوفر تجربة فريدة من العزلة والجمال الطبيعي الخام.";s:14:"description_en";s:235:"The second largest island in the archipelago, highlighted by its pristine white beaches virtually untouched by human hands. [9] Visiting it requires a special boat trip, offering a unique experience of isolation and raw natural beauty.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"island";i:2;s:8:"secluded";i:3;s:8:"pristine";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"جزيرة";i:2;s:10:"منعزل";i:3;s:6:"بكر";}s:8:"latitude";d:12.18;s:9:"longitude";d:52.25;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/beaches/socotra/abd_al_kuri_beach1.jpg";i:1;s:45:"images/beaches/socotra/abd_al_kuri_beach2.jpg";}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:21;a:17:{s:2:"id";i:258;s:7:"city_id";i:8;s:11:"external_id";s:16:"matyaf-waterfall";s:4:"name";s:19:"شلال متياف";s:7:"name_en";s:17:"Matiyaf Waterfall";s:11:"description";s:283:"شلال موسمي مذهل يتدفق مباشرة إلى البحر من أعلى الجروف الساحلية بعد هطول الأمطار الغزيرة. [10] يعتبر منظرًا نادرًا ومدهشًا، ويتطلب الحظ لمشاهدته في كامل قوته.";s:14:"description_en";s:218:"An astonishing seasonal waterfall flowing directly into the sea from the top of the coastal cliffs after heavy rains. [10] Considered a rare and spectacular sight, witnessing it at full force requires a stroke of luck.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:7:"coastal";i:2;s:8:"seasonal";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"ساحلي";i:2;s:10:"موسمي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:12.4;s:9:"longitude";d:53.55;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/beaches/socotra/matyaf_waterfall1.jpg";i:1;s:44:"images/beaches/socotra/matyaf_waterfall2.jpg";}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:22;a:17:{s:2:"id";i:259;s:7:"city_id";i:8;s:11:"external_id";s:25:"socotra-frankincense-tree";s:4:"name";s:36:"شجرة اللبان السقطري";s:7:"name_en";s:25:"Socotra Frankincense Tree";s:11:"description";s:344:"تنمو في سقطرى عدة أنواع من أشجار اللبان النادرة والمستوطنة، والتي تنتج أجود أنواع الصمغ العطري. [4] تنمو هذه الأشجار على المنحدرات الصخرية وتعتبر جزءاً من التراث الاقتصادي والثقافي للجزيرة.";s:14:"description_en";s:222:"Several rare and endemic species of frankincense trees grow on Socotra, producing the finest aromatic resins. [4] These trees thrive on rocky slopes and are considered a part of the island's economic and cultural heritage.";s:10:"categories";a:4:{i:0;s:9:"botanical";i:1;s:7:"endemic";i:2;s:4:"rare";i:3;s:8:"cultural";}s:14:"category_names";a:4:{i:0;s:10:"نباتي";i:1;s:12:"مستوطن";i:2;s:8:"نادر";i:3;s:10:"ثقافي";}s:8:"latitude";d:12.57;s:9:"longitude";d:54.25;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/rare/socotra/frankincense_tree1.jpg";i:1;s:42:"images/rare/socotra/frankincense_tree2.jpg";}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:23;a:17:{s:2:"id";i:260;s:7:"city_id";i:8;s:11:"external_id";s:20:"homhil-infinity-pool";s:4:"name";s:45:"المسبح الطبيعي في حومهيل";s:7:"name_en";s:19:"Homhil Natural Pool";s:11:"description";s:413:"أحد أشهر المسابح الطبيعية في الجزيرة، يقع داخل محمية حومهيل. [1] هو عبارة عن بركة مياه عذبة صافية تقع على حافة جرف صخري، وتوفر إطلالة لا نهائية (Infinity Pool) على الساحل الأزرق في الأسفل، مما يجعله مكاناً مثالياً للسباحة والتقاط الصور.";s:14:"description_en";s:266:"One of the most famous natural pools on the island, situated within the Homhil Reserve. [1] It is a clear freshwater pool perched on the edge of a cliff, providing an infinity pool view of the blue coast below, making it an ideal spot for swimming and taking photos.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"pool";i:2;s:6:"scenic";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"مسبح";i:2;s:21:"مناظر خلابة";i:3;s:6:"مطل";}s:8:"latitude";d:12.58;s:9:"longitude";d:54.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:24;a:17:{s:2:"id";i:261;s:7:"city_id";i:8;s:11:"external_id";s:20:"kalesan-canyon-pools";s:4:"name";s:60:"شلالات ومسابح وادي قريحة (كليسان)";s:7:"name_en";s:43:"Wadi Qarihah (Kalisan) Waterfalls and Pools";s:11:"description";s:395:"وادي مذهل يشتهر بمسابحه الطبيعية ذات المياه البيضاء الكلسية الصافية التي تتخللها شلالات صغيرة. [2] يتطلب الوصول إليه بعض المشي، لكن جمال البرك المائية المتدرجة بين الصخور البيضاء يجعله تجربة فريدة للسباحة والاسترخاء.";s:14:"description_en";s:279:"A stunning valley famous for its natural pools with clear, white calcareous waters interspersed with small waterfalls. [2] Reaching it requires some hiking, but the beauty of the terraced water pools among the white rocks makes it a unique experience for swimming and relaxation.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"pool";i:2;s:9:"waterfall";i:3;s:6:"canyon";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"مسبح";i:2;s:8:"شلال";i:3;s:10:"أخدود";}s:8:"latitude";d:12.4;s:9:"longitude";d:54.15;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:25;a:17:{s:2:"id";i:262;s:7:"city_id";i:8;s:11:"external_id";s:19:"dirhur-canyon-pools";s:4:"name";s:30:"مسابح وادي درهور";s:7:"name_en";s:17:"Wadi Dirhur Pools";s:11:"description";s:389:"في قاع أخدود درهور العميق، توجد العديد من البرك والمسابح الطبيعية التي تتكون من المياه الجارية في الوادي. [3] تعتبر هذه المسابح واحة خضراء ومنعشة في قلب الوادي، ومكاناً رائعاً للهروب من الحرارة والاستمتاع بالطبيعة.";s:14:"description_en";s:246:"At the bottom of the deep Dirhur canyon, numerous natural pools and ponds are formed by the flowing valley waters. [3] These pools act as a refreshing, green oasis in the heart of the valley, and a great place to escape the heat and enjoy nature.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"pool";i:2;s:6:"valley";i:3;s:5:"oasis";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"مسبح";i:2;s:8:"وادي";i:3;s:8:"واحة";}s:8:"latitude";d:12.45;s:9:"longitude";i:54;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:26;a:17:{s:2:"id";i:263;s:7:"city_id";i:8;s:11:"external_id";s:15:"dagub-cave-pool";s:4:"name";s:24:"مسبح كهف دكوب";s:7:"name_en";s:15:"Dogub Cave Pool";s:11:"description";s:335:"كهف ساحلي يقع بالقرب من شاطئ أومق. [4] يتميز هذا الكهف بوجود بركة مياه عذبة في مدخله، حيث يمكن للزوار السباحة في الظل مع الاستمتاع بمنظر الشاطئ والبحر في الخارج، وهي تجربة فريدة من نوعها.";s:14:"description_en";s:236:"A coastal cave located near Aomq Beach. [4] This cave is distinguished by a freshwater pool at its entrance, where visitors can swim in the shade while taking in the view of the beach and sea outside, creating a truly unique experience.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:4:"pool";i:2;s:4:"cave";i:3;s:5:"beach";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"مسبح";i:2;s:6:"كهف";i:3;s:8:"شاطئ";}s:8:"latitude";d:12.35;s:9:"longitude";d:53.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:27;a:17:{s:2:"id";i:264;s:7:"city_id";i:8;s:11:"external_id";s:17:"ras-erissel-beach";s:4:"name";s:30:"شاطئ رأس إيريسيل";s:7:"name_en";s:17:"Ras Erissel Beach";s:11:"description";s:340:"يقع في أقصى الطرف الشرقي للجزيرة، وهو نقطة التقاء بحر العرب بالمحيط الهندي. [8] يتميز الشاطئ بوجود قرى الصيادين التقليدية، وهو مكان رائع لمشاهدة شروق الشمس وتجربة الحياة الساحلية البسيطة.";s:14:"description_en";s:253:"Situated at the extreme eastern end of the island, it is the meeting point of the Arabian Sea and the Indian Ocean. [8] The beach features traditional fishing villages, making it a wonderful place to watch the sunrise and experience simple coastal life.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:7:"natural";i:2;s:7:"fishing";i:3;s:7:"sunrise";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"طبيعي";i:2;s:6:"صيد";i:3;s:19:"شروق الشمس";}s:8:"latitude";d:12.63;s:9:"longitude";d:54.52;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:28;a:17:{s:2:"id";i:265;s:7:"city_id";i:8;s:11:"external_id";s:19:"steroh-lagoon-beach";s:4:"name";s:49:"شاطئ بحيرة استيرو الشاطئية";s:7:"name_en";s:19:"Steroh Lagoon Beach";s:11:"description";s:331:"بحيرة شاطئية (لاجون) تقع على الساحل الجنوبي. [9] تشبه في تكوينها بحيرة ديتوا ولكنها أقل شهرة، وتتميز بمياهها الهادئة والدافئة، وهي مكان رائع لمراقبة الطيور البحرية والاسترخاء في عزلة.";s:14:"description_en";s:229:"A coastal lagoon located on the southern coast. [9] It is similar in formation to Detwah Lagoon but less famous, distinguished by its calm and warm waters. It is a fantastic place for observing seabirds and relaxing in isolation.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"lagoon";i:2;s:7:"natural";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:23:"بحيرة شاطئية";i:2;s:10:"طبيعي";i:3;s:8:"هادئ";}s:8:"latitude";d:12.33;s:9:"longitude";d:53.55;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:19;a:13:{s:2:"id";i:12;s:4:"slug";s:6:"seiyun";s:4:"name";s:10:"سيئون";s:7:"name_en";s:6:"Seiyun";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:15:"seiyun_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:11;s:9:"landmarks";a:11:{i:0;a:17:{s:2:"id";i:323;s:7:"city_id";i:12;s:11:"external_id";s:23:"seiyun-alkathiri-palace";s:4:"name";s:56:"قصر سيئون (قصر السلطان الكثيري)";s:7:"name_en";s:39:"Seiyun Palace (Kathiri Sultan's Palace)";s:11:"description";s:343:"أكبر مبنى طيني في العالم وأبرز معلم في وادي حضرموت. [1] كان القصر مقراً للسلطنة الكثيرية، ويتميز بتصميمه الفريد ولونه الأبيض، ويضم حالياً متحفاً للآثار. صورته مطبوعة على فئة الألف ريال يمني.";s:14:"description_en";s:304:"The largest mud-brick building in the world and the most prominent landmark in Wadi Hadhramaut. [1] The palace was the seat of the Kathiri Sultanate, distinguished by its unique design and white color, and currently houses an archaeological museum. Its image is printed on the 1,000 Yemeni Rial banknote.";s:10:"categories";a:5:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:6:"museum";i:4;s:8:"landmark";}s:14:"category_names";a:5:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:8:"متحف";i:4;s:8:"معلم";}s:8:"latitude";d:15.966;s:9:"longitude";d:48.778;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/seiyun/alkathiri_palace1.jpg";i:1;s:45:"images/landmarks/seiyun/alkathiri_palace2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:324;s:7:"city_id";i:12;s:11:"external_id";s:24:"al-hawtah-palace-complex";s:4:"name";s:41:"مجمع قصور حوطة السلطان";s:7:"name_en";s:28:"Hawta Sultan Palaces Complex";s:11:"description";s:345:"مجموعة من القصور والمباني الطينية الفاخرة التي كانت مقراً صيفياً للسلاطين الكثيريين. [2] تقع في منطقة الحوطة بالقرب من سيئون، وتتميز بزخارفها الجصية ونوافذها الخشبية المنحوتة بشكل فني رائع.";s:14:"description_en";s:236:"A group of luxurious mud-brick palaces and buildings that served as the summer residence for the Kathiri Sultans. [2] Located in the Hawta area near Seiyun, they feature stunning stucco decorations and beautifully carved wooden windows.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:7:"complex";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:8:"مجمع";}s:8:"latitude";d:15.945;s:9:"longitude";d:48.76;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/seiyun/al_hawtah_palace1.jpg";i:1;s:45:"images/landmarks/seiyun/al_hawtah_palace2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:325;s:7:"city_id";i:12;s:11:"external_id";s:19:"seiyun-olympic-park";s:4:"name";s:46:"الحديقة الأولمبية بسيئون";s:7:"name_en";s:19:"Seiyun Olympic Park";s:11:"description";s:418:"تعتبر الحديقة العامة الرئيسية والوجهة الترفيهية الأبرز للعائلات في مدينة سيئون. [1, 2] تقع بالقرب من الملعب الأولمبي، وتضم مساحات خضراء، وألعابًا متنوعة للأطفال، ومرافق للزوار، وتشهد إقبالًا كبيرًا خاصة في الأعياد والمناسبات. [1, 2]";s:14:"description_en";s:298:"Considered the main public park and the most prominent entertainment destination for families in Seiyun city. [1, 2] Located near the Olympic Stadium, it features green spaces, various children's games, and visitor facilities, witnessing large turnouts especially during holidays and events. [1, 2]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";i:3;s:14:"amusement-park";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";i:3;s:10:"ملاهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:326;s:7:"city_id";i:12;s:11:"external_id";s:19:"seiyun-grand-mosque";s:4:"name";s:19:"جامع سيئون";s:7:"name_en";s:13:"Seiyun Mosque";s:11:"description";s:277:"مسجد تاريخي يقع في قلب مدينة سيئون، ويتميز بمئذنته الطينية البيضاء التي تتناغم مع عمارة قصر الكثيري. [3] يعتبر مركزاً دينياً واجتماعياً هاماً في المدينة.";s:14:"description_en";s:215:"A historical mosque located in the heart of Seiyun city, notable for its white mud minaret that harmonizes with the architecture of the Kathiri Palace. [3] It is an important religious and social center in the city.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:7:"islamic";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"إسلامي";i:3;s:12:"معماري";}s:8:"latitude";d:15.965;s:9:"longitude";d:48.777;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/seiyun/seiyun_mosque1.jpg";i:1;s:42:"images/landmarks/seiyun/seiyun_mosque2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:327;s:7:"city_id";i:12;s:11:"external_id";s:15:"seiyun-old-souq";s:4:"name";s:30:"سوق سيئون القديم";s:7:"name_en";s:17:"Old Seiyun Market";s:11:"description";s:316:"سوق تقليدي نابض بالحياة يقع بالقرب من قصر سيئون. [4] يعرض السوق المنتجات المحلية من التوابل والتمور والعسل الحضرمي الشهير، بالإضافة إلى المصنوعات الحرفية والفضيات التقليدية.";s:14:"description_en";s:204:"A vibrant traditional market located near Seiyun Palace. [4] The market offers local products ranging from spices and dates to the famous Hadhrami honey, as well as handicrafts and traditional silverware.";s:10:"categories";a:4:{i:0;s:6:"market";i:1;s:8:"cultural";i:2;s:11:"traditional";i:3;s:11:"handicrafts";}s:14:"category_names";a:4:{i:0;s:6:"سوق";i:1;s:10:"ثقافي";i:2;s:12:"تقليدي";i:3;s:17:"حرف يدوية";}s:8:"latitude";d:15.967;s:9:"longitude";d:48.779;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/seiyun/seiyun_souq1.jpg";i:1;s:40:"images/landmarks/seiyun/seiyun_souq2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:328;s:7:"city_id";i:12;s:11:"external_id";s:19:"qabr-nabi-allah-hud";s:4:"name";s:29:"قبر نبي الله هود";s:7:"name_en";s:19:"Tomb of Prophet Hud";s:11:"description";s:333:"موقع ديني يقع شرق سيئون، ويُعتقد أنه يضم قبر النبي هود عليه السلام. [5] يعتبر مزاراً دينياً هاماً وتقام فيه زيارة سنوية حاشدة في شهر شعبان، ويقصده الزوار من مختلف أنحاء العالم الإسلامي.";s:14:"description_en";s:260:"A religious site located east of Seiyun, believed to contain the tomb of Prophet Hud (peace be upon him). [5] It is an important religious shrine, hosting a massive annual pilgrimage in the month of Sha'ban, attracting visitors from all over the Islamic world.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"pilgrimage";i:2;s:10:"historical";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:8:"مزار";i:2;s:12:"تاريخي";i:3;s:12:"إسلامي";}s:8:"latitude";d:16.083;s:9:"longitude";d:49.341;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/landmarks/seiyun/qabr_hud1.jpg";i:1;s:37:"images/landmarks/seiyun/qabr_hud2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:329;s:7:"city_id";i:12;s:11:"external_id";s:13:"husn-al-falas";s:4:"name";s:17:"حصن الفلس";s:7:"name_en";s:12:"Al-Fils Fort";s:11:"description";s:293:"حصن تاريخي يقع على تلة مرتفعة في مدخل مدينة سيئون. [6] كان يستخدم كنقطة مراقبة وحماية للمدينة، ويوفر إطلالة بانورامية رائعة على المدينة وواحات النخيل المحيطة بها.";s:14:"description_en";s:219:"A historic fort situated on a high hill at the entrance of Seiyun city. [6] It was used as a watchtower and protective point for the city, providing a wonderful panoramic view of the city and its surrounding palm oases.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:9:"viewpoint";i:3;s:8:"military";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:12:"إطلالة";i:3;s:10:"عسكري";}s:8:"latitude";d:15.958;s:9:"longitude";d:48.775;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/seiyun/husn_al_falas1.jpg";i:1;s:42:"images/landmarks/seiyun/husn_al_falas2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:330;s:7:"city_id";i:12;s:11:"external_id";s:21:"tarim-city-of-mosques";s:4:"name";s:19:"مدينة تريم";s:7:"name_en";s:13:"City of Tarim";s:11:"description";s:326:"مدينة تاريخية قريبة من سيئون، تُعرف بأنها "مدينة الـ 365 مسجداً" والعاصمة الروحية والثقافية لوادي حضرموت. [7] تشتهر بمساجدها التاريخية، ومكتباتها الغنية بالمخطوطات، وقصورها الفخمة.";s:14:"description_en";s:227:"A historical city near Seiyun, known as the 'City of 365 Mosques' and the spiritual and cultural capital of Wadi Hadhramaut. [7] It is renowned for its historical mosques, libraries rich in manuscripts, and magnificent palaces.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:9:"religious";i:3;s:8:"cultural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:8:"ديني";i:3;s:10:"ثقافي";}s:8:"latitude";d:16.055;s:9:"longitude";d:48.998;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/seiyun/tarim_city1.jpg";i:1;s:39:"images/landmarks/seiyun/tarim_city2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:331;s:7:"city_id";i:12;s:11:"external_id";s:25:"al-mihdhar-mosque-minaret";s:4:"name";s:45:"مئذنة جامع المحضار (تريم)";s:7:"name_en";s:33:"Al-Mihdhar Mosque Minaret (Tarim)";s:11:"description";s:289:"أطول مئذنة طينية في العالم، بارتفاع يبلغ حوالي 46 متراً. [8] تقع في مدينة تريم المجاورة، وتعتبر تحفة معمارية فريدة من نوعها، بناها الشاعر والعالم أبو بكر بن شهاب.";s:14:"description_en";s:209:"The tallest mud minaret in the world, standing at about 46 meters high. [8] Located in the neighboring city of Tarim, it is a unique architectural masterpiece built by the poet and scholar Abu Bakr bin Shihab.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:13:"architectural";i:2;s:8:"landmark";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"معماري";i:2;s:8:"معلم";i:3;s:12:"إسلامي";}s:8:"latitude";d:16.056;s:9:"longitude";d:49.003;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/landmarks/seiyun/al_mihdhar_minaret1.jpg";i:1;s:47:"images/landmarks/seiyun/al_mihdhar_minaret2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:332;s:7:"city_id";i:12;s:11:"external_id";s:18:"seiyun-palm-groves";s:4:"name";s:39:"واحات النخيل في سيئون";s:7:"name_en";s:17:"Seiyun Palm Oases";s:11:"description";s:326:"تحيط بمدينة سيئون مساحات شاسعة من واحات النخيل الكثيفة التي تشكل منظراً طبيعياً خلاباً. [9] تعتبر هذه الواحات مصدر التمور ومكوناً أساسياً للمشهد الحضرمي، وتوفر أماكن هادئة للتنزه.";s:14:"description_en";s:236:"Seiyun city is surrounded by vast expanses of dense palm oases that form a breathtaking natural landscape. [9] These oases are the source of dates and a fundamental component of the Hadhrami scenery, offering quiet places for strolling.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:5:"oasis";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"واحة";i:2;s:10:"زراعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.97;s:9:"longitude";d:48.78;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/seiyun/seiyun_palms1.jpg";i:1;s:41:"images/landmarks/seiyun/seiyun_palms2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:333;s:7:"city_id";i:12;s:11:"external_id";s:11:"ainat-tombs";s:4:"name";s:32:"مقابر وقباب عينات";s:7:"name_en";s:24:"Tombs and Domes of Einat";s:11:"description";s:336:"بلدة تاريخية تقع شرق تريم، وتشتهر بمقابرها التي تضم أضرحة وقباباً للعديد من العلماء والأولياء الصالحين. [10] تتميز القباب بتصاميمها المعمارية الجصية البيضاء، وتعتبر مزاراً دينياً هاما.";s:14:"description_en";s:246:"A historical town located east of Tarim, famous for its cemeteries containing the shrines and domes of many scholars and righteous saints. [10] The domes feature white stucco architectural designs and are considered an important religious shrine.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:8:"cemetery";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:10:"مقبرة";i:3;s:12:"معماري";}s:8:"latitude";d:16.05;s:9:"longitude";d:49.15;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/seiyun/ainat_tombs1.jpg";i:1;s:40:"images/landmarks/seiyun/ainat_tombs2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:20;a:13:{s:2:"id";i:7;s:4:"slug";s:6:"shibam";s:4:"name";s:8:"شبام";s:7:"name_en";s:6:"Shibam";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:15:"shibam_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:10;s:9:"landmarks";a:10:{i:0;a:17:{s:2:"id";i:227;s:7:"city_id";i:7;s:11:"external_id";s:22:"shibam-old-walled-city";s:4:"name";s:49:"مدينة شبام القديمة المسورة";s:7:"name_en";s:25:"Old Walled City of Shibam";s:11:"description";s:378:"مدينة تاريخية فريدة مدرجة على قائمة اليونسكو للتراث العالمي، تشتهر بمبانيها الطينية الشاهقة التي تعتبر أقدم ناطحات سحاب في العالم. [1] المدينة محاطة بسور دفاعي، وتتميز بتخطيطها الحضري المتقن الذي يعود لقرون.";s:14:"description_en";s:285:"A unique historical city inscribed on the UNESCO World Heritage list, famous for its towering mud-brick buildings considered the oldest skyscrapers in the world. [1] The city is surrounded by a defensive wall and is distinguished by its meticulous urban planning dating back centuries.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:14:"archaeological";i:2;s:6:"unesco";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"أثري";i:2;s:12:"يونسكو";i:3;s:12:"معماري";}s:8:"latitude";d:15.926;s:9:"longitude";d:48.626;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/shibam/shibam_old_city1.jpg";i:1;s:44:"images/landmarks/shibam/shibam_old_city2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:13.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:1;a:17:{s:2:"id";i:228;s:7:"city_id";i:7;s:11:"external_id";s:18:"shibam-skyscrapers";s:4:"name";s:40:"ناطحات السحاب الطينية";s:7:"name_en";s:21:"Mud-Brick Skyscrapers";s:11:"description";s:357:"الميزة الأبرز لشبام، وهي مجموعة من حوالي 500 مبنى طيني يتراوح ارتفاعها بين 5 إلى 11 طابقاً. [2] تمثل هذه المباني تحفة في الهندسة المعمارية التقليدية وتكيفها مع البيئة، وهي مبنية بالكامل من الطوب اللبن.";s:14:"description_en";s:280:"The most prominent feature of Shibam, a cluster of about 500 mud buildings ranging in height from 5 to 11 stories. [2] These buildings represent a masterpiece in traditional architectural engineering and adaptation to the environment, constructed entirely of sun-dried mud bricks.";s:10:"categories";a:4:{i:0;s:13:"architectural";i:1;s:10:"historical";i:2;s:8:"landmark";i:3;s:6:"unesco";}s:14:"category_names";a:4:{i:0;s:12:"معماري";i:1;s:12:"تاريخي";i:2;s:8:"معلم";i:3;s:12:"يونسكو";}s:8:"latitude";d:15.927;s:9:"longitude";d:48.627;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/landmarks/shibam/shibam_skyscrapers1.jpg";i:1;s:47:"images/landmarks/shibam/shibam_skyscrapers2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:2;a:17:{s:2:"id";i:229;s:7:"city_id";i:7;s:11:"external_id";s:21:"al-juma-mosque-shibam";s:4:"name";s:60:"الجامع الكبير (جامع هارون الرشيد)";s:7:"name_en";s:37:"Great Mosque (Harun Al-Rashid Mosque)";s:11:"description";s:313:"أقدم مسجد في شبام، يقع في قلب المدينة القديمة. [3] يُعتقد أن أساساته تعود إلى عهد الخليفة هارون الرشيد في القرن الثامن الميلادي، ويتميز ببساطة تصميمه ومئذنته الطينية الضخمة.";s:14:"description_en";s:237:"The oldest mosque in Shibam, located in the heart of the old city. [3] Its foundations are believed to date back to the reign of Caliph Harun Al-Rashid in the 8th century AD, and it is known for its simple design and massive mud minaret.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:14:"archaeological";i:3;s:7:"islamic";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:8:"أثري";i:3;s:12:"إسلامي";}s:8:"latitude";d:15.9265;s:9:"longitude";d:48.6265;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/shibam/al_juma_mosque1.jpg";i:1;s:43:"images/landmarks/shibam/al_juma_mosque2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:3;a:17:{s:2:"id";i:230;s:7:"city_id";i:7;s:11:"external_id";s:16:"shibam-viewpoint";s:4:"name";s:35:"مطل شبام (جبل الخور)";s:7:"name_en";s:33:"Shibam Viewpoint (Mount Al-Khawr)";s:11:"description";s:313:"أفضل نقطة لمشاهدة المنظر البانورامي الشهير لمدينة شبام. [4] يقع هذا المطل على الضفة المقابلة للوادي، ويوفر إطلالة لا مثيل لها على ناطحات السحاب، خاصة عند شروق الشمس وغروبها.";s:14:"description_en";s:211:"The best spot to witness the famous panoramic view of Shibam. [4] Situated on the opposite bank of the valley, this viewpoint offers an unparalleled view of the skyscrapers, especially during sunrise and sunset.";s:10:"categories";a:4:{i:0;s:9:"viewpoint";i:1;s:6:"scenic";i:2;s:11:"photography";i:3;s:6:"nature";}s:14:"category_names";a:4:{i:0;s:12:"إطلالة";i:1;s:21:"مناظر خلابة";i:2;s:10:"تصوير";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.923;s:9:"longitude";d:48.624;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/shibam/shibam_viewpoint1.jpg";i:1;s:45:"images/landmarks/shibam/shibam_viewpoint2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:4;a:17:{s:2:"id";i:231;s:7:"city_id";i:7;s:11:"external_id";s:16:"shibam-city-gate";s:4:"name";s:36:"بوابة شبام الرئيسية";s:7:"name_en";s:19:"Main Gate of Shibam";s:11:"description";s:313:"المدخل الرئيسي والوحيد حالياً إلى المدينة المسورة. [5] المرور عبر هذه البوابة يشبه الدخول إلى عالم آخر، حيث تفضي إلى شبكة من الأزقة الضيقة والمباني الشاهقة التي تحجب السماء.";s:14:"description_en";s:210:"Currently the sole and main entrance to the walled city. [5] Passing through this gate is like stepping into another world, leading into a network of narrow alleys and towering buildings that block out the sky.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"landmark";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:8:"معلم";}s:8:"latitude";d:15.925;s:9:"longitude";d:48.626;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/shibam/shibam_gate1.jpg";i:1;s:40:"images/landmarks/shibam/shibam_gate2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:5;a:17:{s:2:"id";i:232;s:7:"city_id";i:7;s:11:"external_id";s:15:"wadi-hadhramaut";s:4:"name";s:21:"وادي حضرموت";s:7:"name_en";s:15:"Wadi Hadhramaut";s:11:"description";s:301:"الوادي الشاسع الذي تقع فيه مدينة شبام. [6] يتميز الوادي بواحات النخيل الخضراء التي تتناقض بشكل صارخ مع الجروف الصخرية القاحلة، مما يخلق منظراً طبيعياً فريداً وجميلاً.";s:14:"description_en";s:197:"The vast valley in which the city of Shibam lies. [6] The valley features lush green palm oases that contrast starkly with the arid rocky cliffs, producing a unique and beautiful natural landscape.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:5:"oasis";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:8:"واحة";}s:8:"latitude";d:15.93;s:9:"longitude";d:48.63;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/shibam/wadi_hadhramaut1.jpg";i:1;s:44:"images/landmarks/shibam/wadi_hadhramaut2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:6;a:17:{s:2:"id";i:233;s:7:"city_id";i:7;s:11:"external_id";s:19:"al-hajarain-village";s:4:"name";s:23:"قرية الحجرين";s:7:"name_en";s:20:"Al-Hajjarayn Village";s:11:"description";s:304:"قرية تاريخية مذهلة تقع في وادي دوعن القريب، وهي مبنية على منحدر صخري شاهق. [7] تشبه شبام في طرازها المعماري ولكنها تتميز بموقعها الدرامي، وتعتبر من أجمل القرى في حضرموت.";s:14:"description_en";s:256:"A stunning historical village situated in the nearby Wadi Dawan, built on a steep rocky incline. [7] Similar to Shibam in its architectural style but distinguished by its dramatic location, it is considered one of the most beautiful villages in Hadhramaut.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:7:"village";i:2;s:13:"architectural";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قرية";i:2;s:12:"معماري";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.045;s:9:"longitude";d:48.375;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/shibam/al_hajarain1.jpg";i:1;s:40:"images/landmarks/shibam/al_hajarain2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:7;a:17:{s:2:"id";i:234;s:7:"city_id";i:7;s:11:"external_id";s:16:"marib-dam-shibam";s:4:"name";s:31:"سد شبام (سد الحيط)";s:7:"name_en";s:24:"Shibam Dam (Al-Hait Dam)";s:11:"description";s:331:"نظام ري قديم يعتمد على تحويل مياه السيول من الوادي لري الأراضي الزراعية المحيطة بشبام. [8] هذا النظام الهندسي التقليدي هو الذي سمح بوجود واحات النخيل والزراعة في هذه البيئة الصحراوية.";s:14:"description_en";s:260:"An ancient irrigation system relying on diverting floodwaters from the valley to irrigate the agricultural lands surrounding Shibam. [8] This traditional engineering system is what enabled the existence of palm oases and agriculture in this desert environment.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:11:"engineering";i:2;s:11:"agriculture";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"هندسي";i:2;s:10:"زراعي";i:3;s:8:"مائي";}s:8:"latitude";d:15.935;s:9:"longitude";d:48.62;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/shibam/shibam_dam1.jpg";i:1;s:39:"images/landmarks/shibam/shibam_dam2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:8;a:17:{s:2:"id";i:235;s:7:"city_id";i:7;s:11:"external_id";s:25:"shibam-traditional-houses";s:4:"name";s:45:"البيوت التقليدية في شبام";s:7:"name_en";s:28:"Traditional Houses in Shibam";s:11:"description";s:331:"زيارة أحد المنازل الطينية من الداخل هي تجربة فريدة. [9] يمكن للزوار مشاهدة التصميم الداخلي، وتقسيم الطوابق حسب الوظيفة (تخزين، معيشة، استقبال)، والاستمتاع بالمنظر من النوافذ العلوية.";s:14:"description_en";s:229:"Visiting one of the mud houses from the inside is a unique experience. [9] Visitors can see the interior layout, the division of floors by function (storage, living quarters, reception), and enjoy the view from the upper windows.";s:10:"categories";a:3:{i:0;s:8:"cultural";i:1;s:13:"architectural";i:2;s:10:"experience";}s:14:"category_names";a:3:{i:0;s:10:"ثقافي";i:1;s:12:"معماري";i:2;s:10:"تجربة";}s:8:"latitude";d:15.9268;s:9:"longitude";d:48.6272;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/shibam/shibam_house1.jpg";i:1;s:41:"images/landmarks/shibam/shibam_house2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:9;a:17:{s:2:"id";i:236;s:7:"city_id";i:7;s:11:"external_id";s:16:"jahiliyya-palace";s:4:"name";s:50:"قصر الجاهلية (حصن بن عيذاذة)";s:7:"name_en";s:38:"Al-Jahiliyah Palace (Bin Iyadhah Fort)";s:11:"description";s:326:"حصن قديم يقع على تلة خارج شبام، وكان مقراً لأحد الحكام المحليين. [10] على الرغم من أنه أطلال الآن، إلا أنه يوفر إطلالة جيدة على المدينة والوادي، ويحكي قصصاً عن تاريخ المنطقة السياسي.";s:14:"description_en";s:238:"An old fortress located on a hill outside Shibam, which once served as the seat for a local ruler. [10] Although it is now in ruins, it provides a good view of the city and the valley, recounting stories of the region's political history.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:5:"ruins";i:2;s:8:"fortress";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"أطلال";i:2;s:8:"قلعة";i:3;s:12:"إطلالة";}s:8:"latitude";d:15.928;s:9:"longitude";d:48.623;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/shibam/jahiliyya_palace1.jpg";i:1;s:45:"images/landmarks/shibam/jahiliyya_palace2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:21;a:13:{s:2:"id";i:22;s:4:"slug";s:7:"shabwah";s:4:"name";s:8:"شبوة";s:7:"name_en";s:7:"Shabwah";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:16:"shabwah_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:22;s:9:"landmarks";a:22:{i:0;a:17:{s:2:"id";i:559;s:7:"city_id";i:22;s:11:"external_id";s:14:"shabwah-castle";s:4:"name";s:17:"قلعة شبوة";s:7:"name_en";s:14:"Shabwah Castle";s:11:"description";s:236:"قلعة تاريخية تقع في محافظة شبوة، تتميز بموقعها الاستراتيجي وعمارتها الدفاعية المميزة. تعتبر من أهم المعالم التاريخية في المنطقة.";s:14:"description_en";s:209:"A historic castle situated in Shabwah Governorate, distinguished by its strategic location and distinctive defensive architecture. It is considered one of the most important historical landmarks in the region.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"عسكري";}s:8:"latitude";d:14.53;s:9:"longitude";i:47;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/shabwah/shabwah_castle1.jpg";i:1;s:44:"images/landmarks/shabwah/shabwah_castle2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:1;a:17:{s:2:"id";i:560;s:7:"city_id";i:22;s:11:"external_id";s:19:"shabwa-ancient-city";s:4:"name";s:23:"شبوة القديمة";s:7:"name_en";s:11:"Old Shabwah";s:11:"description";s:382:"العاصمة الأثرية لمملكة حضرموت القديمة، وهي أهم موقع أثري في المحافظة. [1, 2] تقع على حافة صحراء رملة السبعتين، وكانت مركزاً رئيسياً لتجارة اللبان والبخور. تضم أطلال معابد وقصور ونقوشاً تدل على عظمتها الغابرة. [1, 2]";s:14:"description_en";s:336:"The ancient archaeological capital of the Hadhramaut Kingdom, and the most important archaeological site in the governorate. [1, 2] Located on the edge of the Ramlat al-Sab'atayn desert, it was a major hub for the frankincense and incense trade. It houses ruins of temples, palaces, and inscriptions signifying its past grandeur. [1, 2]";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:7:"ancient";i:3;s:7:"capital";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"قديم";i:3;s:10:"عاصمة";}s:8:"latitude";d:15.3667;s:9:"longitude";d:47.0167;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:2;a:17:{s:2:"id";i:561;s:7:"city_id";i:22;s:11:"external_id";s:9:"qana-port";s:4:"name";s:46:"ميناء قنا الأثري (بير علي)";s:7:"name_en";s:30:"Ancient Port of Qana (Bir Ali)";s:11:"description";s:355:"أهم ميناء قديم على ساحل بحر العرب، كان البوابة البحرية لمملكة حضرموت ومنطلق قوافل اللبان. [3, 4] يقع في منطقة بير علي، وتوجد به أطلال ومخازن قديمة، ويتميز بلسانه البركاني (حصن الغراب) الذي كان يحميه.";s:14:"description_en";s:315:"The most vital ancient port on the Arabian Sea coast, acting as the maritime gateway for the Hadhramaut Kingdom and the starting point for frankincense caravans. [3, 4] Located in the Bir Ali area, it features ancient ruins and warehouses, and is noted for the volcanic peninsula (Husn Al-Ghurab) that protected it.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:4:"port";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"ميناء";i:3;s:10:"ساحلي";}s:8:"latitude";d:14.0167;s:9:"longitude";d:48.3333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:17:{s:2:"id";i:562;s:7:"city_id";i:22;s:11:"external_id";s:13:"bir-ali-beach";s:4:"name";s:22:"ساحل بير علي";s:7:"name_en";s:13:"Bir Ali Coast";s:11:"description";s:343:"أحد أجمل السواحل في اليمن، يقع بالقرب من ميناء قنا الأثري. [4, 5] يتميز بشواطئه الرملية البيضاء ومياهه الفيروزية الصافية وتكويناته البركانية السوداء، مما يخلق تبايناً لونياً فريداً وجذاباً.";s:14:"description_en";s:238:"One of the most beautiful coasts in Yemen, situated near the ancient port of Qana. [4, 5] Characterized by its white sandy beaches, clear turquoise waters, and black volcanic formations, it creates a unique and captivating color contrast.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:5:"beach";i:2;s:6:"scenic";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شاطئ";i:2;s:21:"مناظر خلابة";i:3;s:10:"ساحلي";}s:8:"latitude";d:14.01;s:9:"longitude";d:48.33;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:17:{s:2:"id";i:563;s:7:"city_id";i:22;s:11:"external_id";s:12:"wadi-mayfaah";s:4:"name";s:19:"وادي ميفعة";s:7:"name_en";s:13:"Wadi Mayfa'ah";s:11:"description";s:298:"من أكبر وأخصب الأودية في شبوة، ويمتد من المرتفعات حتى يصب في بحر العرب. [6] يشتهر بزراعة النخيل والحبوب، وتنتشر على ضفافه العديد من القرى التاريخية والمواقع الأثرية.";s:14:"description_en";s:233:"One of the largest and most fertile valleys in Shabwah, stretching from the highlands down to the Arabian Sea. [6] Renowned for farming palm trees and grains, its banks are dotted with many historic villages and archaeological sites.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:12:"تاريخي";}s:8:"latitude";d:14.2;s:9:"longitude";d:47.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:17:{s:2:"id";i:564;s:7:"city_id";i:22;s:11:"external_id";s:16:"ataq-public-park";s:4:"name";s:30:"حديقة عتق العامة";s:7:"name_en";s:16:"Ataq Public Park";s:11:"description";s:332:"الحديقة العامة الرئيسية في مدينة عتق، عاصمة المحافظة. [5] تمثل متنفسًا منظمًا للعائلات والأطفال داخل المدينة، وتضم مساحات خضراء وألعابًا ومناطق للجلوس، وتشهد إقبالًا في المناسبات. [5]";s:14:"description_en";s:246:"The main public park in the city of Ataq, the capital of the governorate. [5] Representing an organized retreat for families and children in the city, it includes green spaces, games, and seating areas, witnessing high turnouts during events. [5]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:17:{s:2:"id";i:565;s:7:"city_id";i:22;s:11:"external_id";s:20:"habban-historic-city";s:4:"name";s:38:"مدينة حبان التاريخية";s:7:"name_en";s:23:"Historic City of Habban";s:11:"description";s:328:"مدينة تاريخية كانت عاصمة لسلطنة الواحدي. [7, 8] تتميز بمنازلها الطينية الشاهقة ذات الطراز المعماري الفريد، والتي تشبه ناطحات السحاب الطينية، وتعتبر مثالاً رائعاً للعمارة الشبوانية.";s:14:"description_en";s:233:"An ancient city that was the capital of the Wahidi Sultanate. [7, 8] It is distinguished by its towering mud houses with a unique architectural style resembling mud skyscrapers, presenting a splendid example of Shabwani architecture.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:8:"mudbrick";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:6:"طين";}s:8:"latitude";d:14.35;s:9:"longitude";d:47.06;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:17:{s:2:"id";i:566;s:7:"city_id";i:22;s:11:"external_id";s:25:"ramlat-as-sabateen-desert";s:4:"name";s:36:"صحراء رملة السبعتين";s:7:"name_en";s:26:"Ramlat al-Sab'atayn Desert";s:11:"description";s:297:"صحراء رملية شاسعة تمتد بين محافظات شبوة ومأرب والجوف. [9] توفر مناظر طبيعية صحراوية خلابة من الكثبان الرملية الذهبية، وتعتبر وجهة مثالية لسياحة المغامرات والتخييم.";s:14:"description_en";s:203:"A vast sandy desert spreading across Shabwah, Marib, and Al-Jawf governorates. [9] Showcasing breathtaking desert landscapes of golden dunes, it is an ideal destination for adventure tourism and camping.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"desert";i:2;s:9:"adventure";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"صحراء";i:2;s:12:"مغامرة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.5;s:9:"longitude";d:46.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:8;a:17:{s:2:"id";i:567;s:7:"city_id";i:22;s:11:"external_id";s:10:"azzan-city";s:4:"name";s:19:"مدينة عزان";s:7:"name_en";s:10:"Azzan City";s:11:"description";s:262:"مدينة تاريخية وتجارية هامة تقع في وادي ميفعة. [6] تشتهر أيضاً بمبانيها الطينية العالية والجميلة، وكانت مركزاً تجارياً نشطاً يربط الساحل بالداخل.";s:14:"description_en";s:194:"A historically and commercially important city located in Wadi Mayfa'ah. [6] Also famous for its tall, beautiful mud buildings, it was an active commercial hub linking the coast to the interior.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:6:"market";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:6:"سوق";i:3;s:12:"معماري";}s:8:"latitude";d:14.21;s:9:"longitude";d:47.36;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:9;a:17:{s:2:"id";i:568;s:7:"city_id";i:22;s:11:"external_id";s:12:"balhaf-coast";s:4:"name";s:19:"ساحل بلحاف";s:7:"name_en";s:12:"Balhaf Coast";s:11:"description";s:355:"شريط ساحلي يشتهر بكونه موقعاً لمشروع الغاز الطبيعي المسال، ولكنه يضم أيضاً شواطئ جميلة. [5] يتميز الساحل بوجود فوهة بركانية خامدة تشكل بحيرة صغيرة (بحيرة شوران)، مما يضيف تنوعاً جيولوجياً للمنطقة.";s:14:"description_en";s:237:"A coastal strip famed as the site of a liquefied natural gas project, yet it also boasts beautiful beaches. [5] The coast features a dormant volcanic crater that forms a small lake (Shouran Lake), adding geological diversity to the area.";s:10:"categories";a:4:{i:0;s:7:"coastal";i:1;s:10:"industrial";i:2;s:7:"natural";i:3;s:10:"geological";}s:14:"category_names";a:4:{i:0;s:10:"ساحلي";i:1;s:10:"صناعي";i:2;s:10:"طبيعي";i:3;s:14:"جيولوجي";}s:8:"latitude";d:13.98;s:9:"longitude";d:48.18;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:10;a:17:{s:2:"id";i:569;s:7:"city_id";i:22;s:11:"external_id";s:11:"wadi-jardan";s:4:"name";s:19:"وادي جردان";s:7:"name_en";s:11:"Wadi Jardan";s:11:"description";s:289:"أحد الأودية الرئيسية في شبوة، ويشتهر بخصوبته وأهميته الزراعية. [10] تنتشر فيه زراعة النخيل بشكل واسع، وتوجد به العديد من القرى والمستوطنات التي تعتمد على مياهه.";s:14:"description_en";s:210:"One of the primary valleys in Shabwah, noted for its fertility and agricultural significance. [10] Palm tree cultivation is widespread here, along with numerous villages and settlements that rely on its waters.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:8:"مائي";}s:8:"latitude";i:15;s:9:"longitude";d:47.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:11;a:17:{s:2:"id";i:570;s:7:"city_id";i:22;s:11:"external_id";s:11:"mathaf-ataq";s:4:"name";s:15:"متحف عتق";s:7:"name_en";s:11:"Ataq Museum";s:11:"description";s:332:"المتحف الرئيسي في المحافظة، يقع في العاصمة عتق. [11] يضم المتحف مجموعة هامة من القطع الأثرية التي عُثر عليها في مواقع شبوة المختلفة، مثل شبوة القديمة وقنا، ويعرض تاريخ المحافظة العريق.";s:14:"description_en";s:231:"The main museum of the governorate, located in the capital Ataq. [11] It contains an important collection of artifacts found across various sites in Shabwah, such as Old Shabwah and Qana, exhibiting the province's profound history.";s:10:"categories";a:4:{i:0;s:6:"museum";i:1;s:10:"historical";i:2;s:14:"archaeological";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:8:"متحف";i:1;s:12:"تاريخي";i:2;s:8:"أثري";i:3;s:10:"ثقافي";}s:8:"latitude";d:14.53;s:9:"longitude";d:46.83;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:12;a:17:{s:2:"id";i:571;s:7:"city_id";i:22;s:11:"external_id";s:23:"shuran-crater-lake-park";s:4:"name";s:51:"منتزه بحيرة شوران البركانية";s:7:"name_en";s:26:"Shouran Volcanic Lake Park";s:11:"description";s:375:"تقع بالقرب من بلحاف، وهي بحيرة مالحة تشكلت في فوهة بركان خامد. [1] تعتبر البحيرة ومنطقة الشاطئ المحيطة بها منتزهاً جيولوجياً وطبيعياً فريداً، ومكاناً مثالياً للاستجمام والسباحة والتمتع بالمنظر غير المألوف.";s:14:"description_en";s:263:"Located near Balhaf, it is a saltwater lake formed in the crater of a dormant volcano. [1] The lake and the surrounding beach area are considered a unique geological and natural park, and a perfect spot for relaxation, swimming, and enjoying the uncommon scenery.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:10:"geological";i:3;s:4:"lake";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:14:"جيولوجي";i:3;s:10:"بحيرة";}s:8:"latitude";d:13.99;s:9:"longitude";d:48.28;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:13;a:17:{s:2:"id";i:572;s:7:"city_id";i:22;s:11:"external_id";s:17:"wadi-habban-falls";s:4:"name";s:47:"شلالات وادي حبان الموسمية";s:7:"name_en";s:31:"Wadi Habban Seasonal Waterfalls";s:11:"description";s:301:"في الأجزاء العليا من وادي حبان، وقبل وصوله إلى السهول، يمر الوادي عبر مناطق مرتفعة. بعد الأمطار، تتشكل فيه شلالات وجداول مياه جارية، مما يجذب السكان المحليين للنزهة.";s:14:"description_en";s:193:"In the upper sections of Wadi Habban, before reaching the plains, the valley passes through elevated areas. After rain, waterfalls and running streams form, drawing local residents for outings.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.4;s:9:"longitude";d:47.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:14;a:17:{s:2:"id";i:573;s:7:"city_id";i:22;s:11:"external_id";s:16:"hawra-beach-park";s:4:"name";s:28:"منتزه شاطئ حورة";s:7:"name_en";s:17:"Hawrah Beach Park";s:11:"description";s:268:"شاطئ رملي جميل يقع غرب بير علي. يعتبر أقل شهرة وازدحاماً، مما يجعله منتزهاً ساحلياً هادئاً ومثالياً للاسترخاء والسباحة والاستمتاع بجمال بحر العرب.";s:14:"description_en";s:192:"A beautiful sandy beach located west of Bir Ali. It is less known and less crowded, making it a quiet coastal park perfect for unwinding, swimming, and relishing the beauty of the Arabian Sea.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:5:"beach";i:2;s:7:"natural";i:3;s:7:"coastal";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"شاطئ";i:2;s:10:"طبيعي";i:3;s:10:"ساحلي";}s:8:"latitude";d:14.05;s:9:"longitude";d:48.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:15;a:17:{s:2:"id";i:574;s:7:"city_id";i:22;s:11:"external_id";s:26:"al-saeed-mountain-cascades";s:4:"name";s:34:"شلالات جبال الصعيد";s:7:"name_en";s:29:"Al-Sa'id Mountains Waterfalls";s:11:"description";s:322:"مديرية الصعيد هي منطقة جبلية تقع في غرب شبوة. تتسبب الأمطار الموسمية في تدفق المياه بقوة عبر المنحدرات، مكونة سلسلة من الشلالات المتتالية (Cascades) التي توفر منظراً طبيعياً جذاباً.";s:14:"description_en";s:204:"The Al-Sa'id district is a mountainous area situated in western Shabwah. Seasonal rains induce powerful water flow across the slopes, forming a series of cascades that provide an attractive natural scene.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:14.45;s:9:"longitude";d:46.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:16;a:17:{s:2:"id";i:575;s:7:"city_id";i:22;s:11:"external_id";s:23:"wadi-mayfaah-banks-park";s:4:"name";s:39:"منتزه ضفاف وادي ميفعة";s:7:"name_en";s:24:"Wadi Mayfa'ah Banks Park";s:11:"description";s:328:"تعتبر ضفاف وادي ميفعة الخصبة، خاصة الأجزاء التي تنتشر فيها بساتين النخيل الكثيفة، بمثابة منتزهات طبيعية طويلة. يقصدها السكان المحليون للراحة في ظلال النخيل والاستمتاع بجو الوادي.";s:14:"description_en";s:213:"The fertile banks of Wadi Mayfa'ah, especially parts widespread with dense palm orchards, are regarded as long natural parks. Locals visit them to rest under the shade of the palms and enjoy the valley's ambiance.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"valley";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:10:"زراعة";}s:8:"latitude";d:14.2;s:9:"longitude";d:47.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:17;a:17:{s:2:"id";i:576;s:7:"city_id";i:22;s:11:"external_id";s:20:"armaa-highlands-park";s:4:"name";s:34:"منتزه مرتفعات عرمة";s:7:"name_en";s:20:"Armah Highlands Park";s:11:"description";s:268:"مديرية عرمة هي هضبة مرتفعة تتميز بطبيعتها الصخرية. توفر المنطقة إطلالات واسعة ومناطق هادئة تصلح للتخييم والمشي والاستمتاع بالطبيعة شبه الصحراوية.";s:14:"description_en";s:184:"The Armah district is an elevated plateau defined by its rocky nature. The area grants expansive views and quiet spaces fit for camping, walking, and soaking up the semi-desert nature.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.1;s:9:"longitude";d:47.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:18;a:17:{s:2:"id";i:577;s:7:"city_id";i:22;s:11:"external_id";s:17:"wadi-amaqin-falls";s:4:"name";s:49:"شلالات وادي عمقين الموسمية";s:7:"name_en";s:31:"Wadi 'Amqin Seasonal Waterfalls";s:11:"description";s:263:"وادي عمقين هو أحد الأودية الهامة في مديرية الروضة. في منابعه العليا، تتشكل شلالات موسمية جميلة بعد تدفق السيول من المرتفعات، وتكون وجهة للنزهات.";s:14:"description_en";s:199:"Wadi 'Amqin is a significant valley in the Ar Rawdah district. In its upper sources, beautiful seasonal waterfalls form when floodwaters flow down from the highlands, serving as a picnic destination.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:5:"local";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:8:"محلي";}s:8:"latitude";d:14.5;s:9:"longitude";d:47.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:19;a:17:{s:2:"id";i:578;s:7:"city_id";i:22;s:11:"external_id";s:21:"al-kawr-mountain-park";s:4:"name";s:28:"منتزه جبل الكور";s:7:"name_en";s:18:"Mount Al-Kawr Park";s:11:"description";s:308:"جبل الكور هو سلسلة جبلية ضخمة تفصل بين شبوة وأبين والبيضاء. الأجزاء التابعة لشبوة تتميز بوعورتها وجمالها الطبيعي، وتعتبر منتزهاً مثالياً للمغامرين ومحبي الطبيعة البكر.";s:14:"description_en";s:238:"Mount Al-Kawr is a massive mountain range separating Shabwah, Abyan, and Al Bayda. The sections belonging to Shabwah stand out for their ruggedness and natural beauty, presenting a perfect park for adventurers and lovers of virgin nature.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"adventure";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:12:"مغامرة";i:3;s:10:"طبيعي";}s:8:"latitude";d:14.1;s:9:"longitude";d:46.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:20;a:17:{s:2:"id";i:579;s:7:"city_id";i:22;s:11:"external_id";s:22:"wadi-jardan-oasis-park";s:4:"name";s:41:"منتزه واحات وادي جردان";s:7:"name_en";s:22:"Wadi Jardan Oases Park";s:11:"description";s:297:"تنتشر في وادي جردان واحات كثيفة من أشجار النخيل. تعتبر هذه الواحات بمثابة منتزهات طبيعية خضراء في قلب المناطق الجافة، وتوفر أماكن ظليلة ومناسبة للراحة والاستجمام.";s:14:"description_en";s:187:"Dense palm oases are dispersed throughout Wadi Jardan. These oases act as green natural parks in the heart of the dry regions, offering shady spots suitable for relaxation and recreation.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:5:"oasis";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"واحة";i:3;s:10:"زراعة";}s:8:"latitude";i:15;s:9:"longitude";d:47.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:21;a:17:{s:2:"id";i:580;s:7:"city_id";i:22;s:11:"external_id";s:19:"hisn-al-ghurab-park";s:4:"name";s:30:"منتزه حصن الغراب";s:7:"name_en";s:38:"Fort of the Crow Park (Husn Al-Ghurab)";s:11:"description";s:320:"اللسان البركاني الذي يقع عليه حصن الغراب الأثري في بير علي، يعتبر منتزهاً بحد ذاته. يوفر مساراً للمشي (هايكنج) إلى القمة، مع إطلالات بانورامية مذهلة على الساحل والميناء القديم.";s:14:"description_en";s:219:"The volcanic peninsula housing the archaeological Husn Al-Ghurab in Bir Ali is considered a park in its own right. It provides a hiking trail to the top, with awe-inspiring panoramic views of the coast and the old port.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"hiking";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:12:"هايكنج";i:3;s:12:"تاريخي";}s:8:"latitude";d:14.0167;s:9:"longitude";d:48.3333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:22;a:13:{s:2:"id";i:11;s:4:"slug";s:5:"saada";s:4:"name";s:8:"صعدة";s:7:"name_en";s:6:"Sa'dah";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:14:"saada_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:19;s:9:"landmarks";a:19:{i:0;a:17:{s:2:"id";i:306;s:7:"city_id";i:11;s:11:"external_id";s:14:"saada-old-city";s:4:"name";s:34:"مدينة صعدة القديمة";s:7:"name_en";s:18:"Old City of Sa'dah";s:11:"description";s:359:"مدينة تاريخية فريدة محاطة بسور طيني ضخم، وتعتبر من أقدم المدن المأهولة في اليمن. [1] تتميز بمنازلها الطينية المزخرفة، وأزقتها الضيقة، وأسواقها التقليدية، وتضم العديد من المساجد والمقابر التاريخية.";s:14:"description_en";s:253:"A unique historical city surrounded by a massive mud wall, considered one of the oldest inhabited cities in Yemen. [1] It is characterized by its decorated mud houses, narrow alleys, and traditional markets, and houses many historical mosques and tombs.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:8:"cultural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:10:"ثقافي";}s:8:"latitude";d:16.943;s:9:"longitude";d:43.761;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/saada/saada_old_city1.jpg";i:1;s:42:"images/landmarks/saada/saada_old_city2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:1;a:17:{s:2:"id";i:307;s:7:"city_id";i:11;s:11:"external_id";s:14:"al-hadi-mosque";s:4:"name";s:34:"جامع الإمام الهادي";s:7:"name_en";s:19:"Imam Al-Hadi Mosque";s:11:"description";s:372:"أحد أقدم وأهم المساجد التاريخية في اليمن، أسسه الإمام الهادي يحيى بن الحسين في القرن التاسع الميلادي. [2] يعتبر مركزاً دينياً وعلمياً هاماً، ويتميز بقبابه البيضاء ومئذنته الشاهقة، ويضم ضريح الإمام الهادي.";s:14:"description_en";s:281:"One of the oldest and most important historical mosques in Yemen, founded by Imam Al-Hadi Yahya bin Al-Hussein in the 9th century AD. [2] It is an important religious and scientific center, characterized by its white domes and towering minaret, and houses the tomb of Imam Al-Hadi.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:7:"islamic";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"إسلامي";i:3;s:12:"معماري";}s:8:"latitude";d:16.944;s:9:"longitude";d:43.762;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/saada/al_hadi_mosque1.jpg";i:1;s:42:"images/landmarks/saada/al_hadi_mosque2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:2;a:17:{s:2:"id";i:308;s:7:"city_id";i:11;s:11:"external_id";s:15:"saada-great-dam";s:4:"name";s:46:"سد صعدة الكبير (سد الشهيد)";s:7:"name_en";s:33:"Sa'dah Great Dam (Al-Shaheed Dam)";s:11:"description";s:284:"سد حديث يقع شمال غرب مدينة صعدة، بني لحصاد مياه الأمطار وتغذية المياه الجوفية. [3] شكل السد بحيرة كبيرة أصبحت متنفساً طبيعياً ومنظراً جمالياً للسكان والزوار.";s:14:"description_en";s:220:"A modern dam located northwest of Sa'dah city, built to harvest rainwater and recharge groundwater. [3] The dam formed a large lake that has become a natural retreat and an aesthetic landscape for residents and visitors.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:10:"recreation";i:3;s:6:"modern";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:12:"ترفيهي";i:3;s:8:"حديث";}s:8:"latitude";d:16.98;s:9:"longitude";d:43.73;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/landmarks/saada/saada_dam1.jpg";i:1;s:37:"images/landmarks/saada/saada_dam2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:3;a:17:{s:2:"id";i:309;s:7:"city_id";i:11;s:11:"external_id";s:20:"al-sammad-park-saada";s:4:"name";s:57:"حديقة الشهيد (الحديقة المركزية)";s:7:"name_en";s:30:"Al-Shaheed Park (Central Park)";s:11:"description";s:314:"تعتبر الحديقة العامة الرئيسية والمركزية في مدينة صعدة. [1, 2] تم إعادة تأهيلها وتطويرها لتكون متنفسًا رئيسيًا للعائلات، وتضم مساحات خضراء وألعابًا للأطفال ومرافق للزوار. [1, 2]";s:14:"description_en";s:218:"Considered the main and central public park in Sa'dah city. [1, 2] It was rehabilitated and developed to serve as a primary retreat for families, featuring green spaces, children's games, and visitor facilities. [1, 2]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:310;s:7:"city_id";i:11;s:11:"external_id";s:15:"saada-city-park";s:4:"name";s:30:"حديقة مدينة صعدة";s:7:"name_en";s:16:"Sa'dah City Park";s:11:"description";s:282:"إحدى الحدائق العامة في مدينة صعدة التي تخدم السكان كمتنفس ترفيهي. [3] تضم الحديقة مناطق للجلوس ومساحات خضراء، وتعتبر وجهة للعائلات والأطفال داخل المدينة. [3]";s:14:"description_en";s:209:"One of the public parks in Sa'dah city serving as a recreational retreat for residents. [3] The park includes seating areas and green spaces, and is a destination for families and children within the city. [3]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"neighborhood";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:13:"حي سكني";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:311;s:7:"city_id";i:11;s:11:"external_id";s:9:"wadi-alaf";s:4:"name";s:43:"وادي العبدين (وادي آلاف)";s:7:"name_en";s:26:"Wadi Al-Abdain (Wadi Alaf)";s:11:"description";s:333:"من أشهر الأودية في محافظة صعدة، ويقع في مديرية سحار. [4, 5] يشتهر الوادي بخصوبته ومياهه الجارية ومزارع الرمان والعنب، ويعتبر منتزهًا طبيعيًا مفتوحًا يقصده السكان للنزهة والاستجمام. [4, 5]";s:14:"description_en";s:277:"One of the most famous valleys in Sa'dah Governorate, located in the Sahar district. [4, 5] The valley is famous for its fertility, running waters, and pomegranate and grape farms. It is considered an open natural park frequented by residents for picnics and recreation. [4, 5]";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:12:"natural-park";i:2;s:12:"recreational";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:21:"منتزه طبيعي";i:2;s:12:"ترفيهي";i:3;s:10:"زراعة";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/landmarks/saada/wadi_alaf1.jpg";i:1;s:37:"images/landmarks/saada/wadi_alaf2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:312;s:7:"city_id";i:11;s:11:"external_id";s:24:"saada-fortress-al-qishla";s:4:"name";s:21:"قلعة القشلة";s:7:"name_en";s:17:"Al-Qishlah Castle";s:11:"description";s:319:"حصن تاريخي منيع يقع على تلة تشرف على مدينة صعدة القديمة. [4] كان يستخدم كمقر للحكم ومركز عسكري، ويتميز ببنائه الحجري القوي وأبراجه الدفاعية، ويوفر إطلالة بانورامية على المدينة.";s:14:"description_en";s:260:"An impregnable historical fortress located on a hill overlooking the Old City of Sa'dah. [4] It was used as a seat of governance and a military center, characterized by its strong stone construction and defensive towers, providing a panoramic view of the city.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"military";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:10:"عسكري";i:3;s:12:"إطلالة";}s:8:"latitude";d:16.941;s:9:"longitude";d:43.76;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/saada/saada_fortress1.jpg";i:1;s:42:"images/landmarks/saada/saada_fortress2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:313;s:7:"city_id";i:11;s:11:"external_id";s:15:"tilmis-fortress";s:4:"name";s:15:"حصن تلمص";s:7:"name_en";s:11:"Tulmus Fort";s:11:"description";s:299:"حصن تاريخي منيع يقع على قمة جبل شاهق في مديرية سحار. [7] يعتبر من أهم الحصون الدفاعية في محافظة صعدة، ويتميز بموقعه الاستراتيجي الذي يسيطر على الطرق التجارية القديمة.";s:14:"description_en";s:246:"An impregnable historical fort located atop a towering mountain in the Sahar district. [7] It is considered one of the most important defensive forts in Sa'dah Governorate, distinguished by its strategic location controlling ancient trade routes.";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:8:"fortress";i:2;s:8:"mountain";i:3;s:8:"military";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:8:"قلعة";i:2;s:6:"جبل";i:3;s:10:"عسكري";}s:8:"latitude";d:16.85;s:9:"longitude";d:43.65;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/saada/tilmis_fortress1.jpg";i:1;s:43:"images/landmarks/saada/tilmis_fortress2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:615;s:7:"city_id";i:11;s:11:"external_id";s:9:"wadi-alaf";s:4:"name";s:19:"وادي العلف";s:7:"name_en";s:12:"Wadi Al-Alaf";s:11:"description";s:305:"أحد الأودية الخصبة في محافظة صعدة، ويشتهر بزراعة أجود أنواع العنب والرمان. [8] يعتبر الوادي متنفساً طبيعياً ومزاراً زراعياً يعكس خصوبة أرض صعدة وقدرة أهلها على الزراعة.";s:14:"description_en";s:261:"One of the fertile valleys in Sa'dah Governorate, famous for cultivating the finest types of grapes and pomegranates. [8] The valley is a natural escape and an agricultural attraction that reflects the fertility of Sa'dah's land and its people's farming skills.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:17.05;s:9:"longitude";d:43.6;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:37:"images/landmarks/saada/wadi_alaf1.jpg";i:1;s:37:"images/landmarks/saada/wadi_alaf2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T20:59:01.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}i:9;a:17:{s:2:"id";i:314;s:7:"city_id";i:11;s:11:"external_id";s:20:"jabal-samar-fortress";s:4:"name";s:20:"حصن جبل سمر";s:7:"name_en";s:16:"Mount Samar Fort";s:11:"description";s:306:"موقع أثري وحصن قديم يقع في مديرية مجز. [10] يعود تاريخه إلى عصور ما قبل الإسلام، ويحتوي على نقوش صخرية وبقايا مبانٍ قديمة، مما يدل على الأهمية التاريخية للمنطقة منذ القدم.";s:14:"description_en";s:239:"An archaeological site and ancient fort located in the Majz district. [10] Dating back to pre-Islamic eras, it contains rock inscriptions and remains of ancient buildings, indicating the historical importance of the region since antiquity.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"fortress";i:3;s:5:"ruins";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"قلعة";i:3;s:10:"أطلال";}s:8:"latitude";d:17.15;s:9:"longitude";d:43.5;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/saada/jabal_samar1.jpg";i:1;s:39:"images/landmarks/saada/jabal_samar2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:315;s:7:"city_id";i:11;s:11:"external_id";s:12:"wadi-nashour";s:4:"name";s:17:"وادي نشور";s:7:"name_en";s:11:"Wadi Nushur";s:11:"description";s:346:"من أكبر وأهم الأودية في محافظة صعدة، يقع في مديرية الصفراء. [1] يشتهر بخصوبته العالية وزراعته لمختلف أنواع الفواكه والخضروات، وتتدفق فيه السيول الموسمية بغزارة، مما يجعله شريان حياة للمنطقة.";s:14:"description_en";s:267:"One of the largest and most important valleys in Sa'dah Governorate, located in the As Safra district. [1] Famous for its high fertility and cultivation of various fruits and vegetables, seasonal floods flow abundantly through it, making it a lifeline for the region.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:12:"water-course";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:17:"مجرى مائي";}s:8:"latitude";d:16.8;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/water/saada/wadi_nashour1.jpg";i:1;s:36:"images/water/saada/wadi_nashour2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:11;a:17:{s:2:"id";i:316;s:7:"city_id";i:11;s:11:"external_id";s:12:"wadi-khaywan";s:4:"name";s:19:"وادي خيوان";s:7:"name_en";s:12:"Wadi Khaywan";s:11:"description";s:305:"وادي واسع يقع في الأجزاء الجنوبية من المحافظة، ويمتد إلى محافظة عمران. [2] يعتبر من الأودية الهامة التي تجمع مياه السيول من مناطق واسعة، وتنتشر على ضفافه المزارع والقرى.";s:14:"description_en";s:232:"A wide valley located in the southern parts of the governorate, extending into Amran Governorate. [2] It is considered an important valley that collects floodwaters from vast areas, with farms and villages scattered along its banks.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:16.65;s:9:"longitude";d:43.9;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/water/saada/wadi_khaywan1.jpg";i:1;s:36:"images/water/saada/wadi_khaywan2.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:12;a:17:{s:2:"id";i:317;s:7:"city_id";i:11;s:11:"external_id";s:11:"al-talh-dam";s:4:"name";s:15:"سد الطلح";s:7:"name_en";s:11:"Al-Talh Dam";s:11:"description";s:290:"سد يقع بالقرب من منطقة سوق الطلح الشهير، بني لحماية المنطقة من أخطار السيول وتوفير المياه للزراعة. [3] أصبحت بحيرته منظراً مائياً جميلاً يرتاده السكان المحليون.";s:14:"description_en";s:208:"A dam located near the famous Al-Talh market area, built to protect the region from flood risks and provide water for agriculture. [3] Its lake has become a beautiful waterscape frequented by local residents.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:16:"water-management";i:2;s:11:"agriculture";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:19:"إدارة مياه";i:2;s:10:"زراعي";i:3;s:12:"ترفيهي";}s:8:"latitude";d:16.93;s:9:"longitude";d:43.74;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:35:"images/water/saada/al_talh_dam1.jpg";i:1;s:35:"images/water/saada/al_talh_dam2.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:13;a:17:{s:2:"id";i:318;s:7:"city_id";i:11;s:11:"external_id";s:12:"wadi-dhahyan";s:4:"name";s:19:"وادي ضحيان";s:7:"name_en";s:11:"Wadi Dahyan";s:11:"description";s:276:"وادي رئيسي يقع في مديرية مجز، ويشتهر بأراضيه الزراعية الخصبة. [4] يعتبر الوادي مصدراً هاماً للمياه السطحية والجوفية في المنطقة، وتنمو فيه محاصيل متنوعة.";s:14:"description_en";s:207:"A main valley located in the Majz district, famous for its fertile agricultural lands. [4] The valley is a significant source of surface and groundwater in the region, supporting the growth of diverse crops.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:12:"water-course";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:17:"مجرى مائي";}s:8:"latitude";d:17.1;s:9:"longitude";d:43.45;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/water/saada/wadi_dhahyan1.jpg";i:1;s:36:"images/water/saada/wadi_dhahyan2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:14;a:17:{s:2:"id";i:319;s:7:"city_id";i:11;s:11:"external_id";s:11:"wadi-rahban";s:4:"name";s:19:"وادي رحبان";s:7:"name_en";s:11:"Wadi Rahban";s:11:"description";s:275:"وادي جميل يقع في مديرية ساقين، ويتميز بمناظره الطبيعية الخلابة ومدرجاته الزراعية. [5] يعتبر متنفساً طبيعياً للسكان، وتتدفق فيه المياه بعد هطول الأمطار.";s:14:"description_en";s:219:"A beautiful valley located in the Saqayn district, characterized by its stunning natural landscapes and agricultural terraces. [5] It serves as a natural retreat for locals, with water flowing through it after rainfall.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعي";}s:8:"latitude";d:16.88;s:9:"longitude";d:43.55;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:35:"images/water/saada/wadi_rahban1.jpg";i:1;s:35:"images/water/saada/wadi_rahban2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:15;a:17:{s:2:"id";i:320;s:7:"city_id";i:11;s:11:"external_id";s:10:"saqayn-dam";s:4:"name";s:15:"سد ساقين";s:7:"name_en";s:10:"Saqayn Dam";s:11:"description";s:298:"سد هام يقع في مديرية ساقين، بني بهدف التحكم في مياه السيول وتوفير مصدر مائي مستدام للزراعة في الوادي. [6] يلعب دوراً حيوياً في دعم الاقتصاد المحلي القائم على الزراعة.";s:14:"description_en";s:224:"An important dam located in the Saqayn district, built to control floodwaters and provide a sustainable water source for agriculture in the valley. [6] It plays a vital role in supporting the local agriculture-based economy.";s:10:"categories";a:3:{i:0;s:3:"dam";i:1;s:16:"water-management";i:2;s:11:"agriculture";}s:14:"category_names";a:3:{i:0;s:4:"سد";i:1;s:19:"إدارة مياه";i:2;s:10:"زراعي";}s:8:"latitude";d:16.89;s:9:"longitude";d:43.58;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:34:"images/water/saada/saqayn_dam1.jpg";i:1;s:34:"images/water/saada/saqayn_dam2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:16;a:17:{s:2:"id";i:321;s:7:"city_id";i:11;s:11:"external_id";s:11:"wadi-burkan";s:4:"name";s:19:"وادي بركان";s:7:"name_en";s:11:"Wadi Burkan";s:11:"description";s:292:"وادي يقع في مديرية رازح الحدودية، ويتميز بطبيعته الجبلية الوعرة وجماله الطبيعي. [7] تتدفق فيه المياه بقوة بعد الأمطار، وتنتشر على جوانبه القرى المعلقة بشكل مذهل.";s:14:"description_en";s:230:"A valley located in the border district of Razih, characterized by its rugged mountainous nature and natural beauty. [7] Water flows powerfully through it after rain, and astonishing hanging villages are scattered along its sides.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:6:"جبل";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:17.25;s:9:"longitude";d:43.3;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:35:"images/water/saada/wadi_burkan1.jpg";i:1;s:35:"images/water/saada/wadi_burkan2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:17;a:17:{s:2:"id";i:322;s:7:"city_id";i:11;s:11:"external_id";s:9:"wadi-aqiq";s:4:"name";s:17:"وادي عقيك";s:7:"name_en";s:9:"Wadi Aqiq";s:11:"description";s:303:"أحد الأودية التي تخترق مديرية كتاف في الجزء الشرقي الصحراوي من المحافظة. [8] على الرغم من طبيعته الصحراوية، إلا أنه يشكل مجرى سيول هام وتنمو فيه بعض النباتات الصحراوية.";s:14:"description_en";s:198:"One of the valleys cutting through the Kitaf district in the eastern desert part of the governorate. [8] Despite its desert nature, it forms an important flood channel where some desert plants grow.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"desert";i:2;s:12:"water-course";i:3;s:6:"nature";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"صحراء";i:2;s:17:"مجرى مائي";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.9;s:9:"longitude";d:44.2;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:33:"images/water/saada/wadi_aqiq1.jpg";i:1;s:33:"images/water/saada/wadi_aqiq2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:18;a:17:{s:2:"id";i:614;s:7:"city_id";i:11;s:11:"external_id";s:9:"wadi-alaf";s:4:"name";s:10:"???? ?????";s:7:"name_en";s:10:"???? ?????";s:11:"description";s:168:"??? ??????? ?????? ?? ?????? ????? ?????? ?????? ???? ????? ????? ???????. [8] ????? ?????? ??????? ??????? ??????? ??????? ???? ????? ??? ???? ????? ????? ??? ???????.";s:14:"description_en";s:168:"??? ??????? ?????? ?? ?????? ????? ?????? ?????? ???? ????? ????? ???????. [8] ????? ?????? ??????? ??????? ??????? ??????? ???? ????? ??? ???? ????? ????? ??? ???????.";s:10:"categories";a:4:{i:0;s:4:"wadi";i:1;s:6:"nature";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:4:"????";i:1;s:5:"?????";i:2;s:5:"?????";i:3;s:11:"????? ?????";}s:8:"latitude";d:17.05;s:9:"longitude";d:43.6;s:15:"google_maps_url";s:37:"https://maps.google.com/?q=17.05,43.6";s:6:"images";a:2:{i:0;s:37:"images/landmarks/saada/wadi_alaf1.jpg";i:1;s:37:"images/landmarks/saada/wadi_alaf2.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:06:00.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:23;a:13:{s:2:"id";i:1;s:4:"slug";s:5:"sanaa";s:4:"name";s:10:"صنعاء";s:7:"name_en";s:6:"Sana'a";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:14:"sanaa_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:42;s:9:"landmarks";a:42:{i:0;a:17:{s:2:"id";i:1;s:7:"city_id";i:1;s:11:"external_id";s:14:"sanaa-old-city";s:4:"name";s:36:"مدينة صنعاء القديمة";s:7:"name_en";s:18:"Old City of Sana'a";s:11:"description";s:455:"تعتبر مدينة صنعاء القديمة واحدة من أقدم المدن المأهولة في العالم، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو. تتميز بمبانيها الفريدة المبنية من الطين والآجر والمزينة بزخارف جصية رائعة، وأزقتها الضيقة المتعرجة، وأسواقها التقليدية النابضة بالحياة.";s:14:"description_en";s:309:"The Old City of Sana'a is considered one of the oldest inhabited cities in the world and is a UNESCO World Heritage site. It is distinguished by its unique buildings made of mud and fired bricks, decorated with magnificent gypsum patterns, as well as its narrow winding alleys and vibrant traditional markets.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"ثقافي";}s:8:"latitude";d:15.3559276;s:9:"longitude";d:44.2129208;s:15:"google_maps_url";s:41:"https://maps.app.goo.gl/cZ4QmWNDdpNgFQnc8";s:6:"images";a:1:{i:0;s:64:"https://live.staticflickr.com/65535/52941126870_701c919a6f_b.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:1;a:17:{s:2:"id";i:2;s:7:"city_id";i:1;s:11:"external_id";s:18:"sanaa-great-mosque";s:4:"name";s:38:"الجامع الكبير بصنعاء";s:7:"name_en";s:22:"Great Mosque of Sana'a";s:11:"description";s:262:"من أقدم المساجد الإسلامية، بني في السنة السادسة للهجرة في عهد الرسول محمد، وتم توسعته في العهد الأموي. يضم مكتبة تحتوي على مخطوطات نادرة وقديمة.";s:14:"description_en";s:210:"One of the oldest Islamic mosques, built in the sixth year of the Hijra during the era of Prophet Muhammad, and expanded during the Umayyad period. It includes a library containing rare and ancient manuscripts.";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:15.3533899;s:9:"longitude";d:44.2148815;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTTwVJyEyyrc3kwCRCYpVmqUHzADvmJWMGlvw&s";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:2;a:17:{s:2:"id";i:3;s:7:"city_id";i:1;s:11:"external_id";s:21:"sanaa-national-museum";s:4:"name";s:25:"المتحف الوطني";s:7:"name_en";s:15:"National Museum";s:11:"description";s:188:"متحف تاريخي يرجع تأسيسه إلى عام 1971، يضم أكثر من 30,000 قطعة أثرية يمنية تعكس تاريخ وحضارة اليمن عبر العصور.";s:14:"description_en";s:154:"A historical museum established in 1971, housing more than 30,000 Yemeni artifacts that reflect the history and civilization of Yemen throughout the ages.";s:10:"categories";a:3:{i:0;s:8:"cultural";i:1;s:10:"historical";i:2;s:11:"educational";}s:14:"category_names";a:3:{i:0;s:10:"ثقافي";i:1;s:12:"تاريخي";i:2;s:12:"تعليمي";}s:8:"latitude";d:15.356056;s:9:"longitude";d:44.2067506;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:84:"https://purehistory.org/wp-content/uploads/2013/12/800px-Sana_national_museum_00.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:3;a:17:{s:2:"id";i:4;s:7:"city_id";i:1;s:11:"external_id";s:18:"sanaa-souq-al-milh";s:4:"name";s:17:"سوق الملح";s:7:"name_en";s:26:"Souq Al-Milh (Salt Market)";s:11:"description";s:444:"هو القلب التجاري النابض لصنعاء القديمة، وهو ليس سوقاً للملح فقط بل مجمع لأسواق متخصصة متعددة. يمكنك أن تجد فيه كل شيء من التوابل والبن والجنابي (الخناجر اليمنية) والفضيات والمنسوجات والحرف اليدوية. التجول في أزقته المتفرعة يعتبر رحلة عبر الزمن.";s:14:"description_en";s:342:"It is the beating commercial heart of the Old City of Sana'a. It is not just a market for salt, but a complex of multiple specialized markets. You can find everything there, from spices and coffee to Jambiyas (Yemeni daggers), silverware, textiles, and handicrafts. Wandering through its branching alleys is considered a journey through time.";s:10:"categories";a:3:{i:0;s:6:"market";i:1;s:10:"historical";i:2;s:8:"cultural";}s:14:"category_names";a:3:{i:0;s:6:"سوق";i:1;s:12:"تاريخي";i:2;s:10:"ثقافي";}s:8:"latitude";d:15.3544816;s:9:"longitude";d:44.216745;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:106:"https://ichef.bbci.co.uk/news/640/amz/worldservice/live/assets/images/2014/10/07/141007115034_sam_0808.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:4;a:17:{s:2:"id";i:5;s:7:"city_id";i:1;s:11:"external_id";s:18:"sanaa-dar-al-hajar";s:4:"name";s:17:"دار الحجر";s:7:"name_en";s:26:"Dar Al-Hajar (Rock Palace)";s:11:"description";s:508:"قصر صخري فريد يقع في وادي ظهر شمال غرب صنعاء. بني على قمة صخرة جرانيتية ويعتبر أيقونة للعمارة اليمنية. كان في الأصل حصناً قديماً قبل أن يعيد بناءه الإمام يحيى حميد الدين في ثلاثينيات القرن العشرين ليكون قصره الصيفي. يتميز بتصميمه متعدد الطوابق ونوافذه المزخرفة وإطلالاته الساحرة.";s:14:"description_en";s:338:"A unique rock palace located in Wadi Dhar, northwest of Sana'a. Built atop a granite rock, it is considered an icon of Yemeni architecture. It was originally an ancient fortress before Imam Yahya Hamid ed-Din rebuilt it in the 1930s to serve as his summer palace. It features a multi-story design, decorated windows, and enchanting views.";s:10:"categories";a:3:{i:0;s:13:"architectural";i:1;s:10:"historical";i:2;s:6:"palace";}s:14:"category_names";a:3:{i:0;s:12:"معماري";i:1;s:12:"تاريخي";i:2;s:6:"قصر";}s:8:"latitude";d:15.4412119;s:9:"longitude";d:44.1257303;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:101:"https://cdn.al-ain.com/images/2023/2/24/135-160516-dar-alhajar-yemen-architectural-wonder_700x400.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:5;a:17:{s:2:"id";i:6;s:7:"city_id";i:1;s:11:"external_id";s:18:"sanaa-bab-al-yaman";s:4:"name";s:17:"باب اليمن";s:7:"name_en";s:12:"Bab al-Yemen";s:11:"description";s:449:"هو البوابة الرئيسية المتبقية لسور صنعاء القديم، ويعتبر المدخل الجنوبي للمدينة التاريخية. يعود تاريخه إلى أكثر من ألف عام، ويتميز بتصميمه المهيب الذي يعكس تاريخ صنعاء العريق. يؤدي مباشرة إلى سوق الملح والساحة المقابلة له التي تعج بالنشاط والحياة.";s:14:"description_en";s:297:"It is the main remaining gate of the wall of the Old City of Sana'a and serves as the southern entrance to the historic city. Dating back over a thousand years, it features a majestic design that reflects Sana'a's ancient history. It leads directly to Souq Al-Milh and its vibrant adjacent square.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:4:"gate";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"بوابة";}s:8:"latitude";d:15.3514045;s:9:"longitude";d:44.2162899;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:115:"https://www.yementourism.com/images/aathenewpic/bodyimg/onlyinyemen/Architectures/sanaa-city-in-yemen-1600x1071.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:6;a:17:{s:2:"id";i:7;s:7:"city_id";i:1;s:11:"external_id";s:21:"sanaa-al-saleh-mosque";s:4:"name";s:21:"جامع الصالح";s:7:"name_en";s:15:"Al-Saleh Mosque";s:11:"description";s:463:"أكبر مسجد حديث في اليمن، وهو تحفة معمارية مذهلة تمزج بين الطراز المعماري اليمني التقليدي والفن الإسلامي الحديث. يتميز بقبابه المتعددة ومآذنه الشاهقة وزخارفه الداخلية الدقيقة من الخشب والجبس والنحاس. يتسع لعشرات الآلاف من المصلين ويضم كلية لعلوم القرآن.";s:14:"description_en";s:374:"The largest modern mosque in Yemen, it is a stunning architectural masterpiece that blends traditional Yemeni architecture with modern Islamic art. It is distinguished by its multiple domes, towering minarets, and intricate interior decorations made of wood, gypsum, and copper. It can accommodate tens of thousands of worshipers and includes a college for Quranic sciences.";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:13:"architectural";i:2;s:6:"modern";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"معماري";i:2;s:8:"حديث";}s:8:"latitude";d:15.3265857;s:9:"longitude";d:44.2080902;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:60:"https://dawa.center/images/islamic-centers/5dc4277dc961b.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:7;a:17:{s:2:"id";i:8;s:7:"city_id";i:1;s:11:"external_id";s:20:"sanaa-haddah-village";s:4:"name";s:15:"قرية حدة";s:7:"name_en";s:13:"Hadda Village";s:11:"description";s:421:"منطقة تاريخية تقع جنوب صنعاء، كانت في الماضي قرية منفصلة وتشتهر ببساتينها ومزارع العنب. لا تزال تحتفظ ببعض من طابعها الريفي وتضم بيوتاً وقصوراً قديمة. تشتهر المنطقة حالياً بكونها حياً راقياً يضم العديد من المطاعم والمقاهي الحديثة.";s:14:"description_en";s:290:"A historic area located south of Sana'a, it was once a separate village famous for its orchards and vineyards. It still retains some of its rural character, featuring old houses and palaces. Today, the area is well-known as an upscale neighborhood housing many modern restaurants and cafes.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:12:"recreational";i:2;s:8:"district";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"ترفيهي";i:2;s:4:"حي";}s:8:"latitude";d:15.29044;s:9:"longitude";d:44.1630233;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:62:"https://live.staticflickr.com/5246/5354281290_94793b7900_c.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:8;a:17:{s:2:"id";i:9;s:7:"city_id";i:1;s:11:"external_id";s:20:"sanaa-nuqum-mountain";s:4:"name";s:13:"جبل نقم";s:7:"name_en";s:11:"Mount Nuqum";s:11:"description";s:445:"الجبل الشرقي الذي يطل على مدينة صنعاء ويوفر إطلالة بانورامية رائعة على المدينة القديمة وأحيائها الحديثة. كان موقعاً استراتيجياً عبر التاريخ وتوجد على قمته بقايا قلعة قديمة. يعتبر متنفساً طبيعياً ومقصداً للسكان لمشاهدة منظر الغروب فوق المدينة.";s:14:"description_en";s:333:"The eastern mountain overlooking Sana'a, providing a magnificent panoramic view of the old city and its modern neighborhoods. It has been a strategic location throughout history, and the ruins of an ancient castle sit at its peak. It serves as a natural retreat and a popular destination for locals to watch the sunset over the city.";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:9:"viewpoint";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:6:"مطل";i:2;s:12:"تاريخي";}s:8:"latitude";d:15.3637212;s:9:"longitude";d:44.240603;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:64:"https://a4.pbase.com/u48/bmcmorrow/upload/40669654.yemen1100.JPG";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:9;a:17:{s:2:"id";i:10;s:7:"city_id";i:1;s:11:"external_id";s:16:"sanaa-old-sailah";s:4:"name";s:29:"السائلة القديمة";s:7:"name_en";s:13:"Old Al-Sailah";s:11:"description";s:470:"مجرى مائي موسمي يخترق مدينة صنعاء ويفصل بين شطري المدينة القديمة. تم تحويل أجزاء كبيرة منه إلى طريق حديث، لكن لا يزال مجراه القديم مرئياً بوضوح، وتحيط به المباني التاريخية والجسور القديمة. في موسم الأمطار، تتحول السائلة إلى نهر يضفي جمالاً خاصاً على المدينة.";s:14:"description_en";s:334:"A seasonal waterway cutting through Sana'a, dividing the two halves of the old city. Large parts of it have been converted into a modern road, but its ancient path remains clearly visible, flanked by historical buildings and old bridges. During the rainy season, Al-Sailah transforms into a river, adding a special beauty to the city.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:7:"natural";i:2;s:5:"urban";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"طبيعي";i:2;s:8:"حضري";}s:8:"latitude";d:15.3510254;s:9:"longitude";d:44.2114507;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:232:"https://www.yemenipress.net/wp-content/uploads/2020/04/%D8%B5%D9%88%D8%B1%D8%A9-%D8%AC%D8%AF%D9%8A%D8%AF%D8%A9-%D9%84%D8%B3%D8%A7%D8%A6%D9%84%D8%A9-%D8%B5%D9%86%D8%B9%D8%A7%D8%A1-%D8%A7%D9%84%D9%82%D8%AF%D9%8A%D9%85%D8%A9-%D9%87.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:10;a:17:{s:2:"id";i:11;s:7:"city_id";i:1;s:11:"external_id";s:19:"sanaa-al-mahdi-dome";s:4:"name";s:19:"قبة المهدي";s:7:"name_en";s:15:"Qubbat Al-Mahdi";s:11:"description";s:443:"مسجد وقبة تاريخية تقع في الجانب الغربي من صنعاء القديمة، بناه الإمام المهدي عباس عام 1750م. يتميز المسجد بتصميمه العثماني المتأثر بالعمارة المحلية، وقبته الكبيرة المزخرفة ومئذنته الشاهقة. يعد من أجمل مساجد صنعاء وأحد معالمها المعمارية البارزة.";s:14:"description_en";s:346:"A historic mosque and dome located on the western side of the Old City of Sana'a, built by Imam Al-Mahdi Abbas in 1750 AD. The mosque features an Ottoman design influenced by local architecture, along with a large, ornate dome and a towering minaret. It is considered one of Sana'a's most beautiful mosques and a prominent architectural landmark.";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:13:"architectural";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"معماري";i:2;s:12:"تاريخي";}s:8:"latitude";d:15.35301;s:9:"longitude";d:44.2102336;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:64:"https://a4.pbase.com/u48/bmcmorrow/upload/40669686.yemen1295.JPG";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:11;a:17:{s:2:"id";i:12;s:7:"city_id";i:1;s:11:"external_id";s:20:"sanaa-wadi-dhar-park";s:4:"name";s:41:"منتزه وادي ظهر الطبيعي";s:7:"name_en";s:21:"Wadi Dhar Nature Park";s:11:"description";s:499:"يعتبر المنتزه الطبيعي الأول لسكان العاصمة صنعاء. يقع في وادٍ خصب شمال غرب المدينة، ويشتهر ببساتينه الغناء ومزارع الفاكهة التي يمكن للزوار التجول بينها وشراء المنتجات الطازجة. وجود دار الحجر في قلبه يجعله وجهة مثالية تجمع بين التنزه في الطبيعة والاستمتاع بالتاريخ المعماري.";s:14:"description_en";s:364:"Considered the premier natural park for residents of the capital, Sana'a. Located in a fertile valley northwest of the city, it is famous for its lush orchards and fruit farms where visitors can stroll and buy fresh produce. The presence of Dar al-Hajar in its heart makes it an ideal destination combining nature walks with the enjoyment of architectural history.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:7:"tourism";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:10:"سياحي";i:3;s:10:"عائلي";}s:8:"latitude";d:15.4388749;s:9:"longitude";d:44.1476253;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:101:"https://cdn.al-ain.com/images/2023/2/24/135-160516-dar-alhajar-yemen-architectural-wonder_700x400.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:12;a:17:{s:2:"id";i:13;s:7:"city_id";i:1;s:11:"external_id";s:17:"sanaa-sabeen-park";s:4:"name";s:38:"حديقة ومنتزه السبعين";s:7:"name_en";s:14:"Al-Sabeen Park";s:11:"description";s:444:"أكبر منتزه عام في صنعاء، وهو الرئة الخضراء للمدينة. يوفر مساحات واسعة للنزهات العائلية والاسترخاء على العشب. يضم بحيرة صناعية للقوارب، ومدينة ألعاب متكاملة، وحديقة حيوانات، مما يجعله وجهة ترفيهية شاملة ومكاناً مثالياً لقضاء يوم كامل من المرح.";s:14:"description_en";s:315:"The largest public park in Sana'a, serving as the city's green lung. It provides vast spaces for family picnics and relaxing on the grass. It includes an artificial boating lake, a complete amusement park, and a zoo, making it a comprehensive entertainment destination and an ideal place to spend a full day of fun.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";i:3;s:5:"urban";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:8:"حضري";}s:8:"latitude";d:15.3222456;s:9:"longitude";d:44.2015664;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:143:"https://www.yemenmonitor.com/wp-content/uploads/2020/08/%D8%AD%D8%AF%D9%8A%D9%82%D8%A9-%D8%A7%D9%84%D8%B3%D8%A8%D8%B9%D9%8A%D9%86-780x470-1.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:13;a:17:{s:2:"id";i:14;s:7:"city_id";i:1;s:11:"external_id";s:25:"sanaa-nuqum-mountain-park";s:4:"name";s:24:"منتزه جبل نقم";s:7:"name_en";s:16:"Mount Nuqum Park";s:11:"description";s:447:"منتزه طبيعي مفتوح يقع على سفوح جبل نقم، ويوفر إطلالات بانورامية هي الأجمل على الإطلاق لمدينة صنعاء. يقصده السكان والزوار للاستمتاع بالمنظر، خاصة عند الغروب، وللتنزه في الهواء الطلق بعيداً عن صخب المدينة. توجد به بعض الاستراحات والمقاهي البسيطة.";s:14:"description_en";s:320:"An open natural park located on the slopes of Mount Nuqum, offering arguably the most beautiful panoramic views of Sana'a. It is frequented by locals and visitors to enjoy the scenery, especially at sunset, and for outdoor outings away from the city's hustle and bustle. It features several simple rest houses and cafes.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:9:"viewpoint";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:6:"مطل";i:3;s:12:"ترفيهي";}s:8:"latitude";d:15.3627929;s:9:"longitude";d:44.2377112;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSJWvf0J4oeMm-3lPTJI_m9tadj_3B0quribw&s";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:14;a:17:{s:2:"id";i:15;s:7:"city_id";i:1;s:11:"external_id";s:21:"bani-matar-waterfalls";s:4:"name";s:26:"شلالات بني مطر";s:7:"name_en";s:21:"Bani Matar Waterfalls";s:11:"description";s:193:"منطقة طبيعية خلابة تقع في ضواحي صنعاء، وتعتبر وجهة شهيرة للرحلات والاستمتاع بالطبيعة والمناظر المائية. [2]";s:14:"description_en";s:157:"A breathtaking natural area located on the outskirts of Sana'a, considered a popular destination for excursions and enjoying nature and water landscapes. [2]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:9:"waterfall";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"شلال";i:2;s:12:"ترفيهي";}s:8:"latitude";d:15.204079;s:9:"longitude";d:43.9955428;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:63:"https://live.staticflickr.com/3931/15530657121_9b06f79f93_b.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:15;a:17:{s:2:"id";i:16;s:7:"city_id";i:1;s:11:"external_id";s:15:"haraz-mountains";s:4:"name";s:34:" (الحطيب)منطقة حراز";s:7:"name_en";s:24:"Haraz Region (Al-Hutaib)";s:11:"description";s:221:"منطقة جبلية ساحرة تشتهر بمدرجاتها الزراعية الخضراء وقراها التاريخية المعلقة على قمم الجبال، وتوفر تجربة فريدة للزوار. [2]";s:14:"description_en";s:170:"A charming mountainous region famous for its green agricultural terraces and historical villages hanging on mountain peaks, offering a unique experience for visitors. [2]";s:10:"categories";a:3:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:12:"تاريخي";}s:8:"latitude";d:15.0417828;s:9:"longitude";d:43.7529538;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:58:"https://yemenfuture.net/upimgs/images/YF2024-04-21-539.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:16;a:17:{s:2:"id";i:17;s:7:"city_id";i:1;s:11:"external_id";s:20:"sanaa-al-thawra-park";s:4:"name";s:23:"حديقة الثورة";s:7:"name_en";s:14:"Al-Thawra Park";s:11:"description";s:393:"واحدة من أقدم الحدائق العامة في صنعاء، وتقع بالقرب من الملعب الرياضي. تتميز بأشجارها الكثيفة ومساحاتها الخضراء التي توفر ظلاً وافراً، مما يجعلها مكاناً مفضلاً للنزهات الهادئة. تضم أيضاً بعض الألعاب البسيطة للأطفال.";s:14:"description_en";s:246:"One of the oldest public parks in Sana'a, located near the sports stadium. It is characterized by dense trees and green spaces that provide ample shade, making it a favorite spot for quiet picnics. It also includes some simple rides for children.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:5:"urban";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:12:"ترفيهي";i:2;s:8:"حضري";i:3;s:10:"عائلي";}s:8:"latitude";d:15.387357;s:9:"longitude";d:44.2111386;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:65:"https://yemen-press.net/user_images/news/yp09-01-2018-822466.jpeg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:17;a:17:{s:2:"id";i:18;s:7:"city_id";i:1;s:11:"external_id";s:21:"sanaa-bayt-baws-parks";s:4:"name";s:28:"منتزهات بيت بوس";s:7:"name_en";s:15:"Bait Baws Parks";s:11:"description";s:449:"منطقة تقع جنوب صنعاء وتتميز بطبيعتها الصخرية المرتفعة. تنتشر فيها عدة منتزهات واستراحات خاصة توفر إطلالات جميلة على جنوب العاصمة. يقصدها الناس للاستمتاع بالهدوء وتناول الطعام في الهواء الطلق، بالإضافة إلى استكشاف قرية بيت بوس التاريخية القريبة.";s:14:"description_en";s:322:"An area located south of Sana'a, distinguished by its elevated rocky nature. Several private parks and rest stops are spread throughout, offering beautiful views of the southern part of the capital. People visit to enjoy the tranquility and outdoor dining, as well as to explore the nearby historical village of Bait Baws.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:9:"viewpoint";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:6:"مطل";i:3;s:12:"ترفيهي";}s:8:"latitude";d:15.2856276;s:9:"longitude";d:44.2183711;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQNfKsHkNwmZyvqLY_3PAKVmDxSdfj6onBAFw&s";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:18;a:17:{s:2:"id";i:19;s:7:"city_id";i:1;s:11:"external_id";s:19:"sanaa-fun-city-park";s:4:"name";s:24:"حديقة فن سيتي";s:7:"name_en";s:13:"Fun City Park";s:11:"description";s:391:"أكبر مدينة ألعاب ترفيهية مغلقة ومفتوحة في صنعاء. بالإضافة إلى الألعاب الكهربائية والإلكترونية المتنوعة، يضم المنتزه مساحات خضراء وبحيرة صغيرة ومطاعم، مما يجعله وجهة متكاملة للترفيه العائلي، خاصة للأطفال والشباب.";s:14:"description_en";s:277:"The largest indoor and outdoor amusement park in Sana'a. In addition to a variety of electric and electronic rides, the park features green spaces, a small lake, and restaurants, making it a comprehensive destination for family entertainment, especially for children and youth.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:14:"amusement_park";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:12:"ترفيهي";i:2;s:21:"مدينة ألعاب";i:3;s:10:"عائلي";}s:8:"latitude";d:15.3201007;s:9:"longitude";d:44.2014364;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:78:"https://media.safarway.com/content/31b2be3e-9549-4c3c-8f50-8742d799f449_sm.jpg";}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:19;a:17:{s:2:"id";i:20;s:7:"city_id";i:1;s:11:"external_id";s:23:"sanaa-sailah-rainy-park";s:4:"name";s:40:"متنزه السائلة الموسمي";s:7:"name_en";s:23:"Al-Sailah Seasonal Park";s:11:"description";s:395:"تتحول ضفاف السائلة خلال موسم الأمطار إلى منتزه طبيعي فريد ومؤقت. يتجمع الناس على حوافها لمشاهدة تدفق المياه بين المباني التاريخية، ويصبح المكان أشبه بكرنفال شعبي، حيث تنتشر الباعة المتجولون وتعم أجواء الفرح والبهجة.";s:14:"description_en";s:311:"During the rainy season, the banks of Al-Sailah transform into a unique, temporary natural park. People gather along its edges to watch the water flow between historical buildings, and the place turns into something resembling a popular carnival, filled with street vendors and an atmosphere of joy and delight.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:8:"seasonal";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:10:"موسمي";i:3;s:12:"ترفيهي";}s:8:"latitude";d:15.3458879;s:9:"longitude";d:44.2168867;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:232:"https://www.yemenipress.net/wp-content/uploads/2020/04/%D8%B5%D9%88%D8%B1%D8%A9-%D8%AC%D8%AF%D9%8A%D8%AF%D8%A9-%D9%84%D8%B3%D8%A7%D8%A6%D9%84%D8%A9-%D8%B5%D9%86%D8%B9%D8%A7%D8%A1-%D8%A7%D9%84%D9%82%D8%AF%D9%8A%D9%85%D8%A9-%D9%87.jpg";}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:20;a:17:{s:2:"id";i:21;s:7:"city_id";i:1;s:11:"external_id";s:17:"sanaa-berlin-park";s:4:"name";s:32:"منتزه حديقة برلين";s:7:"name_en";s:11:"Berlin Park";s:11:"description";s:396:"حديقة عامة تقع في حي حدة، تم إنشاؤها كرمز للصداقة اليمنية الألمانية. تتميز بتصميمها الجميل ومساحاتها الخضراء المنسقة، وتضم قطعة أصلية من جدار برلين. تعتبر منتزهاً هادئاً ومثالياً للنزهات العائلية القصيرة والاسترخاء.";s:14:"description_en";s:288:"A public park located in the Hadda neighborhood, established as a symbol of Yemeni-German friendship. It boasts a beautiful design with landscaped green spaces and includes an original piece of the Berlin Wall. It is considered a quiet park, ideal for short family picnics and relaxation.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:5:"urban";i:2;s:12:"recreational";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"حضري";i:2;s:12:"ترفيهي";i:3;s:10:"عائلي";}s:8:"latitude";d:15.3565074;s:9:"longitude";d:44.2283318;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:398:"https://althawrah.ye/wp-content/uploads/2024/07/%D8%A3%D8%AD%D8%B3%D9%86-%D9%81%D8%B1%D9%8A%D9%82-%D9%8A%D9%81%D8%AA%D8%AA%D8%AD-%D9%85%D8%B3%D8%A7%D8%AD%D8%A9-%D8%AC%D8%AF%D9%8A%D8%AF%D8%A9-%D9%84%D9%84%D8%B1%D9%8A%D8%A7%D8%B6%D8%A9-%D8%A7%D9%84%D9%85%D8%B3%D8%AA%D8%AF%D8%A7%D9%85%D8%A9-%D9%85%D9%86-%D8%A3%D8%AC%D9%84-%D8%A7%D9%84%D8%B5%D8%AD%D8%A9-%D9%88%D8%A7%D9%84%D8%AD%D9%8A%D8%A7%D8%A9.jpg";}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:21;a:17:{s:2:"id";i:22;s:7:"city_id";i:1;s:11:"external_id";s:24:"sanaa-airport-road-parks";s:4:"name";s:36:"منتزهات طريق المطار";s:7:"name_en";s:18:"Airport Road Parks";s:11:"description";s:443:"تنتشر على طول طريق المطار العديد من الاستراحات والمنتزهات الخاصة التي تضم مسابح ومساحات خضراء وملاعب للأطفال. تعتبر هذه المنتزهات وجهة مفضلة للعائلات والشباب في عطلات نهاية الأسبوع لقضاء وقت ممتع وممارسة السباحة والأنشطة الترفيهية المختلفة.";s:14:"description_en";s:286:"Scattered along the Airport Road are numerous private rest stops and parks featuring swimming pools, green spaces, and children's playgrounds. These parks are a favorite weekend destination for families and youth to have a good time, swim, and engage in various recreational activities.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:13:"swimming_pool";i:3;s:6:"family";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:12:"ترفيهي";i:2;s:8:"مسبح";i:3;s:10:"عائلي";}s:8:"latitude";d:15.4574378;s:9:"longitude";d:44.224554;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:0:"";}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:22;a:17:{s:2:"id";i:23;s:7:"city_id";i:1;s:11:"external_id";s:16:"sanaa-sayan-park";s:4:"name";s:26:"سد سيان (سنحان)";s:7:"name_en";s:17:"Sian Dam (Sanhan)";s:11:"description";s:450:"يقع في منطقة سيان بمديرية سنحان جنوب شرق صنعاء. وهو منتزه طبيعي يتميز بأرضه المنبسطة وأشجاره المتناثرة، ويقصده الناس للرحلات الخلوية والنزهات، خاصة في فصل الربيع بعد هطول الأمطار حيث تكتسي الأرض بالخضرة. يوفر جواً ريفياً هادئاً بعيداً عن المدينة.";s:14:"description_en";s:313:"Located in the Sian area of the Sanhan district, southeast of Sana'a. It is a natural park known for its flat terrain and scattered trees, frequented by people for outdoor trips and picnics, especially in the spring after the rains when the land turns green. It offers a quiet rural atmosphere away from the city.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:5:"rural";i:3;s:12:"recreational";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"ريفي";i:3;s:12:"ترفيهي";}s:8:"latitude";d:15.1866756;s:9:"longitude";d:44.3387193;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:116:"https://www.yemenmonitor.com/wp-content/uploads/2021/05/186508487_1451857131822455_7118975521435752721_n-780x470.jpg";}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:23;a:17:{s:2:"id";i:24;s:7:"city_id";i:1;s:11:"external_id";s:26:"sanaa-ghumdan-palace-ruins";s:4:"name";s:30:"قصر غمدان (أطلال)";s:7:"name_en";s:22:"Ghumdan Palace (Ruins)";s:11:"description";s:449:"يُعتقد أنه من أقدم القصور الشاهقة في العالم وأول ناطحة سحاب في التاريخ. يقع في قلب صنعاء القديمة شرق الجامع الكبير. لم يتبق من القصر الأصلي الذي تغنى به المؤرخون سوى أطلال وقواعد، لكن موقعه لا يزال يحمل عبق تاريخ أسطوري يعود إلى عصر مملكة سبأ وحمير.";s:14:"description_en";s:397:"Believed to be one of the oldest towering palaces in the world and the first skyscraper in history. It is located in the heart of the Old City of Sana'a, east of the Great Mosque. Nothing remains of the original palace praised by historians except ruins and foundations, but its site still carries the fragrance of a legendary history dating back to the eras of the Sabaean and Himyarite kingdoms.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";}s:8:"latitude";d:15.3546824;s:9:"longitude";d:44.2199309;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTfyvq_6QKW5VFSo2z9MYYSvJRkWcVlHiUE2g&s";}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:24;a:17:{s:2:"id";i:25;s:7:"city_id";i:1;s:11:"external_id";s:25:"sanaa-dhi-marmar-fortress";s:4:"name";s:20:"حصن ذي مرمر";s:7:"name_en";s:15:"Dhi Marmar Fort";s:11:"description";s:403:"حصن تاريخي منيع يقع على قمة جبل شمال صنعاء. يعود تاريخه إلى العصر الحميري، وقد استخدم كحصن عسكري ومقر حكم عبر العصور. يتميز الحصن بأبراجه وأسواره الضخمة المبنية من الحجر، ويحتوي على صهاريج مياه منحوتة في الصخر ونقوش قديمة.";s:14:"description_en";s:342:"An impregnable historical fortress located atop a mountain north of Sana'a. Dating back to the Himyarite era, it has been used as a military fort and a seat of governance throughout the ages. The fort is notable for its massive stone-built towers and walls, and it contains water cisterns carved into the rock along with ancient inscriptions.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"عسكري";}s:8:"latitude";d:15.5450448;s:9:"longitude";d:44.3608045;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:234:"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEju4Y0R53ITROGQOBM22xa_SEcX4FcDpRshpxjZb8rH3-HL0lRqZQ_fJiqzGNYSW-OKFjDPLRBHIRSeVSdGMfmMF-vzH76DnnNzBeQO1WVEkiK35OrCCwf55Nlx8bzUYx1We4yDMnCmNnU/w1200-h630-p-k-no-nu/IMAG1283.jpg";}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:25;a:17:{s:2:"id";i:26;s:7:"city_id";i:1;s:11:"external_id";s:16:"sanaa-rock-tombs";s:4:"name";s:55:"المقابر الصخرية (خولان وسنحان)";s:7:"name_en";s:31:"Rock Tombs (Khawlan and Sanhan)";s:11:"description";s:481:"تنتشر في المناطق المحيطة بصنعاء، خاصة في مناطق خولان وسنحان، العديد من المقابر القديمة المنحوتة في سفوح الجبال. تعود هذه المقابر إلى عصور ما قبل الإسلام، وتدل على طرق الدفن القديمة والمعتقدات الجنائزية لدى اليمنيين القدماء. وهي مواقع أثرية هامة لدراسة تلك الفترة.";s:14:"description_en";s:319:"Scattered in the areas surrounding Sana'a, especially in Khawlan and Sanhan, are many ancient tombs carved into mountain slopes. These tombs date back to pre-Islamic eras and indicate the ancient burial methods and funerary beliefs of the early Yemenis. They are important archaeological sites for studying that period.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:11:"pre-islamic";i:2;s:4:"tomb";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:26:"ما قبل الإسلام";i:2;s:10:"مقبرة";}s:8:"latitude";d:15.2;s:9:"longitude";d:44.4;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:26;a:17:{s:2:"id";i:27;s:7:"city_id";i:1;s:11:"external_id";s:16:"sanaa-shahik-dam";s:4:"name";s:26:"سد شاحك (خولان)";s:7:"name_en";s:20:"Shahik Dam (Khawlan)";s:11:"description";s:505:"أحد السدود الحميرية القديمة التي تم إعادة تأهيلها. يقع في منطقة خولان الطيال، ويتميز ببنائه الحجري الضخم الذي يشهد على براعة الهندسة اليمنية القديمة. يشكل السد بحيرة جميلة وسط الجبال، ويعتبر مصدراً مهماً للري وتغذية المياه الجوفية، بالإضافة إلى كونه معلماً تاريخياً وطبيعياً.";s:14:"description_en";s:403:"One of the ancient Himyarite dams that has been rehabilitated. Located in the Khawlan Al-Tiyal area, it is notable for its massive stone construction that bears witness to the ingenuity of ancient Yemeni engineering. The dam forms a beautiful lake amidst the mountains and is considered an important source for irrigation and groundwater recharge, in addition to being a historical and natural landmark.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:4:"lake";i:2;s:14:"archaeological";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:10:"بحيرة";i:2;s:8:"أثري";i:3;s:8:"مائي";}s:8:"latitude";d:15.3900614;s:9:"longitude";d:44.4292571;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:59:"https://yemenfuture.net/upimgs/images/YF2023-09-10-1840.jpg";}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:27;a:17:{s:2:"id";i:28;s:7:"city_id";i:1;s:11:"external_id";s:25:"sanaa-al-haymatayn-valley";s:4:"name";s:55:"بيت السفياني (الحيمة الخارجية)";s:7:"name_en";s:30:"Bayt Al-Sufyani (Outer Haymah)";s:11:"description";s:455:"وادٍ جبلي ساحر يقع في مديرية الحيمة الخارجية، ويشتهر بمناظره الطبيعية الخلابة ومدرجاته الزراعية الخضراء التي تزرع فيها أجود أنواع الاشجار. تتدفق فيه المياه بعد الأمطار مكونة جداول وشلالات صغيرة، مما يجعله وجهة ممتازة لمحبي الطبيعة الريفية والهدوء.";s:14:"description_en";s:338:"A charming mountain valley located in the Outer Haymah district, famous for its breathtaking natural landscapes and green agricultural terraces where the finest types of trees are grown. Water flows through it after rain, forming small streams and waterfalls, making it an excellent destination for lovers of rural nature and tranquility.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:7:"natural";i:2;s:12:"agricultural";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعي";i:3;s:8:"مائي";}s:8:"latitude";d:14.9892988;s:9:"longitude";d:43.9060004;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRBWUQPjIlXKXaiF5Pp2cSF8UtQWxry904gkg&s";}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:28;a:17:{s:2:"id";i:29;s:7:"city_id";i:1;s:11:"external_id";s:17:"sanaa-habab-ghayl";s:4:"name";s:46:"جبل الجودي سفينه نوح (نهم)";s:7:"name_en";s:30:"Mount Judi - Noah's Ark (Nihm)";s:11:"description";s:268:"جبل الجود يالذي رست عليه سفينة النبي نوح عليه السلام حيث يتمتع يالمناظر الخلابة والاجواء الساحرة، كما يعد وجهة للتنزه  في بيئة طبيعية هادئة وجميلة.";s:14:"description_en";s:215:"Mount Judi, upon which the ark of Prophet Noah (peace be upon him) rested, boasts breathtaking views and a magical atmosphere. It also serves as a destination for hiking in a quiet and beautiful natural environment.";s:10:"categories";a:4:{i:0;s:6:"spring";i:1;s:12:"natural_pool";i:2;s:7:"natural";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:14:"مرتفعات";i:1;s:8:"جبال";i:2;s:10:"طبيعي";i:3;s:8:"ديني";}s:8:"latitude";d:15.5987263;s:9:"longitude";d:44.4107774;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRxlT5-HBk9g655sHZK7BpEuTX97LOktvOIGQ&s";}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:29;a:17:{s:2:"id";i:30;s:7:"city_id";i:1;s:11:"external_id";s:19:"sanaa-sultan-hammam";s:4:"name";s:43:"حمام السلطان (سوق الملح)";s:7:"name_en";s:30:"Hammam Al-Sultan (Salt Market)";s:11:"description";s:471:"أحد أقدم وأشهر الحمامات البخارية التقليدية في صنعاء القديمة. يعود تاريخه إلى العصر العثماني، ولا يزال يعمل حتى اليوم بنفس الطريقة التقليدية. يقصده الناس للاستحمام بالبخار والتدليك (التكييس)، ويُعتقد أن له فوائد في تنظيف الجسم وإزالة السموم واسترخاء العضلات.";s:14:"description_en";s:337:"One of the oldest and most famous traditional steam baths in the Old City of Sana'a. Dating back to the Ottoman era, it still operates today using the same traditional methods. People visit it for steam bathing and scrubbing massages (Takees). It is believed to have benefits in cleansing the body, removing toxins, and relaxing muscles.";s:10:"categories";a:3:{i:0;s:11:"therapeutic";i:1;s:20:"traditional_medicine";i:2;s:6:"hammam";}s:14:"category_names";a:3:{i:0;s:10:"علاجي";i:1;s:17:"طب تقليدي";i:2;s:19:"حمام بخاري";}s:8:"latitude";d:15.3526918;s:9:"longitude";d:44.2073057;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:68:"https://images.cdn-files-a.com/uploads/2371235/800_5d340999dd36d.png";}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:30;a:17:{s:2:"id";i:31;s:7:"city_id";i:1;s:11:"external_id";s:18:"sanaa-shukr-hammam";s:4:"name";s:43:"حمام شكر (صنعاء القديمة)";s:7:"name_en";s:25:"Hammam Shukr (Old Sana'a)";s:11:"description";s:445:"أحد الحمامات البخارية التاريخية الأخرى في صنعاء القديمة، ويتميز بتصميمه المعماري التقليدي. يوفر الحمام تجربة استشفائية متكاملة من خلال غرف البخار متفاوتة الحرارة، والماء الساخن والبارد، وخدمات التدليك التي تساعد على الاسترخاء وتجديد النشاط.";s:14:"description_en";s:293:"Another historical steam bath in the Old City of Sana'a, distinguished by its traditional architectural design. The bath offers a complete therapeutic experience through steam rooms with varying temperatures, hot and cold water, and massage services that help with relaxation and rejuvenation.";s:10:"categories";a:3:{i:0;s:11:"therapeutic";i:1;s:20:"traditional_medicine";i:2;s:6:"hammam";}s:14:"category_names";a:3:{i:0;s:10:"علاجي";i:1;s:17:"طب تقليدي";i:2;s:19:"حمام بخاري";}s:8:"latitude";d:15.3537031;s:9:"longitude";d:44.209776;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTRS58EBpNcK74AS__5CKR6BpqCgIT5FDldlg&s";}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:31;a:17:{s:2:"id";i:32;s:7:"city_id";i:1;s:11:"external_id";s:29:"bayt-al-kabsh-waterfall-otmah";s:4:"name";s:37:"شلال بيت الكبش (عتمة)";s:7:"name_en";s:31:"Bayt Al-Kabsh Waterfall (Utmah)";s:11:"description";s:423:"شلال جميل ومشهور يقع في محمية عتمة، وينحدر من أعالي الجبال ليشكل منظراً طبيعياً جذاباً. [1, 2] يعتبر مقصداً للزوار والسكان المحليين للاستمتاع بجمال تدفق المياه والمناظر الخضراء المحيطة به، وهو أحد المعالم المائية البارزة في المديرية.";s:14:"description_en";s:331:"A beautiful and famous waterfall located in the Utmah Reserve, cascading from the high mountains to form an attractive natural landscape. [1, 2] It is a destination for visitors and locals alike to enjoy the beauty of flowing water and the surrounding greenery, standing out as one of the prominent water landmarks in the district.";s:10:"categories";a:5:{i:0;s:9:"waterfall";i:1;s:6:"nature";i:2;s:6:"scenic";i:3;s:10:"recreation";i:4;s:14:"nature-reserve";}s:14:"category_names";a:5:{i:0;s:8:"شلال";i:1;s:10:"طبيعي";i:2;s:21:"مناظر خلابة";i:3;s:12:"ترفيهي";i:4;s:23:"محمية طبيعية";}s:8:"latitude";d:15.2556907;s:9:"longitude";d:43.9406206;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:225:"https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhWi7sy9uTkHm10o1VwqfkwFk9FfCDZZRQGCVlyuPjp13fVvvgdNz2ik1vQ3KLipR4AyePEkwtYA_SKVofKnabQWL-AEb0MzyF5I-h04MV30m3Ic9DsnlPZkddO1N_5X-FPdKQ4YbOIXBp3/s1600/1686060126192.jpg";}s:10:"sort_order";i:32;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:32;a:17:{s:2:"id";i:33;s:7:"city_id";i:1;s:11:"external_id";s:8:"zoo-park";s:4:"name";s:25:"حديقة الحيوان";s:7:"name_en";s:3:"Zoo";s:11:"description";s:216:"افتتحت عام 1999 وتعتبر متنفسًا سياحيًا مهمًا في أمانة العاصمة، حيث تضم العديد من الحيوانات البرية والزواحف والطيور. [3, 10]";s:14:"description_en";s:153:"Opened in 1999, it is considered an important tourist retreat in the capital secretariat, housing a variety of wild animals, reptiles, and birds. [3, 10]";s:10:"categories";a:3:{i:0;s:3:"zoo";i:1;s:12:"recreational";i:2;s:11:"educational";}s:14:"category_names";a:3:{i:0;s:21:"حديقة حيوان";i:1;s:12:"ترفيهي";i:2;s:12:"تعليمي";}s:8:"latitude";d:15.2875567;s:9:"longitude";d:44.2450172;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:361:"https://www.yemenipress.net/wp-content/uploads/2020/03/%D8%AD%D8%AF%D9%8A%D9%82%D8%A9-%D8%A7%D9%84%D8%AD%D9%8A%D9%88%D8%A7%D9%86-%D8%A8%D8%A3%D9%85%D8%A7%D9%86%D8%A9-%D8%A7%D9%84%D8%B9%D8%A7%D8%B5%D9%85%D8%A9-%D8%AA%D8%AA%D8%B3%D9%84%D9%85-%D8%A7%D8%AB%D9%86%D9%8A%D9%86-%D9%81%D9%87%D9%88%D8%AF-%D8%B9%D8%B1%D8%A8%D9%8A%D8%A9-%D8%A3%D8%B5%D9%8A%D9%84%D8%A9.jpg";}s:10:"sort_order";i:33;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:33;a:17:{s:2:"id";i:34;s:7:"city_id";i:1;s:11:"external_id";s:15:"al-nahdain-park";s:4:"name";s:68:"حديقة السبعين الجديدة (حديقة النهدين)";s:7:"name_en";s:36:"New Al-Sabeen Park (Al-Nahdain Park)";s:11:"description";s:210:"تقع بالقرب من ميدان السبعين، وتعد خيارًا ممتازًا للنزهات العائلية لما توفره من مناطق خضراء ومساحات للعب الأطفال. [9]";s:14:"description_en";s:142:"Located near Al-Sabeen Square, it is an excellent choice for family picnics due to the green areas and children's play spaces it provides. [9]";s:10:"categories";a:2:{i:0;s:4:"park";i:1;s:6:"family";}s:14:"category_names";a:2:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";}s:8:"latitude";d:15.2874775;s:9:"longitude";d:44.2120729;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:71:"https://www.saba.ye/storage/larage/59a56c6b8d04a721930ab4167eba6038.jpg";}s:10:"sort_order";i:34;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:34;a:17:{s:2:"id";i:35;s:7:"city_id";i:1;s:11:"external_id";s:13:"dar-salm-park";s:4:"name";s:45:"(حديقة عشيه)منتزه دار سلم";s:7:"name_en";s:28:"Dar Salm Park (Ashiyah Park)";s:11:"description";s:196:"يضم مساحات خضراء كبيرة ومرافق رياضية ومناطق للجلوس، وهو مكان مثالي للنزهات العائلية والأنشطة الخارجية. [3, 9]";s:14:"description_en";s:136:"Features large green spaces, sports facilities, and seating areas. It is an ideal spot for family picnics and outdoor activities. [3, 9]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";}s:14:"category_names";a:3:{i:0;s:10:"منتزه";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";}s:8:"latitude";d:15.276677;s:9:"longitude";d:44.248371;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:0:"";}s:10:"sort_order";i:35;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:35;a:17:{s:2:"id";i:36;s:7:"city_id";i:1;s:11:"external_id";s:13:"al-rawda-park";s:4:"name";s:23:"حديقة الروضة";s:7:"name_en";s:14:"Al-Rawdah Park";s:11:"description";s:154:"تتميز بأجوائها الهادئة المناسبة للقراءة والاسترخاء، وتقع بالق