1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSUZpPXyFfR4dJp3uVb4Q0UAy_i08R2ZnEG0A&s";}s:10:"sort_order";i:40;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:40;a:17:{s:2:"id";i:41;s:7:"city_id";i:1;s:11:"external_id";s:11:"jamaan-park";s:4:"name";s:47:"حديقة جمعان (حديقة الورود)";s:7:"name_en";s:25:"Gamaan Park (Rose Garden)";s:11:"description";s:116:"حديقة جميلة تم ترشيحها كأحد الأماكن المميزة للنزهات في صنعاء. [1]";s:14:"description_en";s:96:"A beautiful park that has been nominated as one of the special places for picnics in Sana'a. [1]";s:10:"categories";a:2:{i:0;s:4:"park";i:1;s:6:"family";}s:14:"category_names";a:2:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";}s:8:"latitude";d:15.2818122;s:9:"longitude";d:44.2399482;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRT9b5kAmNeskW879_8UMkoftT_lZrhP9zBvQ&s";}s:10:"sort_order";i:41;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:41;a:17:{s:2:"id";i:42;s:7:"city_id";i:1;s:11:"external_id";s:15:"14-october-park";s:4:"name";s:26:"حديقة 14 أكتوبر";s:7:"name_en";s:20:"14th of October Park";s:11:"description";s:134:"تقع بالقرب من "ريماس بلازا"، وتعد متنفسًا إضافيًا للسكان في تلك المنطقة. [1]";s:14:"description_en";s:112:"Located near 'Remas Plaza', it serves as an additional recreational area for residents in that neighborhood. [1]";s:10:"categories";a:1:{i:0;s:4:"park";}s:14:"category_names";a:1:{i:0;s:10:"حديقة";}s:8:"latitude";d:15.3011121;s:9:"longitude";d:44.1996771;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:92:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTzqNAp5EpHc3Dh3eiOJ8RFTTYiSECkWpSCTw&s";}s:10:"sort_order";i:42;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:24;a:13:{s:2:"id";i:2;s:4:"slug";s:4:"aden";s:4:"name";s:6:"عدن";s:7:"name_en";s:4:"Aden";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:13:"aden_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:21;s:9:"landmarks";a:21:{i:0;a:17:{s:2:"id";i:43;s:7:"city_id";i:2;s:11:"external_id";s:13:"aden-cisterns";s:4:"name";s:49:"صهاريج عدن (صهاريج الطويلة)";s:7:"name_en";s:34:"Cisterns of Aden (Tawila Cisterns)";s:11:"description";s:354:"نظام مائي قديم وهندسة معمارية مذهلة، عبارة عن سلسلة من الخزانات المنحوتة في الصخور البركانية لجمع وتخزين مياه الأمطار. يعود تاريخها إلى عصور ما قبل الإسلام، وتعتبر من أهم المعالم الأثرية في عدن.";s:14:"description_en";s:263:"An ancient water system and a stunning architectural feat consisting of a series of cisterns carved into volcanic rock to collect and store rainwater. Dating back to pre-Islamic eras, they are considered one of the most important archaeological landmarks in Aden.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:5:"water";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:8:"مائي";}s:8:"latitude";d:12.7744014;s:9:"longitude";d:45.0292678;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/aden/aden_cisterns1.jpg";i:1;s:40:"images/landmarks/aden/aden_cisterns2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:1;a:17:{s:2:"id";i:44;s:7:"city_id";i:2;s:11:"external_id";s:13:"sira-fortress";s:4:"name";s:17:"قلعة صيرة";s:7:"name_en";s:11:"Sira Castle";s:11:"description";s:306:"حصن تاريخي يقع على جزيرة صيرة البركانية، ويطل على ميناء عدن القديم. [2] لعبت القلعة دورًا دفاعيًا هامًا على مر العصور وتوفر إطلالات بانورامية رائعة على المدينة والبحر. [3]";s:14:"description_en";s:230:"A historic fortress located on the volcanic Sira Island, overlooking the old port of Aden. [2] The castle has played an important defensive role throughout the ages and offers wonderful panoramic views of the city and the sea. [3]";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:8:"military";i:2;s:9:"viewpoint";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:10:"عسكري";i:2;s:12:"إطلالة";}s:8:"latitude";d:12.7790935;s:9:"longitude";d:45.0496757;s:15:"google_maps_url";N;s:6:"images";a:1:{i:0;s:532:"https://www.alinaser.com/public/source/%D8%A3%D8%B1%D8%B4%D9%8A%D9%81%20%D8%A7%D9%84%D8%B5%D9%88%D8%B1/%D8%A7%D9%84%D8%AF%D9%88%D9%84%D8%A9%20%D8%AC%D9%85%D9%87%D9%88%D8%B1%D9%8A%D8%A9%20%D8%A7%D9%84%D9%8A%D9%85%D9%86%20%D8%A7%D9%84%D8%AF%D9%8A%D9%82%D8%B1%D8%A7%D8%B7%D9%8A%D8%A9%20%D8%A7%D9%84%D8%B4%D8%B9%D8%A8%D9%8A%D8%A9/%D8%B3%D9%8A%D8%A7%D8%AD%D8%A9%20%D9%88%D9%85%D8%AA%D8%A7%D8%AD%D9%81%20%D9%88%D8%A7%D8%AB%D8%A7%D8%B1/%D9%82%D9%84%D8%B9%D8%A9%20%D8%B5%D9%8A%D8%B1%D8%A9/252114781_415472253492508_1615054786843090872_n.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:10:22.000000Z";}i:2;a:17:{s:2:"id";i:45;s:7:"city_id";i:2;s:11:"external_id";s:12:"aden-minaret";s:4:"name";s:17:"منارة عدن";s:7:"name_en";s:12:"Aden Minaret";s:11:"description";s:350:"تعتبر أقدم مئذنة مسجد في شبه الجزيرة العربية، وتقع في منطقة كريتر. [4] تتميز بتصميمها المعماري الفريد الذي يعكس التأثيرات الإسلامية القديمة، وهي كل ما تبقى من مسجد قديم كان قائمًا في نفس الموقع.";s:14:"description_en";s:268:"Considered the oldest mosque minaret in the Arabian Peninsula, located in the Crater district. [4] It is distinguished by its unique architectural design reflecting early Islamic influences and is all that remains of an ancient mosque that once stood on the same site.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:9:"religious";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"ديني";i:2;s:12:"معماري";}s:8:"latitude";d:12.7784039;s:9:"longitude";d:45.0401875;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/aden/aden_minaret1.jpg";i:1;s:39:"images/landmarks/aden/aden_minaret2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:3;a:17:{s:2:"id";i:46;s:7:"city_id";i:2;s:11:"external_id";s:17:"little-aden-beach";s:4:"name";s:43:"شاطئ الغدير (عدن الصغرى)";s:7:"name_en";s:29:"Al-Ghadir Beach (Little Aden)";s:11:"description";s:283:"أحد أجمل الشواطئ في عدن، يقع في منطقة البريقة ويتميز برماله الذهبية ومياهه الصافية. [5] يعتبر مكانًا مثاليًا للسباحة والاسترخاء والأنشطة الشاطئية المختلفة.";s:14:"description_en";s:216:"One of the most beautiful beaches in Aden, located in the Al-Buraiqeh area and characterized by its golden sands and crystal-clear waters. [5] It is an ideal spot for swimming, relaxing, and various beach activities.";s:10:"categories";a:3:{i:0;s:6:"nature";i:1;s:5:"beach";i:2;s:10:"recreation";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"شاطئ";i:2;s:12:"ترفيهي";}s:8:"latitude";d:12.7352448;s:9:"longitude";d:44.8846422;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/landmarks/aden/little_aden_beach1.jpg";i:1;s:44:"images/landmarks/aden/little_aden_beach2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:4;a:17:{s:2:"id";i:47;s:7:"city_id";i:2;s:11:"external_id";s:20:"aden-military-museum";s:4:"name";s:34:"المتحف الحربي بعدن";s:7:"name_en";s:23:"Military Museum of Aden";s:11:"description";s:286:"يقع في حي كريتر، ويعرض تاريخ اليمن العسكري عبر مختلف الحقب الزمنية. [6] يضم المتحف مجموعة واسعة من الأسلحة والمعدات والوثائق والصور التي توثق نضالات اليمنيين.";s:14:"description_en";s:230:"Located in the Crater neighborhood, it exhibits Yemen's military history across various time periods. [6] The museum houses a wide range of weapons, equipment, documents, and photographs that document the struggles of the Yemenis.";s:10:"categories";a:3:{i:0;s:6:"museum";i:1;s:10:"historical";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:8:"متحف";i:1;s:12:"تاريخي";i:2;s:10:"عسكري";}s:8:"latitude";d:12.7792717;s:9:"longitude";d:45.0366172;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/landmarks/aden/aden_military_museum1.jpg";i:1;s:47:"images/landmarks/aden/aden_military_museum2.jpg";}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:5;a:17:{s:2:"id";i:48;s:7:"city_id";i:2;s:11:"external_id";s:11:"jabal-hadid";s:4:"name";s:15:"جبل حديد";s:7:"name_en";s:11:"Jabal Hadid";s:11:"description";s:284:"جبل بركاني يطل على مدينة عدن ويوفر نقاط مشاهدة بانورامية للمدينة والميناء. [7] تنتشر على قمته التحصينات العسكرية القديمة التي تعود لفترة الاحتلال البريطاني.";s:14:"description_en";s:222:"A volcanic mountain overlooking the city of Aden, providing panoramic vantage points of the city and the port. [7] Ancient military fortifications dating back to the British occupation period are scattered across its peak.";s:10:"categories";a:3:{i:0;s:6:"nature";i:1;s:9:"viewpoint";i:2;s:10:"historical";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:12:"إطلالة";i:2;s:12:"تاريخي";}s:8:"latitude";d:12.7972168;s:9:"longitude";d:45.0263501;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/landmarks/aden/jabal_hadid1.jpg";i:1;s:38:"images/landmarks/aden/jabal_hadid2.jpg";}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:6;a:17:{s:2:"id";i:49;s:7:"city_id";i:2;s:11:"external_id";s:18:"al-aidaroos-mosque";s:4:"name";s:25:"مسجد العيدروس";s:7:"name_en";s:18:"Al-Aidaroos Mosque";s:11:"description";s:314:"أحد أقدم وأشهر المساجد في عدن، يقع في قلب كريتر. [8] يتميز بقبابه البيضاء ومئذنته الشاهقة، ويُنسب إلى الإمام أبي بكر بن عبد الله العيدروس، وهو مركز ديني وثقافي مهم في المدينة.";s:14:"description_en";s:271:"One of the oldest and most famous mosques in Aden, located in the heart of Crater. [8] Characterized by its white domes and towering minaret, it is attributed to Imam Abu Bakr bin Abdullah Al-Aidaroos, and serves as an important religious and cultural center in the city.";s:10:"categories";a:3:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";}s:8:"latitude";d:12.7724292;s:9:"longitude";d:45.0367231;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:45:"images/landmarks/aden/al_aidaroos_mosque1.jpg";i:1;s:45:"images/landmarks/aden/al_aidaroos_mosque2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:7;a:17:{s:2:"id";i:50;s:7:"city_id";i:2;s:11:"external_id";s:16:"gold-mohur-beach";s:4:"name";s:24:"شاطئ جولد مور";s:7:"name_en";s:16:"Gold Mohur Beach";s:11:"description";s:332:"يقع في منطقة التواهي، وهو شاطئ شهير يشتهر بوجود فندق جولد مور التاريخي. [11] يوفر الشاطئ أجواء هادئة ومناظر خلابة لغروب الشمس، ويعتبر مكانًا مفضلاً للسياح والسكان المحليين على حد سواء.";s:14:"description_en";s:237:"Located in the Tawahi district, it is a famous beach well-known for housing the historic Gold Mohur Hotel. [11] The beach offers a tranquil atmosphere and breathtaking sunset views, making it a favorite spot for both tourists and locals.";s:10:"categories";a:3:{i:0;s:5:"beach";i:1;s:10:"recreation";i:2;s:9:"viewpoint";}s:14:"category_names";a:3:{i:0;s:8:"شاطئ";i:1;s:12:"ترفيهي";i:2;s:12:"إطلالة";}s:8:"latitude";d:12.7719169;s:9:"longitude";d:44.9893467;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:43:"images/landmarks/aden/gold_mohur_beach1.jpg";i:1;s:43:"images/landmarks/aden/gold_mohur_beach2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:8;a:17:{s:2:"id";i:51;s:7:"city_id";i:2;s:11:"external_id";s:18:"elephant-bay-beach";s:4:"name";s:28:"شاطئ خليج الفيل";s:7:"name_en";s:18:"Elephant Bay Beach";s:11:"description";s:291:"شاطئ هادئ وجميل يقع بالقرب من منطقة جولد مور، ويتميز بتكويناته الصخرية الفريدة التي تشبه شكل الفيل. [3] يوفر بيئة طبيعية بكر ومياهاً صافية مناسبة للغطس والسباحة.";s:14:"description_en";s:239:"A quiet and beautiful beach located near the Gold Mohur area, distinguished by unique rock formations that resemble the shape of an elephant. [3] It provides a pristine natural environment and clear waters suitable for diving and swimming.";s:10:"categories";a:3:{i:0;s:6:"nature";i:1;s:5:"beach";i:2;s:10:"geological";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:8:"شاطئ";i:2;s:14:"جيولوجي";}s:8:"latitude";d:12.7699983;s:9:"longitude";d:44.9864175;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:35:"images/parks/aden/elephant_bay1.jpg";i:1;s:35:"images/parks/aden/elephant_bay2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:9;a:17:{s:2:"id";i:52;s:7:"city_id";i:2;s:11:"external_id";s:16:"abu-hisham-beach";s:4:"name";s:26:"شاطئ ساحل أبين";s:7:"name_en";s:17:"Abyan Coast Beach";s:11:"description";s:336:"يمتد على طول ساحل أبين في خور مكسر، وهو الشاطئ الأطول والأكثر ارتيادًا في عدن. [4] يعتبر متنفسًا رئيسيًا للسكان، حيث تقام فيه العديد من الأنشطة الترفيهية والرياضية والمهرجانات الموسمية.";s:14:"description_en";s:224:"Stretching along the Abyan Coast in Khormaksar, it is the longest and most visited beach in Aden. [4] It is considered a major recreational area for residents, hosting many leisure, sports activities, and seasonal festivals.";s:10:"categories";a:3:{i:0;s:5:"beach";i:1;s:10:"recreation";i:2;s:12:"public-space";}s:14:"category_names";a:3:{i:0;s:8:"شاطئ";i:1;s:12:"ترفيهي";i:2;s:19:"مساحة عامة";}s:8:"latitude";d:12.85446;s:9:"longitude";d:45.055081;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/parks/aden/abu_hisham_beach1.jpg";i:1;s:39:"images/parks/aden/abu_hisham_beach2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:10;a:17:{s:2:"id";i:53;s:7:"city_id";i:2;s:11:"external_id";s:13:"fun-city-park";s:4:"name";s:24:"حديقة فن سيتي";s:7:"name_en";s:13:"Fun City Park";s:11:"description";s:288:"متنزه ترفيهي يقع في صيرة ويجمع بين المساحات الخضراء ومجموعة من الألعاب الترفيهية للأطفال والكبار. [6] يعتبر وجهة عائلية متكاملة لقضاء وقت ممتع في الهواء الطلق.";s:14:"description_en";s:215:"An amusement park located in Sira that combines green spaces with a variety of entertaining rides for children and adults. [6] It serves as a comprehensive family destination for spending an enjoyable time outdoors.";s:10:"categories";a:3:{i:0;s:14:"amusement-park";i:1;s:6:"family";i:2;s:10:"recreation";}s:14:"category_names";a:3:{i:0;s:21:"مدينة ملاهي";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";d:12.7776447;s:9:"longitude";d:45.0457795;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:36:"images/parks/aden/fun_city_park1.jpg";i:1;s:36:"images/parks/aden/fun_city_park2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:11;a:17:{s:2:"id";i:54;s:7:"city_id";i:2;s:11:"external_id";s:16:"sira-island-park";s:4:"name";s:45:" فن لاند متنزه جزيرة صيرة";s:7:"name_en";s:24:"Funland Sira Island Park";s:11:"description";s:321:"فن لاند المنطقة المحيطة بقلعة صيرة التاريخية، وهي عبارة عن منتزه  متصلة بالبر الرئيسي. [8] توفر مزيجًا فريدًا من الطبيعة الساحلية والتاريخ، وهي مكان جيد للتنزه واستكشاف المنطقة.";s:14:"description_en";s:222:"Funland encompasses the area surrounding the historic Sira Castle and is a park connected to the mainland. [8] It offers a unique blend of coastal nature and history, making it a great place to stroll and explore the area.";s:10:"categories";a:3:{i:0;s:6:"nature";i:1;s:10:"historical";i:2;s:7:"coastal";}s:14:"category_names";a:3:{i:0;s:10:"طبيعي";i:1;s:12:"تاريخي";i:2;s:10:"ساحلي";}s:8:"latitude";d:12.7806024;s:9:"longitude";d:45.0478499;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:34:"images/parks/aden/sira_island1.jpg";i:1;s:34:"images/parks/aden/sira_island2.jpg";}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:12;a:17:{s:2:"id";i:55;s:7:"city_id";i:2;s:11:"external_id";s:15:"ras-amran-beach";s:4:"name";s:26:"شاطئ رأس عمران";s:7:"name_en";s:15:"Ras Imran Beach";s:11:"description";s:318:"يقع غرب عدن، وهو شاطئ بري واسع يشتهر بأنه موقع لتعشيش السلاحف البحرية. [10] يعتبر وجهة مثالية لمحبي الطبيعة البكر والتخييم، ويوفر تجربة ساحلية مختلفة عن شواطئ المدينة المزدحمة.";s:14:"description_en";s:235:"Located west of Aden, it is a vast wild beach famous as a nesting site for sea turtles. [10] It is an ideal destination for lovers of pristine nature and camping, offering a coastal experience different from the city's crowded beaches.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:5:"beach";i:2;s:8:"wildlife";i:3;s:7:"camping";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"شاطئ";i:2;s:17:"حياة برية";i:3;s:10:"تخييم";}s:8:"latitude";d:12.7643797;s:9:"longitude";d:44.7295077;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:38:"images/parks/aden/ras_amran_beach1.jpg";i:1;s:38:"images/parks/aden/ras_amran_beach2.jpg";}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:13;a:17:{s:2:"id";i:56;s:7:"city_id";i:2;s:11:"external_id";s:12:"gate-of-aden";s:4:"name";s:28:"باب عدن (العقبة)";s:7:"name_en";s:24:"Bab Aden (Al-Aqaba Gate)";s:11:"description";s:344:"بوابة تاريخية محفورة في الجبل، كانت تمثل المدخل البري الوحيد لمدينة عدن القديمة (كريتر). [1] يعتبر هذا المعبر جزءاً من التحصينات الدفاعية القديمة للمدينة، ويشكل منظراً مهيباً عند مدخل كريتر.";s:14:"description_en";s:250:"A historic gate carved into the mountain, which once represented the only land entrance to the old city of Aden (Crater). [1] This passage is part of the city's ancient defensive fortifications and presents a majestic sight at the entrance to Crater.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"military";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:10:"عسكري";}s:8:"latitude";d:12.7883432;s:9:"longitude";d:45.0265832;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:44:"images/archaeological/aden/gate_of_aden1.jpg";i:1;s:44:"images/archaeological/aden/gate_of_aden2.jpg";}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:14;a:17:{s:2:"id";i:57;s:7:"city_id";i:2;s:11:"external_id";s:18:"zoroastrian-temple";s:4:"name";s:60:"معبد النار الزرادشتي (معبد الصمت)";s:7:"name_en";s:42:"Zoroastrian Fire Temple (Tower of Silence)";s:11:"description";s:270:"بقايا معبد قديم للطائفة الزرادشتية التي كانت تقطن عدن. [2] يقع على تلة في كريتر، وكان يستخدم لإقامة طقوس الدفن الخاصة بهم والمعروفة باسم "أبراج الصمت".";s:14:"description_en";s:207:"The remains of an ancient temple belonging to the Zoroastrian community that once inhabited Aden. [2] Situated on a hill in Crater, it was used for their specific burial rituals known as 'Towers of Silence'.";s:10:"categories";a:3:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:9:"religious";}s:14:"category_names";a:3:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"ديني";}s:8:"latitude";d:12.7727577;s:9:"longitude";d:45.0310483;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:50:"images/archaeological/aden/zoroastrian_temple1.jpg";i:1;s:50:"images/archaeological/aden/zoroastrian_temple2.jpg";}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:15;a:17:{s:2:"id";i:58;s:7:"city_id";i:2;s:11:"external_id";s:20:"church-of-st-francis";s:4:"name";s:79:"كنيسة القديس فرنسيس الأسيزي (كنيسة التواهي)";s:7:"name_en";s:44:"St. Francis of Assisi Church (Tawahi Church)";s:11:"description";s:346:"كنيسة كاثوليكية تاريخية بنيت في أواخر القرن التاسع عشر خلال فترة الاستعمار البريطاني. [3] تقع في منطقة التواهي وتتميز بتصميمها المعماري القوطي، وتعتبر من أقدم الكنائس في شبه الجزيرة العربية.";s:14:"description_en";s:251:"A historic Catholic church built in the late 19th century during the British colonial period. [3] Located in the Tawahi area, it is distinguished by its Gothic architectural design and is considered one of the oldest churches in the Arabian Peninsula.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:9:"religious";i:2;s:13:"architectural";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:8:"ديني";i:2;s:12:"معماري";}s:8:"latitude";d:12.7888067;s:9:"longitude";d:44.9797785;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:49:"images/archaeological/aden/st_francis_church1.jpg";i:1;s:49:"images/archaeological/aden/st_francis_church2.jpg";}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:16;a:17:{s:2:"id";i:59;s:7:"city_id";i:2;s:11:"external_id";s:20:"national-museum-aden";s:4:"name";s:63:"اقصر السلطان العبدلي (قصر 14 أكتوبر)";s:7:"name_en";s:45:"Abdali Sultan Palace (14th of October Palace)";s:11:"description";s:287:"كان في الأصل قصر السلطان العبدلي، وتحول لاحقًا إلى متحف وطني يعرض كنوزًا أثرية من مختلف العصور اليمنية القديمة. [4] يقع في كريتر ويتميز بطرازه المعماري الفريد.";s:14:"description_en";s:236:"Originally the palace of the Abdali Sultan, it later transformed into a national museum displaying archaeological treasures from various ancient Yemeni eras. [4] It is located in Crater and is notable for its unique architectural style.";s:10:"categories";a:4:{i:0;s:6:"museum";i:1;s:14:"archaeological";i:2;s:10:"historical";i:3;s:6:"palace";}s:14:"category_names";a:4:{i:0;s:8:"متحف";i:1;s:8:"أثري";i:2;s:12:"تاريخي";i:3;s:6:"قصر";}s:8:"latitude";d:12.7791678;s:9:"longitude";d:45.043016;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:47:"images/archaeological/aden/national_museum1.jpg";i:1;s:47:"images/archaeological/aden/national_museum2.jpg";}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:17;a:17:{s:2:"id";i:60;s:7:"city_id";i:2;s:11:"external_id";s:23:"clock-tower-little-aden";s:4:"name";s:33:"برج الساعة (بيغ بن)";s:7:"name_en";s:28:"Clock Tower (Little Big Ben)";s:11:"description";s:341:"برج ساعة تاريخي يقع بالقرب من مصفاة عدن في البريقة (عدن الصغرى). [7] تم بناؤه في فترة الخمسينيات من القرن الماضي كجزء من تطوير المنطقة السكنية لعمال المصفاة، ويعتبر معلماً بارزاً في المنطقة.";s:14:"description_en";s:235:"A historic clock tower located near the Aden refinery in Al-Buraiqeh (Little Aden). [7] It was built in the 1950s as part of the development of the residential area for refinery workers and stands as a prominent landmark in the region.";s:10:"categories";a:3:{i:0;s:10:"historical";i:1;s:13:"architectural";i:2;s:8:"landmark";}s:14:"category_names";a:3:{i:0;s:12:"تاريخي";i:1;s:12:"معماري";i:2;s:8:"معلم";}s:8:"latitude";d:12.790126;s:9:"longitude";d:44.9816439;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:54:"images/archaeological/aden/little_aden_clocktower1.jpg";i:1;s:54:"images/archaeological/aden/little_aden_clocktower2.jpg";}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:18;a:17:{s:2:"id";i:61;s:7:"city_id";i:2;s:11:"external_id";s:15:"al-kumsari-park";s:4:"name";s:38:"حديقة وملاهي الكمسري";s:7:"name_en";s:29:"Al-Kumsari Park and Amusement";s:11:"description";s:434:"تعتبر من أعرق وأجمل المتنزهات في عدن، تأسست عام 1952. [4, 7] تقع في مديرية دار سعد (أو الشيخ عثمان حسب مصادر أخرى)، وتتميز بمساحاتها الخضراء الواسعة وأشجارها الكثيفة، وتضم مجموعة متنوعة من الألعاب وركوب الخيل، مما يجعلها وجهة عائلية رئيسية. [4, 9]";s:14:"description_en";s:330:"Considered one of the oldest and most beautiful parks in Aden, established in 1952. [4, 7] Located in the Dar Sa'ad district (or Sheikh Othman, according to other sources), it is characterized by its vast green spaces and dense trees, featuring a variety of rides and horseback riding, making it a prime family destination. [4, 9]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:14:"amusement-park";i:2;s:6:"family";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:10:"ملاهي";i:2;s:10:"عائلي";i:3;s:12:"تاريخي";}s:8:"latitude";d:12.8810301;s:9:"longitude";d:44.9842953;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:19;a:17:{s:2:"id";i:62;s:7:"city_id";i:2;s:11:"external_id";s:13:"aden-new-park";s:4:"name";s:24:"حديقة عدن نيو";s:7:"name_en";s:13:"Aden New Park";s:11:"description";s:340:"واحدة من أبرز الوجهات السياحية العائلية الحديثة في عدن، تقع في مديرية خور مكسر. [5] تتميز باتساعها وتوفر مساحات خضراء وممرات للمشي وألعاب متنوعة، بالإضافة إلى قربها من مطاعم ومقاهي. [5, 12, 14]";s:14:"description_en";s:268:"One of the most prominent modern family tourist destinations in Aden, located in the Khormaksar district. [5] It is notable for its expansiveness, offering green spaces, walking paths, and various games, in addition to being close to restaurants and cafes. [5, 12, 14]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:12:"recreational";i:2;s:6:"family";i:3;s:6:"modern";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:12:"ترفيهي";i:2;s:10:"عائلي";i:3;s:8:"حديث";}s:8:"latitude";d:12.7881325;s:9:"longitude";d:45.0406707;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}i:20;a:17:{s:2:"id";i:63;s:7:"city_id";i:2;s:11:"external_id";s:16:"al-ghadeer-beach";s:4:"name";s:25:"الساحل الذهبي";s:7:"name_en";s:10:"Gold Coast";s:11:"description";s:274:"الساحل الذهبي ساحل جميل جدا ويشتهر بكونه وجهة للعائلات التي تبحث عن الهدوء النسبي. [6] يتميز بوجود شاليهات ومنتجعات سياحية توفر خيارات متنوعة للزوار. [6]";s:14:"description_en";s:203:"The Gold Coast is a very beautiful beach, famous as a destination for families looking for relative tranquility. [6] It features chalets and tourist resorts that provide diverse options for visitors. [6]";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:6:"resort";i:2;s:6:"family";i:3;s:5:"quiet";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"منتجع";i:2;s:10:"عائلي";i:3;s:8:"هادئ";}s:8:"latitude";d:12.7663326;s:9:"longitude";d:44.9946902;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:56.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:25;a:13:{s:2:"id";i:18;s:4:"slug";s:5:"amran";s:4:"name";s:10:"عمران";s:7:"name_en";s:5:"Amran";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:14:"amran_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:30;s:9:"landmarks";a:30:{i:0;a:17:{s:2:"id";i:451;s:7:"city_id";i:18;s:11:"external_id";s:19:"thula-historic-city";s:4:"name";s:38:"مدينة ثُلا التاريخية";s:7:"name_en";s:22:"Historic City of Thula";s:11:"description";s:445:"واحدة من أجمل وأكمل المدن التاريخية المحصنة في اليمن، وهي مدرجة على القائمة التمهيدية لليونسكو. [1, 2] تتميز بسورها الحجري الذي يحيط بها، ومنازلها البرجية الشاهقة المبنية من الحجر، وشوارعها المرصوفة، وحصنها المنيع (حصن الغراب) الذي يطل عليها. [1, 2]";s:14:"description_en";s:314:"One of the most beautiful and complete fortified historic cities in Yemen, inscribed on the UNESCO tentative list. [1, 2] It is distinguished by the stone wall surrounding it, its towering stone-built tower houses, its paved streets, and its impregnable fort (Mutahhar Fort/Fort of the Crow) overlooking it. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:6:"unesco";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"يونسكو";i:3;s:12:"معماري";}s:8:"latitude";d:15.5833;s:9:"longitude";d:43.8833;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:1;a:17:{s:2:"id";i:452;s:7:"city_id";i:18;s:11:"external_id";s:15:"hababah-cistern";s:4:"name";s:36:"معلم حَبابة وبركتها";s:7:"name_en";s:28:"Hababah Landmark and Cistern";s:11:"description";s:386:"قرية تاريخية تشتهر ببركتها (سدها) الكبيرة التي يعود تاريخها إلى العصر الحميري. [3, 4] تعتبر البركة تحفة هندسية قديمة لا تزال تستخدم حتى اليوم، وتحيط بها منازل حجرية تقليدية جميلة، مما يخلق منظراً فريداً وجذاباً. [3, 4]";s:14:"description_en";s:284:"A historic village famous for its large cistern (dam) dating back to the Himyarite era. [3, 4] The cistern is considered an ancient engineering masterpiece that is still in use today, surrounded by beautiful traditional stone houses, creating a unique and attractive landscape. [3, 4]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:11:"engineering";i:2;s:5:"water";i:3;s:7:"village";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"هندسي";i:2;s:8:"مائي";i:3;s:8:"قرية";}s:8:"latitude";d:15.5333;s:9:"longitude";d:43.9333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:2;a:17:{s:2:"id";i:453;s:7:"city_id";i:18;s:11:"external_id";s:16:"amran-grand-park";s:4:"name";s:34:"حديقة عمران الكبرى";s:7:"name_en";s:16:"Amran Grand Park";s:11:"description";s:321:"الحديقة العامة الرئيسية في مدينة عمران، مركز المحافظة. [6] تمثل المتنفس الرئيسي المنظم للعائلات داخل المدينة، وتضم مساحات خضراء وألعابًا للأطفال، وتشهد إقبالًا في المناسبات. [6]";s:14:"description_en";s:252:"The main public park in the city of Amran, the center of the governorate. [6] It serves as the primary organized retreat for families within the city, featuring green spaces and children's games, and witnesses large crowds during special occasions. [6]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:17:{s:2:"id";i:454;s:7:"city_id";i:18;s:11:"external_id";s:13:"naait-citadel";s:4:"name";s:15:"حصن ناعط";s:7:"name_en";s:10:"Na'it Fort";s:11:"description";s:365:"موقع أثري وتاريخي هام يقع على قمة جبل، ويعتبر من أقدم المواقع المحصنة في اليمن. [5] كان عاصمة لمملكة بكيل قديماً، ويضم بقايا أسوار وقصور ونقوش سبئية وحميرية، مما يجعله شاهداً على حضارات اليمن القديمة. [5]";s:14:"description_en";s:316:"An important archaeological and historical site located on a mountaintop, considered one of the oldest fortified sites in Yemen. [5] It was the ancient capital of the Bakil Kingdom, containing remains of walls, palaces, and Sabaean and Himyarite inscriptions, making it a witness to ancient Yemeni civilizations. [5]";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:8:"fortress";i:3;s:7:"ancient";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:6:"حصن";i:3;s:8:"قديم";}s:8:"latitude";d:15.65;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:17:{s:2:"id";i:455;s:7:"city_id";i:18;s:11:"external_id";s:11:"raydah-city";s:4:"name";s:19:"مدينة ريدة";s:7:"name_en";s:11:"Raydah City";s:11:"description";s:370:"مدينة تاريخية كانت مركزاً تجارياً هاماً على طريق القوافل القديم. [6] تشتهر بسوقها الأسبوعي التقليدي (سوق الأحد) الذي يعتبر من أقدم وأشهر الأسواق في المنطقة، وكانت مركزاً هاماً للجالية اليهودية في اليمن. [6]";s:14:"description_en";s:291:"A historic city that was an important commercial center on the ancient caravan route. [6] It is famous for its traditional weekly market (Sunday Market), considered one of the oldest and most renowned markets in the region. It was also an important hub for the Jewish community in Yemen. [6]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:6:"market";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:6:"سوق";i:3;s:10:"ثقافي";}s:8:"latitude";d:15.75;s:9:"longitude";d:43.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:17:{s:2:"id";i:456;s:7:"city_id";i:18;s:11:"external_id";s:14:"amran-old-city";s:4:"name";s:36:"مدينة عمران القديمة";s:7:"name_en";s:17:"Old City of Amran";s:11:"description";s:351:"عاصمة المحافظة، وتتميز ببوابتها القديمة (باب اليمن) وأسوارها الطينية. [7] تشتهر بمنازلها المبنية من الطين (الزابور) والتي تتميز بطراز معماري فريد يختلف عن المدن الحجرية المجاورة مثل ثلا وشبام. [7]";s:14:"description_en";s:252:"The capital of the governorate, distinguished by its ancient gate (Bab al-Yemen) and mud walls. [7] It is renowned for its mud-built houses (Zabur) featuring a unique architectural style distinct from neighboring stone cities like Thula and Shibam. [7]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:13:"architectural";i:3;s:8:"mudbrick";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:12:"معماري";i:3;s:6:"طين";}s:8:"latitude";d:15.65;s:9:"longitude";d:43.95;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:17:{s:2:"id";i:457;s:7:"city_id";i:18;s:11:"external_id";s:15:"masani-al-husha";s:4:"name";s:21:"مصانع الحشا";s:7:"name_en";s:16:"Masani' Al-Hasha";s:11:"description";s:326:"موقع أثري يقع في مديرية خمر، ويضم بقايا مدينة قديمة تعود إلى فترة ما قبل الإسلام. [8] يحتوي الموقع على أطلال مبانٍ ضخمة، نقوش، ومقابر صخرية، مما يدل على أنه كان مركزاً حضارياً مهماً.";s:14:"description_en";s:267:"An archaeological site located in the Khamir district, encompassing the remains of an ancient city dating back to the pre-Islamic period. [8] The site contains ruins of massive buildings, inscriptions, and rock tombs, indicating it was a significant civilized center.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:5:"ruins";i:2;s:10:"historical";i:3;s:7:"ancient";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:10:"أطلال";i:2;s:12:"تاريخي";i:3;s:8:"قديم";}s:8:"latitude";d:15.9;s:9:"longitude";d:43.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:17:{s:2:"id";i:458;s:7:"city_id";i:18;s:11:"external_id";s:15:"jabal-dhu-ayban";s:4:"name";s:22:"جبل ذو عيبان";s:7:"name_en";s:16:"Mount Dhu 'Ayban";s:11:"description";s:353:"جبل شاهق يقع بالقرب من مدينة عمران، وتوجد على قمته بقايا حصن تاريخي. [9] يوفر الجبل إطلالات بانورامية رائعة على قاع البون الشاسع والمدن والقرى المحيطة به، ويعتبر وجهة لمحبي الطبيعة والمشي الجبلي.";s:14:"description_en";s:281:"A towering mountain located near the city of Amran, with remains of a historical fort on its summit. [9] The mountain offers fantastic panoramic views of the vast Qa' Al-Bawn plain and its surrounding cities and villages, and is a destination for nature lovers and mountain hikers.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:12:"تاريخي";}s:8:"latitude";d:15.6;s:9:"longitude";i:44;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:8;a:17:{s:2:"id";i:459;s:7:"city_id";i:18;s:11:"external_id";s:15:"al-janat-mosque";s:4:"name";s:34:"مسجد الجنات (حبابة)";s:7:"name_en";s:26:"Al-Jannat Mosque (Hababah)";s:11:"description";s:318:"مسجد تاريخي يقع في قرية حبابة، ويتميز بتصميمه المعماري البسيط والجميل. [4] يعتبر المسجد جزءاً من النسيج العمراني للقرية التاريخية، ويضيف إلى سحرها وأهميتها الثقافية والدينية.";s:14:"description_en";s:246:"A historical mosque located in the village of Hababah, noted for its simple and beautiful architectural design. [4] The mosque is part of the historic village's urban fabric, adding to its charm as well as its cultural and religious significance.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:13:"architectural";i:3;s:6:"mosque";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:12:"معماري";i:3;s:8:"مسجد";}s:8:"latitude";d:15.5333;s:9:"longitude";d:43.9333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:9;a:17:{s:2:"id";i:460;s:7:"city_id";i:18;s:11:"external_id";s:9:"huth-city";s:4:"name";s:17:"مدينة حوث";s:7:"name_en";s:9:"Huth City";s:11:"description";s:320:"مدينة تاريخية وعلمية هامة تقع في شمال المحافظة. [10] كانت مركزاً بارزاً للزيدية، وتضم العديد من المساجد والمكتبات التاريخية، وتشتهر بعلمائها وكثرة هجرها العلمية عبر التاريخ. [10]";s:14:"description_en";s:274:"An important historical and scientific city located in the north of the governorate. [10] It was a prominent center for Zaidism, housing many historical mosques and libraries, and is famous for its scholars and numerous centers of learning (Hijrahs) throughout history. [10]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:4:"city";i:2;s:9:"religious";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:10:"مدينة";i:2;s:8:"ديني";i:3;s:10:"ثقافي";}s:8:"latitude";d:16.1833;s:9:"longitude";d:43.9667;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:10;a:17:{s:2:"id";i:461;s:7:"city_id";i:18;s:11:"external_id";s:10:"qa-al-bawn";s:4:"name";s:17:"قاع البون";s:7:"name_en";s:11:"Qa' Al-Bawn";s:11:"description";s:283:"سهل زراعي واسع وخصب يمتد بين صنعاء وعمران. [9] يعتبر القاع منظراً طبيعياً فريداً، وتتناثر فيه القرى التاريخية والمواقع الأثرية، ويمثل سلة غذاء هامة للمنطقة.";s:14:"description_en";s:229:"A wide, fertile agricultural plain stretching between Sana'a and Amran. [9] The plain is a unique natural landscape dotted with historical villages and archaeological sites, and it represents a crucial breadbasket for the region.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:5:"plain";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:6:"سهل";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.6;s:9:"longitude";d:43.95;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:11;a:17:{s:2:"id";i:462;s:7:"city_id";i:18;s:11:"external_id";s:17:"wadi-dhaher-amran";s:4:"name";s:43:"وادي ضهر (الجزء الشمالي)";s:7:"name_en";s:25:"Wadi Dhar (Northern Part)";s:11:"description";s:326:"يمتد وادي ضهر الشهير من صنعاء شمالاً ليدخل أراضي محافظة عمران. [1] يتميز هذا الجزء بخصوبته وأراضيه الزراعية الواسعة التي تعتمد على مياهه، وتنتشر على ضفافه العديد من القرى والمزارع.";s:14:"description_en";s:258:"The famous Wadi Dhar extends northward from Sana'a to enter the territories of Amran Governorate. [1] This part is distinguished by its fertility and expansive agricultural lands relying on its waters, with numerous villages and farms spread along its banks.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.55;s:9:"longitude";d:44.05;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:12;a:17:{s:2:"id";i:463;s:7:"city_id";i:18;s:11:"external_id";s:16:"sadd-al-maqranah";s:4:"name";s:21:"سد المقرانة";s:7:"name_en";s:15:"Al-Maqranah Dam";s:11:"description";s:323:"يقع في مديرية السودة، وهو سد حديث تم إنشاؤه لحصاد مياه الأمطار والسيول. [2] أصبحت بحيرة السد معلماً طبيعياً في المنطقة، حيث تساهم في دعم الزراعة وتغذية الآبار وتوفر منظراً جميلاً.";s:14:"description_en";s:253:"Located in the Al-Sawdah district, it is a modern dam established to harvest rainwater and floods. [2] The dam's lake has become a natural landmark in the area, contributing to agricultural support, recharging wells, and providing a beautiful landscape.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:11:"engineering";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:10:"هندسي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.7;s:9:"longitude";d:43.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:13;a:17:{s:2:"id";i:464;s:7:"city_id";i:18;s:11:"external_id";s:18:"wadi-al-jawf-upper";s:4:"name";s:45:"منابع وادي الجوف (الخارد)";s:7:"name_en";s:35:"Sources of Wadi Al-Jawf (Al-Kharid)";s:11:"description";s:358:"تبدأ الروافد العليا لوادي الخارد، الذي يشكل لاحقاً وادي الجوف الكبير، من المرتفعات الشرقية لمحافظة عمران. [3] هذه المناطق تشهد تدفقاً للسيول بعد الأمطار، وتشكل مصدراً مائياً هاماً للمناطق الشرقية.";s:14:"description_en";s:248:"The upper tributaries of Wadi Al-Kharid, which later forms the great Wadi Al-Jawf, begin from the eastern highlands of Amran Governorate. [3] These areas witness flood flows after rainfall and form an important water source for the eastern regions.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:6:"source";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:8:"منبع";i:3;s:10:"موسمي";}s:8:"latitude";d:15.8;s:9:"longitude";d:44.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:14;a:17:{s:2:"id";i:465;s:7:"city_id";i:18;s:11:"external_id";s:12:"wadi-shuwaba";s:4:"name";s:19:"وادي شوابة";s:7:"name_en";s:13:"Wadi Shawabah";s:11:"description";s:332:"أحد الأودية الهامة في مديرية خمر، ويشتهر بأراضيه الزراعية الخصبة. [4] يعتمد المزارعون على مياه السيول التي تجري في هذا الوادي لزراعة الحبوب والخضروات، ويعتبر شرياناً حيوياً للمديرية.";s:14:"description_en";s:233:"One of the important valleys in the Khamir district, famous for its fertile agricultural lands. [4] Farmers rely on the floodwaters running through this valley to grow grains and vegetables, making it a vital artery for the district.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"موسمي";}s:8:"latitude";d:15.95;s:9:"longitude";d:43.95;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:15;a:17:{s:2:"id";i:466;s:7:"city_id";i:18;s:11:"external_id";s:11:"sadd-raydah";s:4:"name";s:13:"سد ريدة";s:7:"name_en";s:10:"Raydah Dam";s:11:"description";s:303:"سد صغير يقع بالقرب من مدينة ريدة، تم بناؤه لتعزيز الموارد المائية في المنطقة. [5] يساهم السد في توفير المياه للزراعة المحيطة به، ويشكل بحيرة موسمية تضيف جمالاً للمنطقة.";s:14:"description_en";s:212:"A small dam located near the city of Raydah, built to enhance water resources in the area. [5] The dam helps provide water for the surrounding agriculture and forms a seasonal lake that adds beauty to the region.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:5:"local";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:8:"محلي";}s:8:"latitude";d:15.75;s:9:"longitude";d:43.92;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:16;a:17:{s:2:"id";i:467;s:7:"city_id";i:18;s:11:"external_id";s:12:"wadi-al-aqab";s:4:"name";s:19:"وادي العقب";s:7:"name_en";s:12:"Wadi Al-Aqab";s:11:"description";s:287:"يقع في مديرية السودة، وهو وادٍ جبلي يتميز بمناظره الطبيعية. [2] تجري فيه المياه بعد هطول الأمطار، وتنتشر على جانبيه بعض المزارع والقرى الصغيرة التي تعتمد عليه.";s:14:"description_en";s:206:"Located in the Al-Sawdah district, it is a mountain valley characterized by its natural scenery. [2] Water flows through it after rainfall, and small farms and villages relying on it spread along its sides.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.75;s:9:"longitude";d:43.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:17;a:17:{s:2:"id";i:468;s:7:"city_id";i:18;s:11:"external_id";s:14:"thula-cisterns";s:4:"name";s:30:"مآجل وصهاريج ثلا";s:7:"name_en";s:24:"Thula Cisterns and Pools";s:11:"description";s:361:"بالإضافة إلى حصنها، تشتهر مدينة ثلا بنظامها المائي المتقن الذي يضم العديد من الصهاريج والمآجل (خزانات مياه) المنحوتة في الصخر. [6] هذه المنشآت القديمة تدل على براعة هندسية فائقة في حصاد وتخزين المياه.";s:14:"description_en";s:260:"In addition to its fort, the city of Thula is famous for its elaborate water system, which includes many rock-carved pools and cisterns (water reservoirs). [6] These ancient structures indicate supreme engineering ingenuity in rainwater harvesting and storage.";s:10:"categories";a:4:{i:0;s:5:"water";i:1;s:10:"historical";i:2;s:11:"engineering";i:3;s:7:"cistern";}s:14:"category_names";a:4:{i:0;s:8:"مائي";i:1;s:12:"تاريخي";i:2;s:10:"هندسي";i:3;s:10:"صهريج";}s:8:"latitude";d:15.5833;s:9:"longitude";d:43.8833;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:18;a:17:{s:2:"id";i:469;s:7:"city_id";i:18;s:11:"external_id";s:12:"wadi-dhi-bin";s:4:"name";s:20:"وادي ذي بين";s:7:"name_en";s:12:"Wadi Dhi Bin";s:11:"description";s:295:"وادي رئيسي يقع في مديرية حوث، ويعتبر من المناطق الزراعية الهامة في شمال المحافظة. [7] يعتمد عليه السكان في الزراعة وتوفير المياه، وتزداد أهميته خلال مواسم الأمطار.";s:14:"description_en";s:250:"A major valley located in the Huth district, considered one of the important agricultural areas in the northern part of the governorate. [7] Residents rely on it for agriculture and water supply, and its importance increases during the rainy seasons.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"طبيعي";}s:8:"latitude";d:16.1;s:9:"longitude";d:43.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:19;a:17:{s:2:"id";i:470;s:7:"city_id";i:18;s:11:"external_id";s:14:"sadd-al-ashmor";s:4:"name";s:19:"سد الأشمور";s:7:"name_en";s:13:"Al-Ashmur Dam";s:11:"description";s:300:"يقع في منطقة الأشمور بمديرية عيال سريح، وهو سد محلي يخدم الأراضي الزراعية المحيطة به. [8] يمثل نموذجاً للسدود الصغيرة التي تلعب دوراً كبيراً في دعم المجتمعات الريفية.";s:14:"description_en";s:216:"Located in the Al-Ashmur area of the Iyal Surayh district, it is a local dam serving the surrounding agricultural lands. [8] It represents a model for small dams that play a huge role in supporting rural communities.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:9:"community";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:12:"مجتمعي";i:3;s:10:"زراعة";}s:8:"latitude";d:15.8;s:9:"longitude";d:43.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:20;a:17:{s:2:"id";i:471;s:7:"city_id";i:18;s:11:"external_id";s:12:"wadi-khaywan";s:4:"name";s:19:"وادي خيوان";s:7:"name_en";s:12:"Wadi Khaywan";s:11:"description";s:283:"يقع في أقصى شمال شرق المحافظة، ويعتبر امتداداً للأودية القادمة من صعدة. [3] هو وادٍ ذو أهمية تاريخية وزراعية، وتتدفق فيه السيول بشكل كبير خلال مواسم الأمطار.";s:14:"description_en";s:247:"Located in the far northeast of the governorate, it is considered an extension of the valleys originating from Sa'dah. [3] It is a valley of historical and agricultural significance, with floods flowing heavily through it during the rainy seasons.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:8:"seasonal";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"موسمي";i:3;s:12:"تاريخي";}s:8:"latitude";d:16.3;s:9:"longitude";d:44.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:21;a:17:{s:2:"id";i:472;s:7:"city_id";i:18;s:11:"external_id";s:19:"thula-fortress-park";s:4:"name";s:46:"منتزه حصن ثلا (حصن الغراب)";s:7:"name_en";s:48:"Thula Fort Park (Mutahhar Fort/Fort of the Crow)";s:11:"description";s:379:"المنطقة المحيطة بحصن ثلا والطريق الصاعد إليه تعتبر منتزهاً طبيعياً ومساراً رائعاً للمشي (هايكنج). [1] توفر المنطقة إطلالات بانورامية مذهلة على مدينة ثلا التاريخية وقاع البون، وهي مثالية للاستمتاع بغروب الشمس.";s:14:"description_en";s:255:"The area surrounding Thula Fort and the path leading up to it is considered a natural park and a wonderful hiking trail. [1] The area offers stunning panoramic views of the historic city of Thula and Qa' Al-Bawn, making it perfect for enjoying the sunset.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:9:"viewpoint";i:2;s:6:"hiking";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"مطل";i:2;s:12:"هايكنج";i:3;s:12:"تاريخي";}s:8:"latitude";d:15.58;s:9:"longitude";d:43.87;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:22;a:17:{s:2:"id";i:473;s:7:"city_id";i:18;s:11:"external_id";s:17:"wadi-maswar-falls";s:4:"name";s:47:"شلالات وادي مسور الموسمية";s:7:"name_en";s:31:"Wadi Miswar Seasonal Waterfalls";s:11:"description";s:278:"يقع في مديرية مسور الجبلية، وهو وادٍ تنحدر فيه السيول بقوة بعد الأمطار. تتشكل على طول مجراه شلالات صخرية جميلة، مما يجعله وجهة للمتنزهين من سكان المنطقة.";s:14:"description_en";s:226:"Located in the mountainous district of Miswar, it is a valley where floods descend powerfully after the rains. Beautiful rocky waterfalls form along its course, making it a destination for picnickers among the local residents.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.5;s:9:"longitude";d:43.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:23;a:17:{s:2:"id";i:474;s:7:"city_id";i:18;s:11:"external_id";s:20:"jabal-dhu-ayban-park";s:4:"name";s:33:"منتزه جبل ذو عيبان";s:7:"name_en";s:21:"Mount Dhu 'Ayban Park";s:11:"description";s:327:"سفوح جبل ذو عيبان والمناطق المحيطة به تعتبر منتزهاً طبيعياً مفتوحاً. [2] يقصدها الأهالي للنزهات الخلوية والاستمتاع بالهواء النقي والمناظر الطبيعية الواسعة للسهول والقرى المجاورة.";s:14:"description_en";s:235:"The slopes of Mount Dhu 'Ayban and its surrounding areas are considered an open natural park. [2] Locals visit it for outdoor picnics, enjoying the fresh air, and taking in the expansive natural views of the plains and nearby villages.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.6;s:9:"longitude";i:44;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:24;a:17:{s:2:"id";i:475;s:7:"city_id";i:18;s:11:"external_id";s:26:"al-sudah-mountain-cascades";s:4:"name";s:34:"شلالات جبال السودة";s:7:"name_en";s:30:"Al-Sawdah Mountains Waterfalls";s:11:"description";s:284:"مديرية السودة هي منطقة مرتفعة تتلقى كميات جيدة من الأمطار. تتكون على منحدراتها الجبلية شلالات متتالية (Cascades) أثناء تدفق السيول، مما يخلق مناظر طبيعية رائعة.";s:14:"description_en";s:196:"The Al-Sawdah district is a high-altitude area that receives good amounts of rainfall. During flood flows, successive cascades form on its mountain slopes, creating magnificent natural landscapes.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.72;s:9:"longitude";d:43.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:25;a:17:{s:2:"id";i:476;s:7:"city_id";i:18;s:11:"external_id";s:27:"iyyal-surayh-highlands-park";s:4:"name";s:43:"منتزه مرتفعات عيال سريح";s:7:"name_en";s:26:"Iyal Surayh Highlands Park";s:11:"description";s:307:"تتميز مديرية عيال سريح بمرتفعاتها الجبلية ومناظرها الطبيعية. [4] توفر هذه المرتفعات أماكن هادئة ومطلات طبيعية تصلح للنزهات والتخييم الخفيف والاستمتاع بالهدوء والسكينة.";s:14:"description_en";s:221:"The Iyal Surayh district is notable for its mountainous highlands and natural scenery. [4] These highlands offer quiet places and natural viewpoints suitable for picnics, light camping, and enjoying peace and tranquility.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.75;s:9:"longitude";d:43.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:26;a:17:{s:2:"id";i:477;s:7:"city_id";i:18;s:11:"external_id";s:31:"wadi-al-kharid-headwaters-falls";s:4:"name";s:45:"شلالات منابع وادي الخارد";s:7:"name_en";s:36:"Sources of Wadi Al-Kharid Waterfalls";s:11:"description";s:288:"في الروافد العليا لوادي الخارد شرق عمران، تتسبب السيول القادمة من الجبال في تكوين شلالات موسمية قوية. [5] تعتبر هذه المناطق وجهة للمغامرين لمشاهدة قوة الطبيعة.";s:14:"description_en";s:223:"In the upper tributaries of Wadi Al-Kharid, east of Amran, floods coming from the mountains create powerful seasonal waterfalls. [5] These areas serve as a destination for adventurers seeking to witness the power of nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:6:"قوي";}s:8:"latitude";d:15.8;s:9:"longitude";d:44.15;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:27;a:17:{s:2:"id";i:478;s:7:"city_id";i:18;s:11:"external_id";s:23:"khamir-countryside-park";s:4:"name";s:28:"منتزه أرياف خمر";s:7:"name_en";s:23:"Khamir Countryside Park";s:11:"description";s:291:"الأراضي الزراعية والريف المحيط بمدينة خمر يعتبر منتزهاً طبيعياً. [6] تشتهر المنطقة بزراعة العنب والحبوب، وتوفر بيئة ريفية جميلة وهادئة مناسبة للرحلات العائلية.";s:14:"description_en";s:234:"The agricultural lands and countryside surrounding the city of Khamir are considered a natural park. [6] The area is famous for growing grapes and grains, providing a beautiful and tranquil rural environment suitable for family trips.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:11:"countryside";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:6:"ريف";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:15.9;s:9:"longitude";d:43.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:28;a:17:{s:2:"id";i:479;s:7:"city_id";i:18;s:11:"external_id";s:17:"jabal-yazid-falls";s:4:"name";s:45:"شلالات جبل يزيد الموسمية";s:7:"name_en";s:31:"Jabal Yazid Seasonal Waterfalls";s:11:"description";s:282:"المرتفعات في مديرية جبل يزيد هي مصدر للعديد من السيول. تتشكل على هذه المرتفعات شلالات تنحدر نحو الأودية المحيطة، وتكون مشاهدتها ممتعة بعد الأمطار الغزيرة.";s:14:"description_en";s:203:"The highlands in the Jabal Yazid district are the source of many floods. Waterfalls form on these highlands, cascading down into the surrounding valleys, and making them a joy to watch after heavy rains.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:15.65;s:9:"longitude";d:44.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:29;a:17:{s:2:"id";i:480;s:7:"city_id";i:18;s:11:"external_id";s:20:"hababah-village-park";s:4:"name";s:30:"منتزه قرية حبابة";s:7:"name_en";s:20:"Hababah Village Park";s:11:"description";s:324:"المنطقة المحيطة ببركة حبابة والقرية التاريخية تعتبر منتزهاً بحد ذاتها. [7] يمكن للزوار الجلوس حول البركة والاستمتاع بمنظر انعكاس المباني التاريخية على سطح الماء في جو هادئ وساحر.";s:14:"description_en";s:236:"The area surrounding the Hababah cistern and the historic village is considered a park in itself. [7] Visitors can sit around the pool and enjoy the reflection of historical buildings on the water surface in a quiet, magical atmosphere.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:10:"historical";i:2;s:6:"scenic";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:12:"تاريخي";i:2;s:21:"مناظر خلابة";i:3;s:8:"مائي";}s:8:"latitude";d:15.5333;s:9:"longitude";d:43.9333;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:15.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:26;a:13:{s:2:"id";i:21;s:4:"slug";s:5:"lahij";s:4:"name";s:6:"لحج";s:7:"name_en";s:5:"Lahij";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:14:"lahij_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:41;s:9:"landmarks";a:41:{i:0;a:17:{s:2:"id";i:518;s:7:"city_id";i:21;s:11:"external_id";s:13:"dar-al-aroosa";s:4:"name";s:45:"دار العرائس (قصر السلطان)";s:7:"name_en";s:30:"Dar Al-Arais (Sultan's Palace)";s:11:"description";s:366:"أشهر معلم في مدينة الحوطة، كان القصر الصيفي لسلاطين لحج. [1, 2] يتميز بطرازه المعماري الفريد الذي يمزج بين الطابعين الهندي والعربي، وكان مركزاً للحياة السياسية والثقافية والفنية في السلطنة العبدلية. [1, 2]";s:14:"description_en";s:279:"The most famous landmark in the city of Al-Hawtah, it was the summer palace for the Sultans of Lahij. [1, 2] Featuring a unique architectural style that blends Indian and Arab aesthetics, it was a hub for political, cultural, and artistic life during the Abdali Sultanate. [1, 2]";s:10:"categories";a:4:{i:0;s:10:"historical";i:1;s:6:"palace";i:2;s:13:"architectural";i:3;s:7:"culture";}s:14:"category_names";a:4:{i:0;s:12:"تاريخي";i:1;s:6:"قصر";i:2;s:12:"معماري";i:3;s:10:"ثقافي";}s:8:"latitude";d:13.058;s:9:"longitude";d:44.885;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:1;a:17:{s:2:"id";i:519;s:7:"city_id";i:21;s:11:"external_id";s:22:"al-hawtah-grand-mosque";s:4:"name";s:58:"مسجد الدولة (جامع الحوطة الكبير)";s:7:"name_en";s:40:"State Mosque (Great Mosque of Al-Hawtah)";s:11:"description";s:313:"أقدم وأكبر مسجد في الحوطة، عاصمة المحافظة. [3, 4] بناه السلطان فضل بن علي العبدلي، ويتميز بمنارته الشاهقة وتصميمه الإسلامي التقليدي، ويعتبر المركز الديني الرئيسي في المدينة.";s:14:"description_en";s:241:"The oldest and largest mosque in Al-Hawtah, the capital of the governorate. [3, 4] Built by Sultan Fadhl bin Ali Al-Abdali, it is known for its soaring minaret and traditional Islamic design, serving as the main religious center in the city.";s:10:"categories";a:4:{i:0;s:9:"religious";i:1;s:10:"historical";i:2;s:6:"mosque";i:3;s:13:"architectural";}s:14:"category_names";a:4:{i:0;s:8:"ديني";i:1;s:12:"تاريخي";i:2;s:8:"مسجد";i:3;s:12:"معماري";}s:8:"latitude";d:13.055;s:9:"longitude";d:44.886;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:2;a:17:{s:2:"id";i:520;s:7:"city_id";i:21;s:11:"external_id";s:10:"wadi-tuban";s:4:"name";s:15:"وادي تبن";s:7:"name_en";s:10:"Wadi Tuban";s:11:"description";s:361:"هو شريان الحياة لمحافظة لحج وأحد أكبر أودية اليمن. [5, 6] يشتهر بخصوبته الأسطورية التي منحت لحج لقب "الخضيرة"، وتنتشر على ضفافه بساتين الفواكه والخضروات والمزارع الشاسعة، ويعتبر منظراً طبيعياً خلاباً.";s:14:"description_en";s:283:"It is the lifeline of Lahij Governorate and one of the largest valleys in Yemen. [5, 6] Renowned for its legendary fertility, which earned Lahij the nickname 'The Green,' its banks are lined with fruit and vegetable orchards and vast farms, creating a breathtaking natural landscape.";s:10:"categories";a:4:{i:0;s:7:"natural";i:1;s:6:"valley";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:8:"وادي";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.1;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:3;a:17:{s:2:"id";i:521;s:7:"city_id";i:21;s:11:"external_id";s:18:"karish-hot-springs";s:4:"name";s:36:"حمامات كرش (الحميمي)";s:7:"name_en";s:24:"Kirsh Baths (Al-Humaimi)";s:11:"description";s:373:"مجموعة من الينابيع الكبريتية الحارة تقع في منطقة كرش الحدودية. [7] يقصدها الناس من مختلف المناطق للاستشفاء والعلاج الطبيعي من الأمراض الجلدية والروماتيزم، وتعتبر من أشهر مواقع السياحة العلاجية في المنطقة.";s:14:"description_en";s:240:"A series of hot sulfur springs located in the Kirsh border region. [7] People visit from various areas for natural healing and therapy from skin diseases and rheumatism, making it one of the most popular medical tourism sites in the region.";s:10:"categories";a:4:{i:0;s:6:"health";i:1;s:7:"tourism";i:2;s:7:"natural";i:3;s:6:"spring";}s:14:"category_names";a:4:{i:0;s:6:"صحي";i:1;s:10:"سياحة";i:2;s:10:"طبيعي";i:3;s:10:"ينبوع";}s:8:"latitude";d:13.45;s:9:"longitude";d:44.7;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:4;a:17:{s:2:"id";i:522;s:7:"city_id";i:21;s:11:"external_id";s:11:"jabal-harir";s:4:"name";s:15:"جبل حرير";s:7:"name_en";s:11:"Mount Harir";s:11:"description";s:347:"جبل شاهق يقع في مديرية يافع، ويتميز بمدرجاته الزراعية الخضراء التي تزرع فيها أجود أنواع البن اليافعي. [8] يوفر الجبل إطلالات بانورامية ساحرة ويعتبر مثالاً رائعاً على الزراعة الجبلية في اليمن.";s:14:"description_en";s:257:"A towering mountain located in the Yafa'a district, notable for its green agricultural terraces where the finest types of Yafa'i coffee are grown. [8] The mountain provides magical panoramic views and is a fantastic example of mountain agriculture in Yemen.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:6:"scenic";i:2;s:11:"agriculture";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"جبلي";i:1;s:21:"مناظر خلابة";i:2;s:10:"زراعة";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.8;s:9:"longitude";d:45.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:5;a:17:{s:2:"id";i:523;s:7:"city_id";i:21;s:11:"external_id";s:17:"ras-al-arah-beach";s:4:"name";s:28:"ساحل رأس العارة";s:7:"name_en";s:17:"Ras Al-Arah Coast";s:11:"description";s:309:"شريط ساحلي جميل يقع على مضيق باب المندب في مديرية المضاربة ورأس العارة. [9] يتميز بشواطئه الرملية البيضاء ومياهه الصافية، ويعتبر وجهة للصيد والاستجمام ومراقبة حركة السفن.";s:14:"description_en";s:256:"A beautiful coastal strip located on the Bab al-Mandab Strait in the Al-Madaribah wa Ras Al-Arah district. [9] It is distinguished by its white sandy beaches and clear waters, acting as a destination for fishing, recreation, and observing maritime traffic.";s:10:"categories";a:4:{i:0;s:5:"beach";i:1;s:7:"coastal";i:2;s:7:"natural";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:8:"شاطئ";i:1;s:10:"ساحلي";i:2;s:10:"طبيعي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:12.65;s:9:"longitude";i:44;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:6;a:17:{s:2:"id";i:524;s:7:"city_id";i:21;s:11:"external_id";s:16:"al-habilayn-park";s:4:"name";s:27:"حديقة الحبيلين";s:7:"name_en";s:16:"Al-Habilayn Park";s:11:"description";s:295:"حديقة عامة تقع في مدينة الحبيلين، إحدى المدن الرئيسية في مديرية ردفان. [6] تمثل متنفسًا منظمًا للعائلات والأطفال في المنطقة، وتضم بعض المساحات الخضراء والألعاب. [6]";s:14:"description_en";s:210:"A public park located in the city of Al-Habilayn, one of the main towns in the Radfan district. [6] It serves as an organized retreat for families and children in the area, featuring green spaces and games. [6]";s:10:"categories";a:3:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:7;a:17:{s:2:"id";i:525;s:7:"city_id";i:21;s:11:"external_id";s:16:"al-habilayn-city";s:4:"name";s:27:"مدينة الحبيلين";s:7:"name_en";s:16:"Al-Habilayn City";s:11:"description";s:303:"عاصمة مديرية ردفان، وهي مدينة ذات أهمية تاريخية وعسكرية. [10] كانت مركزاً رئيسياً خلال ثورة 14 أكتوبر ضد الاستعمار البريطاني، وتتميز بموقعها الاستراتيجي في منطقة جبلية.";s:14:"description_en";s:234:"The capital of the Radfan district, a city with historical and military significance. [10] It was a major center during the October 14 Revolution against British colonialism, notable for its strategic location in a mountainous region.";s:10:"categories";a:4:{i:0;s:4:"city";i:1;s:10:"historical";i:2;s:8:"military";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:10:"مدينة";i:1;s:12:"تاريخي";i:2;s:10:"عسكري";i:3;s:8:"جبلي";}s:8:"latitude";d:13.5;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:8;a:17:{s:2:"id";i:526;s:7:"city_id";i:21;s:11:"external_id";s:11:"wadi-maadin";s:4:"name";s:19:"وادي معادن";s:7:"name_en";s:12:"Wadi Ma'adin";s:11:"description";s:287:"أحد الأودية الهامة في مديرية حالمين، ويشتهر بخصوبته ومياهه الجارية. [6] يعتبر الوادي متنفساً طبيعياً للسكان، وتنتشر فيه الزراعة، خاصة زراعة الحبوب والخضروات.";s:14:"description_en";s:228:"One of the key valleys in the Halmin district, famous for its fertility and flowing waters. [6] The valley serves as a natural retreat for locals, where agriculture thrives, particularly the cultivation of grains and vegetables.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:7:"natural";i:2;s:11:"agriculture";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:10:"طبيعي";i:2;s:10:"زراعة";i:3;s:8:"مائي";}s:8:"latitude";d:13.6;s:9:"longitude";i:45;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:9;a:17:{s:2:"id";i:527;s:7:"city_id";i:21;s:11:"external_id";s:17:"al-hawtah-gardens";s:4:"name";s:42:"بساتين الحوطة (الحسيني)";s:7:"name_en";s:32:"Al-Hawtah Orchards (Al-Husseini)";s:11:"description";s:340:"المنطقة الزراعية المحيطة بمدينة الحوطة، والمعروفة ببساتين الحسيني. [5] تشتهر بزراعة المانجو والموز والنخيل، وتعتبر رئة خضراء ومنطقة استجمام ونزهة للسكان، وتعكس تاريخ لحج الزراعي العريق.";s:14:"description_en";s:242:"The agricultural area surrounding Al-Hawtah city, known as Al-Husseini Orchards. [5] Famous for growing mangoes, bananas, and palm trees, it is a green lung and a recreation area for residents, reflecting Lahij's ancient agricultural history.";s:10:"categories";a:4:{i:0;s:11:"agriculture";i:1;s:6:"scenic";i:2;s:7:"natural";i:3;s:4:"park";}s:14:"category_names";a:4:{i:0;s:10:"زراعة";i:1;s:21:"مناظر خلابة";i:2;s:10:"طبيعي";i:3;s:10:"منتزه";}s:8:"latitude";d:13.06;s:9:"longitude";d:44.87;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:10;a:17:{s:2:"id";i:528;s:7:"city_id";i:21;s:11:"external_id";s:12:"jabal-al-arr";s:4:"name";s:26:"جبل العر (يافع)";s:7:"name_en";s:21:"Mount Al-Urr (Yafa'a)";s:11:"description";s:298:"أحد أعلى الجبال في يافع، ويشتهر بحصونه التاريخية وقراه المعلقة على سفوحه. [8] المنطقة غنية بالتاريخ وتعتبر مركزاً لقبائل يافع، وتوفر مناظر طبيعية جبلية وعرة وخلابة.";s:14:"description_en";s:232:"One of the highest mountains in Yafa'a, known for its historical forts and villages hanging on its slopes. [8] The area is rich in history and acts as a center for the Yafa'i tribes, offering rugged and stunning mountain landscapes.";s:10:"categories";a:4:{i:0;s:8:"mountain";i:1;s:10:"historical";i:2;s:8:"fortress";i:3;s:7:"village";}s:14:"category_names";a:4:{i:0;s:8:"جبلي";i:1;s:12:"تاريخي";i:2;s:6:"حصن";i:3;s:8:"قرية";}s:8:"latitude";d:13.75;s:9:"longitude";d:45.3;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:11;a:17:{s:2:"id";i:529;s:7:"city_id";i:21;s:11:"external_id";s:16:"wadi-saghir-lahj";s:4:"name";s:26:"وادي صغير (لحج)";s:7:"name_en";s:19:"Wadi Saghir (Lahij)";s:11:"description";s:303:"أحد الروافد الهامة لوادي تبن، ويمر بالقرب من مدينة الحوطة. [1] يلعب دوراً حيوياً في ري الأراضي الزراعية المحيطة بالمدينة، وتنتشر على ضفافه العديد من المزارع والبساتين.";s:14:"description_en";s:205:"An important tributary of Wadi Tuban, passing near the city of Al-Hawtah. [1] It plays a vital role in irrigating the agricultural lands surrounding the city, with many farms and orchards lining its banks.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.1;s:9:"longitude";d:44.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:12;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:12;a:17:{s:2:"id";i:530;s:7:"city_id";i:21;s:11:"external_id";s:15:"sadd-wadi-tuban";s:4:"name";s:39:"سد وادي تبن (التحويلي)";s:7:"name_en";s:26:"Wadi Tuban Dam (Diversion)";s:11:"description";s:307:"سد تحويلي رئيسي يقع على مجرى وادي تبن. [2] وظيفته الأساسية هي تنظيم وتوزيع مياه السيول عبر شبكة من القنوات لري دلتا تبن الشاسعة، ويعتبر من أهم المنشآت المائية في المحافظة.";s:14:"description_en";s:270:"A major diversion dam located along the course of Wadi Tuban. [2] Its primary function is to regulate and distribute floodwaters through a network of canals to irrigate the vast Tuban Delta. It is considered one of the most important water facilities in the governorate.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:11:"engineering";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:10:"هندسي";i:3;s:10:"زراعة";}s:8:"latitude";d:13.2;s:9:"longitude";d:44.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:13;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:13;a:17:{s:2:"id";i:531;s:7:"city_id";i:21;s:11:"external_id";s:15:"wadi-al-maflahi";s:4:"name";s:23:"وادي المفلحي";s:7:"name_en";s:15:"Wadi Al-Maflahi";s:11:"description";s:273:"وادي رئيسي يقع في مديرية المفلحي في يافع. [3] يشتهر الوادي بخصوبته وزراعة البن اليافعي الفاخر، وتجري فيه المياه بعد هطول الأمطار على المرتفعات الجبلية.";s:14:"description_en";s:225:"A main valley situated in the Al-Maflahi district in Yafa'a. [3] The valley is famous for its fertility and the cultivation of premium Yafa'i coffee, with water flowing through it following rains on the mountainous highlands.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:8:"جبلي";}s:8:"latitude";d:13.7;s:9:"longitude";d:45.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:14;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:14;a:17:{s:2:"id";i:532;s:7:"city_id";i:21;s:11:"external_id";s:11:"wadi-radfan";s:4:"name";s:19:"وادي ردفان";s:7:"name_en";s:11:"Wadi Radfan";s:11:"description";s:284:"وادي هام يقع في منطقة ردفان الجبلية. [4] لعب الوادي دوراً استراتيجياً خلال فترة الثورة، وتتميز ضفافه بالخضرة الموسمية، ويعتبر مصدراً للمياه للمناطق المحيطة.";s:14:"description_en";s:211:"An important valley located in the mountainous Radfan region. [4] It played a strategic role during the revolution period. Its banks feature seasonal greenery, and it is a water source for the surrounding areas.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:10:"historical";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:12:"تاريخي";i:3;s:10:"موسمي";}s:8:"latitude";d:13.45;s:9:"longitude";d:44.85;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:15;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:15;a:17:{s:2:"id";i:533;s:7:"city_id";i:21;s:11:"external_id";s:16:"sadd-al-habilayn";s:4:"name";s:21:"سد الحبيلين";s:7:"name_en";s:15:"Al-Habilayn Dam";s:11:"description";s:253:"سد صغير يقع بالقرب من مدينة الحبيلين في ردفان. [5] تم بناؤه لحصاد مياه الأمطار وتوفير مصدر مياه إضافي للسكان والزراعة في هذه المنطقة الجبلية.";s:14:"description_en";s:195:"A small dam located near Al-Habilayn city in Radfan. [5] It was constructed to harvest rainwater and provide an additional water supply for the residents and agriculture in this mountainous area.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:5:"local";i:3;s:8:"mountain";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:8:"محلي";i:3;s:8:"جبلي";}s:8:"latitude";d:13.5;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:16;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:16;a:17:{s:2:"id";i:534;s:7:"city_id";i:21;s:11:"external_id";s:17:"wadi-al-mudhariba";s:4:"name";s:25:"وادي المضاربة";s:7:"name_en";s:17:"Wadi Al-Madaribah";s:11:"description";s:310:"وادي ساحلي يقع في مديرية المضاربة ورأس العارة ويصب في البحر الأحمر. [6] تجري فيه السيول القادمة من المرتفعات الغربية، وتعتمد عليه الزراعة المحدودة في تلك المنطقة الساحلية.";s:14:"description_en";s:211:"A coastal valley located in the Al-Madaribah wa Ras Al-Arah district, emptying into the Red Sea. [6] Floods from the western highlands flow into it, and the limited agriculture in that coastal zone relies on it.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:7:"coastal";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"ساحلي";i:3;s:10:"موسمي";}s:8:"latitude";d:12.7;s:9:"longitude";d:44.1;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:17;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:17;a:17:{s:2:"id";i:535;s:7:"city_id";i:21;s:11:"external_id";s:9:"wadi-yahr";s:4:"name";s:15:"وادي يهر";s:7:"name_en";s:9:"Wadi Yahr";s:11:"description";s:295:"أحد الأودية الهامة في منطقة يافع، ويشتهر بمناظره الطبيعية الجبلية الخلابة. [3] تنتشر على ضفافه القرى والمدرجات الزراعية التي تزرع فيها مختلف المحاصيل وأشجار البن.";s:14:"description_en";s:193:"One of the vital valleys in the Yafa'a region, celebrated for its stunning mountainous landscapes. [3] Villages and agricultural terraces line its banks, growing various crops and coffee trees.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:6:"scenic";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:21:"مناظر خلابة";i:3;s:10:"زراعة";}s:8:"latitude";d:13.65;s:9:"longitude";d:45.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:18;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:18;a:17:{s:2:"id";i:536;s:7:"city_id";i:21;s:11:"external_id";s:15:"sadd-al-thumair";s:4:"name";s:17:"سد الثمير";s:7:"name_en";s:14:"Al-Thumair Dam";s:11:"description";s:304:"سد ترابي يقع في منطقة كرش، ويهدف إلى حجز مياه السيول للاستفادة منها في الزراعة وتغذية المياه الجوفية. [7] يعتبر من المشاريع المائية الهامة في المناطق الحدودية للمحافظة.";s:14:"description_en";s:210:"An earthen dam located in the Kirsh area, intended to impound floodwaters for use in agriculture and to recharge groundwater. [7] It is considered an important water project in the governorate's border regions.";s:10:"categories";a:4:{i:0;s:3:"dam";i:1;s:5:"water";i:2;s:11:"agriculture";i:3;s:9:"community";}s:14:"category_names";a:4:{i:0;s:4:"سد";i:1;s:8:"مائي";i:2;s:10:"زراعة";i:3;s:12:"مجتمعي";}s:8:"latitude";d:13.4;s:9:"longitude";d:44.75;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:19;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:19;a:17:{s:2:"id";i:537;s:7:"city_id";i:21;s:11:"external_id";s:11:"wadi-halmin";s:4:"name";s:21:"وادي حالمين";s:7:"name_en";s:11:"Wadi Halmin";s:11:"description";s:310:"الوادي الرئيسي في مديرية حالمين، ويتميز بمروره عبر منطقة جبلية ذات طبيعة جميلة. [8] يعتمد عليه السكان بشكل كبير في الزراعة وتوفير المياه، وتزداد أهميته خلال مواسم الأمطار.";s:14:"description_en";s:227:"The main valley in the Halmin district, characterized by its passage through a beautiful mountain landscape. [8] Residents heavily depend on it for farming and water supply, with its importance surging during the rainy seasons.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:8:"mountain";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:8:"جبلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.65;s:9:"longitude";d:45.05;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:20;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:20;a:17:{s:2:"id";i:538;s:7:"city_id";i:21;s:11:"external_id";s:12:"wadi-al-qaha";s:4:"name";s:21:"وادي القاحة";s:7:"name_en";s:13:"Wadi Al-Qahah";s:11:"description";s:270:"وادي يقع في مديرية طور الباحة، وهي منطقة انتقالية بين السهل الساحلي والمرتفعات. [9] تجري فيه السيول الموسمية، وتعتمد عليه الزراعة والرعي في المديرية.";s:14:"description_en";s:210:"A valley located in the Tur Al-Baha district, serving as a transitional zone between the coastal plain and the highlands. [9] Seasonal floods flow through it, supporting agriculture and grazing in the district.";s:10:"categories";a:4:{i:0;s:6:"valley";i:1;s:5:"water";i:2;s:8:"seasonal";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"وادي";i:1;s:8:"مائي";i:2;s:10:"موسمي";i:3;s:10:"زراعة";}s:8:"latitude";d:13.2;s:9:"longitude";d:44.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:21;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:21;a:17:{s:2:"id";i:539;s:7:"city_id";i:21;s:11:"external_id";s:21:"wadi-tuban-delta-park";s:4:"name";s:35:"منتزه دلتا وادي تبن";s:7:"name_en";s:21:"Wadi Tuban Delta Park";s:11:"description";s:338:"تعتبر دلتا وادي تبن الشاسعة، ببساتينها ومزارعها وقنواتها المائية، أكبر منتزه طبيعي مفتوح في المحافظة. [1] يقصدها السكان للنزهات الخلوية (الكشتات) بين المزارع والاستمتاع بالخضرة والهدوء.";s:14:"description_en";s:223:"The vast Tuban Wadi Delta, with its orchards, farms, and water canals, acts as the largest open natural park in the governorate. [1] Locals go there for outdoor picnics among the farms to enjoy the greenery and tranquility.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:11:"agriculture";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:10:"زراعة";i:3;s:21:"مناظر خلابة";}s:8:"latitude";i:13;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:22;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:22;a:17:{s:2:"id";i:540;s:7:"city_id";i:21;s:11:"external_id";s:20:"yafea-mountain-falls";s:4:"name";s:47:"شلالات جبال يافع الموسمية";s:7:"name_en";s:36:"Yafa'a Mountains Seasonal Waterfalls";s:11:"description";s:319:"المرتفعات الشاهقة في يافع (مثل جبل ثمر، جبل العر) هي مصدر للعديد من السيول. بعد الأمطار الغزيرة، تتشكل على هذه المرتفعات شلالات رائعة تنحدر بقوة نحو الوديان، وتوفر مناظر مهيبة.";s:14:"description_en";s:241:"The towering highlands of Yafa'a (such as Mount Thamar and Mount Al-Urr) are the source of many floods. After heavy rains, magnificent waterfalls form on these heights, cascading down powerfully into the valleys and offering majestic sights.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:6:"قوي";}s:8:"latitude";d:13.78;s:9:"longitude";d:45.25;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:23;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:23;a:17:{s:2:"id";i:541;s:7:"city_id";i:21;s:11:"external_id";s:21:"radfan-highlands-park";s:4:"name";s:36:"منتزه مرتفعات ردفان";s:7:"name_en";s:21:"Radfan Highlands Park";s:11:"description";s:338:"المنطقة الجبلية المحيطة بمدينة الحبيلين في ردفان تعتبر منتزهاً طبيعياً. [2] توفر هذه المرتفعات إطلالات بانورامية ومسارات للمشي بين القرى الجبلية، وهي مثالية للاستمتاع بالطبيعة الجبلية.";s:14:"description_en";s:221:"The mountainous area surrounding the city of Al-Habilayn in Radfan is considered a natural park. [2] These highlands offer panoramic views and walking paths among mountain villages, ideal for appreciating mountain nature.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:12:"هايكنج";}s:8:"latitude";d:13.5;s:9:"longitude";d:44.9;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:24;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:24;a:17:{s:2:"id";i:542;s:7:"city_id";i:21;s:11:"external_id";s:20:"wadi-halmin-cascades";s:4:"name";s:34:"شلالات وادي حالمين";s:7:"name_en";s:22:"Wadi Halmin Waterfalls";s:11:"description";s:334:"في الأجزاء العلوية والمنحدرة من وادي حالمين، تتكون شلالات موسمية جميلة عند تدفق مياه الأمطار. [3] تجذب هذه الشلالات المؤقتة السكان المحليين للاستمتاع بمنظر المياه المتدفقة بين الصخور.";s:14:"description_en";s:193:"In the upper and steep sections of Wadi Halmin, beautiful seasonal waterfalls form when rainwater flows. [3] These temporary waterfalls draw locals to admire the water cascading over the rocks.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.68;s:9:"longitude";d:45.08;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:25;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:25;a:17:{s:2:"id";i:543;s:7:"city_id";i:21;s:11:"external_id";s:23:"al-husayni-gardens-park";s:4:"name";s:38:"منتزه بساتين الحسيني";s:7:"name_en";s:25:"Al-Husseini Orchards Park";s:11:"description";s:310:"تعتبر منطقة بساتين الحسيني الشهيرة بزراعة المانجو والموز، منتزهاً زراعياً فريداً. [1] يمكن للزوار التجول في الممرات بين البساتين والاستمتاع بظلال الأشجار ورائحة الفواكه.";s:14:"description_en";s:237:"The renowned Al-Husseini orchards area, famous for growing mangoes and bananas, serves as a unique agricultural park. [1] Visitors can stroll through the pathways between the orchards, enjoying the shade of trees and the scent of fruits.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:11:"agriculture";i:2;s:7:"natural";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"زراعة";i:2;s:10:"طبيعي";i:3;s:14:"استجمام";}s:8:"latitude";d:13.06;s:9:"longitude";d:44.87;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:26;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:26;a:17:{s:2:"id";i:544;s:7:"city_id";i:21;s:11:"external_id";s:26:"jabal-harir-viewpoint-park";s:4:"name";s:33:"منتزه مطل جبل حرير";s:7:"name_en";s:26:"Mount Harir Viewpoint Park";s:11:"description";s:340:"قمة جبل حرير والمناطق المحيطة بها توفر إطلالات بانورامية لا مثيل لها على المدرجات الزراعية والوديان السحيقة. [4] تعتبر هذه المطلات بمثابة منتزهات طبيعية للاستمتاع بجمال الطبيعة اليافعية.";s:14:"description_en";s:215:"The summit of Mount Harir and its surrounding areas provide unparalleled panoramic views of agricultural terraces and deep valleys. [4] These viewpoints act as natural parks for enjoying the beauty of Yafa'i nature.";s:10:"categories";a:4:{i:0;s:9:"viewpoint";i:1;s:4:"park";i:2;s:8:"mountain";i:3;s:6:"scenic";}s:14:"category_names";a:4:{i:0;s:6:"مطل";i:1;s:10:"منتزه";i:2;s:8:"جبلي";i:3;s:21:"مناظر خلابة";}s:8:"latitude";d:13.8;s:9:"longitude";d:45.2;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:27;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:27;a:17:{s:2:"id";i:545;s:7:"city_id";i:21;s:11:"external_id";s:21:"wadi-al-maflahi-falls";s:4:"name";s:53:"شلالات وادي المفلحي الموسمية";s:7:"name_en";s:35:"Wadi Al-Maflahi Seasonal Waterfalls";s:11:"description";s:271:"يتميز وادي المفلحي في يافع بانحداراته في بعض المناطق. بعد الأمطار، تتشكل فيه شلالات صغيرة وجداول مياه جارية بين مزارع البن، مما يضيف إلى جماله وسحره.";s:14:"description_en";s:193:"Wadi Al-Maflahi in Yafa'a is known for its steep inclines in certain areas. Following rainfall, small waterfalls and running streams form among the coffee farms, adding to its beauty and charm.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:11:"agriculture";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:10:"زراعة";}s:8:"latitude";d:13.72;s:9:"longitude";d:45.15;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:28;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:28;a:17:{s:2:"id";i:546;s:7:"city_id";i:21;s:11:"external_id";s:26:"tur-al-baha-highlands-park";s:4:"name";s:45:"منتزه مرتفعات طور الباحة";s:7:"name_en";s:26:"Tur Al-Baha Highlands Park";s:11:"description";s:314:"المرتفعات الجبلية في مديرية طور الباحة، والتي تطل على المناطق الساحلية، توفر أجواءً ألطف ومناظر طبيعية جميلة. [5] تعتبر هذه المناطق متنفساً طبيعياً ومنتزهاً لسكان المديرية.";s:14:"description_en";s:224:"The mountainous highlands in the Tur Al-Baha district, which overlook the coastal regions, offer a milder atmosphere and beautiful natural scenery. [5] These areas are a natural retreat and park for the district's residents.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:7:"natural";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:10:"طبيعي";i:3;s:6:"مطل";}s:8:"latitude";d:13.25;s:9:"longitude";d:44.55;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:29;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:29;a:17:{s:2:"id";i:547;s:7:"city_id";i:21;s:11:"external_id";s:16:"wadi-akhdar-park";s:4:"name";s:36:"منتزه الوادي الأخضر";s:7:"name_en";s:17:"Green Valley Park";s:11:"description";s:298:"اسم يطلق على العديد من المناطق الخصبة في لحج، خاصة أجزاء من وادي تبن وروافده التي تتميز بخضرتها الدائمة. [1] هذه المناطق تعتبر منتزهات طبيعية مفضلة للنزهات العائلية.";s:14:"description_en";s:191:"A name given to many fertile areas in Lahij, especially parts of Wadi Tuban and its tributaries known for their evergreen nature. [1] These spots are favored natural parks for family outings.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:8:"greenery";i:3;s:6:"valley";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"خضرة";i:3;s:8:"وادي";}s:8:"latitude";d:13.15;s:9:"longitude";d:44.8;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:30;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:30;a:17:{s:2:"id";i:548;s:7:"city_id";i:21;s:11:"external_id";s:26:"al-qabaytah-mountain-falls";s:4:"name";s:36:"شلالات جبال القبيطة";s:7:"name_en";s:33:"Al-Qabbaytah Mountains Waterfalls";s:11:"description";s:270:"مديرية القبيطة هي منطقة جبلية وعرة. تتسبب الأمطار الغزيرة في تدفق السيول من منحدراتها، مكونة شلالات موسمية قوية توفر منظراً طبيعياً جذاباً ومؤقتاً.";s:14:"description_en";s:201:"The Al-Qabbaytah district is a rugged mountain region. Heavy downpours cause floods to pour from its slopes, creating powerful seasonal waterfalls that provide an attractive and temporary natural view.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:6:"قوي";}s:8:"latitude";d:13.4;s:9:"longitude";d:44.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:31;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:31;a:17:{s:2:"id";i:549;s:7:"city_id";i:21;s:11:"external_id";s:17:"shaybah-waterfall";s:4:"name";s:17:"شلال شيبة";s:7:"name_en";s:17:"Shaybah Waterfall";s:11:"description";s:368:"يُعتبر من أشهر وأجمل الشلالات الموسمية في القبيطة. ينحدر من مرتفعات عالية في منطقة "شيبة"، ويتميز بقوة تدفقه وجمال منظره وهو يشق طريقه بين الصخور. يجذب الكثير من الزوار من داخل المديرية وخارجها لمشاهدته.";s:14:"description_en";s:285:"Considered one of the most famous and beautiful seasonal waterfalls in Al-Qabbaytah. Cascading from high elevations in the 'Shaybah' area, it is marked by its powerful flow and gorgeous scene as it cuts through the rocks. It attracts many visitors from inside and outside the district.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"scenic";i:3;s:8:"powerful";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:21:"مناظر خلابة";i:3;s:6:"قوي";}s:8:"latitude";d:13.42;s:9:"longitude";d:44.62;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:32;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:32;a:17:{s:2:"id";i:550;s:7:"city_id";i:21;s:11:"external_id";s:20:"ath-thujah-waterfall";s:4:"name";s:19:"شلال الثجة";s:7:"name_en";s:20:"Al-Thajjah Waterfall";s:11:"description";s:265:"شلال موسمي آخر يقع في منطقة الثجة. يتميز بمروره عبر منطقة صخرية ذات طبيعة وعرة، مما يمنحه منظراً فريداً. يعتبر وجهة للمغامرين ومحبي الطبيعة البكر.";s:14:"description_en";s:206:"Another seasonal waterfall located in the Al-Thajjah area. It passes through a rocky region with a rugged nature, giving it a unique look. It is a destination for adventurers and lovers of untouched nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:7:"natural";i:3;s:5:"rocky";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:10:"طبيعي";i:3;s:8:"صخري";}s:8:"latitude";d:13.45;s:9:"longitude";d:44.65;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:33;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:33;a:17:{s:2:"id";i:551;s:7:"city_id";i:21;s:11:"external_id";s:20:"wadi-akhdan-cascades";s:4:"name";s:30:"شلالات وادي أخدن";s:7:"name_en";s:22:"Wadi Akhdan Waterfalls";s:11:"description";s:313:"وادي أخدن هو أحد الأودية الرئيسية في القبيطة. عند تدفق السيول فيه، تتشكل على طول مجراه سلسلة من الشلالات المتتالية (Cascades) والبرك المائية، مما يجعله وجهة للسباحة والاستجمام.";s:14:"description_en";s:206:"Wadi Akhdan is one of the primary valleys in Al-Qabbaytah. When floods flow, a series of successive cascades and water pools form along its course, turning it into a destination for swimming and relaxation.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:6:"valley";i:3;s:10:"recreation";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"وادي";i:3;s:14:"استجمام";}s:8:"latitude";d:13.4;s:9:"longitude";d:44.58;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:34;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:34;a:17:{s:2:"id";i:552;s:7:"city_id";i:21;s:11:"external_id";s:17:"jabal-jalas-falls";s:4:"name";s:28:"شلالات جبل جالس";s:7:"name_en";s:22:"Mount Jalis Waterfalls";s:11:"description";s:325:"جبل جالس هو أحد أعلى القمم في المنطقة. تنحدر من سفوحه العديد من الشلالات الموسمية القوية بعد الأمطار مباشرة، وتوفر هذه الشلالات مناظر بانورامية مهيبة يمكن رؤيتها من مسافات بعيدة.";s:14:"description_en";s:193:"Mount Jalis is one of the highest peaks in the area. Directly after rainfall, many powerful seasonal waterfalls plunge from its slopes, providing majestic panoramic views visible from far away.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:8:"mountain";i:3;s:9:"viewpoint";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"جبلي";i:3;s:6:"مطل";}s:8:"latitude";d:13.48;s:9:"longitude";d:44.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:35;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:35;a:17:{s:2:"id";i:553;s:7:"city_id";i:21;s:11:"external_id";s:18:"al-hadab-waterfall";s:4:"name";s:23:"شلال الهَدَب";s:7:"name_en";s:18:"Al-Hadab Waterfall";s:11:"description";s:277:"يقع في منطقة الهَدَب، وهو شلال موسمي ينحدر من منطقة مرتفعة، ويشتهر بين السكان المحليين كوجهة للنزهة ومشاهدة تدفق المياه في قلب الطبيعة الجبلية القاسية.";s:14:"description_en";s:205:"Situated in the Al-Hadab area, it is a seasonal waterfall falling from high grounds. It is popular among locals as a spot for picnics and watching the water flow in the heart of the rugged mountain nature.";s:10:"categories";a:4:{i:0;s:9:"waterfall";i:1;s:8:"seasonal";i:2;s:5:"local";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:8:"شلال";i:1;s:10:"موسمي";i:2;s:8:"محلي";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.38;s:9:"longitude";d:44.63;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:36;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:36;a:17:{s:2:"id";i:554;s:7:"city_id";i:21;s:11:"external_id";s:16:"jabal-jalas-park";s:4:"name";s:26:"منتزه جبل جالس";s:7:"name_en";s:16:"Mount Jalis Park";s:11:"description";s:359:"يعتبر جبل جالس والمناطق المحيطة به أكبر منتزه طبيعي في القبيطة. يوفر إطلالات بانورامية تمتد لمسافات شاسعة، ويعتبر مكاناً مثالياً للمشي الجبلي (الهايكنج) والتخييم والاستمتاع بالهواء النقي والهدوء.";s:14:"description_en";s:201:"Mount Jalis and its surroundings form the largest natural park in Al-Qabbaytah. Offering sweeping panoramic views, it is a perfect place for hiking, camping, and enjoying the fresh air and tranquility.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:9:"viewpoint";i:3;s:6:"hiking";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:6:"مطل";i:3;s:12:"هايكنج";}s:8:"latitude";d:13.48;s:9:"longitude";d:44.6;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:37;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:37;a:17:{s:2:"id";i:555;s:7:"city_id";i:21;s:11:"external_id";s:24:"al-ashmus-highlands-park";s:4:"name";s:40:"منتزه مرتفعات الأشموس";s:7:"name_en";s:25:"Al-Ashmous Highlands Park";s:11:"description";s:306:"منطقة الأشموس هي منطقة مرتفعة تتميز بمناظرها الطبيعية الخلابة وقراها المتناثرة. تعتبر المنطقة بأكملها منتزهاً طبيعياً مفتوحاً، وتوفر أجواءً ألطف من المناطق المنخفضة.";s:14:"description_en";s:193:"The Al-Ashmous area is a highland marked by its stunning natural scenery and scattered villages. The whole area acts as an open natural park, offering cooler atmospheres than the lower regions.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:6:"scenic";i:3;s:7:"village";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:21:"مناظر خلابة";i:3;s:8:"قرية";}s:8:"latitude";d:13.46;s:9:"longitude";d:44.55;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:38;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:38;a:17:{s:2:"id";i:556;s:7:"city_id";i:21;s:11:"external_id";s:23:"wadi-akhdan-green-areas";s:4:"name";s:54:"منتزه مناطق وادي أخدن الخضراء";s:7:"name_en";s:28:"Wadi Akhdan Green Areas Park";s:11:"description";s:323:"بعد مواسم الأمطار، تتحول ضفاف وادي أخدن وبعض أجزائه إلى مناطق خضراء. يقصدها السكان المحليون للنزهات العائلية (الكشتات) والاستمتاع بالخضرة المؤقتة التي تكسر حدة الطبيعة الصخرية.";s:14:"description_en";s:203:"Following the rainy seasons, the banks and sections of Wadi Akhdan turn into green areas. Locals visit it for family outings to enjoy the temporary greenery that breaks the harshness of the rocky nature.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:7:"natural";i:2;s:6:"valley";i:3;s:8:"seasonal";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:10:"طبيعي";i:2;s:8:"وادي";i:3;s:10:"موسمي";}s:8:"latitude";d:13.4;s:9:"longitude";d:44.58;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:39;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:39;a:17:{s:2:"id";i:557;s:7:"city_id";i:21;s:11:"external_id";s:17:"al-karb-viewpoint";s:4:"name";s:21:"مطل الكَرَب";s:7:"name_en";s:18:"Al-Karab Viewpoint";s:11:"description";s:320:"منطقة الكَرَب هي نقطة مرتفعة ومطل طبيعي شهير في القبيطة. توفر إطلالة رائعة على الوديان والطرق المتعرجة في الأسفل، وهي مكان مفضل للتوقف والاستمتاع بالمنظر، خاصة عند غروب الشمس.";s:14:"description_en";s:226:"The Al-Karab area is an elevated point and a famous natural viewpoint in Al-Qabbaytah. It provides a gorgeous view of the valleys and winding roads below, serving as a favored stop to enjoy the scenery, particularly at sunset.";s:10:"categories";a:4:{i:0;s:9:"viewpoint";i:1;s:4:"park";i:2;s:6:"scenic";i:3;s:7:"natural";}s:14:"category_names";a:4:{i:0;s:6:"مطل";i:1;s:10:"منتزه";i:2;s:21:"مناظر خلابة";i:3;s:10:"طبيعي";}s:8:"latitude";d:13.43;s:9:"longitude";d:44.59;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:40;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}i:40;a:17:{s:2:"id";i:558;s:7:"city_id";i:21;s:11:"external_id";s:24:"al-maqatirah-border-park";s:4:"name";s:36:"منتزه حدود المقاطرة";s:7:"name_en";s:25:"Al-Maqatirah Borders Park";s:11:"description";s:342:"المناطق الحدودية بين القبيطة ومديرية المقاطرة (تعز) هي مناطق جبلية ذات طبيعة جميلة. تعتبر هذه المناطق منتزهات طبيعية مشتركة بين سكان المديريتين، وتتميز بمساراتها الجبلية ومناظرها الوعرة.";s:14:"description_en";s:221:"The border regions between Al-Qabbaytah and the Al-Maqatirah district (Taiz) are beautiful mountainous areas. Acting as shared natural parks for residents of both districts, they feature mountain trails and rugged vistas.";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:8:"mountain";i:2;s:7:"natural";i:3;s:6:"border";}s:14:"category_names";a:4:{i:0;s:10:"منتزه";i:1;s:8:"جبلي";i:2;s:10:"طبيعي";i:3;s:10:"حدودي";}s:8:"latitude";d:13.5;s:9:"longitude";d:44.5;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:41;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:16.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:59.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:27;a:13:{s:2:"id";i:9;s:4:"slug";s:5:"marib";s:4:"name";s:8:"مأرب";s:7:"name_en";s:5:"Marib";s:11:"description";N;s:14:"description_en";s:0:"";s:9:"image_url";s:14:"marib_city.jpg";s:6:"status";s:9:"published";s:8:"category";N;s:15:"landmarks_count";i:11;s:9:"landmarks";a:11:{i:0;a:17:{s:2:"id";i:266;s:7:"city_id";i:9;s:11:"external_id";s:9:"marib-dam";s:4:"name";s:26:"سد مأرب القديم";s:7:"name_en";s:13:"Old Marib Dam";s:11:"description";s:329:"أعجوبة هندسية ومن أشهر السدود في العالم القديم، بني في عهد مملكة سبأ. [1] يعتبر من أهم المعالم الأثرية في اليمن، وتدل بقاياه على عظمة الحضارة التي أدارت المياه ببراعة لري واحات شاسعة.";s:14:"description_en";s:299:"An engineering marvel and one of the most famous dams in the ancient world, built during the era of the Sabaean Kingdom. [1] Considered one of Yemen's most important archaeological landmarks, its ruins testify to the greatness of a civilization that ingeniously managed water to irrigate vast oases.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:11:"engineering";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"هندسي";i:3;s:8:"مائي";}s:8:"latitude";d:15.404;s:9:"longitude";d:45.336;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/marib/marib_dam_old1.jpg";i:1;s:41:"images/landmarks/marib/marib_dam_old2.jpg";}s:10:"sort_order";i:1;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:1;a:17:{s:2:"id";i:267;s:7:"city_id";i:9;s:11:"external_id";s:13:"barran-temple";s:4:"name";s:37:"معبد بران (عرش بلقيس)";s:7:"name_en";s:31:"Baran Temple (Throne of Bilqis)";s:11:"description";s:356:"معبد سبئي شهير كان مخصصاً للإله "المقة" (إله القمر). [2] يشتهر بأعمدته الخمسة الضخمة وبوابته المهيبة والباحة المقدسة التي كانت تقام فيها الطقوس الدينية، ويعتبر من أهم المعابد في شبه الجزيرة العربية.";s:14:"description_en";s:279:"A famous Sabaean temple that was dedicated to the deity 'Almaqah' (the Moon God). [2] It is renowned for its five massive columns, its majestic gate, and the sacred courtyard where religious rituals were held, making it one of the most important temples in the Arabian Peninsula.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:9:"religious";i:3;s:7:"sabaean";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"ديني";i:3;s:8:"سبئي";}s:8:"latitude";d:15.403;s:9:"longitude";d:45.346;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/marib/barran_temple1.jpg";i:1;s:41:"images/landmarks/marib/barran_temple2.jpg";}s:10:"sort_order";i:2;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:2;a:17:{s:2:"id";i:268;s:7:"city_id";i:9;s:11:"external_id";s:11:"awam-temple";s:4:"name";s:39:"معبد أوام (محرم بلقيس)";s:7:"name_en";s:28:"Awwam Temple (Mahram Bilqis)";s:11:"description";s:337:"أكبر معبد في اليمن القديم، وكان المعبد الرئيسي لمملكة سبأ. [3] يتميز بسوره البيضاوي الضخم وأعمدته الثمانية الشاهقة عند المدخل، وكان مركزاً دينياً وسياسياً وحجاً هاماً في العصور القديمة.";s:14:"description_en";s:259:"The largest temple in ancient Yemen and the main temple of the Sabaean Kingdom. [3] Characterized by its massive oval enclosure wall and the eight towering columns at the entrance, it was a crucial religious, political, and pilgrimage center in ancient times.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:9:"religious";i:3;s:7:"sabaean";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:8:"ديني";i:3;s:8:"سبئي";}s:8:"latitude";d:15.4;s:9:"longitude";d:45.355;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/marib/awam_temple1.jpg";i:1;s:39:"images/landmarks/marib/awam_temple2.jpg";}s:10:"sort_order";i:3;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:57.000000Z";}i:3;a:17:{s:2:"id";i:269;s:7:"city_id";i:9;s:11:"external_id";s:14:"old-marib-city";s:4:"name";s:34:"مدينة مأرب القديمة";s:7:"name_en";s:17:"Old City of Marib";s:11:"description";s:332:"أطلال عاصمة مملكة سبأ، تقع على تلة مرتفعة. [4] كانت مدينة محصنة تضم قصوراً ومعابد ومنازل، ولا تزال بقايا أسوارها ومبانيها الحجرية شاهدة على تاريخها العريق وأهميتها كمركز سياسي وتجاري.";s:14:"description_en";s:286:"The ruins of the capital of the Sabaean Kingdom, situated on an elevated hill. [4] It was a fortified city comprising palaces, temples, and houses. The remains of its walls and stone buildings still bear witness to its ancient history and significance as a political and commercial hub.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:5:"ruins";i:3;s:12:"ancient-city";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"أطلال";i:3;s:21:"مدينة قديمة";}s:8:"latitude";d:15.425;s:9:"longitude";d:45.335;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:42:"images/landmarks/marib/old_marib_city1.jpg";i:1;s:42:"images/landmarks/marib/old_marib_city2.jpg";}s:10:"sort_order";i:4;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:4;a:17:{s:2:"id";i:270;s:7:"city_id";i:9;s:11:"external_id";s:17:"marib-public-park";s:4:"name";s:33:"حديقة مأرب العامة ";s:7:"name_en";s:17:"Marib Public Park";s:11:"description";s:352:"تعتبر الحديقة العامة المنظمة الوحيدة داخل مدينة مأرب. [3, 4] تمثل متنفسًا هامًا للعائلات والأطفال داخل المدينة، وتضم مساحات خضراء وألعابًا ومناطق للجلوس، وتشهد إقبالًا كبيرًا خاصة في المساء. [3, 4]";s:14:"description_en";s:255:"Considered the only organized public park within the city of Marib. [3, 4] It represents an important retreat for families and children in the city, featuring green spaces, games, and seating areas. It draws large crowds, especially in the evening. [3, 4]";s:10:"categories";a:4:{i:0;s:4:"park";i:1;s:6:"family";i:2;s:12:"recreational";i:3;s:12:"neighborhood";}s:14:"category_names";a:4:{i:0;s:10:"حديقة";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";i:3;s:13:"حي سكني";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:5;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:5;a:17:{s:2:"id";i:271;s:7:"city_id";i:9;s:11:"external_id";s:15:"marib-land-park";s:4:"name";s:17:"مأرب لاند";s:7:"name_en";s:10:"Marib Land";s:11:"description";s:342:"منتزه ترفيهي خاص يقع في مدينة مأرب، ويعتبر وجهة رئيسية للألعاب والترفيه. [5] يضم مجموعة من الألعاب الكهربائية والإلكترونية، ويستقطب عددًا كبيرًا من الأطفال والعائلات الباحثة عن التسلية. [5]";s:14:"description_en";s:241:"A private amusement park located in Marib city, recognized as a main destination for rides and entertainment. [5] It features a range of electric and electronic games, attracting a large number of children and families seeking amusement. [5]";s:10:"categories";a:3:{i:0;s:14:"amusement-park";i:1;s:6:"family";i:2;s:12:"recreational";}s:14:"category_names";a:3:{i:0;s:10:"ملاهي";i:1;s:10:"عائلي";i:2;s:12:"ترفيهي";}s:8:"latitude";N;s:9:"longitude";N;s:15:"google_maps_url";N;s:6:"images";a:0:{}s:10:"sort_order";i:6;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:6;a:17:{s:2:"id";i:272;s:7:"city_id";i:9;s:11:"external_id";s:13:"marib-dam-new";s:4:"name";s:26:"سد مأرب الجديد";s:7:"name_en";s:13:"New Marib Dam";s:11:"description";s:371:"سد حديث بني في الثمانينيات بدعم من دولة الإمارات العربية المتحدة، بالقرب من موقع السد القديم. [5] يعتبر مشروعاً هندسياً ضخماً ساهم في إحياء الزراعة بالمنطقة، وشكل بحيرة كبيرة أضافت منظراً جمالياً للمنطقة.";s:14:"description_en";s:282:"A modern dam built in the 1980s with the support of the United Arab Emirates, close to the site of the old dam. [5] It is deemed a massive engineering project that contributed to reviving agriculture in the area, forming a large lake that added an aesthetic landscape to the region.";s:10:"categories";a:4:{i:0;s:6:"modern";i:1;s:11:"engineering";i:2;s:3:"dam";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"حديث";i:1;s:10:"هندسي";i:2;s:4:"سد";i:3;s:8:"مائي";}s:8:"latitude";d:15.445;s:9:"longitude";d:45.275;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:41:"images/landmarks/marib/marib_dam_new1.jpg";i:1;s:41:"images/landmarks/marib/marib_dam_new2.jpg";}s:10:"sort_order";i:7;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:7;a:17:{s:2:"id";i:273;s:7:"city_id";i:9;s:11:"external_id";s:12:"marib-museum";s:4:"name";s:34:"متحف مأرب الإقليمي";s:7:"name_en";s:21:"Marib Regional Museum";s:11:"description";s:347:"يضم المتحف مجموعة قيمة من القطع الأثرية التي تم اكتشافها في مواقع مختلفة بمحافظة مأرب. [6] يعرض المتحف تماثيل ونقوش مسندية وأدوات فخارية ومعدنية تحكي تاريخ مملكة سبأ والممالك اليمنية القديمة.";s:14:"description_en";s:258:"The museum houses a valuable collection of artifacts discovered across various sites in the Marib Governorate. [6] It displays statues, Musnad inscriptions, pottery, and metal tools that narrate the history of the Sabaean Kingdom and ancient Yemeni kingdoms.";s:10:"categories";a:4:{i:0;s:6:"museum";i:1;s:14:"archaeological";i:2;s:10:"historical";i:3;s:8:"cultural";}s:14:"category_names";a:4:{i:0;s:8:"متحف";i:1;s:8:"أثري";i:2;s:12:"تاريخي";i:3;s:10:"ثقافي";}s:8:"latitude";d:15.46;s:9:"longitude";d:45.325;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:40:"images/landmarks/marib/marib_museum1.jpg";i:1;s:40:"images/landmarks/marib/marib_museum2.jpg";}s:10:"sort_order";i:8;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:8;a:17:{s:2:"id";i:274;s:7:"city_id";i:9;s:11:"external_id";s:18:"ramlat-al-sabatayn";s:4:"name";s:25:"رملة السبعتين";s:7:"name_en";s:19:"Ramlat al-Sab'atayn";s:11:"description";s:330:"صحراء واسعة من الكثبان الرملية الذهبية تمتد شمال وشمال غرب مأرب. [8] تعتبر منظراً طبيعياً صحراوياً مهيباً، وتجذب هواة المغامرات الصحراوية والتخييم والاستمتاع بجمال الصحراء وصفائها.";s:14:"description_en";s:243:"A vast desert of golden sand dunes stretching north and northwest of Marib. [8] It represents a majestic natural desert landscape, attracting fans of desert adventures, camping, and those seeking to enjoy the beauty and serenity of the desert.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:6:"desert";i:2;s:10:"sand-dunes";i:3;s:9:"adventure";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:10:"صحراء";i:2;s:21:"كثبان رملية";i:3;s:14:"مغامرات";}s:8:"latitude";d:15.8;s:9:"longitude";d:45.5;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:46:"images/landmarks/marib/ramlat_al_sabatayn1.jpg";i:1;s:46:"images/landmarks/marib/ramlat_al_sabatayn2.jpg";}s:10:"sort_order";i:9;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:9;a:17:{s:2:"id";i:275;s:7:"city_id";i:9;s:11:"external_id";s:11:"wadi-adhana";s:4:"name";s:54:"وادي أذنة (قنوات الري القديمة)";s:7:"name_en";s:40:"Wadi Adhanah (Ancient Irrigation Canals)";s:11:"description";s:349:"الوادي الذي كان يرويه سد مأرب القديم عبر شبكة معقدة من قنوات الري. [9] لا تزال آثار القناتين الرئيسيتين (الجيشان والمبسط) وبقايا القنوات الفرعية شاهدة على العبقرية الهندسية للسبئيين في الزراعة.";s:14:"description_en";s:280:"The valley that was irrigated by the Old Marib Dam through a complex network of irrigation canals. [9] The traces of the two main canals (Al-Jaishan and Al-Mabsat) and the remnants of branch canals still stand as witnesses to the engineering genius of the Sabaeans in agriculture.";s:10:"categories";a:4:{i:0;s:14:"archaeological";i:1;s:10:"historical";i:2;s:11:"agriculture";i:3;s:5:"water";}s:14:"category_names";a:4:{i:0;s:8:"أثري";i:1;s:12:"تاريخي";i:2;s:10:"زراعي";i:3;s:8:"مائي";}s:8:"latitude";d:15.41;s:9:"longitude";d:45.34;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/marib/wadi_adhana1.jpg";i:1;s:39:"images/landmarks/marib/wadi_adhana2.jpg";}s:10:"sort_order";i:10;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}i:10;a:17:{s:2:"id";i:276;s:7:"city_id";i:9;s:11:"external_id";s:11:"jabal-balaq";s:4:"name";s:30:"سلسلة جبال البلق";s:7:"name_en";s:20:"Balaq Mountain Range";s:11:"description";s:315:"سلسلة جبلية تحيط بمدينة مأرب من جهة الجنوب والغرب، ومنها تم حفر الصخور لبناء السد القديم. [10] توفر هذه الجبال مناظر طبيعية قاسية وجميلة، وتضم نقوشاً صخرية ومواقع أثرية صغيرة.";s:14:"description_en";s:253:"A mountain range surrounding Marib city from the south and west; from these mountains, rocks were quarried to build the old dam. [10] These mountains offer rugged and beautiful natural scenery, harboring rock inscriptions and small archaeological sites.";s:10:"categories";a:4:{i:0;s:6:"nature";i:1;s:8:"mountain";i:2;s:10:"geological";i:3;s:10:"historical";}s:14:"category_names";a:4:{i:0;s:10:"طبيعي";i:1;s:6:"جبل";i:2;s:14:"جيولوجي";i:3;s:12:"تاريخي";}s:8:"latitude";d:15.38;s:9:"longitude";d:45.25;s:15:"google_maps_url";N;s:6:"images";a:2:{i:0;s:39:"images/landmarks/marib/jabal_balaq1.jpg";i:1;s:39:"images/landmarks/marib/jabal_balaq2.jpg";}s:10:"sort_order";i:11;s:9:"is_active";b:1;s:10:"created_at";s:27:"2026-03-11T01:45:14.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:58.000000Z";}}s:10:"created_at";s:27:"2026-03-11T01:45:12.000000Z";s:10:"updated_at";s:27:"2026-04-07T23:05:55.000000Z";}i:28;a:13:{s:2:"id";i:31;s:4:"slug";s:5:"masor";s:4:"name";s:8:"مصور";s:7:"name_en";s:5:"masor";s:11:"description";s:31:"من اجمل مدن اليمن";s:14:"description_en";s:32:"the very beutifull city in yemen";s:9:"image_url";s:231:"https://cdn.alweb.com/thumbs/arabcountriesguide/article/fit710x532/%D8%A7%D9%83%D8%AA%D8%B4%D9%81-%D8%A3%D8%A8%D8%B1%D8%B2-%D9%85%D9%85%D9%8A%D8%B2%D8%A7%D8%AA-%D8%B9%D8%A7%D8%B5%D9%85%D8%A9-%D8%A7%D9%84%D8%B1%D9%8A%D8%A7%D8%B6.jpg";s:6:"status";s:9:"published";s:8:"category";s:10:"historical";s:15:"landmarks_count";i:0;s:9:"landmarks";a:0:{}s:10:"created_at";s:27:"2026-04-23T21:56:10.000000Z";s:10:"updated_at";s:27:"2026-04-23T21:56:10.000000Z";}}s:5:"links";a:4:{s:5:"first";s:42:"http://localhost:8000/api/v1/cities?page=1";s:4:"last";s:42:"http://localhost:8000/api/v1/cities?page=1";s:4:"prev";N;s:4:"next";N;}s:4:"meta";a:8:{s:12:"current_page";i:1;s:4:"from";i:1;s:9:"last_page";i:1;s:5:"links";a:3:{i:0;a:3:{s:3:"url";N;s:5:"label";s:16:"&laquo; Previous";s:6:"active";b:0;}i:1;a:3:{s:3:"url";s:42:"http://localhost:8000/api/v1/cities?page=1";s:5:"label";s:1:"1";s:6:"active";b:1;}i:2;a:3:{s:3:"url";N;s:5:"label";s:12:"Next &raquo;";s:6:"active";b:0;}}s:4:"path";s:35:"http://localhost:8000/api/v1/cities";s:8:"per_page";i:100;s:2:"to";i:29;s:5:"total";i:29;}}	1780493744
